/// Deterministic xoshiro256++ PRNG for reproducible random tensor generation.
#[derive(Debug, Clone)]
struct Xoshiro256PlusPlus {
    s: [u64; 4],
}

impl Xoshiro256PlusPlus {
    fn new(seed: u64) -> Self {
        // SplitMix64 to expand seed into state
        let mut z = seed;
        let mut s = [0u64; 4];
        for slot in &mut s {
            z = z.wrapping_add(0x9e37_79b9_7f4a_7c15);
            let mut x = z;
            x = (x ^ (x >> 30)).wrapping_mul(0xbf58_476d_1ce4_e5b9);
            x = (x ^ (x >> 27)).wrapping_mul(0x94d0_49bb_1331_11eb);
            *slot = x ^ (x >> 31);
        }
        Self { s }
    }

    fn next_u64(&mut self) -> u64 {
        let result = (self.s[0].wrapping_add(self.s[3]))
            .rotate_left(23)
            .wrapping_add(self.s[0]);
        let t = self.s[1] << 17;
        self.s[2] ^= self.s[0];
        self.s[3] ^= self.s[1];
        self.s[1] ^= self.s[2];
        self.s[0] ^= self.s[3];
        self.s[2] ^= t;
        self.s[3] = self.s[3].rotate_left(45);
        result
    }

    /// Uniform f64 in [0, 1).
    fn next_f64(&mut self) -> f64 {
        (self.next_u64() >> 11) as f64 / ((1u64 << 53) as f64)
    }

    /// Standard normal via Box-Muller transform.
    fn next_normal(&mut self) -> f64 {
        loop {
            let u1 = self.next_f64();
            let u2 = self.next_f64();
            if u1 > 0.0 {
                return (-2.0 * u1.ln()).sqrt() * (2.0 * std::f64::consts::PI * u2).cos();
            }
        }
    }

    /// Gamma(shape) using Marsaglia-Tsang method.
    fn next_gamma(&mut self, shape: f64) -> f64 {
        if shape < 1.0 {
            let u = self.next_f64();
            return self.next_gamma(shape + 1.0) * u.powf(1.0 / shape);
        }
        let d = shape - 1.0 / 3.0;
        let c = 1.0 / (9.0 * d).sqrt();
        loop {
            let x = self.next_normal();
            let v = 1.0 + c * x;
            if v > 0.0 {
                let v = v * v * v;
                let u = self.next_f64();
                if u < 1.0 - 0.0331 * (x * x) * (x * x)
                    || u.ln() < 0.5 * x * x + d * (1.0 - v + v.ln())
                {
                    return d * v;
                }
            }
        }
    }

    /// Beta(alpha, beta) via ratio of Gamma variates.
    fn next_beta(&mut self, alpha: f64, beta: f64) -> f64 {
        let x = self.next_gamma(alpha);
        let y = self.next_gamma(beta);
        x / (x + y)
    }
}

#[derive(Debug, Clone)]
pub struct FrankenTorchSession {
    tape: Tape,
    tensor_tape: TensorTape,
    runtime: RuntimeContext,
    rng: Xoshiro256PlusPlus,
    grad_enabled_stack: Vec<bool>,
    /// Autocast stack: each entry is either None (autocast disabled) or
    /// Some(target_dtype). The top of the stack determines current state.
    autocast_stack: Vec<Option<DType>>,
}

