    pub fn arange(
        &mut self,
        start: f64,
        end: f64,
        step: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !start.is_finite() || !end.is_finite() || !step.is_finite() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "arange: start/end/step must be finite",
                },
            )));
        }
        if step == 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "arange: step must not be zero",
                },
            )));
        }
        let mut values = Vec::new();
        let mut current = start;
        if step > 0.0 {
            while current < end {
                values.push(current);
                let next = current + step;
                if next <= current {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "arange: step does not advance at current floating-point precision",
                        },
                    )));
                }
                current = next;
            }
        } else {
            while current > end {
                values.push(current);
                let next = current + step;
                if next >= current {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "arange: step does not advance at current floating-point precision",
                        },
                    )));
                }
                current = next;
            }
        }
        let n = values.len();
        self.tensor_tape.leaf(values, vec![n], requires_grad)
    }

    /// Create a 2-D identity matrix of size n x n.
    /// Square subsequent mask for transformer decoder attention.
    ///
    /// Equivalent to `torch.nn.Transformer.generate_square_subsequent_mask(sz)`.
    /// Returns a `[sz, sz]` 2-D tensor where each element above the
    /// main diagonal is `-inf` and each element on or below is `0.0`.
    /// Added to attention scores (typically after the QK^T / sqrt(d_k)
    /// scaling) before softmax so that softmax(score + mask) zeros out
    /// the future positions. Tracked under frankentorch-2heg.
    pub fn causal_mask(&mut self, size: usize) -> Result<TensorNodeId, AutogradError> {
        if size == 0 {
            return self.tensor_variable(Vec::new(), vec![0, 0], false);
        }
        let mut data = vec![0.0_f64; size * size];
        for i in 0..size {
            for j in (i + 1)..size {
                data[i * size + j] = f64::NEG_INFINITY;
            }
        }
        self.tensor_variable(data, vec![size, size], false)
    }

    pub fn eye(&mut self, n: usize, requires_grad: bool) -> Result<TensorNodeId, AutogradError> {
        let numel = Self::checked_square_numel(n, "eye shape volume overflow")?;
        let mut values = vec![0.0; numel];
        for i in 0..n {
            values[i * n + i] = 1.0;
        }
        self.tensor_tape.leaf(values, vec![n, n], requires_grad)
    }

    /// Create a diagonal matrix from a 1-D tensor, or extract the diagonal of a 2-D tensor.
    ///
    /// If input is 1-D of length n, returns a 2-D tensor of shape [n, n] with the input as diagonal.
    /// If input is 2-D of shape [m, n], returns a 1-D tensor of length min(m, n) with the diagonal.
    ///
    /// Delegates to `tensor_diag(input, 0)` for the main-diagonal case
    /// (frankentorch-rikh). The previous 1-D path materialised a full
    /// [n, n] identity matrix and did n² multiplications to place n
    /// values; `tensor_diag_embed` (called via `tensor_diag`) writes
    /// only the diagonal positions directly. The previous 2-D path
    /// composed gather + narrow + reshape; `tensor_diagonal` is a
    /// dedicated shape op. Same surface, fewer allocations, single
    /// torch-parity path.
    pub fn diag(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_diag(input, 0)
    }

    /// Return the upper triangular part of a 2-D tensor.
    ///
    /// Elements below the k-th diagonal are set to 0. k=0 is the main diagonal,
    /// k>0 is above, k<0 is below.
    pub fn triu(&mut self, input: TensorNodeId, k: i64) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension to surface actual rank +
            // expected rank (frankentorch-qaux).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];
        let numel = m.checked_mul(n).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triu shape volume overflow",
                },
            ))
        })?;
        // Range-derived fill (frankentorch-98kt): per row i, the
        // upper-triangle column range is [max(0, i + k), n). Skip
        // the per-cell branch and let .fill() compile to memset
        // over the contiguous slice. -O(m*n / 2) iterations + no
        // mispredicts on attention-mask shapes.
        let mut mask = vec![0.0; numel];
        for i in 0..m {
            let start_signed = i as i64 + k;
            let start = start_signed.max(0).min(n as i64) as usize;
            mask[i * n + start..i * n + n].fill(1.0);
        }
        let mask_tensor = self.tensor_variable(mask, vec![m, n], false)?;
        self.tensor_mul(input, mask_tensor)
    }

    /// Return the lower triangular part of a 2-D tensor.
    ///
    /// Elements above the k-th diagonal are set to 0. k=0 is the main diagonal.
    pub fn tril(&mut self, input: TensorNodeId, k: i64) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-qaux).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];
        let numel = m.checked_mul(n).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tril shape volume overflow",
                },
            ))
        })?;
        // Range-derived fill (frankentorch-98kt): per row i, the
        // lower-triangle column range is [0, min(n, max(0, i+k+1))).
        // .fill() compiles to memset over the contiguous slice.
        let mut mask = vec![0.0; numel];
        for i in 0..m {
            let end_signed = i as i64 + k + 1;
            let end = end_signed.max(0).min(n as i64) as usize;
            mask[i * n..i * n + end].fill(1.0);
        }
        let mask_tensor = self.tensor_variable(mask, vec![m, n], false)?;
        self.tensor_mul(input, mask_tensor)
    }

    /// Return the indices of the lower triangular part of a (row, col) matrix.
    ///
    /// Equivalent to `torch.tril_indices(row, col, offset=0)`.
    /// Returns a 2-D tensor of shape `[2, N]` where row 0 contains row indices
    /// and row 1 contains column indices.
    pub fn tril_indices(
        &mut self,
        row: usize,
        col: usize,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        // Range-derived push (frankentorch-nyzz): per row i, the
        // lower-triangle column range is [0, min(col, max(0, i+offset+1))).
        // Skip the per-cell branch and pre-allocate with the
        // worst-case capacity to avoid Vec realloc churn.
        let cap = row.saturating_mul(col);
        let mut rows = Vec::with_capacity(cap);
        let mut cols = Vec::with_capacity(cap);
        for i in 0..row {
            let end_signed = (i as i64) + offset + 1;
            let end = end_signed.max(0).min(col as i64) as usize;
            for j in 0..end {
                rows.push(i as f64);
                cols.push(j as f64);
            }
        }
        let n = rows.len();
        rows.extend(cols);
        self.tensor_variable(rows, vec![2, n], false)
    }

    /// Return the indices of the upper triangular part of a (row, col) matrix.
    ///
    /// Equivalent to `torch.triu_indices(row, col, offset=0)`.
    /// Returns a 2-D tensor of shape `[2, N]` where row 0 contains row indices
    /// and row 1 contains column indices.
    pub fn triu_indices(
        &mut self,
        row: usize,
        col: usize,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        // Range-derived push (frankentorch-nyzz): per row i, the
        // upper-triangle column range is [max(0, i+offset), col).
        // Skip the per-cell branch and pre-allocate with worst-case
        // capacity.
        let cap = row.saturating_mul(col);
        let mut rows = Vec::with_capacity(cap);
        let mut cols = Vec::with_capacity(cap);
        for i in 0..row {
            let start_signed = (i as i64) + offset;
            let start = start_signed.max(0).min(col as i64) as usize;
            for j in start..col {
                rows.push(i as f64);
                cols.push(j as f64);
            }
        }
        let n = rows.len();
        rows.extend(cols);
        self.tensor_variable(rows, vec![2, n], false)
    }

    /// Return the indices of the lower triangular part of a (row, col) matrix.
    ///
    /// Alias for `tril_indices`. Equivalent to `torch.tril_indices(row, col, offset)`.
    pub fn tensor_tril_indices(
        &mut self,
        row: usize,
        col: usize,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tril_indices(row, col, offset)
    }

    /// Return the indices of the upper triangular part of a (row, col) matrix.
    ///
    /// Alias for `triu_indices`. Equivalent to `torch.triu_indices(row, col, offset)`.
    pub fn tensor_triu_indices(
        &mut self,
        row: usize,
        col: usize,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.triu_indices(row, col, offset)
    }

    /// Return the indices for the diagonal of an n×n matrix.
    ///
    /// Equivalent to `torch.diag_indices(n)`. Returns a tuple of two
    /// tensors (row_indices, col_indices) each of shape `[n]`.
    pub fn diag_indices(
        &mut self,
        n: usize,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let indices: Vec<f64> = (0..n).map(|i| i as f64).collect();
        let row_indices = self.tensor_variable(indices.clone(), vec![n], false)?;
        let col_indices = self.tensor_variable(indices, vec![n], false)?;
        Ok((row_indices, col_indices))
    }

    /// Return the indices for the diagonal of an n×n matrix.
    ///
    /// Alias for `diag_indices`. Equivalent to `torch.diag_indices(n)`.
    pub fn tensor_diag_indices(
        &mut self,
        n: usize,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        self.diag_indices(n)
    }

    /// Create a tensor filled with uniform random values in [0, 1).
    pub fn rand(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in rand")?;
        let values: Vec<f64> = (0..numel).map(|_| self.rng.next_f64()).collect();
        self.tensor_tape.leaf(values, shape, requires_grad)
    }

    /// Create a tensor filled with standard normal random values.
    pub fn randn(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in randn")?;
        let values: Vec<f64> = (0..numel).map(|_| self.rng.next_normal()).collect();
        self.tensor_tape.leaf(values, shape, requires_grad)
    }

    /// Create a tensor with the same shape as `other`, filled with uniform random values in [0, 1).
    pub fn rand_like(
        &mut self,
        other: TensorNodeId,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(other)?.clone();
        let shape = meta.shape().to_vec();
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in rand_like")?;
        let tensor = match meta.dtype() {
            DType::F64 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(self.rng.next_f64());
                }
                DenseTensor::from_contiguous_values(values, shape, meta.device())?
            }
            DType::F32 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(self.rng.next_f64() as f32);
                }
                DenseTensor::from_contiguous_values_f32(values, shape, meta.device())?
            }
            DType::F16 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Float16::from_f32(self.rng.next_f64() as f32));
                }
                DenseTensor::from_contiguous_values_f16(values, shape, meta.device())?
            }
            DType::BF16 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(BFloat16::from_f32(self.rng.next_f64() as f32));
                }
                DenseTensor::from_contiguous_values_bf16(values, shape, meta.device())?
            }
            DType::Complex64 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Complex64::new(
                        self.rng.next_f64() as f32,
                        self.rng.next_f64() as f32,
                    ));
                }
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex64(Arc::new(values)),
                )?
            }
            DType::Complex128 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Complex128::new(self.rng.next_f64(), self.rng.next_f64()));
                }
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex128(Arc::new(values)),
                )?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "rand_like: unsupported dtype",
                    },
                )));
            }
        };
        Ok(self.tensor_tape.leaf_tensor(tensor, requires_grad))
    }

    /// Create a tensor with the same shape as `other`, filled with standard normal random values.
    pub fn randn_like(
        &mut self,
        other: TensorNodeId,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(other)?.clone();
        let shape = meta.shape().to_vec();
        let numel = Self::checked_shape_numel(
            &shape,
            "tensor factory shape volume overflow in randn_like",
        )?;
        let tensor = match meta.dtype() {
            DType::F64 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(self.rng.next_normal());
                }
                DenseTensor::from_contiguous_values(values, shape, meta.device())?
            }
            DType::F32 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(self.rng.next_normal() as f32);
                }
                DenseTensor::from_contiguous_values_f32(values, shape, meta.device())?
            }
            DType::F16 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Float16::from_f32(self.rng.next_normal() as f32));
                }
                DenseTensor::from_contiguous_values_f16(values, shape, meta.device())?
            }
            DType::BF16 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(BFloat16::from_f32(self.rng.next_normal() as f32));
                }
                DenseTensor::from_contiguous_values_bf16(values, shape, meta.device())?
            }
            DType::Complex64 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Complex64::new(
                        self.rng.next_normal() as f32,
                        self.rng.next_normal() as f32,
                    ));
                }
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex64(Arc::new(values)),
                )?
            }
            DType::Complex128 => {
                let mut values = Vec::with_capacity(numel);
                for _ in 0..numel {
                    values.push(Complex128::new(
                        self.rng.next_normal(),
                        self.rng.next_normal(),
                    ));
                }
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex128(Arc::new(values)),
                )?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "randn_like: unsupported dtype",
                    },
                )));
            }
        };
        Ok(self.tensor_tape.leaf_tensor(tensor, requires_grad))
    }

    /// Create a tensor filled with random integers in `[low, high)`.
    ///
    /// Equivalent to `torch.randint(low, high, size)`.
    pub fn randint(
        &mut self,
        low: i64,
        high: i64,
        shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if high <= low {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "randint: high must be greater than low",
                },
            )));
        }
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in randint")?;
        let range = high.checked_sub(low).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "randint: high - low range overflow",
                },
            ))
        })? as f64;
        let values: Vec<f64> = (0..numel)
            .map(|_| (self.rng.next_f64() * range).floor() + low as f64)
            .collect();
        self.tensor_tape.leaf(values, shape, false)
    }

    /// Create a 1-D tensor of a random permutation of integers `[0, n)`.
    ///
    /// Equivalent to `torch.randperm(n)`.
    pub fn randperm(&mut self, n: usize) -> Result<TensorNodeId, AutogradError> {
        let mut perm: Vec<f64> = (0..n).map(|i| i as f64).collect();
        // Fisher-Yates shuffle
        for i in (1..n).rev() {
            let j = (self.rng.next_f64() * (i + 1) as f64).floor() as usize;
            let j = j.min(i); // safety clamp
            perm.swap(i, j);
        }
        self.tensor_tape.leaf(perm, vec![n], false)
    }

    /// Sample indices from a probability distribution (with or without replacement).
    ///
    /// Equivalent to `torch.multinomial(input, num_samples, replacement=False)`.
    /// `input` is a 1-D or 2-D tensor of non-negative weights (not required to sum to 1).
    /// Returns a tensor of sampled indices.
    pub fn multinomial(
        &mut self,
        input: TensorNodeId,
        num_samples: usize,
        replacement: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_tensor = self.tensor_tape.tensor(input)?;
        let input_dtype = input_tensor.meta().dtype();
        if !input_dtype.is_floating_point() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multinomial: input must be a real floating-point tensor",
                },
            )));
        }
        let vals = input_tensor
            .contiguous_values_as_f64()
            .map_err(AutogradError::DenseTensor)?;
        let shape = self.tensor_shape(input)?;

        let (batch, num_categories) = match shape.len() {
            1 => (1, shape[0]),
            2 => (shape[0], shape[1]),
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "multinomial: input must be 1-D or 2-D",
                    },
                )));
            }
        };

        if !replacement && num_samples > num_categories {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multinomial: num_samples exceeds num_categories without replacement",
                },
            )));
        }

        let result_len = Self::checked_mul(batch, num_samples, "multinomial output size overflow")?;
        let mut result = Vec::with_capacity(result_len);

        for b in 0..batch {
            let base = Self::checked_mul(b, num_categories, "multinomial index overflow")?;
            let end = Self::checked_add(base, num_categories, "multinomial index overflow")?;
            let mut weights: Vec<f64> = vals[base..end].to_vec();
            for &weight in &weights {
                if !weight.is_finite() || weight < 0.0 {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "multinomial: weights must be finite and non-negative",
                        },
                    )));
                }
            }
            let total: f64 = weights.iter().sum();
            if total <= 0.0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "multinomial: sum of weights must be positive",
                    },
                )));
            }
            if !replacement {
                let positive_count = weights.iter().filter(|&&weight| weight > 0.0).count();
                if num_samples > positive_count {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "multinomial: num_samples exceeds positive-weight categories without replacement",
                        },
                    )));
                }
            }

            for _ in 0..num_samples {
                // Normalize current weights
                let w_sum: f64 = weights.iter().sum();
                let r = self.rng.next_f64() * w_sum;
                let mut cumulative = 0.0;
                let mut chosen = num_categories - 1;
                for (j, &w) in weights.iter().enumerate() {
                    cumulative += w;
                    if r < cumulative {
                        chosen = j;
                        break;
                    }
                }
                result.push(chosen as f64);

                if !replacement {
                    weights[chosen] = 0.0;
                }
            }
        }

        let out_shape = if shape.len() == 1 {
            vec![num_samples]
        } else {
            vec![batch, num_samples]
        };
        self.tensor_variable(result, out_shape, false)
    }

    /// Sample from a Bernoulli distribution.
    ///
    /// Equivalent to `torch.bernoulli(input)`.
    /// `input` contains probabilities in [0, 1]. Returns a tensor of the same shape
    /// with values 0.0 or 1.0 sampled from Bernoulli(p) for each element p.
    pub fn bernoulli(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "bernoulli: autograd not supported (sampling is non-differentiable; use rsample-style reparameterization for diff'able sampling). Tracked under frankentorch-vugw.",
                },
            )));
        }
        let probs = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        for &p in &probs {
            Self::validate_probability(p, "bernoulli: probabilities must be finite and in [0, 1]")?;
        }
        let values: Vec<f64> = probs
            .iter()
            .map(|&p| if self.rng.next_f64() < p { 1.0 } else { 0.0 })
            .collect();
        self.tensor_variable(values, shape, false)
    }

    /// Create a tensor with each element sampled from a Bernoulli distribution
    /// with the given uniform probability.
    ///
    /// Equivalent to `torch.bernoulli(torch.full(shape, p))` or using `Tensor.bernoulli_(p)`.
    pub fn bernoulli_p(
        &mut self,
        shape: Vec<usize>,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        Self::validate_probability(p, "bernoulli_p: p must be finite and in [0, 1]")?;
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in bernoulli")?;
        let values: Vec<f64> = (0..numel)
            .map(|_| if self.rng.next_f64() < p { 1.0 } else { 0.0 })
            .collect();
        self.tensor_variable(values, shape, false)
    }

    /// Sample from a Poisson distribution element-wise.
    ///
    /// Equivalent to `torch.poisson(input)`.
    /// Each element of `input` is the rate parameter λ; returns integer samples
    /// (as f64) from Poisson(λ) for each element.
    pub fn poisson(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "poisson: autograd not supported (sampling is non-differentiable; use rsample-style reparameterization for diff'able sampling). Tracked under frankentorch-vugw.",
                },
            )));
        }
        let rates = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        for &lambda in &rates {
            Self::validate_poisson_rate(lambda)?;
        }

        let values: Vec<f64> = rates
            .iter()
            .map(|&lambda| {
                if lambda == 0.0 {
                    return 0.0;
                }
                // Knuth's algorithm for Poisson sampling
                let l = (-lambda).exp();
                let mut k = 0u64;
                let mut p = 1.0;
                loop {
                    k += 1;
                    p *= self.rng.next_f64();
                    if p <= l {
                        break;
                    }
                }
                (k - 1) as f64
            })
            .collect();
        self.tensor_variable(values, shape, false)
    }

    /// Create a 1-D tensor with `steps` evenly spaced values from `start` to `end` (inclusive).
    pub fn linspace(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let values = if steps == 0 {
            vec![]
        } else if steps == 1 {
            vec![start]
        } else {
            (0..steps)
                .map(|i| start + (end - start) * (i as f64) / ((steps - 1) as f64))
                .collect()
        };
        self.tensor_tape.leaf(values, vec![steps], requires_grad)
    }

    /// Create a 1-D tensor with `steps` logarithmically spaced values.
    ///
    /// Values are `base^linspace(start, end, steps)`.
    /// Default base is 10.0.
    pub fn logspace(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        base: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let values = if steps == 0 {
            vec![]
        } else if steps == 1 {
            vec![base.powf(start)]
        } else {
            (0..steps)
                .map(|i| {
                    let t = start + (end - start) * (i as f64) / ((steps - 1) as f64);
                    base.powf(t)
                })
                .collect()
        };
        self.tensor_tape.leaf(values, vec![steps], requires_grad)
    }

    /// Create a 1-D tensor with geometrically spaced values.
    ///
    /// Equivalent to `numpy.geomspace(start, end, steps)`.
    /// Values are evenly spaced on a log scale (geometric progression).
    pub fn geomspace(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if start == 0.0 || end == 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "geomspace: start and end must be non-zero",
                },
            )));
        }
        if (start < 0.0) != (end < 0.0) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "geomspace: start and end must have the same sign",
                },
            )));
        }
        let values = if steps == 0 {
            vec![]
        } else if steps == 1 {
            vec![start]
        } else {
            let ratio = (end / start).powf(1.0 / (steps - 1) as f64);
            (0..steps).map(|i| start * ratio.powi(i as i32)).collect()
        };
        self.tensor_tape.leaf(values, vec![steps], requires_grad)
    }

    /// Create a tensor without initializing values (filled with zeros in Rust).
    ///
    /// In Rust, memory is always initialized, so `empty` produces zeros.
    /// This is primarily for API compatibility with PyTorch.
    pub fn empty(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in empty")?;
        self.tensor_tape
            .leaf(vec![0.0; numel], shape, requires_grad)
    }

    /// Create an uninitialized tensor with the same shape as `other`.
    ///
    /// In Rust, this produces zeros (see `empty`).
    pub fn empty_like(
        &mut self,
        other: TensorNodeId,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.full_like(other, 0.0, requires_grad)
    }

    /// Create a tensor with the same shape as `other`, filled with `fill_value`.
    pub fn full_like(
        &mut self,
        other: TensorNodeId,
        fill_value: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(other)?.clone();
        let shape = meta.shape().to_vec();
        let numel =
            Self::checked_shape_numel(&shape, "tensor factory shape volume overflow in full_like")?;
        let tensor = match meta.dtype() {
            DType::F64 => {
                DenseTensor::from_contiguous_values(vec![fill_value; numel], shape, meta.device())?
            }
            DType::F32 => DenseTensor::from_contiguous_values_f32(
                vec![fill_value as f32; numel],
                shape,
                meta.device(),
            )?,
            DType::F16 => {
                let value = Float16::from_f32(fill_value as f32);
                DenseTensor::from_contiguous_values_f16(vec![value; numel], shape, meta.device())?
            }
            DType::BF16 => {
                let value = BFloat16::from_f32(fill_value as f32);
                DenseTensor::from_contiguous_values_bf16(vec![value; numel], shape, meta.device())?
            }
            DType::Complex64 => {
                let value = Complex64::new(fill_value as f32, 0.0);
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex64(Arc::new(vec![value; numel])),
                )?
            }
            DType::Complex128 => {
                let value = Complex128::new(fill_value, 0.0);
                DenseTensor::from_typed_storage(
                    meta.clone(),
                    TensorStorage::Complex128(Arc::new(vec![value; numel])),
                )?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "full_like: unsupported dtype",
                    },
                )));
            }
        };
        Ok(self.tensor_tape.leaf_tensor(tensor, requires_grad))
    }

    /// Create a tensor of zeros with the same shape as `other`.
    pub fn zeros_like(
        &mut self,
        other: TensorNodeId,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.full_like(other, 0.0, requires_grad)
    }

    /// Create a tensor of ones with the same shape as `other`.
    pub fn ones_like(
        &mut self,
        other: TensorNodeId,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.full_like(other, 1.0, requires_grad)
    }

    /// Reverse a tensor along the specified dimensions.
    ///
    /// Equivalent to PyTorch's `torch.flip(input, dims)`.
    pub fn tensor_flip(
        &mut self,
        input: TensorNodeId,
        dims: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.flip(input, dims.to_vec())
    }

    /// Repeat a tensor along each dimension.
    ///
    /// `repeats` specifies the number of repetitions for each output dimension.
    /// Its length must be greater than or equal to the input rank; when larger,
    /// leading singleton dimensions are implicitly prepended (PyTorch-compatible).
    pub fn tensor_repeat(
        &mut self,
        input: TensorNodeId,
        repeats: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.repeat(input, repeats.to_vec())
    }

    /// Roll tensor elements along the given dimension by `shift` positions.
    ///
    /// Elements that are shifted beyond the last position are re-introduced at
    /// the first position (circular shift).
    pub fn tensor_roll(
        &mut self,
        input: TensorNodeId,
        shift: i64,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shift = isize::try_from(shift).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_roll shift is out of range for platform isize",
                },
            ))
        })?;
        self.tensor_tape.roll(input, shift, dim)
    }

    pub fn tensor_add(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.add(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    pub fn tensor_mul(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.mul(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    pub fn tensor_sub(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.sub(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    pub fn tensor_div(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.div(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    pub fn tensor_matmul(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.matmul(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    /// Alias for tensor_matmul. Equivalent to torch.mm (matrix multiplication).
    pub fn tensor_mm(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_matmul(lhs, rhs)
    }

    pub fn tensor_dot(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.dot(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    /// Vector dot product of two 1D tensors.
    ///
    /// Equivalent to `torch.vdot(input, other)`. Both inputs must be 1D
    /// with the same number of elements. For complex tensors this would
    /// conjugate the first argument, but for real tensors it is
    /// equivalent to `tensor_dot`.
    pub fn tensor_vdot(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape_a = self.tensor_shape(input)?;
        let shape_b = self.tensor_shape(other)?;

        if shape_a.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vdot: input must be 1-D",
                },
            )));
        }
        if shape_b.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vdot: other must be 1-D",
                },
            )));
        }
        if shape_a[0] != shape_b[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vdot: input and other must have the same number of elements",
                },
            )));
        }

        self.tensor_dot(input, other)
    }

    pub fn tensor_outer(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.outer(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    /// Alias for tensor_outer. Equivalent to torch.ger (generalized outer product).
    pub fn tensor_ger(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_outer(lhs, rhs)
    }

    pub fn tensor_bmm(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.bmm(lhs, rhs, self.mode())?;
        self.record_tensor_operation(&event);
        Ok(out)
    }

    /// Batch matrix multiply with add: `out = beta * input + alpha * (batch1 @ batch2)`.
    ///
    /// Equivalent to `torch.baddbmm(input, batch1, batch2, beta=1, alpha=1)`.
    /// `batch1`: `[B, n, m]`, `batch2`: `[B, m, p]`, `input`: broadcastable to `[B, n, p]`.
    pub fn tensor_baddbmm(
        &mut self,
        input: TensorNodeId,
        batch1: TensorNodeId,
        batch2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let bmm_result = self.tensor_bmm(batch1, batch2)?;
        let out_shape = self.tensor_shape(bmm_result)?;

        // Scale bmm result by alpha
        let alpha_tensor = self.full(out_shape.clone(), alpha, false)?;
        let scaled_bmm = self.tensor_mul(bmm_result, alpha_tensor)?;

        // Scale input by beta and add
        let input_expanded = self.tensor_expand(input, out_shape.clone())?;
        let beta_tensor = self.full(out_shape, beta, false)?;
        let scaled_input = self.tensor_mul(input_expanded, beta_tensor)?;

        self.tensor_add(scaled_input, scaled_bmm)
    }

    /// Batch matrix multiply reduced to 2D with add: `out = beta * M + alpha * sum_b(batch1[b] @ batch2[b])`.
    ///
    /// Equivalent to `torch.addbmm(M, batch1, batch2, beta=1, alpha=1)`.
    /// Sums the batch matrix products and adds to `M`.
    pub fn tensor_addbmm(
        &mut self,
        input: TensorNodeId,
        batch1: TensorNodeId,
        batch2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let bmm_result = self.tensor_bmm(batch1, batch2)?;
        // Sum over batch dimension (dim 0)
        let summed = self.tensor_sum_dim(bmm_result, 0)?;
        let out_shape = self.tensor_shape(summed)?;

        let alpha_tensor = self.full(out_shape.clone(), alpha, false)?;
        let scaled = self.tensor_mul(summed, alpha_tensor)?;

        let input_expanded = self.tensor_expand(input, out_shape.clone())?;
        let beta_tensor = self.full(out_shape, beta, false)?;
        let scaled_input = self.tensor_mul(input_expanded, beta_tensor)?;

        self.tensor_add(scaled_input, scaled)
    }

    /// Scaled dot-product attention (PyTorch 2.0+).
    ///
    /// Equivalent to `torch.nn.functional.scaled_dot_product_attention(query, key, value, attn_mask, dropout_p, is_causal)`.
    ///
    /// Computes: `softmax(Q @ K^T / sqrt(d_k) + mask) @ V`
    ///
    /// `query`: `[*, L, E]`, `key`: `[*, S, E]`, `value`: `[*, S, Ev]`.
    /// Returns: `[*, L, Ev]`.
    pub fn scaled_dot_product_attention(
        &mut self,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
        attn_mask: Option<TensorNodeId>,
        dropout_p: f64,
        is_causal: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if is_causal && attn_mask.is_some() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: attn_mask cannot be combined with is_causal",
                },
            )));
        }
        let q_shape = self.tensor_shape(query)?;
        let k_shape = self.tensor_shape(key)?;

        if q_shape.len() < 2 || k_shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: Q/K must be at least 2-D",
                },
            )));
        }
        if !(0.0..=1.0).contains(&dropout_p) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: dropout_p must be in [0, 1]",
                },
            )));
        }

        let d_k = q_shape.last().copied().ok_or(AutogradError::Dispatch(
            ft_dispatch::DispatchError::Key(ft_dispatch::DispatchKeyError::IncompatibleSet {
                reason: "scaled_dot_product_attention: missing head dimension",
            }),
        ))?;
        if d_k == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: head dimension must be non-zero",
                },
            )));
        }
        let scale = 1.0 / (d_k as f64).sqrt();

        // Q @ K^T — use bmm for 3D batched inputs, matmul for 2D
        let ndim = k_shape.len();
        let key_t = self.tensor_transpose(key, ndim - 2, ndim - 1)?;
        let attn_weights = if ndim >= 3 {
            self.tensor_bmm(query, key_t)?
        } else {
            self.tensor_matmul(query, key_t)?
        };

        // Scale
        let aw_shape = self.tensor_shape(attn_weights)?;
        let softmax_dim = aw_shape.len() - 1;
        let scale_tensor = self.full(aw_shape.clone(), scale, false)?;
        let scaled = self.tensor_mul(attn_weights, scale_tensor)?;

        // Apply causal mask if requested
        let masked = if is_causal {
            let l = aw_shape[aw_shape.len() - 2];
            let s = aw_shape[aw_shape.len() - 1];
            if l == 0 || s == 0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scaled_dot_product_attention: sequence length must be non-zero",
                    },
                )));
            }
            let total = Self::checked_shape_numel(
                &aw_shape,
                "scaled_dot_product_attention: attention shape volume overflow",
            )?;
            let Some(batch_area) = l.checked_mul(s) else {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scaled_dot_product_attention: attention shape volume overflow",
                    },
                )));
            };
            let batch_count = total / batch_area;
            let mut mask_data = Vec::with_capacity(total);
            for _ in 0..batch_count {
                for i in 0..l {
                    for j in 0..s {
                        if j > i {
                            mask_data.push(f64::NEG_INFINITY);
                        } else {
                            mask_data.push(0.0);
                        }
                    }
                }
            }
            let causal_mask = self.tensor_variable(mask_data, aw_shape, false)?;
            self.tensor_add(scaled, causal_mask)?
        } else if let Some(mask) = attn_mask {
            self.tensor_add(scaled, mask)?
        } else {
            scaled
        };

        // Softmax along last dim
        let softmaxed = self.tensor_softmax(masked, softmax_dim)?;

        // Apply dropout
        let dropped = if dropout_p > 0.0 {
            self.functional_dropout(softmaxed, dropout_p, true)?
        } else {
            softmaxed
        };

        // attn_weights @ V
        if ndim >= 3 {
            self.tensor_bmm(dropped, value)
        } else {
            self.tensor_matmul(dropped, value)
        }
    }

    /// Multi-head attention forward pass.
    ///
    /// Equivalent to `torch.nn.functional.multi_head_attention_forward`.
    /// Projects query, key, value through linear layers, applies multi-head attention,
    /// and projects output.
    ///
    /// - `query`: `[tgt_len, batch, embed_dim]` or `[batch, tgt_len, embed_dim]` (if batch_first)
    /// - `key`: `[src_len, batch, embed_dim]` or `[batch, src_len, embed_dim]`
    /// - `value`: `[src_len, batch, embed_dim]` or `[batch, src_len, embed_dim]`
    /// - `in_proj_weight`: combined Q/K/V projection `[3*embed_dim, embed_dim]`
    /// - `in_proj_bias`: combined bias `[3*embed_dim]` (optional)
    /// - `out_proj_weight`: output projection `[embed_dim, embed_dim]`
    /// - `out_proj_bias`: output bias `[embed_dim]` (optional)
    /// - `num_heads`: number of attention heads
    /// - `dropout_p`: dropout probability
    /// - `batch_first`: if true, input shape is `[batch, seq, embed]`
    ///
    /// Returns `(attn_output, attn_weights)`.
    #[allow(clippy::too_many_arguments)]
    pub fn multi_head_attention_forward(
        &mut self,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
        in_proj_weight: TensorNodeId,
        in_proj_bias: Option<TensorNodeId>,
        out_proj_weight: TensorNodeId,
        out_proj_bias: Option<TensorNodeId>,
        num_heads: usize,
        dropout_p: f64,
        attn_mask: Option<TensorNodeId>,
        key_padding_mask: Option<TensorNodeId>,
        need_weights: bool,
        is_causal: bool,
        batch_first: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>), AutogradError> {
        if num_heads == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_head_attention_forward: num_heads must be positive",
                },
            )));
        }
        let q_shape = self.tensor_shape(query)?;
        if q_shape.len() != 3 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_head_attention_forward: query must be 3-D",
                },
            )));
        }
        let (tgt_len, bsz, embed_dim) = if batch_first {
            (q_shape[1], q_shape[0], q_shape[2])
        } else {
            (q_shape[0], q_shape[1], q_shape[2])
        };
        if embed_dim % num_heads != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_head_attention_forward: embed_dim must be divisible by num_heads",
                },
            )));
        }
        let head_dim = embed_dim / num_heads;
        let k_shape = self.tensor_shape(key)?;
        let src_len = if batch_first { k_shape[1] } else { k_shape[0] };

        // Transpose to [seq, batch, embed] if batch_first
        let (q, k, v) = if batch_first {
            let q_t = self.tensor_transpose(query, 0, 1)?;
            let k_t = self.tensor_transpose(key, 0, 1)?;
            let v_t = self.tensor_transpose(value, 0, 1)?;
            (q_t, k_t, v_t)
        } else {
            (query, key, value)
        };

        // Reshape [seq, batch, embed] -> [seq*batch, embed]
        let q_flat = self.tensor_reshape(q, vec![tgt_len * bsz, embed_dim])?;
        let k_flat = self.tensor_reshape(k, vec![src_len * bsz, embed_dim])?;
        let v_flat = self.tensor_reshape(v, vec![src_len * bsz, embed_dim])?;

        // Apply combined Q/K/V projection: [seq*batch, embed] @ [embed, 3*embed]^T
        let in_proj_weight_t = self.tensor_transpose(in_proj_weight, 0, 1)?;
        let w_q = self.tensor_narrow(in_proj_weight_t, 1, 0, embed_dim)?;
        let w_k = self.tensor_narrow(in_proj_weight_t, 1, embed_dim, embed_dim)?;
        let w_v = self.tensor_narrow(in_proj_weight_t, 1, 2 * embed_dim, embed_dim)?;
        let q_proj = self.tensor_matmul(q_flat, w_q)?;
        let k_proj = self.tensor_matmul(k_flat, w_k)?;
        let v_proj = self.tensor_matmul(v_flat, w_v)?;

        // Add biases if present
        let (q_proj, k_proj, v_proj) = if let Some(bias) = in_proj_bias {
            let q_bias = self.tensor_narrow(bias, 0, 0, embed_dim)?;
            let k_bias = self.tensor_narrow(bias, 0, embed_dim, embed_dim)?;
            let v_bias = self.tensor_narrow(bias, 0, 2 * embed_dim, embed_dim)?;
            let q_proj = self.tensor_add(q_proj, q_bias)?;
            let k_proj = self.tensor_add(k_proj, k_bias)?;
            let v_proj = self.tensor_add(v_proj, v_bias)?;
            (q_proj, k_proj, v_proj)
        } else {
            (q_proj, k_proj, v_proj)
        };

        // Reshape to [batch, num_heads, seq_len, head_dim]
        let q_heads = self.tensor_reshape(q_proj, vec![tgt_len, bsz, num_heads, head_dim])?;
        let q_heads = self.tensor_permute(q_heads, vec![1, 2, 0, 3])?;
        let k_heads = self.tensor_reshape(k_proj, vec![src_len, bsz, num_heads, head_dim])?;
        let k_heads = self.tensor_permute(k_heads, vec![1, 2, 0, 3])?;
        let v_heads = self.tensor_reshape(v_proj, vec![src_len, bsz, num_heads, head_dim])?;
        let v_heads = self.tensor_permute(v_heads, vec![1, 2, 0, 3])?;

        // Apply key_padding_mask if present
        let effective_mask = match (attn_mask, key_padding_mask) {
            (Some(am), Some(kpm)) => {
                // Combine: expand key_padding_mask and add to attn_mask
                let kpm_expanded = self.tensor_unsqueeze(kpm, 1)?;
                let kpm_expanded = self.tensor_unsqueeze(kpm_expanded, 2)?;
                let kpm_shape = self.tensor_shape(kpm_expanded)?;
                let zeros = self.tensor_zeros(kpm_shape, false)?;
                let kpm_float = self.tensor_masked_fill(zeros, kpm_expanded, f64::NEG_INFINITY)?;
                Some(self.tensor_add(am, kpm_float)?)
            }
            (Some(am), None) => Some(am),
            (None, Some(kpm)) => {
                let kpm_expanded = self.tensor_unsqueeze(kpm, 1)?;
                let kpm_expanded = self.tensor_unsqueeze(kpm_expanded, 2)?;
                let kpm_shape = self.tensor_shape(kpm_expanded)?;
                let zeros = self.tensor_zeros(kpm_shape, false)?;
                Some(self.tensor_masked_fill(zeros, kpm_expanded, f64::NEG_INFINITY)?)
            }
            (None, None) => None,
        };

        // Apply scaled_dot_product_attention
        let attn_output = self.scaled_dot_product_attention(
            q_heads, k_heads, v_heads, effective_mask, dropout_p, is_causal)?;

        // Compute attention weights if needed
        let attn_weights_out = if need_weights {
            let scale = 1.0 / (head_dim as f64).sqrt();
            let k_t = self.tensor_transpose(k_heads, 2, 3)?;
            let scores = self.tensor_matmul(q_heads, k_t)?;
            let scores_shape = self.tensor_shape(scores)?;
            let scale_tensor = self.full(scores_shape.clone(), scale, false)?;
            let scaled = self.tensor_mul(scores, scale_tensor)?;
            let softmax_dim = scores_shape.len() - 1;
            let weights = self.tensor_softmax(scaled, softmax_dim)?;
            // Average over head dimension (dim 1)
            let avg_weights = self.tensor_mean_dim(weights, 1)?;
            Some(avg_weights)
        } else {
            None
        };

        // Reshape: [batch, num_heads, tgt_len, head_dim] -> [tgt_len, batch, embed_dim]
        let attn_output = self.tensor_permute(attn_output, vec![2, 0, 1, 3])?;
        let attn_output = self.tensor_reshape(attn_output, vec![tgt_len, bsz, embed_dim])?;

        // Flatten for output projection
        let attn_flat = self.tensor_reshape(attn_output, vec![tgt_len * bsz, embed_dim])?;
        let out_proj_weight_t = self.tensor_transpose(out_proj_weight, 0, 1)?;
        let mut output = self.tensor_matmul(attn_flat, out_proj_weight_t)?;
        if let Some(bias) = out_proj_bias {
            output = self.tensor_add(output, bias)?;
        }
        let output = self.tensor_reshape(output, vec![tgt_len, bsz, embed_dim])?;

        // Transpose back if batch_first
        let output = if batch_first {
            self.tensor_transpose(output, 0, 1)?
        } else {
            output
        };

        Ok((output, attn_weights_out))
    }

    /// Extract non-overlapping patches from images (Vision Transformer).
    ///
    /// Converts image into sequence of flattened patch embeddings.
    /// For ViT: image [B, C, H, W] -> patches [B, num_patches, patch_dim]
    ///
    /// Args:
    /// - images: [B, C, H, W] input images
    /// - patch_size: size of each square patch
    ///
    /// Returns: [B, num_patches, C * patch_size * patch_size]
    pub fn patch_embed(
        &mut self,
        images: TensorNodeId,
        patch_size: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(images)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("patch_embed: images must be [B, C, H, W]"));
        }
        let (b, c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        if h % patch_size != 0 || w % patch_size != 0 {
            return Err(Self::incompatible_tensor_args(
                "patch_embed: H and W must be divisible by patch_size",
            ));
        }
        let nh = h / patch_size;
        let nw = w / patch_size;
        let num_patches = nh * nw;
        let patch_dim = c * patch_size * patch_size;
        let data = self.tensor_values(images)?;
        let mut patches = vec![0.0; b * num_patches * patch_dim];
        for bi in 0..b {
            for ph in 0..nh {
                for pw in 0..nw {
                    let patch_idx = ph * nw + pw;
                    for ch in 0..c {
                        for py in 0..patch_size {
                            for px in 0..patch_size {
                                let ih = ph * patch_size + py;
                                let iw = pw * patch_size + px;
                                let src_idx = bi * c * h * w + ch * h * w + ih * w + iw;
                                let dst_idx = bi * num_patches * patch_dim
                                    + patch_idx * patch_dim
                                    + ch * patch_size * patch_size
                                    + py * patch_size
                                    + px;
                                patches[dst_idx] = data[src_idx];
                            }
                        }
                    }
                }
            }
        }
        self.tensor_variable(patches, vec![b, num_patches, patch_dim], false)
    }

    /// Partition tensor into non-overlapping windows (Swin Transformer).
    ///
    /// Args:
    /// - x: [B, H, W, C] input features
    /// - window_size: size of each square window
    ///
    /// Returns: [num_windows * B, window_size, window_size, C]
    pub fn window_partition(
        &mut self,
        x: TensorNodeId,
        window_size: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("window_partition: x must be [B, H, W, C]"));
        }
        let (b, h, w, c) = (shape[0], shape[1], shape[2], shape[3]);
        if h % window_size != 0 || w % window_size != 0 {
            return Err(Self::incompatible_tensor_args(
                "window_partition: H and W must be divisible by window_size",
            ));
        }
        let nh = h / window_size;
        let nw = w / window_size;
        let num_windows = nh * nw;
        let data = self.tensor_values(x)?;
        let mut windows = vec![0.0; b * num_windows * window_size * window_size * c];
        for bi in 0..b {
            for wh in 0..nh {
                for ww in 0..nw {
                    let win_idx = bi * num_windows + wh * nw + ww;
                    for wy in 0..window_size {
                        for wx in 0..window_size {
                            let ih = wh * window_size + wy;
                            let iw = ww * window_size + wx;
                            for ch in 0..c {
                                let src_idx = bi * h * w * c + ih * w * c + iw * c + ch;
                                let dst_idx = win_idx * window_size * window_size * c
                                    + wy * window_size * c
                                    + wx * c
                                    + ch;
                                windows[dst_idx] = data[src_idx];
                            }
                        }
                    }
                }
            }
        }
        self.tensor_variable(windows, vec![b * num_windows, window_size, window_size, c], false)
    }

    /// Reverse window_partition operation (Swin Transformer).
    ///
    /// Args:
    /// - windows: [num_windows * B, window_size, window_size, C]
    /// - window_size: size of each square window
    /// - h, w: original height and width
    ///
    /// Returns: [B, H, W, C]
    pub fn window_reverse(
        &mut self,
        windows: TensorNodeId,
        window_size: usize,
        h: usize,
        w: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(windows)?;
        if shape.len() != 4 || shape[1] != window_size || shape[2] != window_size {
            return Err(Self::incompatible_tensor_args(
                "window_reverse: windows must be [N, window_size, window_size, C]",
            ));
        }
        let c = shape[3];
        let nh = h / window_size;
        let nw = w / window_size;
        let num_windows = nh * nw;
        let b = shape[0] / num_windows;
        let data = self.tensor_values(windows)?;
        let mut output = vec![0.0; b * h * w * c];
        for bi in 0..b {
            for wh in 0..nh {
                for ww in 0..nw {
                    let win_idx = bi * num_windows + wh * nw + ww;
                    for wy in 0..window_size {
                        for wx in 0..window_size {
                            let ih = wh * window_size + wy;
                            let iw = ww * window_size + wx;
                            for ch in 0..c {
                                let src_idx = win_idx * window_size * window_size * c
                                    + wy * window_size * c
                                    + wx * c
                                    + ch;
                                let dst_idx = bi * h * w * c + ih * w * c + iw * c + ch;
                                output[dst_idx] = data[src_idx];
                            }
                        }
                    }
                }
            }
        }
        self.tensor_variable(output, vec![b, h, w, c], false)
    }

    /// Alias for `multi_head_attention_forward`.
    #[allow(clippy::too_many_arguments)]
    pub fn functional_multi_head_attention_forward(
        &mut self,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
        in_proj_weight: TensorNodeId,
        in_proj_bias: Option<TensorNodeId>,
        out_proj_weight: TensorNodeId,
        out_proj_bias: Option<TensorNodeId>,
        num_heads: usize,
        dropout_p: f64,
        attn_mask: Option<TensorNodeId>,
        key_padding_mask: Option<TensorNodeId>,
        need_weights: bool,
        is_causal: bool,
        batch_first: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>), AutogradError> {
        self.multi_head_attention_forward(
            query, key, value, in_proj_weight, in_proj_bias, out_proj_weight, out_proj_bias,
            num_heads, dropout_p, attn_mask, key_padding_mask, need_weights, is_causal, batch_first)
    }

    /// Generate sinusoidal positional encodings for transformer models.
    ///
    /// Equivalent to the positional encoding from "Attention is All You Need".
    /// Returns tensor of shape `[max_len, d_model]` with sinusoidal patterns.
    ///
    /// PE(pos, 2i) = sin(pos / 10000^(2i/d_model))
    /// PE(pos, 2i+1) = cos(pos / 10000^(2i/d_model))
    pub fn sinusoidal_positional_encoding(
        &mut self,
        max_len: usize,
        d_model: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if d_model == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "sinusoidal_positional_encoding: d_model must be positive",
                },
            )));
        }
        let mut pe = vec![0.0_f64; max_len * d_model];
        for pos in 0..max_len {
            for i in 0..(d_model / 2) {
                let angle = (pos as f64) / 10000.0_f64.powf((2 * i) as f64 / d_model as f64);
                pe[pos * d_model + 2 * i] = angle.sin();
                pe[pos * d_model + 2 * i + 1] = angle.cos();
            }
            if d_model % 2 == 1 {
                let i = d_model / 2;
                let angle = (pos as f64) / 10000.0_f64.powf((2 * i) as f64 / d_model as f64);
                pe[pos * d_model + d_model - 1] = angle.sin();
            }
        }
        self.tensor_variable(pe, vec![max_len, d_model], false)
    }

    /// Apply Rotary Position Embedding (RoPE) to query and key tensors.
    ///
    /// RoPE encodes position information through rotation matrices applied to
    /// pairs of dimensions. Used in LLaMA, GPT-NeoX, and many modern LLMs.
    ///
    /// - `q`: query tensor `[..., seq_len, head_dim]`
    /// - `k`: key tensor `[..., seq_len, head_dim]`
    /// - `cos_cached`: precomputed cos values `[seq_len, head_dim/2]` or `[max_seq, head_dim/2]`
    /// - `sin_cached`: precomputed sin values, same shape
    /// - `position_ids`: optional position indices `[batch, seq_len]`
    ///
    /// Returns `(rotated_q, rotated_k)`.
    pub fn apply_rotary_pos_emb(
        &mut self,
        q: TensorNodeId,
        k: TensorNodeId,
        cos_cached: TensorNodeId,
        sin_cached: TensorNodeId,
        position_ids: Option<TensorNodeId>,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let q_shape = self.tensor_shape(q)?;
        let head_dim = *q_shape.last().ok_or(AutogradError::Dispatch(
            ft_dispatch::DispatchError::Key(ft_dispatch::DispatchKeyError::IncompatibleSet {
                reason: "apply_rotary_pos_emb: q must have at least 1 dimension",
            }),
        ))?;
        if head_dim % 2 != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "apply_rotary_pos_emb: head_dim must be even for RoPE",
                },
            )));
        }
        let cos = if let Some(pos_ids) = position_ids {
            self.tensor_index_select(cos_cached, 0, pos_ids)?
        } else {
            cos_cached
        };
        let sin = if let Some(pos_ids) = position_ids {
            self.tensor_index_select(sin_cached, 0, pos_ids)?
        } else {
            sin_cached
        };
        let rotate_half = |sess: &mut Self, x: TensorNodeId| -> Result<TensorNodeId, AutogradError> {
            let shape = sess.tensor_shape(x)?;
            let ndim = shape.len();
            let half = head_dim / 2;
            let x1 = sess.tensor_narrow(x, ndim - 1, 0, half)?;
            let x2 = sess.tensor_narrow(x, ndim - 1, half, half)?;
            let x2_neg = sess.tensor_neg(x2)?;
            sess.tensor_cat(&[x2_neg, x1], ndim - 1)
        };
        let q_embed = {
            let q_cos = self.tensor_mul(q, cos)?;
            let q_rot = rotate_half(self, q)?;
            let q_sin = self.tensor_mul(q_rot, sin)?;
            self.tensor_add(q_cos, q_sin)?
        };
        let k_embed = {
            let k_cos = self.tensor_mul(k, cos)?;
            let k_rot = rotate_half(self, k)?;
            let k_sin = self.tensor_mul(k_rot, sin)?;
            self.tensor_add(k_cos, k_sin)?
        };
        Ok((q_embed, k_embed))
    }

    /// Precompute RoPE frequencies for given max_seq_len and head_dim.
    ///
    /// Returns `(cos_cached, sin_cached)` both of shape `[max_seq_len, head_dim/2]`.
    /// These can be reused across batches and passed to `apply_rotary_pos_emb`.
    pub fn precompute_rope_freqs(
        &mut self,
        max_seq_len: usize,
        head_dim: usize,
        base: f64,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        if head_dim % 2 != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "precompute_rope_freqs: head_dim must be even",
                },
            )));
        }
        let half_dim = head_dim / 2;
        let mut freqs = vec![0.0_f64; half_dim];
        for i in 0..half_dim {
            freqs[i] = 1.0 / base.powf((2 * i) as f64 / head_dim as f64);
        }
        let mut cos_data = vec![0.0_f64; max_seq_len * half_dim];
        let mut sin_data = vec![0.0_f64; max_seq_len * half_dim];
        for pos in 0..max_seq_len {
            for i in 0..half_dim {
                let angle = (pos as f64) * freqs[i];
                cos_data[pos * half_dim + i] = angle.cos();
                sin_data[pos * half_dim + i] = angle.sin();
            }
        }
        let cos_node = self.tensor_variable(cos_data, vec![max_seq_len, half_dim], false)?;
        let sin_node = self.tensor_variable(sin_data, vec![max_seq_len, half_dim], false)?;
        Ok((cos_node, sin_node))
    }

    /// Alias for `sinusoidal_positional_encoding`.
    pub fn functional_sinusoidal_positional_encoding(
        &mut self,
        max_len: usize,
        d_model: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.sinusoidal_positional_encoding(max_len, d_model)
    }

    /// Generate ALiBi (Attention with Linear Biases) position biases.
    ///
    /// ALiBi is a simple, effective positional encoding method that adds linear
    /// biases to attention scores. Used in MPT, BLOOM, and other modern LLMs.
    ///
    /// Returns a bias tensor of shape `[num_heads, seq_len, seq_len]` to add to
    /// attention scores before softmax.
    ///
    /// The bias for head h at position i attending to position j is:
    ///   -slope[h] * |i - j|
    /// where slope[h] = 2^(-8 * h / num_heads) for h in 0..num_heads.
    pub fn alibi_bias(
        &mut self,
        num_heads: usize,
        seq_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if num_heads == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "alibi_bias: num_heads must be positive",
                },
            )));
        }
        let mut slopes = Vec::with_capacity(num_heads);
        let ratio = 8.0 / num_heads as f64;
        for h in 0..num_heads {
            slopes.push(2.0_f64.powf(-ratio * (h + 1) as f64));
        }
        let mut bias = vec![0.0_f64; num_heads * seq_len * seq_len];
        for h in 0..num_heads {
            for i in 0..seq_len {
                for j in 0..seq_len {
                    let distance = (i as i64 - j as i64).abs() as f64;
                    bias[h * seq_len * seq_len + i * seq_len + j] = -slopes[h] * distance;
                }
            }
        }
        self.tensor_variable(bias, vec![num_heads, seq_len, seq_len], false)
    }

    /// Get ALiBi slopes for given number of heads.
    ///
    /// Returns slope values `[num_heads]` where slope[h] = 2^(-8*h/num_heads).
    /// Useful when you want to compute ALiBi bias manually or with different patterns.
    pub fn alibi_slopes(
        &mut self,
        num_heads: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if num_heads == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "alibi_slopes: num_heads must be positive",
                },
            )));
        }
        let ratio = 8.0 / num_heads as f64;
        let slopes: Vec<f64> = (0..num_heads).map(|h| 2.0_f64.powf(-ratio * (h + 1) as f64)).collect();
        self.tensor_variable(slopes, vec![num_heads], false)
    }

    /// Generate a sliding window attention mask.
    ///
    /// Creates a mask for sliding window attention used in models like Mistral.
    /// Positions can only attend to positions within `window_size` distance.
    ///
    /// Returns a mask of shape `[seq_len, seq_len]` where:
    /// - 0.0 for positions within the window (allow attention)
    /// - -inf for positions outside the window (block attention)
    ///
    /// When `causal` is true, also enforces causal masking (no attending to future).
    pub fn sliding_window_mask(
        &mut self,
        seq_len: usize,
        window_size: usize,
        causal: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut mask = vec![0.0_f64; seq_len * seq_len];
        for i in 0..seq_len {
            for j in 0..seq_len {
                let is_in_window = ((i as i64) - (j as i64)).abs() <= window_size as i64;
                let is_causal_ok = !causal || j <= i;
                if !(is_in_window && is_causal_ok) {
                    mask[i * seq_len + j] = f64::NEG_INFINITY;
                }
            }
        }
        self.tensor_variable(mask, vec![seq_len, seq_len], false)
    }

    /// Repeat key/value heads to match query heads for Grouped Query Attention.
    ///
    /// GQA uses fewer K/V heads than Q heads to reduce memory and compute.
    /// This function repeats K/V heads to match the number of Q heads.
    ///
    /// - `kv`: K or V tensor of shape `[batch, num_kv_heads, seq_len, head_dim]`
    /// - `num_q_heads`: number of query heads (must be divisible by num_kv_heads)
    ///
    /// Returns tensor of shape `[batch, num_q_heads, seq_len, head_dim]`.
    ///
    /// Used in LLaMA 2, Mistral, and other modern transformers.
    pub fn repeat_kv(
        &mut self,
        kv: TensorNodeId,
        num_q_heads: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(kv)?;
        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "repeat_kv: input must be 4-D [batch, num_kv_heads, seq_len, head_dim]",
                },
            )));
        }
        let num_kv_heads = shape[1];
        if num_q_heads % num_kv_heads != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "repeat_kv: num_q_heads must be divisible by num_kv_heads",
                },
            )));
        }
        if num_q_heads == num_kv_heads {
            return Ok(kv);
        }
        let n_rep = num_q_heads / num_kv_heads;
        let batch_size = shape[0];
        let seq_len = shape[2];
        let head_dim = shape[3];
        let expanded = self.tensor_unsqueeze(kv, 2)?;
        let new_shape = vec![batch_size, num_kv_heads, n_rep, seq_len, head_dim];
        let tiled = self.tensor_expand(expanded, new_shape.clone())?;
        let final_shape = vec![batch_size, num_q_heads, seq_len, head_dim];
        self.tensor_reshape(tiled, final_shape)
    }

    /// Update KV cache with new key/value tensors for incremental decoding.
    ///
    /// Concatenates new K/V with cached K/V along the sequence dimension.
    ///
    /// - `cache`: optional existing cache `[batch, num_heads, cache_len, head_dim]`
    /// - `new_kv`: new K or V tensor `[batch, num_heads, new_len, head_dim]`
    ///
    /// Returns updated cache tensor `[batch, num_heads, cache_len + new_len, head_dim]`.
    ///
    /// If cache is None, returns new_kv as-is.
    pub fn update_kv_cache(
        &mut self,
        cache: Option<TensorNodeId>,
        new_kv: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        match cache {
            Some(c) => {
                let seq_dim = 2;
                self.tensor_cat(&[c, new_kv], seq_dim)
            }
            None => Ok(new_kv),
        }
    }

    /// Truncate KV cache to maximum length for sliding window attention.
    ///
    /// Keeps only the last `max_len` positions in the cache.
    ///
    /// - `cache`: KV cache `[batch, num_heads, seq_len, head_dim]`
    /// - `max_len`: maximum sequence length to keep
    pub fn truncate_kv_cache(
        &mut self,
        cache: TensorNodeId,
        max_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(cache)?;
        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "truncate_kv_cache: cache must be 4-D",
                },
            )));
        }
        let seq_len = shape[2];
        if seq_len <= max_len {
            return Ok(cache);
        }
        let start = seq_len - max_len;
        self.tensor_narrow(cache, 2, start, max_len)
    }

    /// Tensor contraction over specified dimensions (generalised matrix multiply).
    ///
    /// `dims` is the number of trailing dimensions of `a` to contract with
    /// the leading dimensions of `b`.
    /// Equivalent to PyTorch's `torch.tensordot(a, b, dims=N)`.
    pub fn tensor_tensordot(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
        dims: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        let a_ndim = a_shape.len();
        let b_ndim = b_shape.len();

        if dims > a_ndim || dims > b_ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: dims,
                    ndim: a_ndim.min(b_ndim),
                },
            )));
        }

        // Check that contracted dimensions match
        for i in 0..dims {
            if a_shape[a_ndim - dims + i] != b_shape[i] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: a_shape.clone(),
                        rhs: b_shape.clone(),
                    },
                )));
            }
        }

        // Special case: dims=0 is outer product-like (no contraction)
        if dims == 0 {
            // Reshape a to [..., 1] and b to [1, ...], then matmul
            let a_total =
                Self::checked_shape_numel(&a_shape, "tensordot: lhs shape volume overflow")?;
            let b_total =
                Self::checked_shape_numel(&b_shape, "tensordot: rhs shape volume overflow")?;
            let a_flat = self.tensor_reshape(a, vec![a_total, 1])?;
            let b_flat = self.tensor_reshape(b, vec![1, b_total])?;
            let result = self.tensor_matmul(a_flat, b_flat)?;
            let mut out_shape = a_shape;
            out_shape.extend_from_slice(&b_shape);
            return self.tensor_reshape(result, out_shape);
        }

        // Reshape a: [free_a..., contract...] -> [prod(free_a), prod(contract)]
        let free_a = Self::checked_shape_numel(
            &a_shape[..a_ndim - dims],
            "tensordot: free lhs shape volume overflow",
        )?;
        let contract = Self::checked_shape_numel(
            &a_shape[a_ndim - dims..],
            "tensordot: contract shape volume overflow",
        )?;
        let a_2d = self.tensor_reshape(a, vec![free_a, contract])?;

        // Reshape b: [contract..., free_b...] -> [prod(contract), prod(free_b)]
        let free_b = Self::checked_shape_numel(
            &b_shape[dims..],
            "tensordot: free rhs shape volume overflow",
        )?;
        let b_2d = self.tensor_reshape(b, vec![contract, free_b])?;

        // Matmul: [free_a, contract] @ [contract, free_b] -> [free_a, free_b]
        let result = self.tensor_matmul(a_2d, b_2d)?;

        // Reshape back to [...free_a_dims, ...free_b_dims]
        let mut out_shape: Vec<usize> = a_shape[..a_ndim - dims].to_vec();
        out_shape.extend_from_slice(&b_shape[dims..]);
        if out_shape.is_empty() {
            out_shape.push(1);
        }
        self.tensor_reshape(result, out_shape)
    }

    /// Kronecker product of two tensors.
    ///
    /// If the inputs have different ranks, the lower-rank input is left-padded
    /// with singleton dimensions before multiplying each aligned dimension.
    pub fn tensor_kron(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;

        if a_shape.len() == 1 && b_shape.len() == 1 {
            let outer = self.tensor_outer(a, b)?;
            let total = Self::checked_mul(a_shape[0], b_shape[0], "kron: output shape overflow")?;
            return self.tensor_reshape(outer, vec![total]);
        }

        let rank = a_shape.len().max(b_shape.len());
        let mut a_aligned = vec![1usize; rank - a_shape.len()];
        a_aligned.extend_from_slice(&a_shape);
        let mut b_aligned = vec![1usize; rank - b_shape.len()];
        b_aligned.extend_from_slice(&b_shape);

        let mut out_shape = Vec::with_capacity(rank);
        for (&a_dim, &b_dim) in a_aligned.iter().zip(&b_aligned) {
            out_shape.push(Self::checked_mul(
                a_dim,
                b_dim,
                "kron: output shape overflow",
            )?);
        }
        let total = Self::checked_shape_numel(&out_shape, "kron: output shape volume overflow")?;

        if self.tensor_tape.tensor_requires_grad(a)? || self.tensor_tape.tensor_requires_grad(b)? {
            let mut a_kron_shape = Vec::with_capacity(rank * 2);
            let mut b_kron_shape = Vec::with_capacity(rank * 2);
            let mut interleaved_shape = Vec::with_capacity(rank * 2);
            for (&a_dim, &b_dim) in a_aligned.iter().zip(&b_aligned) {
                a_kron_shape.push(a_dim);
                a_kron_shape.push(1);
                b_kron_shape.push(1);
                b_kron_shape.push(b_dim);
                interleaved_shape.push(a_dim);
                interleaved_shape.push(b_dim);
            }

            let a_view = self.tensor_reshape(a, a_kron_shape)?;
            let b_view = self.tensor_reshape(b, b_kron_shape)?;
            let a_expanded = self.tensor_expand(a_view, interleaved_shape.clone())?;
            let b_expanded = self.tensor_expand(b_view, interleaved_shape)?;
            let product = self.tensor_mul(a_expanded, b_expanded)?;
            return self.tensor_reshape(product, out_shape);
        }

        let a_vals = self.tensor_values(a)?;
        let b_vals = self.tensor_values(b)?;
        if total == 0 {
            return self.tensor_variable(Vec::new(), out_shape, false);
        }

        // Precompute contiguous strides for the aligned shapes ONCE before the
        // hot loop (frankentorch-ys3y). The earlier implementation allocated a
        // fresh `Vec<usize>` of length `rank` on every iteration of the
        // doubly-nested loop via a `decode_coords` closure, which made a 2D x
        // 2D kron of N x N inputs do O(N^4) Vec allocations. With strides in
        // hand we can decompose `a_linear` and `b_linear` into per-dim
        // coordinates with simple integer division and recombine into
        // `out_linear` without any per-iteration heap activity.
        //
        // All bounds below are mathematically guaranteed to fit in `usize`:
        // for any valid (a_linear, b_linear), each dim's `out_coord` is in
        // `[0, out_shape[dim])`, and the running `out_linear` stays in
        // `[0, total)` (already validated to fit in `usize` above). We keep
        // checked arithmetic anyway to match the surrounding hardening style
        // and to fail closed on any future invariant violation.
        let a_strides = contiguous_strides(&a_aligned);
        let b_strides = contiguous_strides(&b_aligned);

        let mut result = vec![0.0f64; total];
        for (a_linear, &a_val) in a_vals.iter().enumerate() {
            for (b_linear, &b_val) in b_vals.iter().enumerate() {
                let mut out_linear = 0usize;
                for dim in 0..rank {
                    // contiguous_strides guarantees stride >= 1 for every dim
                    // when the shape is non-empty, and we already short-
                    // circuited when `total == 0`.
                    let a_coord = (a_linear / a_strides[dim]) % a_aligned[dim];
                    let b_coord = (b_linear / b_strides[dim]) % b_aligned[dim];
                    let scaled_a = Self::checked_mul(
                        a_coord,
                        b_aligned[dim],
                        "kron: output coordinate overflow",
                    )?;
                    let out_coord =
                        Self::checked_add(scaled_a, b_coord, "kron: output coordinate overflow")?;
                    out_linear = Self::checked_add(
                        Self::checked_mul(
                            out_linear,
                            out_shape[dim],
                            "kron: output index overflow",
                        )?,
                        out_coord,
                        "kron: output index overflow",
                    )?;
                }
                result[out_linear] = a_val * b_val;
            }
        }

        self.tensor_variable(result, out_shape, false)
    }

    /// Einstein summation.
    ///
    /// Supports 1- and 2-operand equations via compact index notation.
    /// Decomposes into permute/reshape/matmul/sum operations for backward compatibility.
    ///
    /// Examples:
    /// - `"ij,jk->ik"` — matrix multiply
    /// - `"ii->"` — trace
    /// - `"ij->ji"` — transpose
    /// - `"i,j->ij"` — outer product
    /// - `"i,i->"` — dot product
    /// - `"bij,bjk->bik"` — batch matmul
    pub fn tensor_einsum(
        &mut self,
        equation: &str,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Parse equation: "subscripts -> output" or just "subscripts" (implicit output)
        let (input_part, output_part) = if let Some(pos) = equation.find("->") {
            (&equation[..pos], Some(&equation[pos + 2..]))
        } else {
            (equation, None)
        };

        let input_subs: Vec<&str> = input_part.split(',').collect();
        if input_subs.len() != tensors.len() {
            return Err(make_err(
                "einsum: number of subscripts must match number of tensors",
            ));
        }

        // Validate characters: only lowercase ASCII letters
        for ch in equation.chars() {
            if ch != ',' && ch != '-' && ch != '>' && ch != ' ' && !ch.is_ascii_lowercase() {
                return Err(make_err(
                    "einsum: only lowercase ASCII letters allowed in subscripts",
                ));
            }
        }

        // Parse subscripts into index lists
        let input_indices: Vec<Vec<char>> = input_subs
            .iter()
            .map(|s| s.chars().filter(|c| c.is_ascii_lowercase()).collect())
            .collect();

        // Validate shapes match subscripts
        for (i, indices) in input_indices.iter().enumerate() {
            let shape = self.tensor_shape(tensors[i])?;
            if shape.len() != indices.len() {
                return Err(make_err("einsum: subscript length must match tensor ndim"));
            }
        }

        // Build dimension size map
        let mut dim_sizes: std::collections::HashMap<char, usize> =
            std::collections::HashMap::new();
        for (i, indices) in input_indices.iter().enumerate() {
            let shape = self.tensor_shape(tensors[i])?;
            for (d, &idx) in indices.iter().enumerate() {
                if let Some(&existing) = dim_sizes.get(&idx) {
                    if existing != shape[d] {
                        return Err(make_err(
                            "einsum: dimension size mismatch for repeated index",
                        ));
                    }
                } else {
                    dim_sizes.insert(idx, shape[d]);
                }
            }
        }

        // Determine output indices
        let output_indices: Vec<char> = if let Some(out) = output_part {
            out.chars().filter(|c| c.is_ascii_lowercase()).collect()
        } else {
            // Implicit: sorted unique indices that appear exactly once across all inputs
            let mut counts: std::collections::HashMap<char, usize> =
                std::collections::HashMap::new();
            for indices in &input_indices {
                for &ch in indices {
                    *counts.entry(ch).or_insert(0) += 1;
                }
            }
            let mut out: Vec<char> = counts
                .into_iter()
                .filter(|(_, count)| *count == 1)
                .map(|(ch, _)| ch)
                .collect();
            out.sort();
            out
        };

        // Handle based on number of operands
        match tensors.len() {
            1 => self.einsum_unary(&input_indices[0], &output_indices, tensors[0], &dim_sizes),
            2 => self.einsum_binary(
                &input_indices[0],
                &input_indices[1],
                &output_indices,
                tensors[0],
                tensors[1],
                &dim_sizes,
            ),
            _ => {
                // Multi-operand: pairwise reduction left-to-right
                // Determine which indices to contract at each step
                let mut current = tensors[0];
                let mut current_indices = input_indices[0].clone();
                for i in 1..tensors.len() {
                    let rhs_indices = &input_indices[i];
                    // For intermediate steps, keep all indices needed downstream
                    let is_last = i == tensors.len() - 1;
                    let intermediate_out: Vec<char> = if is_last {
                        output_indices.clone()
                    } else {
                        // Keep indices that appear in remaining inputs or final output
                        let mut needed: std::collections::HashSet<char> =
                            output_indices.iter().copied().collect();
                        for idx_set in &input_indices[(i + 1)..] {
                            for &ch in idx_set {
                                needed.insert(ch);
                            }
                        }
                        let mut out: Vec<char> = current_indices
                            .iter()
                            .chain(rhs_indices.iter())
                            .copied()
                            .filter(|ch| needed.contains(ch))
                            .collect();
                        // Deduplicate while preserving order
                        let mut seen = std::collections::HashSet::new();
                        out.retain(|ch| seen.insert(*ch));
                        out
                    };
                    current = self.einsum_binary(
                        &current_indices,
                        rhs_indices,
                        &intermediate_out,
                        current,
                        tensors[i],
                        &dim_sizes,
                    )?;
                    current_indices = intermediate_out;
                }
                Ok(current)
            }
        }
    }

    fn einsum_unary(
        &mut self,
        input_idx: &[char],
        output_idx: &[char],
        tensor: TensorNodeId,
        _dim_sizes: &std::collections::HashMap<char, usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Check for trace pattern: repeated index in input
        let mut repeated: Vec<char> = Vec::new();
        {
            let mut seen = std::collections::HashSet::new();
            for &ch in input_idx {
                if !seen.insert(ch) && !repeated.contains(&ch) {
                    repeated.push(ch);
                }
            }
        }

        if !repeated.is_empty() {
            // Trace-like: extract diagonal(s) then sum/permute
            if repeated.len() == 1 {
                let repeated_ch = repeated[0];
                let repeated_positions: Vec<usize> = input_idx
                    .iter()
                    .enumerate()
                    .filter_map(|(position, &ch)| (ch == repeated_ch).then_some(position))
                    .collect();
                if repeated_positions.len() == 2 {
                    return self.einsum_unary_single_repeated_index(
                        input_idx,
                        output_idx,
                        tensor,
                        &repeated_positions,
                    );
                }
            }
            return Err(make_err(
                "einsum: unsupported repeated-index pattern for single operand",
            ));
        }

        // No repeated indices: transpose + sum over contracted dims
        // First, figure out which input dims map to which output dims
        let contract_dims: Vec<usize> = input_idx
            .iter()
            .enumerate()
            .filter(|(_, ch)| !output_idx.contains(ch))
            .map(|(i, _)| i)
            .collect();

        let mut current = tensor;

        if output_idx.is_empty() && contract_dims.len() == input_idx.len() {
            // Sum all elements
            let shape = self.tensor_shape(current)?;
            let total = Self::checked_shape_numel(&shape, "einsum: input shape volume overflow")?;
            let flat = self.tensor_reshape(current, vec![total])?;
            return self.tensor_sum_dim(flat, 0);
        }

        // Permute to bring output indices first, then contracted dims
        let mut perm: Vec<usize> = Vec::with_capacity(input_idx.len());
        for &out_ch in output_idx {
            let pos = input_idx
                .iter()
                .position(|&ch| ch == out_ch)
                .ok_or_else(|| make_err("einsum: output index not found in input"))?;
            perm.push(pos);
        }
        for &cd in &contract_dims {
            perm.push(cd);
        }

        if perm.len() == input_idx.len() {
            // Check if permutation is identity
            let is_identity = perm.iter().enumerate().all(|(i, &v)| v == i);
            if !is_identity {
                current = self.tensor_permute(current, perm)?;
            }
        }

        // Sum over the trailing (contracted) dimensions from last to first
        for _ in 0..contract_dims.len() {
            let shape = self.tensor_shape(current)?;
            let last_dim = shape.len() - 1;
            current = self.tensor_sum_dim(current, last_dim)?;
        }

        // If output is scalar, ensure shape
        if output_idx.is_empty() {
            let shape = self.tensor_shape(current)?;
            if shape != [1] {
                current = self.tensor_reshape(current, vec![1])?;
            }
        }

        Ok(current)
    }

    fn einsum_unary_single_repeated_index(
        &mut self,
        input_idx: &[char],
        output_idx: &[char],
        tensor: TensorNodeId,
        repeated_positions: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        let mut seen_output = std::collections::HashSet::new();
        for &ch in output_idx {
            if !seen_output.insert(ch) {
                return Err(make_err("einsum: duplicate output index"));
            }
            if !input_idx.contains(&ch) {
                return Err(make_err("einsum: output index not found in input"));
            }
        }

        let shape = self.tensor_shape(tensor)?;
        let first_repeated = repeated_positions[0];
        let second_repeated = repeated_positions[1];
        if shape[first_repeated] != shape[second_repeated] {
            return Err(make_err(
                "einsum: dimension size mismatch for repeated index",
            ));
        }

        let output_positions: Vec<usize> = output_idx
            .iter()
            .map(|&ch| {
                input_idx
                    .iter()
                    .position(|&input_ch| input_ch == ch)
                    .expect("output index membership validated above")
            })
            .collect();
        let output_shape = if output_positions.is_empty() {
            vec![1]
        } else {
            output_positions
                .iter()
                .map(|&position| shape[position])
                .collect()
        };
        let output_len =
            Self::checked_shape_numel(&output_shape, "einsum: output shape volume overflow")?;
        let input_len = Self::checked_shape_numel(&shape, "einsum: input shape volume overflow")?;
        let input_strides = contiguous_strides(&shape);
        let output_strides = contiguous_strides(&output_shape);
        let mut input_to_output = Vec::new();

        for input_linear in 0..input_len {
            let first_coord =
                (input_linear / input_strides[first_repeated]) % shape[first_repeated];
            let second_coord =
                (input_linear / input_strides[second_repeated]) % shape[second_repeated];
            if first_coord != second_coord {
                continue;
            }

            let mut output_linear = 0usize;
            for (output_dim, &input_dim) in output_positions.iter().enumerate() {
                let coord = (input_linear / input_strides[input_dim]) % shape[input_dim];
                let offset = Self::checked_mul(
                    coord,
                    output_strides[output_dim],
                    "einsum: output index overflow",
                )?;
                output_linear =
                    Self::checked_add(output_linear, offset, "einsum: output index overflow")?;
            }
            input_to_output.push((input_linear, output_linear));
        }

        match self.tensor_dtype(tensor)? {
            DType::F64 | DType::F32 => {
                let forward_map = input_to_output.clone();
                let backward_map = input_to_output;
                let output_shape_for_forward = output_shape.clone();
                self.tensor_apply_function(
                    &[tensor],
                    move |_ctx, inputs| {
                        let (values, _shape) = inputs[0];
                        let mut output = vec![0.0_f64; output_len];
                        for &(input_linear, output_linear) in &forward_map {
                            output[output_linear] += values[input_linear];
                        }
                        Ok((output, output_shape_for_forward.clone()))
                    },
                    move |_ctx, grad_outputs| {
                        let grad_output = grad_outputs[0];
                        let mut grad_input = vec![0.0_f64; input_len];
                        for &(input_linear, output_linear) in &backward_map {
                            grad_input[input_linear] += grad_output[output_linear];
                        }
                        Ok(vec![Some(grad_input)])
                    },
                )
            }
            _ => Err(make_err(
                "einsum: repeated-index unary requires f32 or f64 tensor",
            )),
        }
    }

    fn einsum_binary(
        &mut self,
        lhs_idx: &[char],
        rhs_idx: &[char],
        output_idx: &[char],
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        _dim_sizes: &std::collections::HashMap<char, usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let make_err = |reason: &'static str| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))
        };

        // Categorize indices:
        // - batch: appear in both inputs AND in output
        // - contract: appear in both inputs but NOT in output
        // - free_lhs: appear only in lhs (and in output)
        // - free_rhs: appear only in rhs (and in output)
        let lhs_set: std::collections::HashSet<char> = lhs_idx.iter().copied().collect();
        let rhs_set: std::collections::HashSet<char> = rhs_idx.iter().copied().collect();

        let mut batch_chars: Vec<char> = Vec::new();
        let mut contract_chars: Vec<char> = Vec::new();
        let mut free_lhs_chars: Vec<char> = Vec::new();
        let mut free_rhs_chars: Vec<char> = Vec::new();

        // Process lhs indices in order
        for &ch in lhs_idx {
            if rhs_set.contains(&ch) {
                if output_idx.contains(&ch) {
                    if !batch_chars.contains(&ch) {
                        batch_chars.push(ch);
                    }
                } else if !contract_chars.contains(&ch) {
                    contract_chars.push(ch);
                }
            } else if !free_lhs_chars.contains(&ch) {
                free_lhs_chars.push(ch);
            }
        }
        for &ch in rhs_idx {
            if !lhs_set.contains(&ch) && !free_rhs_chars.contains(&ch) {
                free_rhs_chars.push(ch);
            }
        }

        // Helpers to locate a subscript char's axis in the original index lists.
        // These chars are categorized FROM lhs_idx/rhs_idx, but return an error
        // if invariants are violated to avoid panics.
        let lhs_pos = |ch: &char| -> Result<usize, AutogradError> {
            lhs_idx
                .iter()
                .position(|c| c == ch)
                .ok_or_else(|| make_err("einsum: subscript char not found in lhs indices"))
        };
        let rhs_pos = |ch: &char| -> Result<usize, AutogradError> {
            rhs_idx
                .iter()
                .position(|c| c == ch)
                .ok_or_else(|| make_err("einsum: subscript char not found in rhs indices"))
        };

        // Build permutation for lhs: [batch..., free_lhs..., contract...]
        let mut lhs_perm =
            Vec::with_capacity(batch_chars.len() + free_lhs_chars.len() + contract_chars.len());
        for ch in batch_chars
            .iter()
            .chain(free_lhs_chars.iter())
            .chain(contract_chars.iter())
        {
            lhs_perm.push(lhs_pos(ch)?);
        }

        // Build permutation for rhs: [batch..., contract..., free_rhs...]
        let mut rhs_perm =
            Vec::with_capacity(batch_chars.len() + contract_chars.len() + free_rhs_chars.len());
        for ch in batch_chars
            .iter()
            .chain(contract_chars.iter())
            .chain(free_rhs_chars.iter())
        {
            rhs_perm.push(rhs_pos(ch)?);
        }

        let lhs_shape = self.tensor_shape(lhs)?;
        let rhs_shape = self.tensor_shape(rhs)?;

        // Compute dimension sizes after permutation
        let mut batch_size: usize = 1;
        for ch in &batch_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            batch_size = batch_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: batch size overflow"))?;
        }
        let mut free_lhs_size: usize = 1;
        for ch in &free_lhs_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            free_lhs_size = free_lhs_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: free lhs size overflow"))?;
        }
        let mut contract_size: usize = 1;
        for ch in &contract_chars {
            let dim = lhs_shape[lhs_pos(ch)?];
            contract_size = contract_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: contract size overflow"))?;
        }
        let mut free_rhs_size: usize = 1;
        for ch in &free_rhs_chars {
            let dim = rhs_shape[rhs_pos(ch)?];
            free_rhs_size = free_rhs_size
                .checked_mul(dim)
                .ok_or_else(|| make_err("einsum: free rhs size overflow"))?;
        }

        // Permute tensors
        let mut lhs_p = lhs;
        if !lhs_perm.iter().enumerate().all(|(i, &v)| v == i) {
            lhs_p = self.tensor_permute(lhs_p, lhs_perm)?;
        }
        let mut rhs_p = rhs;
        if !rhs_perm.iter().enumerate().all(|(i, &v)| v == i) {
            rhs_p = self.tensor_permute(rhs_p, rhs_perm)?;
        }

        // Handle the case where there are no contractions (element-wise or outer product)
        if contract_chars.is_empty() && batch_chars.is_empty() {
            // Outer product case: reshape lhs to [M, 1], rhs to [1, N], matmul
            let m = free_lhs_size.max(1);
            let n = free_rhs_size.max(1);
            let lhs_2d = self.tensor_reshape(lhs_p, vec![m, 1])?;
            let rhs_2d = self.tensor_reshape(rhs_p, vec![1, n])?;
            let result = self.tensor_matmul(lhs_2d, rhs_2d)?;
            // Reshape to output shape
            let mut out_shape: Vec<usize> = Vec::new();
            for &ch in output_idx {
                if free_lhs_chars.contains(&ch) {
                    out_shape.push(lhs_shape[lhs_pos(&ch)?]);
                } else if free_rhs_chars.contains(&ch) {
                    out_shape.push(rhs_shape[rhs_pos(&ch)?]);
                }
            }
            if out_shape.is_empty() {
                out_shape.push(1);
            }
            return self.tensor_reshape(result, out_shape);
        }

        if contract_chars.is_empty() {
            // Batch + free only: element-wise multiply with broadcasting
            let m = free_lhs_size.max(1);
            let n = free_rhs_size.max(1);
            let lhs_3d = self.tensor_reshape(lhs_p, vec![batch_size, m, 1])?;
            let rhs_3d = self.tensor_reshape(rhs_p, vec![batch_size, 1, n])?;
            let result = self.tensor_bmm(lhs_3d, rhs_3d)?;
            let mut out_shape: Vec<usize> = Vec::new();
            for &ch in output_idx {
                if batch_chars.contains(&ch) || free_lhs_chars.contains(&ch) {
                    out_shape.push(lhs_shape[lhs_pos(&ch)?]);
                } else if free_rhs_chars.contains(&ch) {
                    out_shape.push(rhs_shape[rhs_pos(&ch)?]);
                }
            }
            if out_shape.is_empty() {
                out_shape.push(1);
            }
            return self.tensor_reshape(result, out_shape);
        }

        // General case with contraction
        let m = free_lhs_size.max(1);
        let k = contract_size.max(1);
        let n = free_rhs_size.max(1);

        let result = if batch_chars.is_empty() {
            // No batch: 2D matmul [M, K] @ [K, N] -> [M, N]
            let lhs_2d = self.tensor_reshape(lhs_p, vec![m, k])?;
            let rhs_2d = self.tensor_reshape(rhs_p, vec![k, n])?;
            self.tensor_matmul(lhs_2d, rhs_2d)?
        } else {
            // Batch: 3D bmm [B, M, K] @ [B, K, N] -> [B, M, N]
            let b = batch_size;
            let lhs_3d = self.tensor_reshape(lhs_p, vec![b, m, k])?;
            let rhs_3d = self.tensor_reshape(rhs_p, vec![b, k, n])?;
            self.tensor_bmm(lhs_3d, rhs_3d)?
        };

        // Reshape to output shape
        let mut out_shape: Vec<usize> = Vec::new();
        for &ch in output_idx {
            if batch_chars.contains(&ch)
                || free_lhs_chars.contains(&ch)
                || contract_chars.contains(&ch)
            {
                out_shape.push(lhs_shape[lhs_pos(&ch)?]);
            } else if free_rhs_chars.contains(&ch) {
                out_shape.push(rhs_shape[rhs_pos(&ch)?]);
            }
        }

        if out_shape.is_empty() {
            // Scalar output: already [B, M, N] = [1, 1, 1]
            let flat = self.tensor_reshape(result, vec![1])?;
            return Ok(flat);
        }

        self.tensor_reshape(result, out_shape)
    }

    /// Apply a custom autograd function.
    ///
    /// `forward_fn` receives a `&mut FunctionCtx` and input data (values + shapes),
    /// returns output (values, shape).
    ///
    /// `backward_fn` receives the saved context and incoming gradients,
    /// returns one `Option<Vec<f64>>` per input.
    pub fn tensor_apply_function<F, B>(
        &mut self,
        inputs: &[TensorNodeId],
        forward_fn: F,
        backward_fn: B,
    ) -> Result<TensorNodeId, AutogradError>
    where
        F: FnOnce(
            &mut FunctionCtx,
            &[(&[f64], &[usize])],
        ) -> Result<(Vec<f64>, Vec<usize>), AutogradError>,
        B: Fn(&FunctionCtx, &[&[f64]]) -> Result<Vec<Option<Vec<f64>>>, AutogradError>
            + Send
            + Sync
            + 'static,
    {
        self.tensor_tape
            .apply_function(inputs, forward_fn, backward_fn)
    }

    /// Cross product of two 3-element vectors.
    ///
    /// Both inputs must be 1D tensors of length 3.
    /// Returns a 1D tensor of length 3: c = a × b.
    pub fn tensor_cross(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape != [3] || b_shape != [3] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_shape,
                    rhs: b_shape,
                },
            )));
        }

        // Cross product is bilinear, so the Jacobian-vector products
        // are themselves cross products:
        //     grad_a = b × grad_c
        //     grad_b = grad_c × a
        // Wrap in tensor_apply_function with this analytical backward.
        // Save a and b for backward. Tracked under frankentorch-j2rj.
        self.tensor_apply_function(
            &[a, b],
            |ctx, inputs| {
                let (av, _a_shape) = inputs[0];
                let (bv, _b_shape) = inputs[1];
                let result = vec![
                    av[1] * bv[2] - av[2] * bv[1],
                    av[2] * bv[0] - av[0] * bv[2],
                    av[0] * bv[1] - av[1] * bv[0],
                ];
                ctx.save_for_backward(av.to_vec(), vec![3]);
                ctx.save_for_backward(bv.to_vec(), vec![3]);
                Ok((result, vec![3]))
            },
            |ctx, grad_outputs| {
                let g = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let av = &saved[0];
                let bv = &saved[1];
                // grad_a = b × grad_c
                let grad_a = vec![
                    bv[1] * g[2] - bv[2] * g[1],
                    bv[2] * g[0] - bv[0] * g[2],
                    bv[0] * g[1] - bv[1] * g[0],
                ];
                // grad_b = grad_c × a
                let grad_b = vec![
                    g[1] * av[2] - g[2] * av[1],
                    g[2] * av[0] - g[0] * av[2],
                    g[0] * av[1] - g[1] * av[0],
                ];
                Ok(vec![Some(grad_a), Some(grad_b)])
            },
        )
    }

    /// Dot product along the last dimension (batched dot product).
    ///
    /// For 1D inputs: equivalent to `tensor_dot`.
    /// For N-D inputs: dot product along the last dimension, output has one fewer dim.
    pub fn tensor_vecdot(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape != b_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_shape.clone(),
                    rhs: b_shape,
                },
            )));
        }
        if a_shape.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim: 0, ndim: 1 },
            )));
        }
        if a_shape.len() == 1 {
            return self.tensor_dot(a, b);
        }
        // For N-D: element-wise multiply then sum along last dim
        let prod = self.tensor_mul(a, b)?;
        let last_dim = a_shape.len() - 1;
        self.tensor_sum_dim(prod, last_dim)
    }

    /// Embed a 1D vector as the diagonal of a 2D matrix.
    ///
    /// `diag_embed([1,2,3])` produces `[[1,0,0],[0,2,0],[0,0,3]]`.
    /// `offset` controls which diagonal: 0=main, 1=super, -1=sub.
    pub fn tensor_diag_embed(
        &mut self,
        input: TensorNodeId,
        offset: i32,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 1,
                },
            )));
        }
        let k = shape[0];
        let abs_offset = offset.unsigned_abs() as usize;
        let n = Self::checked_add(k, abs_offset, "diag_embed: output size overflow")?;
        let numel = Self::checked_mul(n, n, "diag_embed: output size overflow")?;
        let _ = Self::checked_mul(
            numel,
            std::mem::size_of::<f64>(),
            "diag_embed: output size overflow",
        )?;

        // Forward is purely linear in the input — output[row, col] is
        // input[i] when (row, col) is on the requested diagonal,
        // 0 otherwise. Backward extracts the diagonal:
        //     grad_input[i] = grad_output[row, col]
        // for the same (row, col) the forward used. Wrap in
        // tensor_apply_function with this analytical backward.
        // Tracked under frankentorch-d180.
        let positive_offset = offset >= 0;
        self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _in_shape) = inputs[0];
                let mut result = vec![0.0_f64; n * n];
                for (i, &v) in vals.iter().enumerate().take(k) {
                    let (row, col) = if positive_offset {
                        (i, i + abs_offset)
                    } else {
                        (i + abs_offset, i)
                    };
                    result[row * n + col] = v;
                }
                Ok((result, vec![n, n]))
            },
            move |_ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; k];
                for (i, slot) in grad_in.iter_mut().enumerate().take(k) {
                    let (row, col) = if positive_offset {
                        (i, i + abs_offset)
                    } else {
                        (i + abs_offset, i)
                    };
                    *slot = grad_y[row * n + col];
                }
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// `torch.diag(input, diagonal=0)` parity dispatch.
    ///
    /// torch.diag is overloaded: a 1-D input becomes a 2-D matrix with
    /// the input on the requested diagonal (delegates to
    /// `tensor_diag_embed`); a 2-D input returns the requested diagonal
    /// as a 1-D tensor (delegates to `tensor_diagonal`). Higher-rank
    /// inputs are rejected — torch raises a `RuntimeError` for them.
    /// Both delegate paths are autograd-aware via the existing
    /// implementations.
    pub fn tensor_diag(
        &mut self,
        input: TensorNodeId,
        diagonal: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            1 => {
                let offset_i32 = i32::try_from(diagonal).map_err(|_| {
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "diag: 1-D diagonal offset out of i32 range",
                        },
                    ))
                })?;
                self.tensor_diag_embed(input, offset_i32)
            }
            2 => self.tensor_diagonal(input, diagonal),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            ))),
        }
    }

    /// Return unique elements from a 1D tensor.
    ///
    /// If `sorted` is true (default), output is sorted ascending.
    /// If `return_inverse` is true, also returns index mapping input -> unique.
    /// If `return_counts` is true, also returns count of each unique value.
    pub fn tensor_unique(
        &mut self,
        input: TensorNodeId,
        sorted: bool,
        return_inverse: bool,
        return_counts: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique: autograd not supported (set deduplication is non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;

        // Collect unique values preserving first-occurrence order.
        //
        // Use IEEE 754 `==` to match torch.unique / numpy.unique:
        //   * 0.0 == -0.0 is true → merged (PyTorch behaviour)
        //   * NaN == NaN is false → every NaN is its own unique entry
        //   * Distinct subnormals (e.g. 5e-324 vs 1e-323) compare !=
        //     and stay distinct
        //
        // The previous heuristic `(u - v).abs() < f64::EPSILON ||
        // (u.is_nan() && v.is_nan())` silently merged any pair of
        // values within machine epsilon — incorrectly fusing
        // subnormals whose absolute distance is well below f64::EPSILON
        // — and merged every NaN bit pattern into one entry, both of
        // which violate the "Equivalent to torch.unique" contract.
        let mut unique_vals: Vec<f64> = Vec::new();
        let mut inverse_indices: Vec<usize> = Vec::with_capacity(vals.len());

        for &v in &vals {
            let pos = unique_vals.iter().position(|&u| u == v);
            match pos {
                Some(idx) => inverse_indices.push(idx),
                None => {
                    inverse_indices.push(unique_vals.len());
                    unique_vals.push(v);
                }
            }
        }

        if sorted {
            // Sort unique values and remap inverse indices
            let mut order: Vec<usize> = (0..unique_vals.len()).collect();
            order.sort_by(|&a, &b| unique_vals[a].total_cmp(&unique_vals[b]));
            let mut remap = vec![0usize; unique_vals.len()];
            for (new_idx, &old_idx) in order.iter().enumerate() {
                remap[old_idx] = new_idx;
            }
            let sorted_vals: Vec<f64> = order.iter().map(|&i| unique_vals[i]).collect();
            unique_vals = sorted_vals;
            for idx in &mut inverse_indices {
                *idx = remap[*idx];
            }
        }

        let unique_len = unique_vals.len();
        let unique_node = self.tensor_variable(unique_vals, vec![unique_len], false)?;

        let inverse_node = if return_inverse {
            let inv_f64: Vec<f64> = inverse_indices.iter().map(|&i| i as f64).collect();
            let n = inv_f64.len();
            Some(self.tensor_variable(inv_f64, vec![n], false)?)
        } else {
            None
        };

        let counts_node = if return_counts {
            let mut counts = vec![0.0f64; unique_len];
            for &idx in &inverse_indices {
                counts[idx] += 1.0;
            }
            Some(self.tensor_variable(counts, vec![unique_len], false)?)
        } else {
            None
        };

        Ok((unique_node, inverse_node, counts_node))
    }

    /// Remove consecutive duplicate elements from a 1D tensor.
    ///
    /// Unlike `unique`, only removes adjacent duplicates (O(n) without sorting).
    pub fn tensor_unique_consecutive(
        &mut self,
        input: TensorNodeId,
        return_inverse: bool,
        return_counts: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique_consecutive: autograd not supported (consecutive deduplication is non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;

        let mut unique_vals: Vec<f64> = Vec::new();
        let mut inverse_indices: Vec<usize> = Vec::with_capacity(vals.len());
        let mut counts: Vec<f64> = Vec::new();

        for &v in &vals {
            let is_duplicate = match unique_vals.last() {
                Some(last) => (last - v).abs() < f64::EPSILON || (last.is_nan() && v.is_nan()),
                None => false,
            };
            if !is_duplicate {
                unique_vals.push(v);
                counts.push(1.0);
            } else if let Some(count) = counts.last_mut() {
                *count += 1.0;
            } else {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "unique_consecutive: internal count state missing",
                    },
                )));
            }
            inverse_indices.push(unique_vals.len() - 1);
        }

        let unique_len = unique_vals.len();
        let unique_node = self.tensor_variable(unique_vals, vec![unique_len], false)?;

        let inverse_node = if return_inverse {
            let inv_f64: Vec<f64> = inverse_indices.iter().map(|&i| i as f64).collect();
            let n = inv_f64.len();
            Some(self.tensor_variable(inv_f64, vec![n], false)?)
        } else {
            None
        };

        let counts_node = if return_counts {
            Some(self.tensor_variable(counts, vec![unique_len], false)?)
        } else {
            None
        };

        Ok((unique_node, inverse_node, counts_node))
    }

    /// Return unique slices of the input tensor along a given dimension.
    ///
    /// Equivalent to `torch.unique(input, dim=dim)` or `torch.unique_dim`.
    /// Returns unique slices along the specified dimension, optionally with
    /// inverse indices and counts.
    pub fn tensor_unique_dim(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        sorted: bool,
        return_inverse: bool,
        return_counts: bool,
    ) -> Result<(TensorNodeId, Option<TensorNodeId>, Option<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique_dim: autograd not supported (uniqueness is non-differentiable)",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        if dim >= shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unique_dim: dimension out of range",
                },
            )));
        }
        let vals = self.tensor_values(input)?;
        let dim_size = shape[dim];
        // Calculate the size of each slice along dim
        let outer_size: usize = shape[..dim].iter().product();
        let inner_size: usize = shape[dim + 1..].iter().product();
        let slice_numel = inner_size;
        let total_slices = outer_size * dim_size;
        // Extract slices and find unique ones
        let mut slices: Vec<(usize, Vec<f64>)> = Vec::with_capacity(total_slices);
        for outer in 0..outer_size {
            for d in 0..dim_size {
                let mut slice_data = Vec::with_capacity(slice_numel);
                for inner in 0..inner_size {
                    let idx = outer * dim_size * inner_size + d * inner_size + inner;
                    slice_data.push(vals[idx]);
                }
                slices.push((outer * dim_size + d, slice_data));
            }
        }
        // Group by outer and find unique within each
        // For simplicity, treat entire slice as key and deduplicate globally
        let mut unique_indices: Vec<usize> = Vec::new();
        let mut seen: std::collections::HashMap<Vec<i64>, usize> = std::collections::HashMap::new();
        let mut inverse: Vec<f64> = Vec::with_capacity(slices.len());
        let mut counts_map: std::collections::HashMap<usize, usize> = std::collections::HashMap::new();
        for (idx, slice) in slices.iter() {
            // Convert to bits for comparison (handles NaN)
            let key: Vec<i64> = slice.iter().map(|&v| v.to_bits() as i64).collect();
            if let Some(&unique_idx) = seen.get(&key) {
                inverse.push(unique_idx as f64);
                *counts_map.entry(unique_idx).or_insert(0) += 1;
            } else {
                let new_idx = unique_indices.len();
                seen.insert(key, new_idx);
                unique_indices.push(*idx);
                inverse.push(new_idx as f64);
                counts_map.insert(new_idx, 1);
            }
        }
        if sorted {
            // Sort unique slices lexicographically
            unique_indices.sort_by(|&a, &b| {
                let slice_a = &slices[a].1;
                let slice_b = &slices[b].1;
                for (va, vb) in slice_a.iter().zip(slice_b.iter()) {
                    match va.partial_cmp(vb) {
                        Some(std::cmp::Ordering::Equal) => continue,
                        Some(ord) => return ord,
                        None => {
                            // Handle NaN
                            if va.is_nan() && vb.is_nan() {
                                continue;
                            } else if va.is_nan() {
                                return std::cmp::Ordering::Greater;
                            } else {
                                return std::cmp::Ordering::Less;
                            }
                        }
                    }
                }
                std::cmp::Ordering::Equal
            });
        }
        // Build output tensor
        let unique_count = unique_indices.len();
        let mut new_shape = shape.clone();
        new_shape[dim] = unique_count;
        let mut out_vals = Vec::with_capacity(outer_size * unique_count * inner_size);
        for outer in 0..outer_size {
            for ui in 0..unique_count {
                let orig_d = unique_indices[ui] % dim_size;
                for inner in 0..inner_size {
                    let idx = outer * dim_size * inner_size + orig_d * inner_size + inner;
                    out_vals.push(vals[idx]);
                }
            }
        }
        let unique_node = self.tensor_variable(out_vals, new_shape, false)?;
        let inverse_node = if return_inverse {
            let n = inverse.len();
            Some(self.tensor_variable(inverse, vec![n], false)?)
        } else {
            None
        };
        let counts_node = if return_counts {
            let counts: Vec<f64> = (0..unique_count)
                .map(|i| *counts_map.get(&i).unwrap_or(&0) as f64)
                .collect();
            Some(self.tensor_variable(counts, vec![unique_count], false)?)
        } else {
            None
        };
        Ok((unique_node, inverse_node, counts_node))
    }

    /// Count the number of occurrences of each value in a 1-D non-negative integer tensor.
    ///
    /// Equivalent to `torch.bincount(input, weights=None, minlength=0)`.
    /// Input values are truncated to integers. Negative values cause an error.
    /// If `weights` is provided, it must have the same length and the output
    /// accumulates weights instead of unit counts.
    pub fn tensor_bincount(
        &mut self,
        input: TensorNodeId,
        weights: Option<TensorNodeId>,
        minlength: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let vals = self.tensor_values(input)?;
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() != 1 {
            // Surface the actual rank so callers see 'expected 1-D
            // but got N-D' instead of an opaque static reason
            // (frankentorch-8sct).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: 0,
                    ndim: input_shape.len(),
                },
            )));
        }

        if let Some(w) = weights {
            let w_shape = self.tensor_shape(w)?;
            if w_shape.len() != 1 || w_shape[0] != input_shape[0] {
                // ShapeMismatch carries both shapes so the caller can
                // distinguish 'wrong rank' from 'wrong length' without
                // reparsing a static string (frankentorch-8sct).
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: input_shape.clone(),
                        rhs: w_shape,
                    },
                )));
            }
        }

        // Find max value to determine output size
        let mut max_val: Option<i64> = None;
        for &v in &vals {
            if !v.is_finite() || v != v.floor() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input must contain finite integer values",
                    },
                )));
            }
            let iv = v as i64;
            if iv < 0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input must be non-negative",
                    },
                )));
            }
            let iv_u = iv as u128;
            if iv_u > usize::MAX as u128 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "bincount: input value too large",
                    },
                )));
            }
            max_val = Some(max_val.map_or(iv, |cur| cur.max(iv)));
        }

        let out_len = match max_val {
            Some(m) => {
                let m_usize = usize::try_from(m).map_err(|_| {
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "bincount: input value too large",
                        },
                    ))
                })?;
                let base = m_usize.checked_add(1).ok_or({
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "bincount: output size overflow",
                        },
                    ))
                })?;
                base.max(minlength)
            }
            None => minlength, // empty input
        };
        let _ = Self::checked_mul(
            out_len,
            std::mem::size_of::<f64>(),
            "bincount output size overflow",
        )?;

        // Compose via tensor_scatter_add so gradients flow back to the
        // weights tensor when present. Tracked under frankentorch-9r3c.
        // Previous body extracted both input and weight values + rebuilt
        // a non-grad leaf, severing autograd through every weighted
        // bincount call (focal-loss-style class re-weighting, etc.).
        // The input (bin indices) is integer-valued and intrinsically
        // non-differentiable; only weights flow gradients.
        if vals.is_empty() {
            return self.tensor_variable(vec![0.0; out_len], vec![out_len], false);
        }
        let zeros = self.full(vec![out_len], 0.0, false)?;
        // input itself is the index tensor; reshape pass-through to
        // make the autograd contract clear (and so we can pass the
        // original requires_grad=false integer tensor as the index).
        if let Some(weights) = weights {
            self.tensor_scatter_add(zeros, 0, input, weights)
        } else {
            // Unweighted case: src = ones of same shape as input.
            let ones = self.full(vec![vals.len()], 1.0, false)?;
            self.tensor_scatter_add(zeros, 0, input, ones)
        }
    }

    /// Compute the histogram of a tensor.
    ///
    /// Equivalent to `torch.histc(input, bins=100, min=0, max=0)`.
    /// Divides the range `[min, max]` into `bins` equal-width bins and counts
    /// elements falling into each bin. If `min == max`, the range is set to
    /// `[input.min(), input.max()]`.
    ///
    /// Values outside `[min, max]` are *ignored* (not counted in any bin),
    /// matching PyTorch's `torch.histc` and NumPy's `numpy.histogram`. The
    /// upper boundary is inclusive: values exactly equal to `max` land in
    /// the last bin (`bins - 1`).
    pub fn tensor_histc(
        &mut self,
        input: TensorNodeId,
        bins: usize,
        min_val: f64,
        max_val: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: autograd not supported (integer counts are non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        if bins == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: bins must be > 0",
                },
            )));
        }
        if !min_val.is_finite() || !max_val.is_finite() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: min and max must be finite",
                },
            )));
        }
        if min_val > max_val {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histc: min must be <= max",
                },
            )));
        }

        let vals = self.tensor_values(input)?;
        for &v in &vals {
            if !v.is_finite() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histc: input values must be finite",
                    },
                )));
            }
        }

        let (lo, hi) = if (min_val - max_val).abs() < f64::EPSILON {
            // Auto-range from data
            let mut data_min = f64::INFINITY;
            let mut data_max = f64::NEG_INFINITY;
            for &v in &vals {
                if v < data_min {
                    data_min = v;
                }
                if v > data_max {
                    data_max = v;
                }
            }
            if data_min == data_max {
                (data_min - 0.5, data_max + 0.5)
            } else {
                (data_min, data_max)
            }
        } else {
            (min_val, max_val)
        };

        let mut counts = vec![0.0f64; bins];
        let bin_width = (hi - lo) / bins as f64;

        // Match PyTorch / numpy semantics: values outside [lo, hi] are
        // ignored (not counted in any bin). The upper boundary is
        // inclusive — values exactly equal to `hi` land in the last
        // bin (the floor((v-lo)/bin_width) computation maps `v == hi`
        // to bin `bins`, which we cap to `bins - 1`).
        //
        // Previously this clamped out-of-range values to the first /
        // last bin, which violated the "Equivalent to torch.histc"
        // contract: torch.histc(x=[-10, 0.5, 1.5, 100], bins=2,
        // min=0, max=2) returns [1, 1] (just the in-range elements),
        // not [2, 2].
        for &v in &vals {
            if v < lo || v > hi {
                continue;
            }
            #[allow(clippy::cast_sign_loss, clippy::cast_possible_truncation)]
            let raw_bin = ((v - lo) / bin_width) as usize;
            let bin = raw_bin.min(bins - 1);
            counts[bin] += 1.0;
        }

        self.tensor_variable(counts, vec![bins], false)
    }

    /// Compute a histogram and return `(hist, bin_edges)`.
    ///
    /// Equivalent to `torch.histogram(input, bins, range=(min, max),
    /// weight=weight, density=density)` for integer `bins`. The input is
    /// flattened, values outside the range are ignored, and the rightmost
    /// edge is inclusive for the final bin.
    pub fn tensor_histogram(
        &mut self,
        input: TensorNodeId,
        bins: usize,
        min_val: f64,
        max_val: f64,
        weight: Option<TensorNodeId>,
        density: bool,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogram: autograd not supported (integer counts are non-differentiable). Tracked under frankentorch-jk0k.",
                },
            )));
        }
        if let Some(weight_id) = weight
            && self.tensor_requires_grad(weight_id)?
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogram: autograd not supported for weight. Tracked under frankentorch-jk0k.",
                },
            )));
        }
        if bins == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogram: bins must be > 0",
                },
            )));
        }
        if !min_val.is_finite() || !max_val.is_finite() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogram: min and max must be finite",
                },
            )));
        }
        if min_val > max_val {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogram: min must be <= max",
                },
            )));
        }

        let vals = self.tensor_values(input)?;
        for &v in &vals {
            if !v.is_finite() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histogram: input values must be finite",
                    },
                )));
            }
        }

        let weight_vals = if let Some(weight_id) = weight {
            let weights = self.tensor_values(weight_id)?;
            if weights.len() != vals.len() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histogram: weight must have the same number of elements as input",
                    },
                )));
            }
            for &w in &weights {
                if !w.is_finite() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "histogram: weight values must be finite",
                        },
                    )));
                }
            }
            Some(weights)
        } else {
            None
        };

        let (lo, hi) = if (min_val - max_val).abs() < f64::EPSILON {
            if vals.is_empty() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histogram: auto range requires non-empty input",
                    },
                )));
            }
            let mut data_min = f64::INFINITY;
            let mut data_max = f64::NEG_INFINITY;
            for &v in &vals {
                if v < data_min {
                    data_min = v;
                }
                if v > data_max {
                    data_max = v;
                }
            }
            if data_min == data_max {
                (data_min - 0.5, data_max + 0.5)
            } else {
                (data_min, data_max)
            }
        } else {
            (min_val, max_val)
        };

        let bin_width = (hi - lo) / bins as f64;
        let mut counts = vec![0.0f64; bins];

        for (idx, &v) in vals.iter().enumerate() {
            if v < lo || v > hi {
                continue;
            }
            #[allow(clippy::cast_sign_loss, clippy::cast_possible_truncation)]
            let raw_bin = ((v - lo) / bin_width) as usize;
            let bin = raw_bin.min(bins - 1);
            let contribution = weight_vals.as_ref().map_or(1.0, |weights| weights[idx]);
            counts[bin] += contribution;
        }

        if density {
            let total: f64 = counts.iter().sum();
            let scale = total * bin_width;
            for count in &mut counts {
                *count /= scale;
            }
        }

        let edge_count = Self::checked_add(bins, 1, "histogram: edge count overflow")?;
        let mut edges = Vec::with_capacity(edge_count);
        for i in 0..edge_count {
            edges.push(lo + bin_width * i as f64);
        }

        let hist = self.tensor_variable(counts, vec![bins], false)?;
        let bin_edges = self.tensor_variable(edges, vec![edge_count], false)?;
        Ok((hist, bin_edges))
    }

    /// Compute a multi-dimensional histogram.
    ///
    /// Equivalent to `torch.histogramdd`. Input is a 2D tensor where each row is a sample
    /// and each column is a dimension. Returns histogram counts and list of bin edges per dimension.
    ///
    /// `bins` specifies the number of bins per dimension.
    /// `ranges` specifies (min, max) per dimension (or None for auto-range).
    pub fn tensor_histogramdd(
        &mut self,
        input: TensorNodeId,
        bins: &[usize],
        ranges: Option<&[(f64, f64)]>,
        density: bool,
    ) -> Result<(TensorNodeId, Vec<TensorNodeId>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogramdd: autograd not supported (integer counts are non-differentiable)",
                },
            )));
        }

        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogramdd: input must be 2D (N samples x D dimensions)",
                },
            )));
        }
        let n_samples = shape[0];
        let n_dims = shape[1];

        if bins.len() != n_dims {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "histogramdd: bins length must match number of dimensions",
                },
            )));
        }
        for &b in bins {
            if b == 0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histogramdd: all bin counts must be > 0",
                    },
                )));
            }
        }

        if let Some(r) = ranges {
            if r.len() != n_dims {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "histogramdd: ranges length must match number of dimensions",
                    },
                )));
            }
        }

        let vals = self.tensor_values(input)?;

        // Compute ranges per dimension
        let dim_ranges: Vec<(f64, f64)> = if let Some(r) = ranges {
            r.to_vec()
        } else {
            (0..n_dims)
                .map(|d| {
                    let mut lo = f64::INFINITY;
                    let mut hi = f64::NEG_INFINITY;
                    for s in 0..n_samples {
                        let v = vals[s * n_dims + d];
                        if v < lo {
                            lo = v;
                        }
                        if v > hi {
                            hi = v;
                        }
                    }
                    if lo == hi {
                        (lo - 0.5, hi + 0.5)
                    } else {
                        (lo, hi)
                    }
                })
                .collect()
        };

        // Compute bin widths per dimension
        let bin_widths: Vec<f64> = bins
            .iter()
            .zip(&dim_ranges)
            .map(|(&b, &(lo, hi))| (hi - lo) / b as f64)
            .collect();

        // Initialize histogram counts
        let total_bins: usize = bins.iter().product();
        let mut counts = vec![0.0f64; total_bins];

        // Process each sample
        for s in 0..n_samples {
            let mut bin_indices = Vec::with_capacity(n_dims);
            let mut valid = true;
            for d in 0..n_dims {
                let v = vals[s * n_dims + d];
                let (lo, hi) = dim_ranges[d];
                if v < lo || v > hi {
                    valid = false;
                    break;
                }
                #[allow(clippy::cast_sign_loss, clippy::cast_possible_truncation)]
                let raw_bin = ((v - lo) / bin_widths[d]) as usize;
                let bin = raw_bin.min(bins[d] - 1);
                bin_indices.push(bin);
            }
            if valid {
                // Convert multi-index to linear index (row-major)
                let mut linear_idx = 0;
                let mut stride = 1;
                for d in (0..n_dims).rev() {
                    linear_idx += bin_indices[d] * stride;
                    stride *= bins[d];
                }
                counts[linear_idx] += 1.0;
            }
        }

        if density {
            let total: f64 = counts.iter().sum();
            let cell_volume: f64 = bin_widths.iter().product();
            let scale = total * cell_volume;
            if scale > 0.0 {
                for count in &mut counts {
                    *count /= scale;
                }
            }
        }

        let hist = self.tensor_variable(counts, bins.to_vec(), false)?;

        // Create bin edge tensors for each dimension
        let mut edge_tensors = Vec::with_capacity(n_dims);
        for d in 0..n_dims {
            let edge_count = bins[d] + 1;
            let (lo, _) = dim_ranges[d];
            let edges: Vec<f64> = (0..edge_count)
                .map(|i| lo + bin_widths[d] * i as f64)
                .collect();
            let edge_tensor = self.tensor_variable(edges, vec![edge_count], false)?;
            edge_tensors.push(edge_tensor);
        }

        Ok((hist, edge_tensors))
    }

    /// Create a block diagonal matrix from provided 2-D tensors.
    ///
    /// Equivalent to `torch.block_diag(*tensors)`. Each tensor is placed
    /// along the diagonal of the output matrix, with zeros elsewhere.
    /// 1-D tensors are treated as (1, N) matrices.
    pub fn tensor_block_diag(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return self.tensor_variable(vec![], vec![0, 0], false);
        }

        // Pre-compute block (rows, cols), output total dimensions, and
        // (row_offset, col_offset) per block. The forward + backward
        // closures need both the per-block extents (to walk the block)
        // and the offsets (to map block coords ↔ output coords).
        // We also preserve the original input shape (1-D vs 2-D) so
        // gradients return as the same rank.
        let mut block_meta: Vec<(usize, usize, usize, usize, Vec<usize>)> =
            Vec::with_capacity(tensors.len());
        for &t in tensors {
            let shape = self.tensor_shape(t)?;
            let (rows, cols) = match shape.len() {
                1 => (1, shape[0]),
                2 => (shape[0], shape[1]),
                _ => {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "block_diag: all tensors must be 1-D or 2-D",
                        },
                    )));
                }
            };
            block_meta.push((rows, cols, 0, 0, shape.clone()));
        }
        // Fill row/col offsets sequentially.
        let mut row_offset = 0usize;
        let mut col_offset = 0usize;
        for entry in &mut block_meta {
            entry.2 = row_offset;
            entry.3 = col_offset;
            row_offset = Self::checked_add(row_offset, entry.0, "block_diag: output overflow")?;
            col_offset = Self::checked_add(col_offset, entry.1, "block_diag: output overflow")?;
        }
        let total_rows = row_offset;
        let total_cols = col_offset;
        let numel = Self::checked_mul(total_rows, total_cols, "block_diag: output overflow")?;
        let _ = Self::checked_mul(
            numel,
            std::mem::size_of::<f64>(),
            "block_diag: output overflow",
        )?;

        // Forward + backward closures need the metadata at backward
        // time. tensor_apply_function captures via Send + Sync, so we
        // clone into the closures.
        let block_meta_fwd = block_meta.clone();
        let block_meta_bwd = block_meta.clone();
        self.tensor_apply_function(
            tensors,
            move |_ctx, inputs| {
                let mut data = vec![0.0_f64; total_rows * total_cols];
                for (i, (vals, _shape)) in inputs.iter().enumerate() {
                    let (rows, cols, row_off, col_off, _) = block_meta_fwd[i];
                    let expected = rows.checked_mul(cols).ok_or(AutogradError::Dispatch(
                        ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "block_diag: block size overflow",
                            },
                        ),
                    ))?;
                    if vals.len() != expected {
                        return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "block_diag: values length does not match shape",
                            },
                        )));
                    }
                    // Copy each contiguous row as a slice to avoid per-cell scatter.
                    for r in 0..rows {
                        let dst_start = (row_off + r) * total_cols + col_off;
                        let src_start = r * cols;
                        data[dst_start..dst_start + cols]
                            .copy_from_slice(&vals[src_start..src_start + cols]);
                    }
                }
                Ok((data, vec![total_rows, total_cols]))
            },
            move |_ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let mut grads: Vec<Option<Vec<f64>>> = Vec::with_capacity(block_meta_bwd.len());
                for (rows, cols, row_off, col_off, original_shape) in &block_meta_bwd {
                    let mut grad_block = vec![0.0_f64; rows * cols];
                    // Copy each contiguous gradient row back into the source block.
                    for r in 0..*rows {
                        let src_start = (row_off + r) * total_cols + col_off;
                        let dst_start = r * cols;
                        grad_block[dst_start..dst_start + *cols]
                            .copy_from_slice(&grad_y[src_start..src_start + *cols]);
                    }
                    // Original 1-D inputs deserve a flat-1-D gradient
                    // (rows == 1 && shape.len() == 1) — the storage
                    // is row-major so the same Vec works.
                    let _ = original_shape;
                    grads.push(Some(grad_block));
                }
                Ok(grads)
            },
        )
    }

    /// Generate a Vandermonde matrix from a 1-D input tensor.
    ///
    /// Equivalent to `torch.vander(x, N=None, increasing=False)`.
    /// If `n` is None, N = len(x). Each row `i` is `[x[i]^(N-1), ..., x[i]^0]`
    /// (decreasing) or `[x[i]^0, ..., x[i]^(N-1)]` (increasing).
    pub fn tensor_vander(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
        increasing: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            // Migrate to InvalidDimension (frankentorch-qaux).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 1,
                },
            )));
        }
        let rows = shape[0];
        let cols = n.unwrap_or(rows);
        if cols > i32::MAX as usize {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vander: N too large",
                },
            )));
        }
        let numel = Self::checked_mul(rows, cols, "vander: output size overflow")?;
        let _ = Self::checked_mul(
            numel,
            std::mem::size_of::<f64>(),
            "vander: output size overflow",
        )?;

        // Forward: output[i, j] = x[i]^exp_j   where
        //     exp_j = j if increasing else cols-1-j.
        // Backward (each row depends only on x[i]):
        //     d output[i, j] / d x[i] = exp_j * x[i]^(exp_j - 1)   (0 when exp_j == 0)
        //     grad_input[i] = sum_j grad_output[i, j] * exp_j * x[i]^(exp_j - 1)
        // Save x for backward. Tracked under frankentorch-j3kg.
        self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, _in_shape) = inputs[0];
                if vals.len() != rows {
                    // Surface both actual lengths so the caller
                    // can diagnose the closure-time mismatch
                    // without grepping a static reason
                    // (frankentorch-zurt).
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                        ft_kernel_cpu::KernelError::ShapeMismatch {
                            lhs: vec![vals.len()],
                            rhs: vec![rows],
                        },
                    )));
                }
                let mut data = vec![0.0_f64; numel];
                for i in 0..rows {
                    for j in 0..cols {
                        let exp = if increasing { j } else { cols - 1 - j };
                        data[i * cols + j] = vals[i].powi(exp as i32);
                    }
                }
                ctx.save_for_backward(vals.to_vec(), vec![rows]);
                Ok((data, vec![rows, cols]))
            },
            move |ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                let mut grad_in = vec![0.0_f64; rows];
                for i in 0..rows {
                    let xi = x_vals[i];
                    let mut acc = 0.0_f64;
                    for j in 0..cols {
                        let exp = if increasing { j } else { cols - 1 - j };
                        if exp == 0 {
                            // d x^0 / dx = 0; constant column contributes nothing.
                            continue;
                        }
                        let power = (exp - 1) as i32;
                        let coeff = exp as f64;
                        acc += grad_y[i * cols + j] * coeff * xi.powi(power);
                    }
                    grad_in[i] = acc;
                }
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Create a complex tensor from magnitude and phase angle.
    ///
    /// Equivalent to `torch.polar(abs, angle)`.
    /// Returns a complex tensor where `real = abs * cos(angle)` and `imag = abs * sin(angle)`.
    ///
    /// Inputs should be F32 tensors (Complex64 output) or F64 tensors (Complex128 output).
    pub fn tensor_polar(
        &mut self,
        abs: TensorNodeId,
        angle: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compute real = abs * cos(angle), imag = abs * sin(angle) via autograd ops
        let cos_angle = self.tensor_cos(angle)?;
        let sin_angle = self.tensor_sin(angle)?;
        let real = self.tensor_mul(abs, cos_angle)?;
        let imag = self.tensor_mul(abs, sin_angle)?;
        self.tensor_complex(real, imag)
    }

    /// Cartesian product of 1-D tensors.
    ///
    /// Equivalent to `torch.cartesian_prod(*tensors)`.
    /// Returns a 2-D tensor where each row is one element of the Cartesian product.
    pub fn tensor_cartesian_prod(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cartesian_prod: need at least one tensor",
                },
            )));
        }

        // Validate shapes + collect lengths.
        let mut lengths: Vec<usize> = Vec::with_capacity(tensors.len());
        for &t in tensors {
            let s = self.tensor_shape(t)?;
            if s.len() != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "cartesian_prod: all inputs must be 1-D",
                    },
                )));
            }
            lengths.push(s[0]);
        }
        let n_tensors = lengths.len();
        let mut total_rows = 1usize;
        for &len in &lengths {
            total_rows = total_rows.checked_mul(len).ok_or(AutogradError::Dispatch(
                ft_dispatch::DispatchError::Key(ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cartesian_prod: total row count overflow",
                }),
            ))?;
        }
        let _ = total_rows
            .checked_mul(n_tensors)
            .ok_or(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cartesian_prod: output size overflow",
                },
            )))?;

        // Pre-compute the (row, k) → input_index_in_tensor_k mapping.
        // The forward gathers; the backward scatters. Tracked under
        // frankentorch-7ude.
        let mut mapping: Vec<Vec<usize>> = vec![Vec::with_capacity(total_rows); n_tensors];
        let mut indices = vec![0usize; n_tensors];
        for _ in 0..total_rows {
            for k in 0..n_tensors {
                mapping[k].push(indices[k]);
            }
            for k in (0..n_tensors).rev() {
                indices[k] += 1;
                if indices[k] < lengths[k] {
                    break;
                }
                indices[k] = 0;
            }
        }

        let mapping_for_fwd = mapping.clone();
        let mapping_for_bwd = mapping;
        let lengths_clone = lengths;
        let total_rows_c = total_rows;
        let n_tensors_c = n_tensors;

        self.tensor_apply_function(
            tensors,
            move |_ctx, inputs| {
                let mut result = Vec::with_capacity(total_rows_c * n_tensors_c);
                for row in 0..total_rows_c {
                    for (k, mapping_k) in mapping_for_fwd.iter().enumerate() {
                        let idx = mapping_k[row];
                        let (vals, _shape) = inputs[k];
                        result.push(vals[idx]);
                    }
                }
                Ok((result, vec![total_rows_c, n_tensors_c]))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                // For each input tensor k, scatter g[row, k] back to
                // grad_input_k[mapping[k][row]].
                let mut grads: Vec<Option<Vec<f64>>> = Vec::with_capacity(n_tensors_c);
                for k in 0..n_tensors_c {
                    let mut grad_k = vec![0.0_f64; lengths_clone[k]];
                    for row in 0..total_rows_c {
                        let i = mapping_for_bwd[k][row];
                        grad_k[i] += g[row * n_tensors_c + k];
                    }
                    grads.push(Some(grad_k));
                }
                Ok(grads)
            },
        )
    }

    /// All r-length combinations of elements from a 1-D tensor.
    ///
    /// Equivalent to `torch.combinations(input, r, with_replacement)`.
    /// Returns a 2-D tensor where each row is one combination.
    pub fn tensor_combinations(
        &mut self,
        input: TensorNodeId,
        r: usize,
        with_replacement: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            // Migrate to InvalidDimension (frankentorch-qaux).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 1,
                },
            )));
        }
        let n = shape[0];

        // Pre-compute the index-mapping: combo_indices is a flat list
        // of (input_position) for each (combo, slot_in_combo) cell of
        // the output. Use the same recursive enumeration as before
        // but track indices instead of values. The mapping is then
        // captured by the forward (gather) and backward (scatter)
        // closures in tensor_apply_function. Tracked under
        // frankentorch-d214 — previously this body extracted values,
        // built the output in plain f64, and rebuilt a non-grad leaf.
        let mut combo_indices: Vec<usize> = Vec::new();
        let mut current_indices: Vec<usize> = Vec::with_capacity(r);

        fn generate_idx(
            n: usize,
            r: usize,
            start: usize,
            current: &mut Vec<usize>,
            out: &mut Vec<usize>,
            with_replacement: bool,
        ) {
            if current.len() == r {
                out.extend_from_slice(current);
                return;
            }
            for i in start..n {
                current.push(i);
                let next = if with_replacement { i } else { i + 1 };
                generate_idx(n, r, next, current, out, with_replacement);
                current.pop();
            }
        }

        generate_idx(
            n,
            r,
            0,
            &mut current_indices,
            &mut combo_indices,
            with_replacement,
        );

        let num_combos = combo_indices.len().checked_div(r).unwrap_or(1);
        let total = Self::checked_mul(num_combos, r, "combinations output size overflow")?;

        if num_combos == 0 {
            return self.tensor_variable(vec![], vec![0, r], false);
        }

        let mapping_for_fwd = combo_indices.clone();
        let mapping_for_bwd = combo_indices;
        self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _shape) = inputs[0];
                let result: Vec<f64> = mapping_for_fwd.iter().map(|&i| vals[i]).collect();
                Ok((result, vec![num_combos, r]))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; n];
                for (out_pos, &in_pos) in mapping_for_bwd.iter().enumerate() {
                    grad_in[in_pos] += g[out_pos];
                }
                let _ = total; // keep total in scope for size validation above
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Compute r-length combinations with replacement from a 1D input tensor.
    ///
    /// Equivalent to `torch.combinations(input, r, with_replacement=True)`.
    /// This is a convenience wrapper around `tensor_combinations` with
    /// `with_replacement=true`.
    pub fn tensor_combinations_with_replacement(
        &mut self,
        input: TensorNodeId,
        r: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_combinations(input, r, true)
    }

    /// Compute batched pairwise distance between two sets of vectors.
    ///
    /// Equivalent to `torch.cdist(x1, x2, p=2.0)`.
    /// x1: (B, P, M) or (P, M), x2: (B, R, M) or (R, M).
    /// Returns: (B, P, R) or (P, R) matrix of Lp distances.
    pub fn tensor_cdist(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let x1_shape = self.tensor_shape(x1)?;
        let x2_shape = self.tensor_shape(x2)?;
        Self::validate_nonnegative_norm_order(p, "cdist: p must be in [0, inf]")?;

        let (batch, p_dim, m1, r_dim, m2, batched) = match (x1_shape.len(), x2_shape.len()) {
            (2, 2) => (1, x1_shape[0], x1_shape[1], x2_shape[0], x2_shape[1], false),
            (3, 3) => {
                if x1_shape[0] != x2_shape[0] {
                    // Surface both shapes so the caller can see the
                    // actual batch sizes (frankentorch-zf6b).
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                        ft_kernel_cpu::KernelError::ShapeMismatch {
                            lhs: x1_shape,
                            rhs: x2_shape,
                        },
                    )));
                }
                (
                    x1_shape[0],
                    x1_shape[1],
                    x1_shape[2],
                    x2_shape[1],
                    x2_shape[2],
                    true,
                )
            }
            _ => {
                // Surface the actual x1 rank that was given so the
                // caller sees 'expected 2 or 3 but got N' instead
                // of an opaque static reason (frankentorch-zf6b).
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::InvalidDimension {
                        dim: 0,
                        ndim: x1_shape.len(),
                    },
                )));
            }
        };

        if m1 != m2 {
            // Caller compares lhs/rhs at the last dim to see which
            // feature size disagreed (frankentorch-zf6b).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: x1_shape,
                    rhs: x2_shape,
                },
            )));
        }
        let m = m1;

        // Autograd path for finite p > 0 composes through broadcasted
        // sub + abs + pow + sum_dim + pow. p == +inf uses the same
        // broadcasted difference and reduces through tensor_amax so
        // gradients route to the max-distance coordinate. p == 0 stays
        // fail-loud below because the count metric is not differentiable.
        if ((p.is_finite() && p > 0.0) || p == f64::INFINITY) && batch * p_dim * r_dim > 0 {
            let (x1_b, x2_b, expand_target, sum_dim_idx, out_shape) = if batched {
                // x1: [B, P, M], x2: [B, R, M]
                // x1_b: [B, P, 1, M], x2_b: [B, 1, R, M], target: [B, P, R, M]
                let x1_u = self.tensor_unsqueeze(x1, 2)?;
                let x2_u = self.tensor_unsqueeze(x2, 1)?;
                (
                    x1_u,
                    x2_u,
                    vec![batch, p_dim, r_dim, m],
                    3,
                    vec![batch, p_dim, r_dim],
                )
            } else {
                // x1: [P, M], x2: [R, M]
                // x1_b: [P, 1, M], x2_b: [1, R, M], target: [P, R, M]
                let x1_u = self.tensor_unsqueeze(x1, 1)?;
                let x2_u = self.tensor_unsqueeze(x2, 0)?;
                (x1_u, x2_u, vec![p_dim, r_dim, m], 2, vec![p_dim, r_dim])
            };
            let x1_e = self.tensor_expand(x1_b, expand_target.clone())?;
            let x2_e = self.tensor_expand(x2_b, expand_target)?;
            let diff = self.tensor_sub(x1_e, x2_e)?;
            let abs_diff = self.tensor_abs(diff)?;
            if p == f64::INFINITY {
                let result = self.tensor_amax(abs_diff, sum_dim_idx)?;
                return self.tensor_reshape(result, out_shape);
            }
            let pow_diff = self.tensor_pow(abs_diff, p)?;
            let sum = self.tensor_sum_dim(pow_diff, sum_dim_idx)?;
            let result = self.tensor_pow(sum, 1.0 / p)?;
            // Reshape ensures the output shape contract matches the
            // original direct-path output (sum_dim already reduces
            // the right axis; we just need to confirm the shape).
            return self.tensor_reshape(result, out_shape);
        }

        if p == 0.0
            && (self.tensor_tape.tensor_requires_grad(x1)?
                || self.tensor_tape.tensor_requires_grad(x2)?)
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cdist: autograd not supported for p=0 counting metric",
                },
            )));
        }

        // Non-grad fallback path for p == 0, p == inf, or empty output.
        let x1_vals = self.tensor_values(x1)?;
        let x2_vals = self.tensor_values(x2)?;

        let mut result = vec![0.0f64; batch * p_dim * r_dim];

        for b in 0..batch {
            let x1_base = b * p_dim * m;
            let x2_base = b * r_dim * m;
            let out_base = b * p_dim * r_dim;

            for i in 0..p_dim {
                for j in 0..r_dim {
                    let mut dist = 0.0f64;
                    if p == f64::INFINITY {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            if diff > dist {
                                dist = diff;
                            }
                        }
                    } else if p == 0.0 {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            if diff > f64::EPSILON {
                                dist += 1.0;
                            }
                        }
                    } else {
                        for k in 0..m {
                            let diff =
                                (x1_vals[x1_base + i * m + k] - x2_vals[x2_base + j * m + k]).abs();
                            dist += diff.powf(p);
                        }
                        dist = dist.powf(1.0 / p);
                    }
                    result[out_base + i * r_dim + j] = dist;
                }
            }
        }

        let out_shape = if batched {
            vec![batch, p_dim, r_dim]
        } else {
            vec![p_dim, r_dim]
        };
        self.tensor_variable(result, out_shape, false)
    }

    /// Compute pairwise distance between all pairs of row vectors in a 2-D tensor.
    ///
    /// Equivalent to `torch.nn.functional.pdist(input, p=2)`.
    /// Input: (N, M) tensor. Returns: 1-D tensor of N*(N-1)/2 distances.
    pub fn tensor_pdist(
        &mut self,
        input: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-oitu).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        Self::validate_nonnegative_norm_order(p, "pdist: p must be in [0, inf]")?;
        let n = shape[0];
        let m = shape[1];
        let out_len = n * (n - 1) / 2;

        // For finite p > 0, compose through index_select + sub + abs +
        // pow + sum_dim + pow primitives so gradients flow to the
        // input. PyTorch's torch.nn.functional.pdist IS differentiable
        // for finite p > 0 (sub-gradient at the abs corner). p == +inf
        // uses the same row-pair diff and tensor_amax for max-routing
        // gradients. p == 0 (counting metric) remains fail-loud below.
        // Tracked under frankentorch-0i8u and frankentorch-hzc6.
        if ((p.is_finite() && p > 0.0) || p == f64::INFINITY) && out_len > 0 {
            // Build row_i and row_j index tensors of length out_len.
            #[allow(clippy::cast_precision_loss)]
            let mut row_i_idx = Vec::with_capacity(out_len);
            #[allow(clippy::cast_precision_loss)]
            let mut row_j_idx = Vec::with_capacity(out_len);
            for i in 0..n {
                for j in (i + 1)..n {
                    row_i_idx.push(i as f64);
                    row_j_idx.push(j as f64);
                }
            }
            let row_i_t = self.tensor_tape.leaf(row_i_idx, vec![out_len], false)?;
            let row_j_t = self.tensor_tape.leaf(row_j_idx, vec![out_len], false)?;
            let left = self.tensor_index_select(input, 0, row_i_t)?;
            let right = self.tensor_index_select(input, 0, row_j_t)?;
            let diff = self.tensor_sub(left, right)?;
            let abs_diff = self.tensor_abs(diff)?;
            if p == f64::INFINITY {
                return self.tensor_amax(abs_diff, 1);
            }
            let pow_diff = self.tensor_pow(abs_diff, p)?;
            let sum = self.tensor_sum_dim(pow_diff, 1)?; // [out_len]
            return self.tensor_pow(sum, 1.0 / p);
        }

        if p == 0.0 && self.tensor_tape.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pdist: autograd not supported for p=0 counting metric",
                },
            )));
        }

        // Non-grad paths for p == 0, p == inf, or empty output —
        // fall back to the original direct computation.
        let vals = self.tensor_values(input)?;
        let mut result = Vec::with_capacity(out_len);
        for i in 0..n {
            for j in (i + 1)..n {
                let mut dist = 0.0f64;
                if p == f64::INFINITY {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        if diff > dist {
                            dist = diff;
                        }
                    }
                } else if p == 0.0 {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        if diff > f64::EPSILON {
                            dist += 1.0;
                        }
                    }
                } else {
                    for k in 0..m {
                        let diff = (vals[i * m + k] - vals[j * m + k]).abs();
                        dist += diff.powf(p);
                    }
                    dist = dist.powf(1.0 / p);
                }
                result.push(dist);
            }
        }

        self.tensor_variable(result, vec![out_len], false)
    }

    /// Convert class indices to one-hot encoded tensors.
    ///
    /// Equivalent to `torch.nn.functional.one_hot(input, num_classes)`.
    /// Input must be a 1D tensor of integer indices in [0, num_classes).
    /// Output is a 2D tensor of shape (input_len, num_classes).
    pub fn tensor_one_hot(
        &mut self,
        input: TensorNodeId,
        num_classes: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "one_hot: input must be 1D",
                },
            )));
        }
        let n = shape[0];
        let values = self.tensor_values(input)?;
        let mut result = vec![0.0_f64; n * num_classes];
        for (i, &idx) in values.iter().enumerate() {
            let class_idx = idx as usize;
            if class_idx >= num_classes {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "one_hot: class index out of range",
                    },
                )));
            }
            result[i * num_classes + class_idx] = 1.0;
        }
        self.tensor_variable(result, vec![n, num_classes], false)
    }

    /// Look up embeddings from a weight matrix.
    ///
    /// Equivalent to `torch.nn.functional.embedding(input, weight, padding_idx)`.
    /// Returns embeddings for each index in input.
    ///
    /// - `input`: Indices into the embedding table, any shape
    /// - `weight`: Embedding weight matrix, shape (num_embeddings, embedding_dim)
    /// - `padding_idx`: If set, entries at this index are zeroed
    pub fn tensor_embedding(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        padding_idx: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if weight_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding: weight must be 2D (num_embeddings, embedding_dim)",
                },
            )));
        }
        let num_embeddings = weight_shape[0];
        let embedding_dim = weight_shape[1];
        let input_vals = self.tensor_values(input)?;
        let weight_vals = self.tensor_values(weight)?;
        let num_indices: usize = input_shape.iter().product();
        let mut result = Vec::with_capacity(num_indices * embedding_dim);
        for &idx in &input_vals {
            let idx = idx as usize;
            if idx >= num_embeddings {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: index out of range",
                    },
                )));
            }
            if padding_idx == Some(idx) {
                result.extend(std::iter::repeat(0.0).take(embedding_dim));
            } else {
                let start = idx * embedding_dim;
                result.extend_from_slice(&weight_vals[start..start + embedding_dim]);
            }
        }
        let mut out_shape = input_shape;
        out_shape.push(embedding_dim);
        self.tensor_variable(result, out_shape, false)
    }

    /// Compute sums or means of embedding bags.
    ///
    /// Equivalent to `torch.nn.functional.embedding_bag(input, weight, offsets, mode)`.
    /// Groups embeddings by offsets and reduces each group.
    ///
    /// - `input`: 1D tensor of indices
    /// - `weight`: Embedding weight matrix, shape (num_embeddings, embedding_dim)
    /// - `offsets`: 1D tensor of starting indices for each bag
    /// - `mode`: "sum", "mean", or "max"
    pub fn tensor_embedding_bag(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        offsets: TensorNodeId,
        mode: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        let offsets_shape = self.tensor_shape(offsets)?;
        if input_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding_bag: input must be 1D",
                },
            )));
        }
        if weight_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding_bag: weight must be 2D",
                },
            )));
        }
        if offsets_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding_bag: offsets must be 1D",
                },
            )));
        }
        let num_embeddings = weight_shape[0];
        let embedding_dim = weight_shape[1];
        let num_bags = offsets_shape[0];
        let input_vals = self.tensor_values(input)?;
        let weight_vals = self.tensor_values(weight)?;
        let offsets_vals = self.tensor_values(offsets)?;
        let input_len = input_vals.len();
        let mut result = Vec::with_capacity(num_bags * embedding_dim);
        for b in 0..num_bags {
            let start = offsets_vals[b] as usize;
            let end = if b + 1 < num_bags {
                offsets_vals[b + 1] as usize
            } else {
                input_len
            };
            let bag_size = end.saturating_sub(start);
            let mut agg = vec![0.0_f64; embedding_dim];
            for i in start..end.min(input_len) {
                let idx = input_vals[i] as usize;
                if idx >= num_embeddings {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "embedding_bag: index out of range",
                        },
                    )));
                }
                let emb_start = idx * embedding_dim;
                for j in 0..embedding_dim {
                    let val = weight_vals[emb_start + j];
                    match mode {
                        "sum" | "mean" => agg[j] += val,
                        "max" => {
                            if i == start || val > agg[j] {
                                agg[j] = val;
                            }
                        }
                        _ => {}
                    }
                }
            }
            if mode == "mean" && bag_size > 0 {
                for v in &mut agg {
                    *v /= bag_size as f64;
                }
            }
            result.extend(agg);
        }
        match mode {
            "sum" | "mean" | "max" => {}
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding_bag: mode must be 'sum', 'mean', or 'max'",
                    },
                )));
            }
        }
        self.tensor_variable(result, vec![num_bags, embedding_dim], false)
    }

    /// Compute cosine similarity between tensors along a dimension.
    ///
    /// Equivalent to `torch.nn.functional.cosine_similarity(x1, x2, dim, eps)`.
    /// Returns cos(angle) = (x1 · x2) / (||x1|| * ||x2||).
    pub fn tensor_cosine_similarity(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
        dim: usize,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape1 = self.tensor_shape(x1)?;
        let shape2 = self.tensor_shape(x2)?;
        if shape1 != shape2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape1,
                    rhs: shape2,
                },
            )));
        }
        // dot = sum(x1 * x2, dim)
        let prod = self.tensor_mul(x1, x2)?;
        let dot = self.tensor_sum_dim(prod, dim)?;
        // norm1 = sqrt(sum(x1^2, dim))
        let x1_sq = self.tensor_mul(x1, x1)?;
        let norm1_sq = self.tensor_sum_dim(x1_sq, dim)?;
        let norm1 = self.tensor_sqrt(norm1_sq)?;
        // norm2 = sqrt(sum(x2^2, dim))
        let x2_sq = self.tensor_mul(x2, x2)?;
        let norm2_sq = self.tensor_sum_dim(x2_sq, dim)?;
        let norm2 = self.tensor_sqrt(norm2_sq)?;
        // denom = max(norm1 * norm2, eps)
        let norm_prod = self.tensor_mul(norm1, norm2)?;
        let eps_shape = self.tensor_shape(norm_prod)?;
        let eps_t = self.full(eps_shape, eps, false)?;
        let denom = self.tensor_maximum(norm_prod, eps_t)?;
        self.tensor_div(dot, denom)
    }

    /// Pairwise distance between two tensors.
    ///
    /// Equivalent to `torch.nn.functional.pairwise_distance(x1, x2, p, eps)`.
    /// Computes ||x1 - x2||_p along the last dimension.
    pub fn tensor_pairwise_distance(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
        p: f64,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape1 = self.tensor_shape(x1)?;
        let shape2 = self.tensor_shape(x2)?;
        if shape1 != shape2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape1,
                    rhs: shape2,
                },
            )));
        }
        let diff = self.tensor_sub(x1, x2)?;
        let ndim = shape1.len();
        let last_dim = if ndim > 0 { ndim - 1 } else { 0 };
        // norm_dim returns the p-norm along the dimension
        let dist = self.tensor_norm_dim(diff, p, last_dim)?;
        // Add eps for numerical stability
        let eps_shape = self.tensor_shape(dist)?;
        let eps_t = self.full(eps_shape, eps, false)?;
        self.tensor_add(dist, eps_t)
    }

    /// Normalize a tensor along a dimension using Lp norm.
    ///
    /// Equivalent to `torch.nn.functional.normalize(input, p, dim, eps)`.
    /// Returns input / max(||input||_p, eps) along the specified dimension.
    pub fn tensor_normalize(
        &mut self,
        input: TensorNodeId,
        p: f64,
        dim: usize,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        // norm = ||input||_p along dim
        let norm = self.tensor_norm_dim(input, p, dim)?;
        // unsqueeze norm back to original dim for broadcasting
        let norm_unsq = self.tensor_unsqueeze(norm, dim)?;
        // denom = max(norm, eps)
        let eps_shape = self.tensor_shape(norm_unsq)?;
        let eps_t = self.full(eps_shape, eps, false)?;
        let denom = self.tensor_maximum(norm_unsq, eps_t)?;
        self.tensor_div(input, denom)
    }

    // ── Loss Functions ───────────────────────────────────────────────────

    /// Mean squared error loss.
    ///
    /// Equivalent to `torch.nn.functional.mse_loss(input, target, reduction)`.
    /// Reduction can be "none", "mean", or "sum".
    pub fn tensor_mse_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(input, target)?;
        let sq = self.tensor_mul(diff, diff)?;
        match reduction {
            "none" => Ok(sq),
            "mean" => self.tensor_mean(sq),
            "sum" => self.tensor_sum(sq),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "mse_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// L1 loss (mean absolute error).
    ///
    /// Equivalent to `torch.nn.functional.l1_loss(input, target, reduction)`.
    pub fn tensor_l1_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(input, target)?;
        let abs_diff = self.tensor_abs(diff)?;
        match reduction {
            "none" => Ok(abs_diff),
            "mean" => self.tensor_mean(abs_diff),
            "sum" => self.tensor_sum(abs_diff),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "l1_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Smooth L1 loss (Huber loss with delta=1).
    ///
    /// Equivalent to `torch.nn.functional.smooth_l1_loss(input, target, reduction, beta)`.
    /// Uses L2 loss for |x| < beta, L1 loss otherwise.
    pub fn tensor_smooth_l1_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
        beta: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(input, target)?;
        let abs_diff = self.tensor_abs(diff)?;
        let shape = self.tensor_shape(abs_diff)?;
        let beta_t = self.full(shape.clone(), beta, false)?;
        let half = self.full(shape.clone(), 0.5, false)?;
        let half_beta = self.full(shape, 0.5 * beta, false)?;
        // L2 part: 0.5 * x^2 / beta
        let sq_scaled = self.tensor_mul(diff, diff)?;
        let l2_part = self.tensor_div(sq_scaled, beta_t)?;
        let l2_part = self.tensor_mul(l2_part, half)?;
        // L1 part: |x| - 0.5 * beta
        let l1_part = self.tensor_sub(abs_diff, half_beta)?;
        // mask: |x| < beta
        let abs_diff2 = self.tensor_abs(diff)?;
        let beta_t2 = self.full(self.tensor_shape(abs_diff2)?, beta, false)?;
        let mask = self.tensor_lt(abs_diff2, beta_t2)?;
        let loss = self.tensor_where(mask, l2_part, l1_part)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "smooth_l1_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Binary cross entropy loss.
    ///
    /// Equivalent to `torch.nn.functional.binary_cross_entropy(input, target, reduction)`.
    /// Input should be probabilities in [0, 1].
    pub fn tensor_bce_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        // BCE = -[target * log(input) + (1-target) * log(1-input)]
        let log_input = self.tensor_log(input)?;
        let term1 = self.tensor_mul(target, log_input)?;
        let shape = self.tensor_shape(input)?;
        let ones = self.full(shape, 1.0, false)?;
        let one_minus_target = self.tensor_sub(ones, target)?;
        let one_minus_input = self.tensor_sub(ones, input)?;
        let log_one_minus_input = self.tensor_log(one_minus_input)?;
        let term2 = self.tensor_mul(one_minus_target, log_one_minus_input)?;
        let sum_terms = self.tensor_add(term1, term2)?;
        let loss = self.tensor_neg(sum_terms)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "bce_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Alias for tensor_bce_loss.
    ///
    /// Equivalent to `torch.nn.functional.binary_cross_entropy(input, target, reduction)`.
    pub fn tensor_binary_cross_entropy(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_bce_loss(input, target, reduction)
    }

    /// Binary cross entropy with logits (numerically stable).
    ///
    /// Equivalent to `torch.nn.functional.binary_cross_entropy_with_logits`.
    /// More numerically stable than sigmoid + BCE.
    pub fn tensor_bce_with_logits_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        // BCE_logits = max(input, 0) - input * target + log(1 + exp(-|input|))
        let shape = self.tensor_shape(input)?;
        let zeros = self.full(shape.clone(), 0.0, false)?;
        let relu_input = self.tensor_maximum(input, zeros)?;
        let input_target = self.tensor_mul(input, target)?;
        let term1 = self.tensor_sub(relu_input, input_target)?;
        let abs_input = self.tensor_abs(input)?;
        let neg_abs_input = self.tensor_neg(abs_input)?;
        let exp_term = self.tensor_exp(neg_abs_input)?;
        let ones = self.full(shape, 1.0, false)?;
        let one_plus_exp = self.tensor_add(ones, exp_term)?;
        let log_term = self.tensor_log(one_plus_exp)?;
        let loss = self.tensor_add(term1, log_term)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "bce_with_logits_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Alias for tensor_bce_with_logits_loss.
    ///
    /// Equivalent to `torch.nn.functional.binary_cross_entropy_with_logits`.
    pub fn tensor_binary_cross_entropy_with_logits(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_bce_with_logits_loss(input, target, reduction)
    }

    /// Negative log likelihood loss.
    ///
    /// Equivalent to `torch.nn.functional.nll_loss(input, target, reduction)`.
    /// Input should be log-probabilities from log_softmax.
    /// Target contains class indices (not one-hot encoded).
    pub fn tensor_nll_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let target_shape = self.tensor_shape(target)?;
        if input_shape.len() != 2 || target_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "nll_loss: input must be 2D (N, C), target must be 1D (N,)",
                },
            )));
        }
        if input_shape[0] != target_shape[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "nll_loss: batch size mismatch",
                },
            )));
        }
        let n = input_shape[0];
        let c = input_shape[1];
        let input_vals = self.tensor_values(input)?;
        let target_vals = self.tensor_values(target)?;
        let mut losses = Vec::with_capacity(n);
        for i in 0..n {
            let class_idx = target_vals[i] as usize;
            if class_idx >= c {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "nll_loss: target class index out of range",
                    },
                )));
            }
            losses.push(-input_vals[i * c + class_idx]);
        }
        let loss = self.tensor_variable(losses.clone(), vec![n], false)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "nll_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Cross entropy loss (log_softmax + nll_loss combined).
    ///
    /// Equivalent to `torch.nn.functional.cross_entropy(input, target, reduction)`.
    /// Input should be raw logits. Target contains class indices.
    pub fn tensor_cross_entropy(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let log_probs = self.tensor_log_softmax(input, 1)?;
        self.tensor_nll_loss(log_probs, target, reduction)
    }

    /// Kullback-Leibler divergence loss.
    ///
    /// Equivalent to `torch.nn.functional.kl_div(input, target, reduction, log_target)`.
    /// Input should be log-probabilities. If log_target=true, target is also log-probs.
    pub fn tensor_kl_div(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
        log_target: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let loss = if log_target {
            let exp_target = self.tensor_exp(target)?;
            let diff = self.tensor_sub(target, input)?;
            self.tensor_mul(exp_target, diff)?
        } else {
            let log_target_t = self.tensor_log(target)?;
            let diff = self.tensor_sub(log_target_t, input)?;
            self.tensor_mul(target, diff)?
        };
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            "batchmean" => {
                let sum = self.tensor_sum(loss)?;
                let shape = self.tensor_shape(input)?;
                let batch_size = shape[0] as f64;
                let batch_t = self.full(vec![], batch_size, false)?;
                self.tensor_div(sum, batch_t)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "kl_div: reduction must be 'none', 'mean', 'sum', or 'batchmean'",
                },
            ))),
        }
    }

    /// Huber loss (smooth L1 with configurable delta).
    ///
    /// Equivalent to `torch.nn.functional.huber_loss(input, target, reduction, delta)`.
    pub fn tensor_huber_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
        delta: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_smooth_l1_loss(input, target, reduction, delta)
    }

    /// Hinge embedding loss for margin-based classification.
    ///
    /// Equivalent to `torch.nn.functional.hinge_embedding_loss`.
    pub fn tensor_hinge_embedding_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        margin: f64,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let zeros = self.full(shape.clone(), 0.0, false)?;
        let margin_t = self.full(shape.clone(), margin, false)?;
        let ones = self.full(shape, 1.0, false)?;
        let margin_minus_input = self.tensor_sub(margin_t, input)?;
        let hinge = self.tensor_maximum(zeros, margin_minus_input)?;
        let mask_pos = self.tensor_eq(target, ones)?;
        let loss = self.tensor_where(mask_pos, input, hinge)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "hinge_embedding_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Soft margin loss for binary classification.
    ///
    /// Equivalent to `torch.nn.functional.soft_margin_loss`.
    /// Loss = log(1 + exp(-target * input))
    pub fn tensor_soft_margin_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let prod = self.tensor_mul(target, input)?;
        let neg_prod = self.tensor_neg(prod)?;
        let exp_term = self.tensor_exp(neg_prod)?;
        let shape = self.tensor_shape(exp_term)?;
        let ones = self.full(shape, 1.0, false)?;
        let one_plus_exp = self.tensor_add(ones, exp_term)?;
        let loss = self.tensor_log(one_plus_exp)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "soft_margin_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Gaussian negative log-likelihood loss.
    ///
    /// Equivalent to `torch.nn.functional.gaussian_nll_loss`.
    /// Loss = 0.5 * (log(var) + (target - input)^2 / var + log(2π))
    ///
    /// - `input`: mean predictions
    /// - `target`: observed values
    /// - `var`: variance (must be positive)
    /// - `full`: if true, include the constant log(2π) term
    pub fn tensor_gaussian_nll_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        var: TensorNodeId,
        reduction: &str,
        full: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(target, input)?;
        let diff_sq = self.tensor_mul(diff.clone(), diff)?;
        let scaled = self.tensor_div(diff_sq, var)?;
        let log_var = self.tensor_log(var)?;
        let term = self.tensor_add(log_var, scaled)?;
        let loss = if full {
            let shape = self.tensor_shape(term)?;
            let log_2pi = self.full(shape, (2.0 * std::f64::consts::PI).ln(), false)?;
            let with_const = self.tensor_add(term, log_2pi)?;
            let half = self.full(self.tensor_shape(with_const)?, 0.5, false)?;
            self.tensor_mul(half, with_const)?
        } else {
            let half = self.full(self.tensor_shape(term)?, 0.5, false)?;
            self.tensor_mul(half, term)?
        };
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "gaussian_nll_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Poisson negative log-likelihood loss.
    ///
    /// Equivalent to `torch.nn.functional.poisson_nll_loss`.
    /// Loss = exp(input) - target * input     if log_input=true
    /// Loss = input - target * log(input)     if log_input=false
    ///
    /// - `input`: predicted rate (or log-rate if log_input=true)
    /// - `target`: observed counts (non-negative integers)
    /// - `log_input`: if true, input is log(rate)
    /// - `full`: if true, add Stirling approx of log(target!)
    /// - `eps`: small value for numerical stability when log_input=false
    pub fn tensor_poisson_nll_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        log_input: bool,
        full: bool,
        eps: f64,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let loss = if log_input {
            let exp_input = self.tensor_exp(input)?;
            let target_times_input = self.tensor_mul(target, input)?;
            self.tensor_sub(exp_input, target_times_input)?
        } else {
            let shape = self.tensor_shape(input)?;
            let eps_t = self.full(shape, eps, false)?;
            let input_plus_eps = self.tensor_add(input, eps_t)?;
            let log_input_eps = self.tensor_log(input_plus_eps)?;
            let target_log = self.tensor_mul(target, log_input_eps)?;
            self.tensor_sub(input, target_log)?
        };
        let loss = if full {
            let shape = self.tensor_shape(target)?;
            let ones = self.full(shape.clone(), 1.0, false)?;
            let half = self.full(shape.clone(), 0.5, false)?;
            let log_2pi = self.full(shape, (2.0 * std::f64::consts::PI).ln(), false)?;
            let target_plus_1 = self.tensor_add(target, ones)?;
            let log_target_p1 = self.tensor_log(target_plus_1)?;
            let target_log_t = self.tensor_mul(target, log_target_p1)?;
            let stirling_1 = self.tensor_sub(target_log_t, target)?;
            let half_log_2pi_t = self.tensor_mul(half, log_2pi)?;
            let stirling = self.tensor_add(stirling_1, half_log_2pi_t)?;
            self.tensor_add(loss, stirling)?
        } else {
            loss
        };
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "poisson_nll_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Margin ranking loss for ranking tasks.
    ///
    /// Equivalent to `torch.nn.functional.margin_ranking_loss`.
    /// Loss = max(0, -y * (x1 - x2) + margin)
    /// where y is +1 if x1 should be ranked higher, -1 otherwise.
    pub fn tensor_margin_ranking_loss(
        &mut self,
        input1: TensorNodeId,
        input2: TensorNodeId,
        target: TensorNodeId,
        margin: f64,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(input1, input2)?;
        let target_diff = self.tensor_mul(target, diff)?;
        let neg_target_diff = self.tensor_neg(target_diff)?;
        let shape = self.tensor_shape(neg_target_diff)?;
        let margin_t = self.full(shape.clone(), margin, false)?;
        let with_margin = self.tensor_add(neg_target_diff, margin_t)?;
        let zeros = self.full(shape, 0.0, false)?;
        let loss = self.tensor_maximum(zeros, with_margin)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "margin_ranking_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Cosine embedding loss for similarity learning.
    ///
    /// Equivalent to `torch.nn.functional.cosine_embedding_loss`.
    /// For target=1: loss = 1 - cos(x1, x2)
    /// For target=-1: loss = max(0, cos(x1, x2) - margin)
    pub fn tensor_cosine_embedding_loss(
        &mut self,
        input1: TensorNodeId,
        input2: TensorNodeId,
        target: TensorNodeId,
        margin: f64,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compute cosine similarity (assuming last dimension)
        let shape1 = self.tensor_shape(input1)?;
        let dim = shape1.len() - 1;
        let cos_sim = self.tensor_cosine_similarity(input1, input2, dim, 1e-8)?;
        let shape = self.tensor_shape(cos_sim)?;
        let ones = self.full(shape.clone(), 1.0, false)?;
        let pos_loss = self.tensor_sub(ones, cos_sim)?;
        let margin_t = self.full(shape.clone(), margin, false)?;
        let neg_margin = self.tensor_sub(cos_sim, margin_t)?;
        let zeros = self.full(shape.clone(), 0.0, false)?;
        let neg_loss = self.tensor_maximum(zeros, neg_margin)?;
        let mask_pos = self.tensor_eq(target, ones)?;
        let loss = self.tensor_where(mask_pos, pos_loss, neg_loss)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cosine_embedding_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Triplet margin loss for metric learning.
    ///
    /// Equivalent to `torch.nn.functional.triplet_margin_loss`.
    /// Loss = max(0, d(anchor, positive) - d(anchor, negative) + margin)
    pub fn tensor_triplet_margin_loss(
        &mut self,
        anchor: TensorNodeId,
        positive: TensorNodeId,
        negative: TensorNodeId,
        margin: f64,
        p: f64,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compute distances
        let diff_pos = self.tensor_sub(anchor, positive)?;
        let diff_neg = self.tensor_sub(anchor, negative)?;
        let shape = self.tensor_shape(diff_pos)?;
        let dim = shape.len() - 1;
        let d_pos = self.tensor_norm_dim(diff_pos, p, dim)?;
        let d_neg = self.tensor_norm_dim(diff_neg, p, dim)?;
        let diff = self.tensor_sub(d_pos, d_neg)?;
        let margin_shape = self.tensor_shape(diff)?;
        let margin_t = self.full(margin_shape.clone(), margin, false)?;
        let with_margin = self.tensor_add(diff, margin_t)?;
        let zeros = self.full(margin_shape, 0.0, false)?;
        let loss = self.tensor_maximum(zeros, with_margin)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triplet_margin_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Connectionist Temporal Classification loss.
    ///
    /// Equivalent to `torch.nn.functional.ctc_loss`.
    /// Used for sequence-to-sequence problems where alignment is unknown.
    ///
    /// - `log_probs`: Log probabilities, shape (T, N, C) - time, batch, classes
    /// - `targets`: Target sequences concatenated, shape (sum of target lengths,)
    /// - `input_lengths`: Length of each input sequence, shape (N,)
    /// - `target_lengths`: Length of each target sequence, shape (N,)
    /// - `blank`: Index of the blank label (default 0)
    /// - `zero_infinity`: If true, infinities in loss are zeroed
    pub fn tensor_ctc_loss(
        &mut self,
        log_probs: TensorNodeId,
        targets: TensorNodeId,
        input_lengths: TensorNodeId,
        target_lengths: TensorNodeId,
        blank: usize,
        reduction: &str,
        zero_infinity: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let lp_shape = self.tensor_shape(log_probs)?;
        if lp_shape.len() != 3 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ctc_loss: log_probs must be 3D (T, N, C)",
                },
            )));
        }
        let t_len = lp_shape[0];
        let batch_size = lp_shape[1];
        let num_classes = lp_shape[2];
        if blank >= num_classes {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ctc_loss: blank index out of range",
                },
            )));
        }
        let lp_vals = self.tensor_values(log_probs)?;
        let tgt_vals = self.tensor_values(targets)?;
        let in_lens = self.tensor_values(input_lengths)?;
        let tgt_lens = self.tensor_values(target_lengths)?;
        if in_lens.len() != batch_size || tgt_lens.len() != batch_size {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ctc_loss: length arrays must match batch size",
                },
            )));
        }
        let mut losses = Vec::with_capacity(batch_size);
        let mut tgt_offset = 0usize;
        for b in 0..batch_size {
            let in_len = in_lens[b] as usize;
            let tgt_len = tgt_lens[b] as usize;
            if in_len > t_len {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "ctc_loss: input length exceeds time dimension",
                    },
                )));
            }
            let target_seq: Vec<usize> = tgt_vals[tgt_offset..tgt_offset + tgt_len]
                .iter()
                .map(|&x| x as usize)
                .collect();
            tgt_offset += tgt_len;
            // CTC forward pass with alpha probabilities
            // State space: 2*L + 1 where L is target length (interleaved with blanks)
            let state_len = 2 * tgt_len + 1;
            let neg_inf = f64::NEG_INFINITY;
            let mut alpha = vec![vec![neg_inf; state_len]; in_len + 1];
            alpha[0][0] = 0.0; // Start at blank
            if state_len > 1 {
                alpha[0][1] = 0.0; // Or first label
            }
            let get_label = |s: usize| -> usize {
                if s % 2 == 0 {
                    blank
                } else {
                    target_seq[s / 2]
                }
            };
            for t in 0..in_len {
                let lp_offset = (t * batch_size + b) * num_classes;
                for s in 0..state_len {
                    let label = get_label(s);
                    let lp = lp_vals[lp_offset + label];
                    let mut score = alpha[t][s];
                    if s > 0 {
                        score = log_sum_exp(score, alpha[t][s - 1]);
                    }
                    if s > 1 && get_label(s) != get_label(s - 2) {
                        score = log_sum_exp(score, alpha[t][s - 2]);
                    }
                    alpha[t + 1][s] = score + lp;
                }
            }
            let final_score = if state_len > 1 {
                log_sum_exp(alpha[in_len][state_len - 1], alpha[in_len][state_len - 2])
            } else if state_len == 1 {
                alpha[in_len][0]
            } else {
                0.0
            };
            let loss = -final_score;
            let loss = if zero_infinity && !loss.is_finite() {
                0.0
            } else {
                loss
            };
            losses.push(loss);
        }
        let loss = self.tensor_variable(losses, vec![batch_size], false)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ctc_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Multi-class margin loss (SVM-style).
    ///
    /// Equivalent to `torch.nn.functional.multi_margin_loss`.
    /// Loss = sum_j max(0, margin - x[y] + x[j])^p / C for j != y
    /// where C is the number of classes.
    ///
    /// - `input`: Shape (N, C), raw scores for each class
    /// - `target`: Shape (N,), target class indices
    /// - `p`: Power (1 or 2)
    /// - `margin`: Margin value (default 1.0)
    /// - `weight`: Optional per-class weights, shape (C,)
    pub fn tensor_multi_margin_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        p: usize,
        margin: f64,
        weight: Option<TensorNodeId>,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        if p != 1 && p != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_margin_loss: p must be 1 or 2",
                },
            )));
        }
        let input_shape = self.tensor_shape(input)?;
        let target_shape = self.tensor_shape(target)?;
        if input_shape.len() != 2 || target_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_margin_loss: input must be 2D (N, C), target must be 1D (N,)",
                },
            )));
        }
        let n = input_shape[0];
        let c = input_shape[1];
        if target_shape[0] != n {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_margin_loss: batch size mismatch",
                },
            )));
        }
        let input_vals = self.tensor_values(input)?;
        let target_vals = self.tensor_values(target)?;
        let weights = if let Some(w) = weight {
            let w_shape = self.tensor_shape(w)?;
            if w_shape.len() != 1 || w_shape[0] != c {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "multi_margin_loss: weight must be 1D with length C",
                    },
                )));
            }
            Some(self.tensor_values(w)?)
        } else {
            None
        };
        let mut losses = Vec::with_capacity(n);
        for i in 0..n {
            let y = target_vals[i] as usize;
            if y >= c {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "multi_margin_loss: target class index out of range",
                    },
                )));
            }
            let x_y = input_vals[i * c + y];
            let mut sum = 0.0;
            for j in 0..c {
                if j != y {
                    let x_j = input_vals[i * c + j];
                    let margin_term = margin - x_y + x_j;
                    if margin_term > 0.0 {
                        let loss_j = if p == 1 {
                            margin_term
                        } else {
                            margin_term * margin_term
                        };
                        let w = weights.as_ref().map_or(1.0, |ws| ws[y]);
                        sum += w * loss_j;
                    }
                }
            }
            losses.push(sum / c as f64);
        }
        let loss = self.tensor_variable(losses, vec![n], false)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_margin_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Multilabel margin loss for multi-label classification.
    ///
    /// Equivalent to `torch.nn.functional.multilabel_margin_loss`.
    /// Loss = sum_j max(0, 1 - (x[y_j] - x[i])) / x.size(1) for i not in y and j in y
    ///
    /// - `input`: Shape (N, C), scores for each label
    /// - `target`: Shape (N, C), target labels where positive indices are valid labels
    ///   and negative values (e.g., -1) mark ignored positions
    pub fn tensor_multilabel_margin_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let target_shape = self.tensor_shape(target)?;
        if input_shape.len() != 2 || target_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_margin_loss: input and target must be 2D (N, C)",
                },
            )));
        }
        if input_shape != target_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_margin_loss: input and target shapes must match",
                },
            )));
        }
        let n = input_shape[0];
        let c = input_shape[1];
        let input_vals = self.tensor_values(input)?;
        let target_vals = self.tensor_values(target)?;
        let mut losses = Vec::with_capacity(n);
        for i in 0..n {
            let row_offset = i * c;
            // Collect positive label indices (non-negative target values)
            let positive_indices: Vec<usize> = (0..c)
                .filter(|&j| target_vals[row_offset + j] >= 0.0)
                .map(|j| target_vals[row_offset + j] as usize)
                .filter(|&idx| idx < c)
                .collect();
            let mut sum = 0.0;
            for &y_j in &positive_indices {
                let x_y = input_vals[row_offset + y_j];
                for k in 0..c {
                    if !positive_indices.contains(&k) {
                        let x_k = input_vals[row_offset + k];
                        let margin_term = 1.0 - x_y + x_k;
                        if margin_term > 0.0 {
                            sum += margin_term;
                        }
                    }
                }
            }
            losses.push(sum / c as f64);
        }
        let loss = self.tensor_variable(losses, vec![n], false)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_margin_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    /// Multilabel soft margin loss for multi-label classification.
    ///
    /// Equivalent to `torch.nn.functional.multilabel_soft_margin_loss`.
    /// Loss = -1/C * sum_j (y_j * log(sigmoid(x_j)) + (1-y_j) * log(1-sigmoid(x_j)))
    ///
    /// - `input`: Shape (N, C), raw scores (logits)
    /// - `target`: Shape (N, C), binary targets (0 or 1)
    /// - `weight`: Optional per-label weights, shape (C,)
    pub fn tensor_multilabel_soft_margin_loss(
        &mut self,
        input: TensorNodeId,
        target: TensorNodeId,
        weight: Option<TensorNodeId>,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let target_shape = self.tensor_shape(target)?;
        if input_shape.len() != 2 || target_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_soft_margin_loss: input and target must be 2D (N, C)",
                },
            )));
        }
        if input_shape != target_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_soft_margin_loss: input and target shapes must match",
                },
            )));
        }
        let n = input_shape[0];
        let c = input_shape[1];
        let weights = if let Some(w) = weight {
            let w_shape = self.tensor_shape(w)?;
            if w_shape.len() != 1 || w_shape[0] != c {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "multilabel_soft_margin_loss: weight must be 1D with length C",
                    },
                )));
            }
            Some(self.tensor_values(w)?)
        } else {
            None
        };
        let input_vals = self.tensor_values(input)?;
        let target_vals = self.tensor_values(target)?;
        let mut losses = Vec::with_capacity(n);
        for i in 0..n {
            let row_offset = i * c;
            let mut sum = 0.0;
            for j in 0..c {
                let x = input_vals[row_offset + j];
                let y = target_vals[row_offset + j];
                let w = weights.as_ref().map_or(1.0, |ws| ws[j]);
                // log(sigmoid(x)) = x - softplus(x) = -softplus(-x)
                // log(1 - sigmoid(x)) = -softplus(x)
                let softplus_x = (1.0 + x.exp()).ln();
                let softplus_neg_x = (1.0 + (-x).exp()).ln();
                let log_sigmoid = -softplus_neg_x;
                let log_one_minus_sigmoid = -softplus_x;
                sum += w * (y * log_sigmoid + (1.0 - y) * log_one_minus_sigmoid);
            }
            losses.push(-sum / c as f64);
        }
        let loss = self.tensor_variable(losses, vec![n], false)?;
        match reduction {
            "none" => Ok(loss),
            "mean" => self.tensor_mean(loss),
            "sum" => self.tensor_sum(loss),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multilabel_soft_margin_loss: reduction must be 'none', 'mean', or 'sum'",
                },
            ))),
        }
    }

    pub fn tensor_trace(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.trace(input, self.mode())?;
        self.record_tensor_reduction_operation(&event);
        Ok(out)
    }

    pub fn tensor_lerp(
        &mut self,
        start: TensorNodeId,
        end: TensorNodeId,
        weight: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self.tensor_tape.lerp(start, end, weight, self.mode())?;
        self.record_tensor_lerp_operation(&event);
        Ok(out)
    }

    /// In-place lerp: target = target + weight * (end - target).
    pub fn tensor_lerp_(
        &mut self,
        target: TensorNodeId,
        end: TensorNodeId,
        weight: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let end_vals = self.tensor_values(end)?;
        if target_vals.len() != end_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(end)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(end_vals.iter())
            .map(|(&s, &e)| s + weight * (e - s))
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("lerp_", target, Some(format!("weight={weight}")));
        Ok(())
    }

    /// `torch.addcmul`: `input + value * tensor1 * tensor2`.
    ///
    /// Composed through autograd-aware primitives, so gradients flow to
    /// `input`, `tensor1`, and `tensor2` (`grad_t1 = value*t2*g`,
    /// `grad_t2 = value*t1*g`). Matches torch 2.12 (frankentorch-tf10).
    pub fn tensor_addcmul(
        &mut self,
        input: TensorNodeId,
        tensor1: TensorNodeId,
        tensor2: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let prod = self.tensor_mul(tensor1, tensor2)?;
        let scaled = self.scale_by_constant(prod, value)?;
        self.tensor_add(input, scaled)
    }

    /// `torch.addcdiv`: `input + value * tensor1 / tensor2`.
    ///
    /// Composed through autograd-aware primitives (frankentorch-tf10).
    pub fn tensor_addcdiv(
        &mut self,
        input: TensorNodeId,
        tensor1: TensorNodeId,
        tensor2: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let quot = self.tensor_div(tensor1, tensor2)?;
        let scaled = self.scale_by_constant(quot, value)?;
        self.tensor_add(input, scaled)
    }

    /// In-place addcmul: target += value * tensor1 * tensor2.
    pub fn tensor_addcmul_(
        &mut self,
        target: TensorNodeId,
        tensor1: TensorNodeId,
        tensor2: TensorNodeId,
        value: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let t1_vals = self.tensor_values(tensor1)?;
        let t2_vals = self.tensor_values(tensor2)?;
        if target_vals.len() != t1_vals.len() || target_vals.len() != t2_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(tensor1)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(t1_vals.iter())
            .zip(t2_vals.iter())
            .map(|((&t, &t1), &t2)| t + value * t1 * t2)
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("addcmul_", target, Some(format!("value={value}")));
        Ok(())
    }

    /// In-place addcdiv: target += value * tensor1 / tensor2.
    pub fn tensor_addcdiv_(
        &mut self,
        target: TensorNodeId,
        tensor1: TensorNodeId,
        tensor2: TensorNodeId,
        value: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let t1_vals = self.tensor_values(tensor1)?;
        let t2_vals = self.tensor_values(tensor2)?;
        if target_vals.len() != t1_vals.len() || target_vals.len() != t2_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(tensor1)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(t1_vals.iter())
            .zip(t2_vals.iter())
            .map(|((&t, &t1), &t2)| t + value * t1 / t2)
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("addcdiv_", target, Some(format!("value={value}")));
        Ok(())
    }

    /// Multiplies `node` by a non-grad scalar constant. `value == 1.0`
    /// is returned unchanged so the common default adds no tape node.
    fn scale_by_constant(
        &mut self,
        node: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if value == 1.0 {
            return Ok(node);
        }
        let shape = self.tensor_shape(node)?;
        let constant = self.full(shape, value, false)?;
        self.tensor_mul(node, constant)
    }

    pub fn tensor_addmm(
        &mut self,
        input: TensorNodeId,
        mat1: TensorNodeId,
        mat2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) = self
            .tensor_tape
            .addmm(input, mat1, mat2, beta, alpha, self.mode())?;
        self.record_tensor_addmm_operation(&event);
        Ok(out)
    }

    pub fn tensor_addmv(
        &mut self,
        input: TensorNodeId,
        mat: TensorNodeId,
        vec_input: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let (out, event) =
            self.tensor_tape
                .addmv(input, mat, vec_input, beta, alpha, self.mode())?;
        self.record_tensor_addmv_operation(&event);
        Ok(out)
    }

    /// Ensure `input` has at least 1 dimension.
    ///
    /// Equivalent to `torch.atleast_1d(input)`. 0-D scalars are
    /// reshaped to `[1]`; tensors with rank ≥ 1 are returned
    /// unchanged. Composes through autograd-aware tensor_reshape.
    /// Tracked under frankentorch-oi03.
    pub fn tensor_atleast_1d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            self.tensor_reshape(input, vec![1])
        } else {
            Ok(input)
        }
    }

    /// Ensure `input` has at least 2 dimensions.
    ///
    /// Equivalent to `torch.atleast_2d(input)`. 0-D scalars become
    /// `[1, 1]`; 1-D `[N]` becomes `[1, N]`; tensors with rank ≥ 2
    /// are returned unchanged. Tracked under frankentorch-oi03.
    pub fn tensor_atleast_2d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            0 => self.tensor_reshape(input, vec![1, 1]),
            1 => {
                let n = shape[0];
                self.tensor_reshape(input, vec![1, n])
            }
            _ => Ok(input),
        }
    }

    /// Ensure `input` has at least 3 dimensions.
    ///
    /// Equivalent to `torch.atleast_3d(input)`. 0-D becomes `[1, 1, 1]`;
    /// 1-D `[N]` becomes `[1, N, 1]`; 2-D `[N, M]` becomes `[N, M, 1]`;
    /// tensors with rank ≥ 3 are returned unchanged. The asymmetric
    /// padding (left for the 1-D case, right for the 2-D case) matches
    /// PyTorch and numpy semantics. Tracked under frankentorch-oi03.
    pub fn tensor_atleast_3d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            0 => self.tensor_reshape(input, vec![1, 1, 1]),
            1 => {
                let n = shape[0];
                self.tensor_reshape(input, vec![1, n, 1])
            }
            2 => {
                let (n, m) = (shape[0], shape[1]);
                self.tensor_reshape(input, vec![n, m, 1])
            }
            _ => Ok(input),
        }
    }

    /// Matrix-vector product: `out = M @ v`.
    ///
    /// Equivalent to `torch.mv(input, vec_input)`. `input` must be a 2-D
    /// matrix of shape `[m, n]` and `vec_input` a 1-D vector of shape
    /// `[n]`; the result is a 1-D vector of shape `[m]`.
    /// Composes through autograd-aware tensor_reshape + tensor_matmul,
    /// so gradients flow to both inputs. Tracked under frankentorch-256l.
    pub fn tensor_mv(
        &mut self,
        input: TensorNodeId,
        vec_input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let m_shape = self.tensor_shape(input)?;
        let v_shape = self.tensor_shape(vec_input)?;
        if m_shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-oitu).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: m_shape.len(),
                    ndim: 2,
                },
            )));
        }
        if v_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: v_shape.len(),
                    ndim: 1,
                },
            )));
        }
        if m_shape[1] != v_shape[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: m_shape.clone(),
                    rhs: v_shape.clone(),
                },
            )));
        }
        let n = v_shape[0];
        let m = m_shape[0];
        let v_2d = self.tensor_reshape(vec_input, vec![n, 1])?;
        let out_2d = self.tensor_matmul(input, v_2d)?;
        self.tensor_reshape(out_2d, vec![m])
    }

