    /// Scaled Exponential Linear Unit.
    ///
    /// selu(x) = scale * (max(0,x) + min(0, alpha*(exp(x)-1)))
    /// where scale and alpha are fixed for self-normalizing networks.
    /// Tracked under frankentorch-8g3v.
    pub fn tensor_selu(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        const ALPHA: f64 = 1.6732632423543772848170429916717;
        const SCALE: f64 = 1.0507009873554804934193349852946;
        let out = self.tensor_apply_function(
            &[input],
            |ctx, inputs| {
                let (vals, shape) = inputs[0];
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                let values: Vec<f64> = vals
                    .iter()
                    .map(|&x| {
                        if x > 0.0 {
                            SCALE * x
                        } else {
                            SCALE * ALPHA * (x.exp() - 1.0)
                        }
                    })
                    .collect();
                Ok((values, shape.to_vec()))
            },
            |ctx, grad_outputs| {
                let grad_out = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                if grad_out.len() != x_vals.len() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "selu backward: gradient length mismatch",
                        },
                    )));
                }
                let grad_in: Vec<f64> = x_vals
                    .iter()
                    .zip(grad_out.iter())
                    .map(|(&x, &go)| {
                        if x > 0.0 {
                            go * SCALE
                        } else {
                            go * SCALE * ALPHA * x.exp()
                        }
                    })
                    .collect();
                Ok(vec![Some(grad_in)])
            },
        )?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("selu in={} out={}", input.0, out.0),
        );
        Ok(out)
    }

    /// Continuously Differentiable Exponential Linear Unit.
    ///
    /// celu(x, alpha) = max(0,x) + min(0, alpha*(exp(x/alpha)-1))
    /// Default alpha = 1.0.
    /// Tracked under frankentorch-fk1i.
    pub fn tensor_celu(
        &mut self,
        input: TensorNodeId,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let out = self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, shape) = inputs[0];
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                let values: Vec<f64> = vals
                    .iter()
                    .map(|&x| {
                        if x > 0.0 {
                            x
                        } else {
                            alpha * ((x / alpha).exp() - 1.0)
                        }
                    })
                    .collect();
                Ok((values, shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let grad_out = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                if grad_out.len() != x_vals.len() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "celu backward: gradient length mismatch",
                        },
                    )));
                }
                let grad_in: Vec<f64> = x_vals
                    .iter()
                    .zip(grad_out.iter())
                    .map(
                        |(&x, &go)| {
                            if x > 0.0 { go } else { go * (x / alpha).exp() }
                        },
                    )
                    .collect();
                Ok(vec![Some(grad_in)])
            },
        )?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("celu in={} out={}", input.0, out.0),
        );
        Ok(out)
    }

    /// Parametric ReLU activation.
    ///
    /// prelu(x, weight) = max(0,x) + weight * min(0,x)
    /// Weight is a 1D tensor (per-channel) or scalar broadcasted.
    /// Tracked under frankentorch-bf19.
    pub fn tensor_prelu(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let weight_vals = self.tensor_values(weight)?;
        let input_vals = self.tensor_values(input)?;

        let result: Vec<f64> = if weight_vals.len() == 1 {
            let w = weight_vals[0];
            input_vals
                .iter()
                .map(|&x| if x >= 0.0 { x } else { w * x })
                .collect()
        } else {
            let num_channels = weight_vals.len();
            let channel_size: usize = if input_shape.len() >= 2 {
                input_shape[2..].iter().product()
            } else {
                1
            };
            input_vals
                .iter()
                .enumerate()
                .map(|(i, &x)| {
                    let c = if input_shape.len() >= 2 {
                        (i / channel_size) % num_channels
                    } else {
                        i % num_channels
                    };
                    if x >= 0.0 { x } else { weight_vals[c] * x }
                })
                .collect()
        };

        let out = self.tensor_variable(result, input_shape, false)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("prelu in={} weight={} out={}", input.0, weight.0, out.0),
        );
        Ok(out)
    }

    /// Randomized Leaky ReLU (inference mode).
    ///
    /// rrelu(x, lower, upper) = x if x >= 0, else x * (lower + upper) / 2
    /// Uses midpoint slope for deterministic inference.
    /// Tracked under frankentorch-r8ik.
    pub fn tensor_rrelu(
        &mut self,
        input: TensorNodeId,
        lower: f64,
        upper: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let slope = (lower + upper) / 2.0;
        let out = self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, shape) = inputs[0];
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                let values: Vec<f64> = vals
                    .iter()
                    .map(|&x| if x >= 0.0 { x } else { slope * x })
                    .collect();
                Ok((values, shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let grad_out = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                if grad_out.len() != x_vals.len() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "rrelu backward: gradient length mismatch",
                        },
                    )));
                }
                let grad_in: Vec<f64> = x_vals
                    .iter()
                    .zip(grad_out.iter())
                    .map(|(&x, &go)| if x >= 0.0 { go } else { go * slope })
                    .collect();
                Ok(vec![Some(grad_in)])
            },
        )?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("rrelu in={} out={}", input.0, out.0),
        );
        Ok(out)
    }

