    /// Modified Bessel function of the first kind, order 0.
    ///
    /// Equivalent to `torch.special.i0(input)`. Uses the
    /// Abramowitz & Stegun 9.8.1 / 9.8.2 piecewise polynomial.
    /// Even in `x`. Autograd-aware via the analytical backward
    /// `d/dx i0(x) = i1(x)` — wired through tensor_apply_function
    /// using the i1 scalar helper from frankentorch-ner6. Tracked
    /// under frankentorch-2vxa (forward) + frankentorch-urmm
    /// (autograd unblock).
    pub fn tensor_special_i0(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_apply_function(
            &[input],
            |ctx, inputs| {
                let (vals, shape) = inputs[0];
                let result: Vec<f64> = vals.iter().map(|&x| bessel_i0_scalar(x)).collect();
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                Ok((result, shape.to_vec()))
            },
            |ctx, grad_outputs| {
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                let grad_y = grad_outputs[0];
                // d/dx i0(x) = i1(x).
                let grad_x: Vec<f64> = x_vals
                    .iter()
                    .zip(grad_y.iter())
                    .map(|(&x, &gy)| gy * bessel_i1_scalar(x))
                    .collect();
                Ok(vec![Some(grad_x)])
            },
        )
    }

    /// Exponentially scaled modified Bessel of the first kind,
    /// order 0: `i0e(x) = exp(-|x|) * i0(x)`.
    ///
    /// Equivalent to `torch.special.i0e(input)`. Stays bounded
    /// for large `|x|` where `i0(x)` would overflow. Same
    /// fail-loud autograd policy as `tensor_special_i0`. Tracked
    /// under frankentorch-2vxa.
    pub fn tensor_special_i0e(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware via product rule (frankentorch-0wcm,
        // unblocked by ner6's i1e):
        //   d/dx i0e(x) = i1e(x) - sign(x) * i0e(x)
        //
        // i0e has a corner at x = 0 (derivative jumps from -1 to
        // +1). Convention: sign(0) = 0 gives gradient = i1e(0) =
        // 0, matching torch's autograd choice for the
        // non-differentiable point.
        self.tensor_apply_function(
            &[input],
            |ctx, inputs| {
                let (vals, shape) = inputs[0];
                let result: Vec<f64> = vals.iter().map(|&x| bessel_i0e_scalar(x)).collect();
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                Ok((result, shape.to_vec()))
            },
            |ctx, grad_outputs| {
                let saved = ctx.saved_tensors();
                let x_vals = &saved[0];
                let grad_y = grad_outputs[0];
                let grad_x: Vec<f64> = x_vals
                    .iter()
                    .zip(grad_y.iter())
                    .map(|(&x, &gy)| {
                        let signum = if x > 0.0 {
                            1.0
                        } else if x < 0.0 {
                            -1.0
                        } else {
                            0.0
                        };
                        gy * (bessel_i1e_scalar(x) - signum * bessel_i0e_scalar(x))
                    })
                    .collect();
                Ok(vec![Some(grad_x)])
            },
        )
    }

    /// Modified Bessel function of the first kind, order 1.
    ///
    /// Equivalent to `torch.special.i1(input)`. Uses A&S 9.8.3
