    /// Element-wise threshold activation.
    ///
    /// Equivalent to `torch.threshold(input, threshold, value)` and
    /// `torch.nn.functional.threshold(input, threshold, value)`:
    /// returns `x` where `x > threshold`, else `value`. The
    /// distinguishing trait from `tensor_relu` is that the cutoff
    /// and the replacement are independent parameters — useful for
    /// gating layers in inference and for sparsifying logits with a
    /// custom sentinel. Composes through autograd-aware
    /// `tensor_gt` + `tensor_where`; gradient is 1 where x >
    /// threshold and 0 elsewhere (matches torch). Tracked under
    /// frankentorch-hptx.
    pub fn tensor_threshold(
        &mut self,
        input: TensorNodeId,
        threshold: f64,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        // For non-NaN input x: return x if x > threshold else value.
        // For NaN input: propagate NaN (matches current torch.threshold;
        // older torch returned the value branch since NaN > t is false,
        // but the current upstream behavior propagates NaN through
        // threshold). frankentorch-w9kc.
        let shape = self.tensor_shape(input)?;
        let threshold_t = self.full(shape.clone(), threshold, false)?;
        let value_t = self.full(shape.clone(), value, false)?;
        let nan_t = self.full(shape, f64::NAN, false)?;
        let nan_mask = self.tensor_isnan(input)?;
        let above_mask = self.tensor_gt(input, threshold_t)?;
        let above_or_value = self.tensor_where(above_mask, input, value_t)?;
        self.tensor_where(nan_mask, nan_t, above_or_value)
    }

