    /// `torch.clamp(input, min=min_tensor, max=max_tensor)` parity:
    /// per-element clamp with tensor bounds.
    ///
    /// Equivalent to `torch.clamp` when both `min` and `max` are
    /// tensors. Composes through autograd-aware
    /// `tensor_maximum(input, min)` followed by
    /// `tensor_minimum(result, max)` — gradients route to whichever
    /// operand achieved the per-element extremum at each step.
    /// NaN in any operand propagates to the output (matches the
    /// `min_tensor_contiguous_f64` / `max_tensor_contiguous_f64`
    /// kernel-level NaN handling).
    ///
    /// All three tensors must share the same shape (broadcasting is
    /// available via the existing `tensor_broadcast_to` if a caller
    /// needs differently-shaped bounds).
    ///
    /// Tracked under frankentorch-zbi2.
    pub fn tensor_clamp_tensor(
        &mut self,
        input: TensorNodeId,
        min: TensorNodeId,
        max: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let in_shape = self.tensor_shape(input)?;
        let min_shape = self.tensor_shape(min)?;
        let max_shape = self.tensor_shape(max)?;
        if in_shape != min_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: in_shape,
                    rhs: min_shape,
                },
            )));
        }
        if in_shape != max_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: in_shape,
                    rhs: max_shape,
                },
            )));
        }
        // tensor_maximum(x, min) lifts each element to at least
        // min[i]; tensor_minimum then caps at max[i]. Both ops are
        // autograd-aware and propagate NaN.
        let lifted = self.tensor_maximum(input, min)?;
        self.tensor_minimum(lifted, max)
    }

    /// Per-tensor affine quantization: `q = clamp(round(x/scale) + zero_point, qmin, qmax)`.
    ///
    /// Output values are q-space integers in `[qmin, qmax]` but stored in
    /// the input dtype. Backward uses the PyTorch fake-quantization
    /// cachemask contract: unclamped values receive a straight-through
    /// gradient scaled by `1 / scale`, while clamped values receive zero.
    ///
    /// # Errors
    /// - `scale` must be finite and `> 0.0`
    /// - `qmin` must be `< qmax`
    pub fn tensor_quantize_per_tensor(
        &mut self,
        input: TensorNodeId,
        scale: f64,
        zero_point: i64,
        qmin: i64,
        qmax: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        Self::validate_qparams(scale, zero_point, qmin, qmax)?;
        #[allow(clippy::cast_precision_loss)]
        let qmin_f = qmin as f64;
        #[allow(clippy::cast_precision_loss)]
        let qmax_f = qmax as f64;
        #[allow(clippy::cast_precision_loss)]
        let zero_point_f = zero_point as f64;
        let inv_scale = 1.0 / scale;

        self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, shape) = inputs[0];
                let mut mask = Vec::with_capacity(vals.len());
                let q_vals = vals
                    .iter()
                    .map(|&x| {
                        let q = (x * inv_scale).round_ties_even() + zero_point_f;
                        mask.push(if q >= qmin_f && q <= qmax_f { 1.0 } else { 0.0 });
                        q.clamp(qmin_f, qmax_f)
                    })
                    .collect::<Vec<_>>();
                ctx.save_for_backward(mask, shape.to_vec());
                Ok((q_vals, shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let mask = &ctx.saved_tensors()[0];
                let grad = grad_outputs[0]
                    .iter()
                    .zip(mask.iter())
                    .map(|(grad, &keep)| grad * keep * inv_scale)
                    .collect::<Vec<_>>();
                Ok(vec![Some(grad)])
            },
        )
    }

    /// Per-tensor affine dequantization: `x = (q - zero_point) * scale`.
    ///
    /// # Errors
    /// - `scale` must be finite and `> 0.0`
    pub fn tensor_dequantize_per_tensor(
        &mut self,
        quantized: TensorNodeId,
        scale: f64,
        zero_point: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        if !scale.is_finite() || scale <= 0.0 {
            return Err(AutogradError::Dispatch(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_dequantize_per_tensor: scale must be finite and > 0",
                }
                .into(),
            ));
        }
        let zp = self.full_like(quantized, zero_point as f64, false)?;
        let shifted = self.tensor_sub(quantized, zp)?;
        let scale_t = self.full_like(shifted, scale, false)?;
        self.tensor_mul(shifted, scale_t)
    }

    /// Fake-quantize: `dequantize(quantize_per_tensor(x))`. Simulates
    /// the precision loss of `[qmin, qmax]` quantization while keeping
    /// values in the input dtype. The composition is differentiable for
    /// unclamped values and masks gradients for clamped values, matching
    /// PyTorch's fake-quantization cachemask backward contract.
    ///
    /// # Errors
    /// - `scale` must be finite and `> 0.0`
    /// - `qmin` must be `< qmax`
    pub fn tensor_fake_quantize_per_tensor(
        &mut self,
        input: TensorNodeId,
        scale: f64,
        zero_point: i64,
        qmin: i64,
        qmax: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let q = self.tensor_quantize_per_tensor(input, scale, zero_point, qmin, qmax)?;
        self.tensor_dequantize_per_tensor(q, scale, zero_point)
    }

    /// Per-channel affine quantization along a specified axis.
    ///
    /// Each channel has its own scale and zero_point. For example, with axis=0
    /// and input shape [C, H, W], each of C channels gets its own quantization
    /// parameters from scales[c] and zero_points[c].
    ///
    /// Equivalent to `torch.quantize_per_channel(input, scales, zero_points, axis, dtype)`.
    pub fn tensor_quantize_per_channel(
        &mut self,
        input: TensorNodeId,
        scales: &[f64],
        zero_points: &[i64],
        axis: i64,
        qmin: i64,
        qmax: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len() as i64;
        let axis_norm = if axis < 0 { ndim + axis } else { axis } as usize;

        if axis_norm >= shape.len() {
            return Err(Self::incompatible_tensor_args(
                "quantize_per_channel: axis out of bounds",
            ));
        }
        if scales.len() != shape[axis_norm] || zero_points.len() != shape[axis_norm] {
            return Err(Self::incompatible_tensor_args(
                "quantize_per_channel: scales/zero_points length must match dim at axis",
            ));
        }
        for &s in scales {
            if !s.is_finite() || s <= 0.0 {
                return Err(Self::incompatible_tensor_args(
                    "quantize_per_channel: all scales must be finite and > 0",
                ));
            }
        }

        let input_data = self.tensor_values(input)?;
        let numel = input_data.len();
        let mut out_data = vec![0.0; numel];

        let stride_before: usize = shape[..axis_norm].iter().product();
        let channel_size = shape[axis_norm];
        let stride_after: usize = shape[(axis_norm + 1)..].iter().product::<usize>().max(1);

        #[allow(clippy::cast_precision_loss)]
        let qmin_f = qmin as f64;
        #[allow(clippy::cast_precision_loss)]
        let qmax_f = qmax as f64;

        for before in 0..stride_before {
            for c in 0..channel_size {
                let inv_scale = 1.0 / scales[c];
                #[allow(clippy::cast_precision_loss)]
                let zp = zero_points[c] as f64;
                for after in 0..stride_after {
                    let idx = before * channel_size * stride_after + c * stride_after + after;
                    let x = input_data[idx];
                    let q = (x * inv_scale).round_ties_even() + zp;
                    out_data[idx] = q.clamp(qmin_f, qmax_f);
                }
            }
        }

        self.tensor_variable(out_data, shape, false)
    }

    /// Per-channel affine dequantization along a specified axis.
    ///
    /// Equivalent to `torch.dequantize` for per-channel quantized tensors.
    pub fn tensor_dequantize_per_channel(
        &mut self,
        quantized: TensorNodeId,
        scales: &[f64],
        zero_points: &[i64],
        axis: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(quantized)?;
        let ndim = shape.len() as i64;
        let axis_norm = if axis < 0 { ndim + axis } else { axis } as usize;

        if axis_norm >= shape.len() {
            return Err(Self::incompatible_tensor_args(
                "dequantize_per_channel: axis out of bounds",
            ));
        }
        if scales.len() != shape[axis_norm] || zero_points.len() != shape[axis_norm] {
            return Err(Self::incompatible_tensor_args(
                "dequantize_per_channel: scales/zero_points length must match dim at axis",
            ));
        }

        let q_data = self.tensor_values(quantized)?;
        let numel = q_data.len();
        let mut out_data = vec![0.0; numel];

        let stride_before: usize = shape[..axis_norm].iter().product();
        let channel_size = shape[axis_norm];
        let stride_after: usize = shape[(axis_norm + 1)..].iter().product::<usize>().max(1);

        for before in 0..stride_before {
            for c in 0..channel_size {
                let scale = scales[c];
                #[allow(clippy::cast_precision_loss)]
                let zp = zero_points[c] as f64;
                for after in 0..stride_after {
                    let idx = before * channel_size * stride_after + c * stride_after + after;
                    let q = q_data[idx];
                    out_data[idx] = (q - zp) * scale;
                }
            }
        }

        self.tensor_variable(out_data, shape, false)
    }

    /// Per-channel fake quantization for quantization-aware training.
    ///
    /// Equivalent to `torch.fake_quantize_per_channel_affine`.
    pub fn tensor_fake_quantize_per_channel(
        &mut self,
        input: TensorNodeId,
        scales: &[f64],
        zero_points: &[i64],
        axis: i64,
        qmin: i64,
        qmax: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let q = self.tensor_quantize_per_channel(input, scales, zero_points, axis, qmin, qmax)?;
        self.tensor_dequantize_per_channel(q, scales, zero_points, axis)
    }

    /// Alias for tensor_quantize_per_channel.
    pub fn functional_quantize_per_channel(
        &mut self,
        input: TensorNodeId,
        scales: &[f64],
        zero_points: &[i64],
        axis: i64,
        qmin: i64,
        qmax: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_quantize_per_channel(input, scales, zero_points, axis, qmin, qmax)
    }

