    pub fn tensor_isnan(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_float_classify(UnaryOp::IsNan, input)
    }

    pub fn tensor_isinf(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_float_classify(UnaryOp::IsInf, input)
    }

    /// 0/1 mask of element-wise `x == +∞`.
    ///
    /// Equivalent to `torch.isposinf(input)`. Compose via tensor_eq
    /// against a +∞ constant of the same shape. Non-differentiable
    /// mask results do not require grad, matching tensor_eq and the
    /// other classification ops. Tracked under frankentorch-f8dl.
    pub fn tensor_isposinf(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(input)?.clone();
        let shape = meta.shape().to_vec();
        let posinf = match meta.dtype() {
            DType::F64 => self.full(shape, f64::INFINITY, false)?,
            DType::F32 => {
                let numel = Self::checked_shape_numel(&shape, "isposinf shape volume overflow")?;
                self.tensor_variable_f32(vec![f32::INFINITY; numel], shape, false)?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "isposinf requires f32 or f64 tensors",
                    },
                )));
            }
        };
        self.tensor_eq(input, posinf)
    }

    /// 0/1 mask of element-wise `x == -∞`.
    ///
    /// Equivalent to `torch.isneginf(input)`. Sister to `tensor_isposinf`.
    /// Tracked under frankentorch-f8dl.
    pub fn tensor_isneginf(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(input)?.clone();
        let shape = meta.shape().to_vec();
        let neginf = match meta.dtype() {
            DType::F64 => self.full(shape, f64::NEG_INFINITY, false)?,
            DType::F32 => {
                let numel = Self::checked_shape_numel(&shape, "isneginf shape volume overflow")?;
                self.tensor_variable_f32(vec![f32::NEG_INFINITY; numel], shape, false)?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "isneginf requires f32 or f64 tensors",
                    },
                )));
            }
        };
        self.tensor_eq(input, neginf)
    }

    pub fn tensor_isfinite(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_float_classify(UnaryOp::IsFinite, input)
    }

    /// Returns a 0/1 mask indicating which elements are real (imaginary part is zero).
    ///
    /// For non-complex tensors, returns all 1.0s (all elements are real).
    /// For complex tensors, returns 1.0 where imag(x) == 0.
    ///
    /// Equivalent to `torch.isreal(input)`.
    pub fn tensor_isreal(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let dtype = self.tensor_dtype(input)?;
        if !dtype.is_complex() {
            let shape = self.tensor_shape(input)?;
            return self.full(shape, 1.0, false);
        }
        let imag = self.tensor_imag(input)?;
        let zero = self.full(self.tensor_shape(imag)?, 0.0, false)?;
        self.tensor_eq(imag, zero)
    }

    /// 0/1 mask of the IEEE 754 sign bit of `input`.
    ///
    /// Equivalent to `torch.signbit(input)` — true (1.0) where the
    /// sign bit is set: negative numbers, `-0.0`, `-inf`, and the
    /// negative-NaN bit pattern. Composing through `tensor_lt`
    /// against zero would silently drop `-0.0` (since `-0.0 < 0.0`
    /// is false in IEEE 754), so this routes through Rust's
    /// `f64::is_sign_negative` on the raw values to preserve
    /// torch parity.
    ///
    /// Non-differentiable (boolean mask); fail-loud on requires_grad
    /// like the other classification ops. Tracked under
    /// frankentorch-z50h.
    pub fn tensor_signbit(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "signbit: autograd not supported (boolean mask is non-differentiable). Tracked under frankentorch-z50h.",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if !matches!(dtype, DType::F32 | DType::F64) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "signbit requires f32 or f64 tensors",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let vals = self.tensor_values(input)?;
        let result: Vec<f64> = vals
            .iter()
            .map(|&v| if v.is_sign_negative() { 1.0 } else { 0.0 })
            .collect();
        match dtype {
            DType::F32 => {
                let f32_result: Vec<f32> = result.into_iter().map(|v| v as f32).collect();
                self.tensor_variable_f32(f32_result, shape, false)
            }
            _ => self.tensor_variable(result, shape, false),
        }
    }

