    /// Return `true` when tensors have identical shape and element values.
    ///
    /// NaN values are considered unequal (matching PyTorch `torch.equal`).
    pub fn tensor_equal(
        &self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
    ) -> Result<bool, AutogradError> {
        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;

        if lhs_meta.shape() != rhs_meta.shape() || lhs_meta.dtype() != rhs_meta.dtype() {
            return Ok(false);
        }

        for (l, r) in lhs_values.iter().zip(rhs_values.iter()) {
            if l.is_nan() || r.is_nan() {
                return Ok(false);
            }
            if l != r {
                return Ok(false);
            }
        }
        Ok(true)
    }

    /// Return `true` when tensors are elementwise close within tolerance.
    ///
    /// Uses: `|a - b| <= atol + rtol * |b|`.
    pub fn tensor_allclose(
        &self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        rtol: f64,
        atol: f64,
        equal_nan: bool,
    ) -> Result<bool, AutogradError> {
        if !rtol.is_finite() || !atol.is_finite() || rtol < 0.0 || atol < 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "allclose requires finite non-negative rtol and atol",
                },
            )));
        }

        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;

        if lhs_meta.shape() != rhs_meta.shape() || lhs_meta.dtype() != rhs_meta.dtype() {
            return Ok(false);
        }

        for (l, r) in lhs_values.iter().zip(rhs_values.iter()) {
            if l.is_nan() || r.is_nan() {
                if equal_nan && l.is_nan() && r.is_nan() {
                    continue;
                }
                return Ok(false);
            }

            if l.is_infinite() || r.is_infinite() {
                if l == r {
                    continue;
                }
                return Ok(false);
            }

            let tolerance = atol + rtol * r.abs();
            if (l - r).abs() > tolerance {
                return Ok(false);
            }
        }
        Ok(true)
    }

    /// Element-wise close-comparison mask, returning 0.0/1.0 tensor.
    ///
    /// Equivalent to `torch.isclose(lhs, rhs, rtol, atol, equal_nan)`.
    /// Each element is 1.0 when `|lhs - rhs| <= atol + rtol * |rhs|`,
    /// else 0.0. NaN handling follows PyTorch: NaN never closes to
    /// anything unless `equal_nan=true` and both sides are NaN. ±inf
    /// is close only to itself.
    ///
    /// Non-differentiable: fails loud on tracked inputs to avoid
    /// silently severing the autograd tape. Tracked under
    /// frankentorch-rvjs.
    pub fn tensor_isclose(
        &mut self,
        lhs: TensorNodeId,
        rhs: TensorNodeId,
        rtol: f64,
        atol: f64,
        equal_nan: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !rtol.is_finite() || !atol.is_finite() || rtol < 0.0 || atol < 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "isclose requires finite non-negative rtol and atol",
                },
            )));
        }
        if self.tensor_requires_grad(lhs)? || self.tensor_requires_grad(rhs)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "isclose: autograd not supported (close-comparison mask is non-differentiable). Tracked under frankentorch-rvjs.",
                },
            )));
        }

        let (lhs_values, lhs_meta) = self.tensor_values_meta(lhs)?;
        let (rhs_values, rhs_meta) = self.tensor_values_meta(rhs)?;
        if lhs_meta.shape() != rhs_meta.shape() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: lhs_meta.shape().to_vec(),
                    rhs: rhs_meta.shape().to_vec(),
                },
            )));
        }

        let result: Vec<f64> = lhs_values
            .iter()
            .zip(rhs_values.iter())
            .map(|(&l, &r)| {
                if l.is_nan() || r.is_nan() {
                    if equal_nan && l.is_nan() && r.is_nan() {
                        1.0
                    } else {
                        0.0
                    }
                } else if l.is_infinite() || r.is_infinite() {
                    if l == r { 1.0 } else { 0.0 }
                } else {
                    let tolerance = atol + rtol * r.abs();
                    if (l - r).abs() <= tolerance { 1.0 } else { 0.0 }
                }
            })
            .collect();
        let shape = lhs_meta.shape().to_vec();
        self.tensor_variable(result, shape, false)
    }

    /// In-place isnan: target = isnan(target) ? 1.0 : 0.0.
    pub fn tensor_isnan_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let result = self.tensor_isnan(target)?;
        let result_vals = self.tensor_values(result)?;
        self.update_tensor_values_for_float(target, result_vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("isnan_", target, None);
        Ok(())
    }

