    /// DropBlock regularization for convolutional networks.
    ///
    /// Drops contiguous blocks of feature map instead of individual elements.
    /// More effective than dropout for conv layers (Ghiasi et al., 2018).
    ///
    /// Args:
    /// - input: [N, C, H, W] feature maps
    /// - block_size: size of square blocks to drop
    /// - p: probability of dropping (gamma is computed internally)
    /// - training: apply dropblock only during training
    pub fn dropblock2d(
        &mut self,
        input: TensorNodeId,
        block_size: usize,
        p: f64,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !training || p == 0.0 {
            return Ok(input);
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("dropblock2d: input must be [N, C, H, W]"));
        }
        let (n, c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let block_size = block_size.min(h).min(w);
        let feat_area = (h * w) as f64;
        let block_area = (block_size * block_size) as f64;
        let valid_h = h - block_size + 1;
        let valid_w = w - block_size + 1;
        let valid_area = (valid_h * valid_w) as f64;
        let gamma = p * feat_area / (block_area * valid_area);
        let mut mask = vec![1.0; n * c * h * w];
        for bi in 0..n {
            for ci in 0..c {
                for yi in 0..valid_h {
                    for xi in 0..valid_w {
                        if self.rng.next_f64() < gamma {
                            for by in 0..block_size {
                                for bx in 0..block_size {
                                    let idx = bi * c * h * w + ci * h * w + (yi + by) * w + (xi + bx);
                                    mask[idx] = 0.0;
                                }
                            }
                        }
                    }
                }
            }
        }
        let kept: f64 = mask.iter().sum();
        let total = mask.len() as f64;
        let scale = total / kept.max(1.0);
        let mask_scaled: Vec<f64> = mask.into_iter().map(|m| m * scale).collect();
        let mask_t = self.tensor_variable(mask_scaled, shape, false)?;
        self.tensor_mul(input, mask_t)
    }

    /// Stochastic depth (drop path) regularization.
    ///
    /// Randomly drops entire residual branches during training.
    /// Used in EfficientNet, DeiT, and other deep networks.
    ///
    /// Args:
    /// - input: input tensor (the residual branch output)
    /// - drop_prob: probability of dropping the entire branch
    /// - training: apply stochastic depth only during training
    pub fn stochastic_depth(
        &mut self,
        input: TensorNodeId,
        drop_prob: f64,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !training || drop_prob == 0.0 {
            return Ok(input);
        }
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            return Ok(input);
        }
        let batch_size = shape[0];
        let mut keep_mask = Vec::with_capacity(batch_size);
        let keep_prob = 1.0 - drop_prob;
        for _ in 0..batch_size {
            let keep = if self.rng.next_f64() < keep_prob { 1.0 / keep_prob } else { 0.0 };
            keep_mask.push(keep);
        }
        let broadcast_shape: Vec<usize> = std::iter::once(batch_size)
            .chain(std::iter::repeat(1).take(shape.len() - 1))
            .collect();
        let mask_t = self.tensor_variable(keep_mask, broadcast_shape, false)?;
        self.tensor_mul(input, mask_t)
    }

    /// Label smoothing cross entropy loss.
    ///
    /// Softens the target distribution by mixing with uniform distribution.
    /// CE with soft labels: (1 - smoothing) * one_hot + smoothing / num_classes
    ///
    /// Args:
    /// - logits: [N, C] unnormalized logits
    /// - targets: [N] integer class indices
    /// - smoothing: label smoothing factor (0 = no smoothing)
    pub fn label_smoothing_cross_entropy(
        &mut self,
        logits: TensorNodeId,
        targets: TensorNodeId,
        smoothing: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(logits)?;
        if shape.len() != 2 {
            return Err(Self::incompatible_tensor_args(
                "label_smoothing_cross_entropy: logits must be [N, C]",
            ));
        }
        let (n, c) = (shape[0], shape[1]);
        let target_data = self.tensor_values(targets)?;
        let mut soft_targets = vec![smoothing / c as f64; n * c];
        let confidence = 1.0 - smoothing;
        for i in 0..n {
            let cls = target_data[i] as usize;
            if cls < c {
                soft_targets[i * c + cls] += confidence;
            }
        }
        let soft_t = self.tensor_variable(soft_targets, vec![n, c], false)?;
        let log_probs = self.tensor_log_softmax(logits, 1)?;
        let neg_log_probs = self.tensor_neg(log_probs)?;
        let losses = self.tensor_mul(soft_t, neg_log_probs)?;
        let sum_losses = self.tensor_sum_dim(losses, 1)?;
        self.tensor_mean(sum_losses)
    }

    /// Shake-Shake regularization for ResNet branches.
    ///
    /// Randomly interpolates between two branches during training.
    /// During inference, uses average of branches.
    ///
    /// Args:
    /// - branch1: first branch output
    /// - branch2: second branch output
    /// - training: use random interpolation during training
    pub fn shake_shake(
        &mut self,
        branch1: TensorNodeId,
        branch2: TensorNodeId,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(branch1)?;
        if training && !shape.is_empty() {
            let batch_size = shape[0];
            let alphas: Vec<f64> = (0..batch_size).map(|_| self.rng.next_f64()).collect();
            let broadcast_shape: Vec<usize> = std::iter::once(batch_size)
                .chain(std::iter::repeat(1).take(shape.len() - 1))
                .collect();
            let alpha_t = self.tensor_variable(alphas.clone(), broadcast_shape.clone(), false)?;
            let one_minus_alpha: Vec<f64> = alphas.into_iter().map(|a| 1.0 - a).collect();
            let one_minus_alpha_t = self.tensor_variable(one_minus_alpha, broadcast_shape, false)?;
            let scaled1 = self.tensor_mul(branch1, alpha_t)?;
            let scaled2 = self.tensor_mul(branch2, one_minus_alpha_t)?;
            self.tensor_add(scaled1, scaled2)
        } else {
            let sum = self.tensor_add(branch1, branch2)?;
            let half = self.full(shape, 0.5, false)?;
            self.tensor_mul(sum, half)
        }
    }

    /// Look up embeddings from a weight matrix.
    ///
    /// Equivalent to `torch.nn.functional.embedding(input, weight)`.
    /// `input` is a tensor of integer indices, `weight` is `[num_embeddings, embedding_dim]`.
    /// Returns a tensor where each index is replaced by the corresponding row of `weight`.
    pub fn functional_embedding(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose via tensor_reshape + tensor_index_select so gradients
        // flow back to the weight tensor. Tracked under
        // frankentorch-b9od. Previous body extracted both indices and
        // weight values, looked up rows in plain f64, and rebuilt a
        // non-grad leaf — silently severing autograd through every
        // F.embedding call (used directly outside the nn.Embedding
        // wrapper in custom transformer blocks, etc.).
        let input_shape = self.tensor_shape(input)?;
        let w_shape = self.tensor_shape(weight)?;
        if w_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "embedding: weight must be 2-D [num_embeddings, embedding_dim]",
                },
            )));
        }
        let emb_dim = w_shape[1];

        let total = input_shape.iter().product::<usize>();
        // Validate indices once via a values read (non-grad path on
        // input — input is an integer index tensor and therefore
        // never has requires_grad in any sane training loop). This
        // matches the validation that tensor_index_select itself
        // performs internally; do it here too to keep the prior
        // error messages in place.
        let indices = self.tensor_values(input)?;
        for &idx_f in &indices {
            if !idx_f.is_finite() || idx_f < 0.0 || idx_f.fract() != 0.0 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: indices must be non-negative integer-valued",
                    },
                )));
            }
            if (idx_f as usize) >= w_shape[0] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "embedding: index out of range",
                    },
                )));
            }
        }

        let flat_indices = self.tensor_reshape(input, vec![total])?;
        let selected = self.tensor_index_select(weight, 0, flat_indices)?;
        let mut out_shape = input_shape;
        out_shape.push(emb_dim);
        self.tensor_reshape(selected, out_shape)
    }

    /// Embedding bag (sum/mean/max of embeddings). Alias for tensor_embedding_bag.
    pub fn functional_embedding_bag(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        offsets: TensorNodeId,
        mode: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_embedding_bag(input, weight, offsets, mode)
    }

    /// Apply a linear transformation: `y = x @ weight^T + bias`.
    ///
    /// Equivalent to `torch.nn.functional.linear(input, weight, bias)`.
    /// `input`: `[*, in_features]`, `weight`: `[out_features, in_features]`,
    /// `bias` (optional): `[out_features]`.
    pub fn tensor_linear(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_linear(input, weight, bias)
    }

    /// Apply a linear transformation: `y = x @ weight^T + bias`.
    ///
    /// Equivalent to `torch.nn.functional.linear(input, weight, bias)`.
    /// `input`: `[*, in_features]`, `weight`: `[out_features, in_features]`,
    /// `bias` (optional): `[out_features]`.
    pub fn functional_linear(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let weight_t = self.tensor_transpose(weight, 0, 1)?;
        let output = self.tensor_matmul(input, weight_t)?;
        match bias {
            Some(b) => {
                let out_shape = self.tensor_shape(output)?;
                let expanded = self.tensor_expand(b, out_shape)?;
                self.tensor_add(output, expanded)
            }
            None => Ok(output),
        }
    }

    /// Scaled dot-product attention mechanism.
    ///
    /// Equivalent to `torch.nn.functional.scaled_dot_product_attention`.
    ///
    /// Computes: `softmax(Q @ K^T / sqrt(d_k)) @ V` with optional masking and dropout.
    ///
    /// - `query`: [..., seq_len, d_k]
    /// - `key`: [..., seq_len_kv, d_k]
    /// - `value`: [..., seq_len_kv, d_v]
    /// - `attn_mask`: optional mask tensor (None for causal, or explicit mask)
    /// - `is_causal`: if true, applies causal (lower triangular) mask
    /// - `scale`: optional scale factor (default: 1/sqrt(d_k))
    pub fn tensor_scaled_dot_product_attention(
        &mut self,
        query: TensorNodeId,
        key: TensorNodeId,
        value: TensorNodeId,
        attn_mask: Option<TensorNodeId>,
        is_causal: bool,
        scale: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        let query_shape = self.tensor_shape(query)?;
        let key_shape = self.tensor_shape(key)?;
        if query_shape.len() < 2 || key_shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scaled_dot_product_attention: query and key must be at least 2D",
                },
            )));
        }
        let d_k = query_shape[query_shape.len() - 1];
        let scale_factor = scale.unwrap_or(1.0 / (d_k as f64).sqrt());
        let key_t = self.tensor_transpose(key, key_shape.len() - 2, key_shape.len() - 1)?;
        let scores = self.tensor_matmul(query, key_t)?;
        let scores_shape = self.tensor_shape(scores)?;
        let scale_t = self.full(scores_shape.clone(), scale_factor, false)?;
        let scaled_scores = self.tensor_mul(scores, scale_t)?;
        let masked_scores = if is_causal {
            let seq_len = scores_shape[scores_shape.len() - 2];
            let seq_len_kv = scores_shape[scores_shape.len() - 1];
            let mut mask_vals = vec![0.0_f64; seq_len * seq_len_kv];
            for i in 0..seq_len {
                for j in 0..seq_len_kv {
                    if j > i {
                        mask_vals[i * seq_len_kv + j] = f64::NEG_INFINITY;
                    }
                }
            }
            let mask_node = self.tensor_variable(mask_vals, vec![seq_len, seq_len_kv], false)?;
            let expanded_mask = self.tensor_expand(mask_node, scores_shape.clone())?;
            self.tensor_add(scaled_scores, expanded_mask)?
        } else if let Some(mask) = attn_mask {
            self.tensor_add(scaled_scores, mask)?
        } else {
            scaled_scores
        };
        let ndim = scores_shape.len();
        let attn_weights = self.tensor_softmax(masked_scores, ndim - 1)?;
        self.tensor_matmul(attn_weights, value)
    }

    /// Bilinear transformation: `y[k] = x1 @ W[k] @ x2^T + b[k]`.
    ///
    /// Equivalent to `torch.nn.functional.bilinear(input1, input2, weight, bias)`.
    /// `input1`: `[*, in1_features]`, `input2`: `[*, in2_features]`,
    /// `weight`: `[out_features, in1_features, in2_features]`,
    /// `bias` (optional): `[out_features]`.
    pub fn functional_bilinear(
        &mut self,
        input1: TensorNodeId,
        input2: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let weight_shape = self.tensor_shape(weight)?;
        if weight_shape.len() != 3 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "bilinear: weight must be 3-D [out_features, in1_features, in2_features]",
                },
            )));
        }
        let out_features = weight_shape[0];
        let input1_shape = self.tensor_shape(input1)?;
        let batch_shape: Vec<usize> = input1_shape[..input1_shape.len() - 1].to_vec();
        let mut output_parts = Vec::with_capacity(out_features);
        for k in 0..out_features {
            let w_k = self.tensor_select(weight, 0, k)?;
            let temp = self.tensor_matmul(input1, w_k)?;
            let input2_t = self.tensor_transpose(input2, input1_shape.len() - 1, input1_shape.len() - 1)?;
            let out_k = self.tensor_matmul(temp, input2_t)?;
            output_parts.push(out_k);
        }
        let output = self.tensor_stack(&output_parts, batch_shape.len())?;
        match bias {
            Some(b) => {
                let out_shape = self.tensor_shape(output)?;
                let expanded = self.tensor_expand(b, out_shape)?;
                self.tensor_add(output, expanded)
            }
            None => Ok(output),
        }
    }

    /// Alias for functional_bilinear.
    pub fn tensor_bilinear(
        &mut self,
        input1: TensorNodeId,
        input2: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_bilinear(input1, input2, weight, bias)
    }

    /// Apply a 1D convolution.
    ///
    /// Alias for `functional_conv1d`.
    pub fn tensor_conv1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_conv1d(input, weight, bias, stride, padding)
    }

    /// Apply a 1D convolution: `y = conv1d(input, weight, bias)`.
    ///
    /// Equivalent to `torch.nn.functional.conv1d(input, weight, bias, stride, padding)`.
    /// `input`: `[N, C_in, L]`, `weight`: `[C_out, C_in, K]`, `bias` (optional): `[C_out]`.
    pub fn functional_conv1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: stride must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input must be 3-D [N, C_in, L]",
            ));
        }
        if weight_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: weight must be 3-D [C_out, C_in, K]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_len = input_shape[2];
        let out_channels = weight_shape[0];
        let weight_in_channels = weight_shape[1];
        let kernel_size = weight_shape[2];

        if kernel_size == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv1d: kernel size must be greater than zero",
            ));
        }
        if in_channels != weight_in_channels {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input channels do not match weight",
            ));
        }

        if let Some(bias) = bias {
            let bias_shape = self.tensor_shape(bias)?;
            if bias_shape != vec![out_channels] {
                return Err(Self::incompatible_tensor_args(
                    "conv1d: bias must have shape [C_out]",
                ));
            }
        }

        let padded = if padding > 0 {
            self.tensor_pad(input, &[padding, padding], 0.0)?
        } else {
            input
        };
        let padded_len = input_len + 2 * padding;
        if padded_len < kernel_size {
            return Err(Self::incompatible_tensor_args(
                "conv1d: input too short for kernel size and padding",
            ));
        }

        let output_len = (padded_len - kernel_size) / stride + 1;
        let patch_width = in_channels * kernel_size;
        let mut patches = Vec::with_capacity(output_len);
        for out_index in 0..output_len {
            let start = out_index * stride;
            let patch = self.tensor_narrow(padded, 2, start, kernel_size)?;
            let flat = self.tensor_reshape(patch, vec![batch_size, 1, patch_width])?;
            patches.push(flat);
        }

        let unfolded = self.tensor_cat(&patches, 1)?;
        let weight_flat = self.tensor_reshape(weight, vec![out_channels, patch_width])?;
        let weight_t = self.tensor_transpose(weight_flat, 0, 1)?;
        let weight_us = self.tensor_unsqueeze(weight_t, 0)?;
        let weight_expanded =
            self.tensor_expand(weight_us, vec![batch_size, patch_width, out_channels])?;
        let output = self.tensor_bmm(unfolded, weight_expanded)?;
        let output = self.tensor_transpose(output, 1, 2)?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1])?;
                let bias = self.tensor_expand(bias, vec![batch_size, out_channels, output_len])?;
                self.tensor_add(output, bias)
            }
            None => Ok(output),
        }
    }

    /// Apply a 2D convolution.
    ///
    /// Alias for `functional_conv2d`.
    pub fn tensor_conv2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_conv2d(input, weight, bias, stride, padding)
    }

    /// Apply a 2D convolution: `y = conv2d(input, weight, bias)`.
    ///
    /// Equivalent to `torch.nn.functional.conv2d(input, weight, bias, stride, padding)`.
    /// `input`: `[N, C_in, H, W]`, `weight`: `[C_out, C_in, K_h, K_w]`.
    pub fn functional_conv2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_h, stride_w) = stride;
        let (padding_h, padding_w) = padding;
        if stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input must be 4-D [N, C_in, H, W]",
            ));
        }
        if weight_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: weight must be 4-D [C_out, C_in, K_h, K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        let out_channels = weight_shape[0];
        let weight_in_channels = weight_shape[1];
        let kernel_h = weight_shape[2];
        let kernel_w = weight_shape[3];

        if kernel_h == 0 || kernel_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv2d: kernel dimensions must be greater than zero",
            ));
        }
        if in_channels != weight_in_channels {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input channels do not match weight",
            ));
        }

        if let Some(bias) = bias {
            let bias_shape = self.tensor_shape(bias)?;
            if bias_shape != vec![out_channels] {
                return Err(Self::incompatible_tensor_args(
                    "conv2d: bias must have shape [C_out]",
                ));
            }
        }

        let padded = if padding_h > 0 || padding_w > 0 {
            self.tensor_pad(input, &[padding_w, padding_w, padding_h, padding_h], 0.0)?
        } else {
            input
        };
        let pad_h = Self::checked_mul(padding_h, 2, "conv2d padding overflow")?;
        let pad_w = Self::checked_mul(padding_w, 2, "conv2d padding overflow")?;
        let padded_h = Self::checked_add(input_h, pad_h, "conv2d padding overflow")?;
        let padded_w = Self::checked_add(input_w, pad_w, "conv2d padding overflow")?;
        if padded_h < kernel_h || padded_w < kernel_w {
            return Err(Self::incompatible_tensor_args(
                "conv2d: input too small for kernel size and padding",
            ));
        }

        let output_h = (padded_h - kernel_h) / stride_h;
        let output_h = Self::checked_add(output_h, 1, "conv2d output height overflow")?;
        let output_w = (padded_w - kernel_w) / stride_w;
        let output_w = Self::checked_add(output_w, 1, "conv2d output width overflow")?;
        let patch_width = Self::checked_mul(in_channels, kernel_h, "conv2d patch width overflow")?;
        let patch_width = Self::checked_mul(patch_width, kernel_w, "conv2d patch width overflow")?;
        let patch_count = Self::checked_mul(output_h, output_w, "conv2d patch count overflow")?;
        let mut patches = Vec::with_capacity(patch_count);
        for out_h in 0..output_h {
            let row_start = Self::checked_mul(out_h, stride_h, "conv2d row start overflow")?;
            let row_slice = self.tensor_narrow(padded, 2, row_start, kernel_h)?;
            for out_w in 0..output_w {
                let col_start = Self::checked_mul(out_w, stride_w, "conv2d col start overflow")?;
                let patch = self.tensor_narrow(row_slice, 3, col_start, kernel_w)?;
                let flat = self.tensor_reshape(patch, vec![batch_size, 1, patch_width])?;
                patches.push(flat);
            }
        }

        let unfolded = self.tensor_cat(&patches, 1)?;
        let weight_flat = self.tensor_reshape(weight, vec![out_channels, patch_width])?;
        let weight_t = self.tensor_transpose(weight_flat, 0, 1)?;
        let weight_us = self.tensor_unsqueeze(weight_t, 0)?;
        let weight_expanded =
            self.tensor_expand(weight_us, vec![batch_size, patch_width, out_channels])?;
        let output = self.tensor_bmm(unfolded, weight_expanded)?;
        let output = self.tensor_transpose(output, 1, 2)?;
        let output =
            self.tensor_reshape(output, vec![batch_size, out_channels, output_h, output_w])?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1])?;
                let bias =
                    self.tensor_expand(bias, vec![batch_size, out_channels, output_h, output_w])?;
                self.tensor_add(output, bias)
            }
            None => Ok(output),
        }
    }

    /// Apply a 3D convolution.
    ///
    /// Alias for `functional_conv3d`.
    pub fn tensor_conv3d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize, usize),
        padding: (usize, usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_conv3d(input, weight, bias, stride, padding)
    }

    /// Apply 3D convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv3d(input, weight, bias, stride, padding)`.
    /// Input: `[N, C_in, D, H, W]`, Weight: `[C_out, C_in, K_d, K_h, K_w]`.
    pub fn functional_conv3d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize, usize),
        padding: (usize, usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_d, stride_h, stride_w) = stride;
        let (padding_d, padding_h, padding_w) = padding;
        if stride_d == 0 || stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: stride dimensions must be greater than zero",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 5 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: input must be 5-D [N, C_in, D, H, W]",
            ));
        }
        if weight_shape.len() != 5 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: weight must be 5-D [C_out, C_in, K_d, K_h, K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_d = input_shape[2];
        let input_h = input_shape[3];
        let input_w = input_shape[4];
        let out_channels = weight_shape[0];
        let kernel_d = weight_shape[2];
        let kernel_h = weight_shape[3];
        let kernel_w = weight_shape[4];

        if in_channels != weight_shape[1] {
            return Err(Self::incompatible_tensor_args(
                "conv3d: input channels do not match weight",
            ));
        }

        if kernel_d == 0 || kernel_h == 0 || kernel_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv3d: kernel dimensions must be greater than zero",
            ));
        }
        if let Some(bias_id) = bias {
            let bias_shape = self.tensor_shape(bias_id)?;
            if bias_shape != vec![out_channels] {
                return Err(Self::incompatible_tensor_args(
                    "conv3d: bias must have shape [C_out]",
                ));
            }
        }

        // Compose via tensor_pad + tensor_narrow + tensor_reshape +
        // tensor_cat + tensor_bmm so gradients flow back to both input
        // and weight. Tracked under frankentorch-lgj2. Previous body
        // ran the convolution in plain f64 and rebuilt a non-grad
        // leaf, severing autograd through every functional_conv3d
        // call (3D CNNs, video models, medical imaging).
        //
        // Mirrors the conv2d composition with an extra D axis: extract
        // 3D sub-patches via narrow on dims 2, 3, 4; flatten each
        // patch to [N, 1, C_in*K_d*K_h*K_w]; cat across patches;
        // reshape weight to [C_out, C_in*K_d*K_h*K_w] and bmm with
        // batched expand; transpose and reshape to
        // [N, C_out, D_out, H_out, W_out].
        let padded = if padding_d > 0 || padding_h > 0 || padding_w > 0 {
            self.tensor_pad(
                input,
                &[
                    padding_w, padding_w, padding_h, padding_h, padding_d, padding_d,
                ],
                0.0,
            )?
        } else {
            input
        };
        let pad_d_total = Self::checked_mul(padding_d, 2, "conv3d padding depth overflow")?;
        let pad_h_total = Self::checked_mul(padding_h, 2, "conv3d padding height overflow")?;
        let pad_w_total = Self::checked_mul(padding_w, 2, "conv3d padding width overflow")?;
        let padded_d = Self::checked_add(input_d, pad_d_total, "conv3d padded depth overflow")?;
        let padded_h = Self::checked_add(input_h, pad_h_total, "conv3d padded height overflow")?;
        let padded_w = Self::checked_add(input_w, pad_w_total, "conv3d padded width overflow")?;
        if padded_d < kernel_d || padded_h < kernel_h || padded_w < kernel_w {
            return Err(Self::incompatible_tensor_args(
                "conv3d: input too small for kernel size and padding",
            ));
        }

        let output_d = (padded_d - kernel_d) / stride_d + 1;
        let output_h = (padded_h - kernel_h) / stride_h + 1;
        let output_w = (padded_w - kernel_w) / stride_w + 1;
        let patch_width = Self::checked_mul(in_channels, kernel_d, "conv3d patch width overflow")?;
        let patch_width = Self::checked_mul(patch_width, kernel_h, "conv3d patch width overflow")?;
        let patch_width = Self::checked_mul(patch_width, kernel_w, "conv3d patch width overflow")?;
        let hw_out = Self::checked_mul(output_h, output_w, "conv3d patch count overflow")?;
        let patch_count = Self::checked_mul(output_d, hw_out, "conv3d patch count overflow")?;

        let mut patches = Vec::with_capacity(patch_count);
        for out_d in 0..output_d {
            let depth_start = Self::checked_mul(out_d, stride_d, "conv3d depth start overflow")?;
            let depth_slice = self.tensor_narrow(padded, 2, depth_start, kernel_d)?;
            for out_h in 0..output_h {
                let row_start = Self::checked_mul(out_h, stride_h, "conv3d row start overflow")?;
                let row_slice = self.tensor_narrow(depth_slice, 3, row_start, kernel_h)?;
                for out_w in 0..output_w {
                    let col_start =
                        Self::checked_mul(out_w, stride_w, "conv3d col start overflow")?;
                    let patch = self.tensor_narrow(row_slice, 4, col_start, kernel_w)?;
                    let flat = self.tensor_reshape(patch, vec![batch_size, 1, patch_width])?;
                    patches.push(flat);
                }
            }
        }

        let unfolded = self.tensor_cat(&patches, 1)?;
        let weight_flat = self.tensor_reshape(weight, vec![out_channels, patch_width])?;
        let weight_t = self.tensor_transpose(weight_flat, 0, 1)?;
        let weight_us = self.tensor_unsqueeze(weight_t, 0)?;
        let weight_expanded =
            self.tensor_expand(weight_us, vec![batch_size, patch_width, out_channels])?;
        let output = self.tensor_bmm(unfolded, weight_expanded)?;
        let output = self.tensor_transpose(output, 1, 2)?;
        let out_node = self.tensor_reshape(
            output,
            vec![batch_size, out_channels, output_d, output_h, output_w],
        )?;

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1, 1])?;
                let bias = self.tensor_expand(
                    bias,
                    vec![batch_size, out_channels, output_d, output_h, output_w],
                )?;
                self.tensor_add(out_node, bias)
            }
            None => Ok(out_node),
        }
    }

    /// Apply 1D transposed convolution. Alias for `functional_conv_transpose1d`.
    pub fn tensor_conv_transpose1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
        output_padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_conv_transpose1d(input, weight, bias, stride, padding, output_padding)
    }

    /// Apply 1D transposed convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv_transpose1d(input, weight, bias, stride, padding, output_padding)`.
    /// Input: `[N, C_in, L]`, Weight: `[C_in, C_out, K]`.
    pub fn functional_conv_transpose1d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: usize,
        padding: usize,
        output_padding: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        if stride == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: stride must be > 0",
            ));
        }
        if output_padding >= stride {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: output_padding must be < stride",
            ));
        }
        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 3 || weight_shape.len() != 3 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: input must be 3-D [N, C_in, L], weight 3-D [C_in, C_out, K]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_l = input_shape[2];
        let out_channels = weight_shape[1];
        let kernel_l = weight_shape[2];

        if input_l == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: input length must be > 0",
            ));
        }
        if kernel_l == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: kernel size must be > 0",
            ));
        }

        if in_channels != weight_shape[0] {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose1d: input channels do not match weight",
            ));
        }

        let output_l = Self::checked_conv_transpose_output_dim(
            ConvTransposeOutputDimSpec {
                input: input_l,
                stride,
                kernel: kernel_l,
                padding,
                output_padding,
            },
            ConvTransposeOutputDimErrors {
                overflow: "conv_transpose1d output length overflow",
                padding_overflow: "conv_transpose1d padding overflow",
                underflow: "conv_transpose1d: output size underflow from padding",
            },
        )?;

        // Compose via tensor_narrow + tensor_matmul + tensor_pad +
        // tensor_add so gradients flow back to input and weight.
        // Tracked under frankentorch-zjf6. Previously the body ran
        // the transposed convolution in plain f64 and rebuilt a
        // non-grad leaf, severing autograd through every F.conv_t1d
        // call (U-Net decoders, GANs, segmentation upsamplers).
        //
        // Mirrors the ConvTranspose1d nn.Module composition:
        // for each kernel position k, for each input position i,
        // contribute x[:, :, i] @ w[:, :, k] at output position
        // i*stride + k - padding. Implemented via narrow + matmul
        // + pad + accumulating add.
        let result_shape = vec![batch_size, out_channels, output_l];
        let mut result = if self.tensor_dtype(input)? == DType::F32 {
            self.zeros_f32(result_shape, false)?
        } else {
            self.zeros(result_shape, false)?
        };
        for k in 0..kernel_l {
            let w_k = self.tensor_narrow(weight, 2, k, 1)?;
            let w_k = self.tensor_squeeze(w_k, 2)?; // [in_channels, out_channels]
            for il in 0..input_l {
                let out_pos_raw = il * stride + k;
                if out_pos_raw < padding || out_pos_raw - padding >= output_l {
                    continue;
                }
                let out_pos = out_pos_raw - padding;
                let x_i = self.tensor_narrow(input, 2, il, 1)?;
                let x_i = self.tensor_squeeze(x_i, 2)?; // [batch, in_channels]
                let contrib = self.tensor_matmul(x_i, w_k)?; // [batch, out_channels]
                let contrib = self.tensor_unsqueeze(contrib, 2)?; // [batch, out_channels, 1]
                let pad_left = out_pos;
                let pad_right = output_l - out_pos - 1;
                let contrib_padded = self.tensor_pad(contrib, &[pad_left, pad_right], 0.0)?;
                result = self.tensor_add(result, contrib_padded)?;
            }
        }

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1])?;
                let bias = self.tensor_expand(bias, vec![batch_size, out_channels, output_l])?;
                self.tensor_add(result, bias)
            }
            None => Ok(result),
        }
    }

    /// Apply 2D transposed convolution. Alias for `functional_conv_transpose2d`.
    pub fn tensor_conv_transpose2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
        output_padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_conv_transpose2d(input, weight, bias, stride, padding, output_padding)
    }

    /// Apply 2D transposed convolution.
    ///
    /// Equivalent to `torch.nn.functional.conv_transpose2d(input, weight, bias, stride, padding, output_padding)`.
    /// Input: `[N, C_in, H, W]`, Weight: `[C_in, C_out, K_h, K_w]`.
    pub fn functional_conv_transpose2d(
        &mut self,
        input: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
        stride: (usize, usize),
        padding: (usize, usize),
        output_padding: (usize, usize),
    ) -> Result<TensorNodeId, AutogradError> {
        let (stride_h, stride_w) = stride;
        let (padding_h, padding_w) = padding;
        let (output_padding_h, output_padding_w) = output_padding;
        if stride_h == 0 || stride_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: stride must be > 0",
            ));
        }
        if output_padding_h >= stride_h || output_padding_w >= stride_w {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: output_padding must be < stride",
            ));
        }

        let input_shape = self.tensor_shape(input)?;
        let weight_shape = self.tensor_shape(weight)?;
        if input_shape.len() != 4 || weight_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: input 4-D [N,C_in,H,W], weight 4-D [C_in,C_out,K_h,K_w]",
            ));
        }

        let batch_size = input_shape[0];
        let in_channels = input_shape[1];
        let input_h = input_shape[2];
        let input_w = input_shape[3];
        let out_channels = weight_shape[1];
        let kernel_h = weight_shape[2];
        let kernel_w = weight_shape[3];

        if input_h == 0 || input_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: input spatial dims must be > 0",
            ));
        }
        if kernel_h == 0 || kernel_w == 0 {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: kernel size must be > 0",
            ));
        }

        if in_channels != weight_shape[0] {
            return Err(Self::incompatible_tensor_args(
                "conv_transpose2d: input channels do not match weight",
            ));
        }

        let output_h = Self::checked_conv_transpose_output_dim(
            ConvTransposeOutputDimSpec {
                input: input_h,
                stride: stride_h,
                kernel: kernel_h,
                padding: padding_h,
                output_padding: output_padding_h,
            },
            ConvTransposeOutputDimErrors {
                overflow: "conv_transpose2d output height overflow",
                padding_overflow: "conv_transpose2d padding overflow",
                underflow: "conv_transpose2d: output height underflow from padding",
            },
        )?;

        let output_w = Self::checked_conv_transpose_output_dim(
            ConvTransposeOutputDimSpec {
                input: input_w,
                stride: stride_w,
                kernel: kernel_w,
                padding: padding_w,
                output_padding: output_padding_w,
            },
            ConvTransposeOutputDimErrors {
                overflow: "conv_transpose2d output width overflow",
                padding_overflow: "conv_transpose2d padding overflow",
                underflow: "conv_transpose2d: output width underflow from padding",
            },
        )?;

        // Compose via tensor_narrow + tensor_matmul + tensor_pad +
        // tensor_add so gradients flow back to input and weight.
        // Tracked under frankentorch-zjf6. Same scatter-and-accumulate
        // pattern as conv_transpose1d, with two spatial axes:
        // for each kernel (kh, kw), each input position (ih, iw),
        // compute x[:, :, ih, iw] @ w[:, :, kh, kw] and pad it to
        // the right output position before accumulating.
        let result_shape = vec![batch_size, out_channels, output_h, output_w];
        let mut result = if self.tensor_dtype(input)? == DType::F32 {
            self.zeros_f32(result_shape, false)?
        } else {
            self.zeros(result_shape, false)?
        };
        for kh in 0..kernel_h {
            for kw in 0..kernel_w {
                let w_kh = self.tensor_narrow(weight, 2, kh, 1)?;
                let w_kw = self.tensor_narrow(w_kh, 3, kw, 1)?;
                let w_kw = self.tensor_squeeze(w_kw, 3)?;
                let w_kw = self.tensor_squeeze(w_kw, 2)?; // [in_channels, out_channels]
                for ih in 0..input_h {
                    for iw in 0..input_w {
                        let oh_raw = ih * stride_h + kh;
                        let ow_raw = iw * stride_w + kw;
                        if oh_raw < padding_h
                            || ow_raw < padding_w
                            || oh_raw - padding_h >= output_h
                            || ow_raw - padding_w >= output_w
                        {
                            continue;
                        }
                        let oh = oh_raw - padding_h;
                        let ow = ow_raw - padding_w;
                        let x_ih = self.tensor_narrow(input, 2, ih, 1)?;
                        let x_iw = self.tensor_narrow(x_ih, 3, iw, 1)?;
                        let x_iw = self.tensor_squeeze(x_iw, 3)?;
                        let x_iw = self.tensor_squeeze(x_iw, 2)?; // [batch, in_channels]
                        let contrib = self.tensor_matmul(x_iw, w_kw)?; // [batch, out_channels]
                        let contrib = self.tensor_unsqueeze(contrib, 2)?;
                        let contrib = self.tensor_unsqueeze(contrib, 3)?; // [batch, out_channels, 1, 1]
                        let pad_left = ow;
                        let pad_right = output_w - ow - 1;
                        let pad_top = oh;
                        let pad_bottom = output_h - oh - 1;
                        let contrib_padded = self.tensor_pad(
                            contrib,
                            &[pad_left, pad_right, pad_top, pad_bottom],
                            0.0,
                        )?;
                        result = self.tensor_add(result, contrib_padded)?;
                    }
                }
            }
        }

        match bias {
            Some(bias) => {
                let bias = self.tensor_reshape(bias, vec![1, out_channels, 1, 1])?;
                let bias =
                    self.tensor_expand(bias, vec![batch_size, out_channels, output_h, output_w])?;
                self.tensor_add(result, bias)
            }
            None => Ok(result),
        }
    }

    /// Apply 1D average pooling. Alias for `functional_avg_pool1d`.
    pub fn tensor_avg_pool1d(
        &mut self,
        input: TensorNodeId,
        kernel_size: usize,
        stride: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.functional_avg_pool1d(input, kernel_size, stride)
    }

