    pub fn tensor_reshape(
        &mut self,
        input: TensorNodeId,
        new_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.reshape(input, new_shape)
    }

    /// Reshape `input` to have the same shape as `other`.
    ///
    /// Equivalent to `torch.reshape(input, other.shape)` or
    /// `input.reshape_as(other)`. Element counts must match.
    pub fn tensor_reshape_as(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let target_shape = self.tensor_shape(other)?;
        self.tensor_reshape(input, target_shape)
    }

    pub fn tensor_view(
        &mut self,
        input: TensorNodeId,
        new_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.view(input, new_shape)
    }

    /// View `input` with the same shape as `other`.
    ///
    /// Equivalent to `torch.Tensor.view_as(other)` — thin wrapper
    /// over `tensor_view` that takes a reference tensor instead of
    /// an explicit shape. Element counts must match (a strict view,
    /// not a broadcast). Tracked under frankentorch-0uc1.
    pub fn tensor_view_as(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let other_shape = self.tensor_shape(other)?;
        self.tensor_view(input, other_shape)
    }

    /// Create a tensor with specified size and stride, reading from input storage.
    /// PyTorch's as_strided creates a view; FrankenTorch materializes a copy.
    pub fn tensor_as_strided(
        &mut self,
        input: TensorNodeId,
        size: Vec<usize>,
        stride: Vec<usize>,
        storage_offset: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if size.len() != stride.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "as_strided: size and stride must have same length",
                },
            )));
        }
        let offset = storage_offset.unwrap_or(0);
        let values = self.tensor_tape.values(input)?;
        let numel: usize = size.iter().product();
        let mut result = Vec::with_capacity(numel);

        fn index_to_offset(idx: usize, size: &[usize], stride: &[usize]) -> usize {
            let mut offset = 0;
            let mut remaining = idx;
            for (i, &dim_size) in size.iter().enumerate().rev() {
                let coord = remaining % dim_size;
                remaining /= dim_size;
                offset += coord * stride[i];
            }
            offset
        }

        for i in 0..numel {
            let src_idx = offset + index_to_offset(i, &size, &stride);
            if src_idx >= values.len() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "as_strided: index out of bounds",
                    },
                )));
            }
            result.push(values[src_idx]);
        }
        self.tensor_variable(result, size, false)
    }

    pub fn tensor_squeeze(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.squeeze(input, dim)
    }

    pub fn tensor_unsqueeze(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.unsqueeze(input, dim)
    }

    pub fn tensor_transpose(
        &mut self,
        input: TensorNodeId,
        dim0: usize,
        dim1: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.transpose(input, dim0, dim1)
    }

    /// Transpose the last two dimensions of `input`.
    ///
    /// Equivalent to `torch.Tensor.mT` and
    /// `torch.transpose(input, -2, -1)`. Works on any input of rank
    /// ≥ 2 — common in batched matmul code where the rank may not
    /// be known at the call site. Composes through autograd-aware
    /// tensor_transpose; gradient flows unchanged.
    /// Tracked under frankentorch-1mcj.
    pub fn tensor_matrix_transpose(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "matrix_transpose: input must have at least 2 dimensions",
                },
            )));
        }
        let last = shape.len() - 1;
        self.tensor_transpose(input, last - 1, last)
    }

    /// Transpose a 0-D, 1-D, or 2-D tensor.
    ///
    /// Equivalent to `torch.t(input)`. For 0-D and 1-D tensors returns
    /// the input unchanged; for 2-D tensors transposes dimensions 0 and
    /// 1. Errors on tensors with more than 2 dimensions.
    pub fn tensor_t(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        match shape.len() {
            0 | 1 => Ok(input),
            2 => self.tensor_transpose(input, 0, 1),
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "t: input must have <= 2 dimensions",
                },
            ))),
        }
    }

    /// Conjugate transpose (Hermitian adjoint) of the last two dimensions.
    ///
    /// Equivalent to `torch.adjoint(input)`. For complex tensors this
    /// performs conjugation and transpose; for real tensors it is
    /// equivalent to `tensor_matrix_transpose`. Requires at least 2D.
    pub fn tensor_adjoint(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let transposed = self.tensor_matrix_transpose(input)?;
        let dtype = self.tensor_dtype(transposed)?;
        if dtype == DType::Complex64 || dtype == DType::Complex128 {
            self.tensor_conj(transposed)
        } else {
            Ok(transposed)
        }
    }

    /// Hermitian transpose; alias for `tensor_adjoint`.
    ///
    /// Equivalent to accessing `.H` on a tensor in PyTorch.
    #[allow(non_snake_case)]
    pub fn tensor_H(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_adjoint(input)
    }

    #[allow(non_snake_case)]
    pub fn tensor_mT(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_matrix_transpose(input)
    }

    #[allow(non_snake_case)]
    pub fn tensor_mH(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_adjoint(input)
    }

    /// 2-D tensor transpose property.
    ///
    /// Equivalent to `tensor.T` in PyTorch. For 2-D tensors, swaps dimensions.
    /// For 0-D and 1-D tensors, returns the input unchanged.
    #[allow(non_snake_case)]
    pub fn tensor_T(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if ndim <= 1 {
            Ok(input)
        } else if ndim == 2 {
            self.tensor_transpose(input, 0, 1)
        } else {
            Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor.T is only valid for tensors with <= 2 dimensions",
                },
            )))
        }
    }

    /// Copy variant of tensor.T.
    ///
    /// Equivalent to `tensor.t_copy()`.
    /// Since ft-api creates copies, this is identical to `tensor_T`.
    #[allow(non_snake_case)]
    pub fn tensor_t_copy(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_T(input)
    }

    /// Swap two dimensions; alias for `tensor_transpose`.
    ///
    /// Equivalent to `torch.swapaxes(input, dim0, dim1)`. PyTorch
    /// keeps both names for numpy compatibility (numpy uses
    /// `swapaxes`). Tracked under frankentorch-1qxf.
    pub fn tensor_swapaxes(
        &mut self,
        input: TensorNodeId,
        dim0: usize,
        dim1: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_transpose(input, dim0, dim1)
    }

    /// Swap two dimensions; alias for `tensor_transpose`.
    ///
    /// Equivalent to `torch.swapdims(input, dim0, dim1)`. PyTorch
    /// keeps swapaxes / swapdims as separate aliases for transpose.
    /// Tracked under frankentorch-1qxf.
    pub fn tensor_swapdims(
        &mut self,
        input: TensorNodeId,
        dim0: usize,
        dim1: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_transpose(input, dim0, dim1)
    }

    pub fn tensor_permute(
        &mut self,
        input: TensorNodeId,
        dims: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.permute(input, dims)
    }

    pub fn tensor_flatten(
        &mut self,
        input: TensorNodeId,
        start_dim: usize,
        end_dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.flatten(input, start_dim, end_dim)
    }

    pub fn tensor_unflatten(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        sizes: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.unflatten(input, dim, sizes)
    }

    /// Flatten a tensor to 1-D.
    ///
    /// Equivalent to `torch.ravel(input)` — returns a 1-D tensor
    /// containing all elements in row-major (C-contiguous) order.
    /// Empty input returns an empty 1-D tensor. Composes through
    /// autograd-aware tensor_flatten over the full rank.
    /// Tracked under frankentorch-icld.
    pub fn tensor_ravel(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            // 0-D scalar → 1-element 1-D tensor.
            return self.tensor_reshape(input, vec![1]);
        }
        let last_dim = shape.len() - 1;
        self.tensor_flatten(input, 0, last_dim)
    }

    /// In-place flatten.
    ///
    /// Equivalent to `tensor.flatten_(start_dim, end_dim)`.
    /// Since ft-api creates new nodes rather than views, this copies the
    /// flattened values back to the target tensor.
    pub fn tensor_flatten_(
        &mut self,
        target: TensorNodeId,
        start_dim: usize,
        end_dim: usize,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let result = self.tensor_flatten(target, start_dim, end_dim)?;
        let result_vals = self.tensor_values(result)?;
        self.update_tensor_values_for_float(target, result_vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "flatten_",
            target,
            Some(format!("start_dim={start_dim}, end_dim={end_dim}")),
        );
        Ok(())
    }

    /// Convert multi-dimensional indices to flat indices.
    ///
    /// Equivalent to `torch.ravel_multi_index(multi_index, dims)`.
    /// Takes a tensor of shape `(ndim, ...)` where each row contains
    /// indices for that dimension, and returns flat indices of shape `(...)`.
    ///
    /// Example: for dims=[2,3], indices [[0,1], [1,2]] -> [1, 5]
    /// i.e., (0,1) -> 0*3+1=1, (1,2) -> 1*3+2=5
    pub fn tensor_ravel_multi_index(
        &mut self,
        multi_index: TensorNodeId,
        dims: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(multi_index)?;
        if shape.is_empty() || shape[0] != dims.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ravel_multi_index: first dim of multi_index must match dims length",
                },
            )));
        }
        let ndim = dims.len();
        let out_shape: Vec<usize> = shape[1..].to_vec();
        let out_size: usize = out_shape.iter().product();

        let strides: Vec<usize> = {
            let mut s = vec![1usize; ndim];
            for i in (0..ndim - 1).rev() {
                s[i] = s[i + 1] * dims[i + 1];
            }
            s
        };

        let strides_clone = strides.clone();
        self.tensor_apply_function(
            &[multi_index],
            move |_ctx, inputs| {
                let (vals, in_shape) = inputs[0];
                let ndim = in_shape[0];
                let n = in_shape[1..].iter().product::<usize>();
                let mut result = vec![0.0_f64; n];
                for i in 0..n {
                    let mut flat_idx = 0usize;
                    for d in 0..ndim {
                        let idx = vals[d * n + i] as usize;
                        flat_idx += idx * strides_clone[d];
                    }
                    result[i] = flat_idx as f64;
                }
                let out = if in_shape.len() == 1 {
                    vec![1]
                } else {
                    in_shape[1..].to_vec()
                };
                Ok((result, out))
            },
            move |_ctx, _grad_outputs| {
                // Index operations have undefined gradients
                let _ = out_size;
                Ok(vec![None])
            },
        )
    }

    /// Convert flat indices to multi-dimensional indices.
    ///
    /// Equivalent to `torch.unravel_index(indices, shape)`.
    /// Takes flat indices and returns a tuple of tensors, one per dimension,
    /// containing the multi-dimensional indices.
    pub fn tensor_unravel_index(
        &mut self,
        indices: TensorNodeId,
        shape: Vec<usize>,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let idx_shape = self.tensor_shape(indices)?;
        let ndim = shape.len();

        let strides: Vec<usize> = {
            let mut s = vec![1usize; ndim];
            for i in (0..ndim - 1).rev() {
                s[i] = s[i + 1] * shape[i + 1];
            }
            s
        };

        let mut result_tensors = Vec::with_capacity(ndim);
        for d in 0..ndim {
            let stride = strides[d];
            let dim_size = shape[d];
            let out_shape = idx_shape.clone();
            self.tensor_apply_function(
                &[indices],
                move |_ctx, inputs| {
                    let (vals, _in_shape) = inputs[0];
                    let result: Vec<f64> = vals
                        .iter()
                        .map(|&v| ((v as usize / stride) % dim_size) as f64)
                        .collect();
                    Ok((result, out_shape.clone()))
                },
                move |_ctx, _grad_outputs| {
                    // Index operations have undefined gradients
                    Ok(vec![None])
                },
            )
            .map(|t| result_tensors.push(t))?;
        }
        Ok(result_tensors)
    }

    /// Remove all size-1 dimensions from `input`.
    ///
    /// Equivalent to `torch.squeeze(input)` (no-dim variant). Removes
    /// every dimension whose size is 1, in any position. Composes
    /// through autograd-aware tensor_reshape with the size-1-stripped
    /// shape. Tracked under frankentorch-icld.
    pub fn tensor_squeeze_all(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let new_shape: Vec<usize> = shape.iter().copied().filter(|&d| d != 1).collect();
        if new_shape == shape {
            // No 1-dims to strip — return unchanged.
            return Ok(input);
        }
        self.tensor_reshape(input, new_shape)
    }

    pub fn tensor_narrow(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        start: usize,
        length: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.narrow(input, dim, start, length)
    }

    /// Equivalent to `torch.narrow_copy`. Returns a contiguous copy of the
    /// narrowed tensor.
    ///
    /// In FrankenTorch, all tensors use value semantics (no aliasing views),
    /// so this is functionally identical to `tensor_narrow`. Provided for
    /// PyTorch API compatibility.
    pub fn tensor_narrow_copy(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        start: usize,
        length: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        // In FrankenTorch tensors are already value-based; narrow doesn't
        // create aliases. contiguous() would be a no-op; just delegate.
        self.tensor_narrow(input, dim, start, length)
    }

    pub fn tensor_expand(
        &mut self,
        input: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_tape.expand(input, target_shape)
    }

    /// Broadcast `input` to `target_shape` with full broadcasting rules.
    ///
    /// Equivalent to `torch.broadcast_to(input, shape)`. Differs from
    /// `tensor_expand` in two ways:
    ///   - accepts a target shape with HIGHER rank than input;
    ///     prepends size-1 dims on the left to match rank.
    ///   - validates broadcast compatibility per dim: each input dim
    ///     must be either 1 or exactly the target dim.
    ///
    /// Composes through autograd-aware tensor_reshape + tensor_expand,
    /// so gradients flow unchanged. Tracked under frankentorch-h2zt.
    pub fn tensor_broadcast_to(
        &mut self,
        input: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        if input_shape.len() > target_shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "broadcast_to: target rank must be >= input rank",
                },
            )));
        }
        let prefix = target_shape.len() - input_shape.len();
        // Validate each input dim is broadcast-compatible with the
        // corresponding (right-aligned) target dim.
        for (i, &in_dim) in input_shape.iter().enumerate() {
            let tgt_dim = target_shape[prefix + i];
            if in_dim != tgt_dim && in_dim != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: input_shape.clone(),
                        rhs: target_shape.clone(),
                    },
                )));
            }
        }
        // Prepend size-1 dims to match target rank, then expand.
        let mut padded_shape = vec![1usize; prefix];
        padded_shape.extend_from_slice(&input_shape);
        let reshaped = if padded_shape == input_shape {
            input
        } else {
            self.tensor_reshape(input, padded_shape)?
        };
        self.tensor_expand(reshaped, target_shape)
    }

    /// Broadcast a list of tensors to a common shape.
    ///
    /// Equivalent to `torch.broadcast_tensors(*tensors)`. Computes
    /// the right-aligned per-dim broadcast of every input shape and
    /// returns each input broadcast to that joint shape via
    /// tensor_broadcast_to. Autograd-aware: the broadcast_to backward
    /// sums gradient over broadcasted dims, so each input's gradient
    /// flows back unaffected by sibling shapes. Tracked under
    /// frankentorch-j0yz.
    pub fn tensor_broadcast_tensors(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        if tensors.is_empty() {
            return Ok(Vec::new());
        }
        let mut joint_shape = self.tensor_shape(tensors[0])?;
        for &t in &tensors[1..] {
            let shape = self.tensor_shape(t)?;
            joint_shape = Self::broadcast_shape(&joint_shape, &shape)?;
        }
        let mut out = Vec::with_capacity(tensors.len());
        for &t in tensors {
            out.push(self.tensor_broadcast_to(t, joint_shape.clone())?);
        }
        Ok(out)
    }

    /// Compute the broadcast shape of multiple tensor shapes.
    ///
    /// Equivalent to `torch.broadcast_shapes(*shapes)`. Returns the shape
    /// that would result from broadcasting tensors of the given shapes together.
    /// Does not create any tensors - pure shape computation.
    pub fn tensor_broadcast_shapes(
        &self,
        tensors: &[TensorNodeId],
    ) -> Result<Vec<usize>, AutogradError> {
        if tensors.is_empty() {
            return Ok(Vec::new());
        }
        let mut joint_shape = self.tensor_shape(tensors[0])?;
        for &t in &tensors[1..] {
            let shape = self.tensor_shape(t)?;
            joint_shape = Self::broadcast_shape(&joint_shape, &shape)?;
        }
        Ok(joint_shape)
    }

    /// Indices of non-zero elements; alias for `tensor_nonzero`.
    ///
    /// Equivalent to `torch.argwhere(input)` — a numpy-compatible
    /// alias for `torch.nonzero(input)` that returns indices as a
    /// `[M, ndim]` 2-D non-grad tensor. Tracked under frankentorch-j0yz.
    pub fn tensor_argwhere(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_nonzero(input)
    }

    /// Broadcast `input` to match `other`'s shape.
    ///
    /// Equivalent to `torch.Tensor.expand_as(other)` — thin wrapper
    /// around `tensor_broadcast_to(input, other.shape)`. Tracked
    /// under frankentorch-h2zt.
    pub fn tensor_expand_as(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let target_shape = self.tensor_shape(other)?;
        self.tensor_broadcast_to(input, target_shape)
    }

    pub fn tensor_split(
        &mut self,
        input: TensorNodeId,
        split_sizes: &[usize],
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_tape.split(input, split_sizes, dim)
    }

    pub fn tensor_chunk(
        &mut self,
        input: TensorNodeId,
        chunks: usize,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_tape.chunk(input, chunks, dim)
    }

    /// `torch.split_with_sizes(input, split_sizes, dim)` parity
    /// alias for `tensor_split`. PyTorch exposes the named
    /// variant of split that mirrors the original argument name.
    /// Tracked under frankentorch-8uxl.
    pub fn tensor_split_with_sizes(
        &mut self,
        input: TensorNodeId,
        split_sizes: &[usize],
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_split(input, split_sizes, dim)
    }

    /// Split tensor into sections, allowing uneven splits.
    ///
    /// Equivalent to `numpy.array_split(ary, indices_or_sections, axis)`.
    /// Unlike tensor_chunk which requires even division, array_split handles
    /// cases where dim_size % sections != 0 by making first (dim_size % sections)
    /// chunks have one extra element.
    pub fn tensor_array_split(
        &mut self,
        input: TensorNodeId,
        sections: usize,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        if sections == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "array_split: sections must be > 0",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }
        let dim_size = shape[dim];
        let base_size = dim_size / sections;
        let remainder = dim_size % sections;
        let mut split_sizes = Vec::with_capacity(sections);
        for i in 0..sections {
            if i < remainder {
                split_sizes.push(base_size + 1);
            } else {
                split_sizes.push(base_size);
            }
        }
        self.tensor_split(input, &split_sizes, dim)
    }

    /// `torch.unsafe_chunk(input, chunks, dim)` parity alias for
    /// `tensor_chunk`. In PyTorch the difference is that
    /// unsafe_chunk skips a runtime autograd safety check; in
    /// ft-api both go through the same tensor_tape path so they
    /// are equivalent. Tracked under frankentorch-8uxl.
    pub fn tensor_unsafe_chunk(
        &mut self,
        input: TensorNodeId,
        chunks: usize,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_chunk(input, chunks, dim)
    }

    pub fn tensor_unbind(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }
        let dim_size = shape[dim];
        let mut results = Vec::with_capacity(dim_size);
        for i in 0..dim_size {
            let narrowed = self.tensor_narrow(input, dim, i, 1)?;
            let squeezed = self.tensor_squeeze(narrowed, dim)?;
            results.push(squeezed);
        }
        Ok(results)
    }

    pub fn tensor_meshgrid(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        if inputs.is_empty() {
            return Ok(Vec::new());
        }
        let mut sizes = Vec::with_capacity(inputs.len());
        for &id in inputs {
            let shape = self.tensor_shape(id)?;
            if shape.len() != 1 {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::ShapeMismatch {
                        lhs: shape,
                        rhs: vec![0],
                    },
                )));
            }
            sizes.push(shape[0]);
        }
        let ndim = sizes.len();
        let mut results = Vec::with_capacity(ndim);
        for (i, &id) in inputs.iter().enumerate() {
            // Reshape to have size 1 in all dims except dim i
            let mut reshape_dims = vec![1; ndim];
            reshape_dims[i] = sizes[i];
            let reshaped = self.tensor_reshape(id, reshape_dims)?;
            // Expand to full grid shape
            let expanded = self.tensor_expand(reshaped, sizes.clone())?;
            results.push(expanded);
        }
        Ok(results)
    }

    /// Generates a normalized 2-D sampling grid from affine transforms.
    pub fn tensor_affine_grid(
        &mut self,
        theta: TensorNodeId,
        output_size: Vec<usize>,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if output_size.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: only 2-D output_size [N, C, H, W] is supported",
                },
            )));
        }

        let theta_tensor = self.tensor_tape.tensor(theta)?;
        let theta_meta = theta_tensor.meta().clone();
        if theta_meta.shape().len() != 3 || theta_meta.shape()[1] != 2 || theta_meta.shape()[2] != 3
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta must have shape [N, 2, 3]",
                },
            )));
        }

        let batch = output_size[0];
        let out_h = output_size[2];
        let out_w = output_size[3];
        if theta_meta.shape()[0] != batch {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta batch must match output_size batch",
                },
            )));
        }

        let output_shape = vec![batch, out_h, out_w, 2];
        let numel =
            Self::checked_shape_numel(&output_shape, "affine_grid output shape volume overflow")?;

        // Autograd path: tensor_apply_function computes in f64 and
        // materializes the output in theta's floating dtype. The
        // forward is linear in theta (each grid cell is
        // t00*x + t01*y + t02 / t10*x + t11*y + t12), so backward is
        // the same accumulator with grad_grid in place of the
        // constant 1. Tracked under frankentorch-bfj5 and extended to
        // F32 under frankentorch-8mrg.
        if self.tensor_tape.tensor_requires_grad(theta)? {
            if !matches!(
                theta_tensor.typed_storage(),
                TensorStorage::F32(_) | TensorStorage::F64(_)
            ) {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "affine_grid: theta must be float32 or float64",
                    },
                )));
            }
            let out_h_c = out_h;
            let out_w_c = out_w;
            let batch_c = batch;
            let output_shape_c = output_shape.clone();
            let align_corners_c = align_corners;
            let out_id = self.tensor_apply_function(
                &[theta],
                move |_ctx, inputs| {
                    let (theta_vals, _shape) = inputs[0];
                    let mut grid = Vec::with_capacity(numel);
                    for n in 0..batch_c {
                        let base = n * 6;
                        let t00 = theta_vals[base];
                        let t01 = theta_vals[base + 1];
                        let t02 = theta_vals[base + 2];
                        let t10 = theta_vals[base + 3];
                        let t11 = theta_vals[base + 4];
                        let t12 = theta_vals[base + 5];
                        for h in 0..out_h_c {
                            let y = Self::affine_grid_axis_coordinate(h, out_h_c, align_corners_c);
                            for w in 0..out_w_c {
                                let x =
                                    Self::affine_grid_axis_coordinate(w, out_w_c, align_corners_c);
                                grid.push(t00 * x + t01 * y + t02);
                                grid.push(t10 * x + t11 * y + t12);
                            }
                        }
                    }
                    Ok((grid, output_shape_c.clone()))
                },
                move |_ctx, grad_outputs| {
                    let grad_grid = grad_outputs[0];
                    // grad_theta has shape [batch, 2, 3], flat layout.
                    let mut grad_theta = vec![0.0_f64; batch_c * 2 * 3];
                    for n in 0..batch_c {
                        let base = n * 6;
                        for h in 0..out_h_c {
                            let y = Self::affine_grid_axis_coordinate(h, out_h_c, align_corners_c);
                            for w in 0..out_w_c {
                                let x =
                                    Self::affine_grid_axis_coordinate(w, out_w_c, align_corners_c);
                                let cell = (n * out_h_c * out_w_c + h * out_w_c + w) * 2;
                                let g0 = grad_grid[cell];
                                let g1 = grad_grid[cell + 1];
                                grad_theta[base] += g0 * x;
                                grad_theta[base + 1] += g0 * y;
                                grad_theta[base + 2] += g0;
                                grad_theta[base + 3] += g1 * x;
                                grad_theta[base + 4] += g1 * y;
                                grad_theta[base + 5] += g1;
                            }
                        }
                    }
                    Ok(vec![Some(grad_theta)])
                },
            )?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!(
                    "affine_grid theta={} out={} align_corners={align_corners} (autograd)",
                    theta.0, out_id.0
                ),
            );
            return Ok(out_id);
        }

        match theta_tensor.typed_storage() {
            TensorStorage::F32(values) => {
                let mut grid = Vec::with_capacity(numel);
                for n in 0..batch {
                    let base = n * 6;
                    let t00 = f64::from(values[base]);
                    let t01 = f64::from(values[base + 1]);
                    let t02 = f64::from(values[base + 2]);
                    let t10 = f64::from(values[base + 3]);
                    let t11 = f64::from(values[base + 4]);
                    let t12 = f64::from(values[base + 5]);
                    for h in 0..out_h {
                        let y = Self::affine_grid_axis_coordinate(h, out_h, align_corners);
                        for w in 0..out_w {
                            let x = Self::affine_grid_axis_coordinate(w, out_w, align_corners);
                            grid.push((t00 * x + t01 * y + t02) as f32);
                            grid.push((t10 * x + t11 * y + t12) as f32);
                        }
                    }
                }
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F32, theta_meta.device()),
                        TensorStorage::F32(Arc::new(grid)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "affine_grid theta={} out={} align_corners={align_corners}",
                        theta.0, out.0
                    ),
                );
                Ok(out)
            }
            TensorStorage::F64(values) => {
                let mut grid = Vec::with_capacity(numel);
                for n in 0..batch {
                    let base = n * 6;
                    let t00 = values[base];
                    let t01 = values[base + 1];
                    let t02 = values[base + 2];
                    let t10 = values[base + 3];
                    let t11 = values[base + 4];
                    let t12 = values[base + 5];
                    for h in 0..out_h {
                        let y = Self::affine_grid_axis_coordinate(h, out_h, align_corners);
                        for w in 0..out_w {
                            let x = Self::affine_grid_axis_coordinate(w, out_w, align_corners);
                            grid.push(t00 * x + t01 * y + t02);
                            grid.push(t10 * x + t11 * y + t12);
                        }
                    }
                }
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F64, theta_meta.device()),
                        TensorStorage::F64(Arc::new(grid)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "affine_grid theta={} out={} align_corners={align_corners}",
                        theta.0, out.0
                    ),
                );
                Ok(out)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "affine_grid: theta must be float32 or float64",
                },
            ))),
        }
    }

    /// Samples a 4-D `NCHW` input using a normalized 2-D grid.
    pub fn tensor_grid_sample(
        &mut self,
        input: TensorNodeId,
        grid: TensorNodeId,
        mode: GridSampleMode,
        padding_mode: GridSamplePaddingMode,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_tensor = self.tensor_tape.tensor(input)?;
        let grid_tensor = self.tensor_tape.tensor(grid)?;
        let input_meta = input_tensor.meta().clone();
        let grid_meta = grid_tensor.meta().clone();

        if input_meta.shape().len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: only 4-D input [N, C, H, W] is supported",
                },
            )));
        }
        if grid_meta.shape().len() != 4 || grid_meta.shape()[3] != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: grid must have shape [N, H, W, 2]",
                },
            )));
        }

        let batch = input_meta.shape()[0];
        let channels = input_meta.shape()[1];
        let in_h = input_meta.shape()[2];
        let in_w = input_meta.shape()[3];
        let out_batch = grid_meta.shape()[0];
        let out_h = grid_meta.shape()[1];
        let out_w = grid_meta.shape()[2];
        if batch != out_batch {
            // Surface both full shapes so the caller can see
            // which batch sizes were given (frankentorch-p947).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: input_meta.shape().to_vec(),
                    rhs: grid_meta.shape().to_vec(),
                },
            )));
        }

        let grid_values = match grid_tensor.typed_storage() {
            TensorStorage::F32(values) => values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>(),
            TensorStorage::F64(values) => values.as_ref().clone(),
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "grid_sample: grid must be float32 or float64",
                    },
                )));
            }
        };

        let output_shape = vec![batch, channels, out_h, out_w];
        let plan = GridSamplePlan {
            batch,
            channels,
            in_h,
            in_w,
            out_h,
            out_w,
            mode,
            padding_mode,
            align_corners,
        };

        let input_requires_grad = self.tensor_tape.tensor_requires_grad(input)?;
        let grid_requires_grad = self.tensor_tape.tensor_requires_grad(grid)?;
        if input_requires_grad || grid_requires_grad {
            let matching_float_dtype = matches!(
                (input_tensor.typed_storage(), grid_tensor.typed_storage()),
                (TensorStorage::F32(_), TensorStorage::F32(_))
                    | (TensorStorage::F64(_), TensorStorage::F64(_))
            );
            if !matching_float_dtype {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "grid_sample: autograd requires matching f32 or f64 input and grid tensors",
                    },
                )));
            }

            let plan_c = plan;
            let output_shape_c = output_shape.clone();
            let out = self.tensor_apply_function(
                &[input, grid],
                move |ctx, inputs| {
                    let (input_values, input_shape) = inputs[0];
                    let (grid_values, grid_shape) = inputs[1];
                    let output = Self::grid_sample_f64(input_values, grid_values, plan_c);
                    ctx.save_for_backward(input_values.to_vec(), input_shape.to_vec());
                    ctx.save_for_backward(grid_values.to_vec(), grid_shape.to_vec());
                    Ok((output, output_shape_c.clone()))
                },
                move |ctx, grad_outputs| {
                    let saved = ctx.saved_tensors();
                    let input_values = &saved[0];
                    let grid_values = &saved[1];
                    let (grad_input, grad_grid) = match plan_c.mode {
                        GridSampleMode::Bilinear => Self::grid_sample_bilinear_backward_f64(
                            input_values,
                            grid_values,
                            grad_outputs[0],
                            plan_c,
                        )?,
                        GridSampleMode::Nearest => Self::grid_sample_nearest_backward_f64(
                            input_values,
                            grid_values,
                            grad_outputs[0],
                            plan_c,
                        )?,
                    };
                    Ok(vec![Some(grad_input), Some(grad_grid)])
                },
            )?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!(
                    "grid_sample input={} grid={} out={} mode={mode:?} padding={padding_mode:?} align_corners={align_corners} (autograd)",
                    input.0, grid.0, out.0
                ),
            );
            return Ok(out);
        }

        match input_tensor.typed_storage() {
            TensorStorage::F32(values) => {
                let input_values = values.iter().map(|&v| f64::from(v)).collect::<Vec<_>>();
                let output = Self::grid_sample_f64(&input_values, &grid_values, plan);
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F32, input_meta.device()),
                        TensorStorage::F32(Arc::new(
                            output.into_iter().map(|v| v as f32).collect(),
                        )),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "grid_sample input={} grid={} out={} mode={mode:?} padding={padding_mode:?} align_corners={align_corners}",
                        input.0, grid.0, out.0
                    ),
                );
                Ok(out)
            }
            TensorStorage::F64(values) => {
                let output = Self::grid_sample_f64(values.as_ref(), &grid_values, plan);
                let out = self.tensor_tape.leaf_tensor(
                    DenseTensor::from_typed_storage(
                        TensorMeta::from_shape(output_shape, DType::F64, input_meta.device()),
                        TensorStorage::F64(Arc::new(output)),
                    )?,
                    false,
                );
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "grid_sample input={} grid={} out={} mode={mode:?} padding={padding_mode:?} align_corners={align_corners}",
                        input.0, grid.0, out.0
                    ),
                );
                Ok(out)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "grid_sample: input must be float32 or float64",
                },
            ))),
        }
    }

    pub fn tensor_diagonal(
        &mut self,
        input: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let dtype = self.tensor_dtype(input)?;
        if !matches!(dtype, DType::F64 | DType::F32) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_diagonal requires f32 or f64 tensors",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];
        let (row_start, col_start, diag_len) = if offset >= 0 {
            let col_start = offset as usize;
            if col_start >= n {
                return match dtype {
                    DType::F64 => self.tensor_variable(vec![], vec![0], false),
                    DType::F32 => self.tensor_variable_f32(vec![], vec![0], false),
                    _ => unreachable!("dtype checked above"),
                };
            }
            let diag_len = m.min(n - col_start);
            (0, col_start, diag_len)
        } else {
            let row_start = (-offset) as usize;
            if row_start >= m {
                return match dtype {
                    DType::F64 => self.tensor_variable(vec![], vec![0], false),
                    DType::F32 => self.tensor_variable_f32(vec![], vec![0], false),
                    _ => unreachable!("dtype checked above"),
                };
            }
            let diag_len = n.min(m - row_start);
            (row_start, 0, diag_len)
        };
        // Extract diagonal elements by gathering flat indices. This
        // composes through reshape + index_select, so dtype and
        // autograd behavior are inherited from the shared tensor tape
        // path for both F64 and F32.
        let flat_len = Self::checked_mul(m, n, "tensor_diagonal input shape overflow")?;
        let flat = self.tensor_reshape(input, vec![flat_len])?;
        let indices: Vec<f64> = (0..diag_len)
            .map(|i| ((row_start + i) * n + col_start + i) as f64)
            .collect();
        let index_node = self.tensor_variable(indices, vec![diag_len], false)?;
        self.tensor_index_select(flat, 0, index_node)
    }

    /// Copy variant of diagonal.
    ///
    /// Equivalent to `tensor.diagonal_copy(offset)`.
    /// Since ft-api creates copies, this is identical to `tensor_diagonal`.
    pub fn tensor_diagonal_copy(
        &mut self,
        input: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_diagonal(input, offset)
    }

    /// Embed values from src into the diagonal of input.
    ///
    /// Equivalent to `torch.diagonal_scatter(input, src, offset)`.
    /// Returns a copy of input with the diagonal replaced by src values.
    /// Tracked under frankentorch-ac92.
    pub fn tensor_diagonal_scatter(
        &mut self,
        input: TensorNodeId,
        src: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "diagonal_scatter: input must be 2-D",
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];

        let (row_start, col_start, diag_len) = if offset >= 0 {
            let col_start = offset as usize;
            if col_start >= n {
                return Ok(input);
            }
            let diag_len = m.min(n - col_start);
            (0, col_start, diag_len)
        } else {
            let row_start = (-offset) as usize;
            if row_start >= m {
                return Ok(input);
            }
            let diag_len = n.min(m - row_start);
            (row_start, 0, diag_len)
        };

        let src_vals = self.tensor_values(src)?;
        if src_vals.len() != diag_len {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "diagonal_scatter: src length must match diagonal length",
                },
            )));
        }

        let mut result = self.tensor_values(input)?;
        for (i, &value) in src_vals.iter().enumerate() {
            let idx = (row_start + i) * n + col_start + i;
            result[idx] = value;
        }

        self.tensor_variable(result, shape, false)
    }

    /// Extract lower triangular part of a 2D matrix.
    ///
    /// Equivalent to `torch.tril(input, diagonal)`.
    /// Elements above the k-th diagonal are zeroed.
    /// Tracked under frankentorch-avfl.
    pub fn tensor_tril(
        &mut self,
        input: TensorNodeId,
        diagonal: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tril: input must be a 2-D tensor",
                },
            )));
        }

        let (m, n) = (shape[0], shape[1]);
        let vals = self.tensor_values(input)?;
        let mut result = vec![0.0; m * n];
        for i in 0..m {
            for j in 0..n {
                if (j as i64) <= (i as i64) + diagonal {
                    result[i * n + j] = vals[i * n + j];
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// Extract upper triangular part of a 2D matrix.
    ///
    /// Equivalent to `torch.triu(input, diagonal)`.
    /// Elements below the k-th diagonal are zeroed.
    /// Tracked under frankentorch-avfl.
    pub fn tensor_triu(
        &mut self,
        input: TensorNodeId,
        diagonal: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triu: input must be a 2-D tensor",
                },
            )));
        }

        let (m, n) = (shape[0], shape[1]);
        let vals = self.tensor_values(input)?;
        let mut result = vec![0.0; m * n];
        for i in 0..m {
            for j in 0..n {
                if (j as i64) >= (i as i64) + diagonal {
                    result[i * n + j] = vals[i * n + j];
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// In-place lower triangular: zero elements above the k-th diagonal.
    pub fn tensor_tril_(
        &mut self,
        target: TensorNodeId,
        diagonal: i64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let shape = self.tensor_shape(target)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tril_: input must be a 2-D tensor",
                },
            )));
        }
        let (m, n) = (shape[0], shape[1]);
        let mut vals = self.tensor_values(target)?;
        for i in 0..m {
            for j in 0..n {
                if (j as i64) > (i as i64) + diagonal {
                    vals[i * n + j] = 0.0;
                }
            }
        }
        self.update_tensor_values_for_float(target, vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "tril_",
            target,
            Some(format!("diagonal={diagonal}")),
        );
        Ok(())
    }

    /// In-place upper triangular: zero elements below the k-th diagonal.
    pub fn tensor_triu_(
        &mut self,
        target: TensorNodeId,
        diagonal: i64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let shape = self.tensor_shape(target)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triu_: input must be a 2-D tensor",
                },
            )));
        }
        let (m, n) = (shape[0], shape[1]);
        let mut vals = self.tensor_values(target)?;
        for i in 0..m {
            for j in 0..n {
                if (j as i64) < (i as i64) + diagonal {
                    vals[i * n + j] = 0.0;
                }
            }
        }
        self.update_tensor_values_for_float(target, vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "triu_",
            target,
            Some(format!("diagonal={diagonal}")),
        );
        Ok(())
    }

    /// Embed src tensor at a selected index along a dimension.
    ///
    /// Equivalent to `torch.select_scatter(input, src, dim, index)`.
    /// Tracked under frankentorch-ksqe.
    pub fn tensor_select_scatter(
        &mut self,
        input: TensorNodeId,
        src: TensorNodeId,
        dim: i64,
        index: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if ndim == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select_scatter: input must have at least 1 dimension",
                },
            )));
        }

        let dim = if dim < 0 { ndim as i64 + dim } else { dim } as usize;
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select_scatter: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim];
        let index = if index < 0 {
            dim_size as i64 + index
        } else {
            index
        } as usize;
        if index >= dim_size {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select_scatter: index out of range",
                },
            )));
        }

        let src_shape = self.tensor_shape(src)?;
        let expected_src_shape: Vec<usize> = shape
            .iter()
            .enumerate()
            .filter(|&(i, _)| i != dim)
            .map(|(_, &s)| s)
            .collect();
        if src_shape != expected_src_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select_scatter: src shape must match input shape with dim removed",
                },
            )));
        }

        let mut result = self.tensor_values(input)?;
        let src_vals = self.tensor_values(src)?;

        let stride: usize = shape[dim + 1..].iter().product();
        let outer_stride: usize = shape[dim..].iter().product();

        for (src_idx, &val) in src_vals.iter().enumerate() {
            let outer = src_idx / stride;
            let inner = src_idx % stride;
            let dst_idx = outer * outer_stride + index * stride + inner;
            result[dst_idx] = val;
        }

        self.tensor_variable(result, shape, false)
    }

    /// Embed src tensor into a slice of input along a dimension.
    ///
    /// Equivalent to `torch.slice_scatter(input, src, dim, start, end, step)`.
    /// Tracked under frankentorch-eikp.
    pub fn tensor_slice_scatter(
        &mut self,
        input: TensorNodeId,
        src: TensorNodeId,
        dim: i64,
        start: Option<i64>,
        end: Option<i64>,
        step: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        if step <= 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "slice_scatter: step must be positive",
                },
            )));
        }

        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if ndim == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "slice_scatter: input must have at least 1 dimension",
                },
            )));
        }

        let dim = if dim < 0 { ndim as i64 + dim } else { dim } as usize;
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "slice_scatter: dim out of range",
                },
            )));
        }

        let dim_size = shape[dim] as i64;
        let start = start
            .map(|s| if s < 0 { dim_size + s } else { s })
            .unwrap_or(0)
            .max(0)
            .min(dim_size) as usize;
        let end = end
            .map(|e| if e < 0 { dim_size + e } else { e })
            .unwrap_or(dim_size)
            .max(0)
            .min(dim_size) as usize;
        let step = step as usize;

        let slice_len = if end > start {
            (end - start).div_ceil(step)
        } else {
            0
        };

        let src_shape = self.tensor_shape(src)?;
        let mut expected_shape = shape.clone();
        expected_shape[dim] = slice_len;
        if src_shape != expected_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "slice_scatter: src shape must match slice shape",
                },
            )));
        }

        let mut result = self.tensor_values(input)?;
        let src_vals = self.tensor_values(src)?;

        let inner_stride: usize = shape[dim + 1..].iter().product();
        let outer_stride: usize = shape[dim..].iter().product();
        let outer_count: usize = shape[..dim].iter().product();

        for outer in 0..outer_count {
            for (slice_idx, dim_idx) in (start..end).step_by(step).enumerate() {
                for inner in 0..inner_stride {
                    let src_idx =
                        outer * (slice_len * inner_stride) + slice_idx * inner_stride + inner;
                    let dst_idx = outer * outer_stride + dim_idx * inner_stride + inner;
                    result[dst_idx] = src_vals[src_idx];
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    /// Reduce source into input at indices using specified reduce operation.
    ///
    /// Equivalent to `torch.index_reduce(input, dim, index, source, reduce)`.
    /// Reduce modes: "prod", "mean", "amax", "amin".
    /// Tracked under frankentorch-p78l.
    pub fn tensor_index_reduce(
        &mut self,
        input: TensorNodeId,
        dim: i64,
        index: TensorNodeId,
        source: TensorNodeId,
        reduce: &str,
        include_self: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if ndim == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_reduce: input must have at least 1 dimension",
                },
            )));
        }

        let dim = if dim < 0 { ndim as i64 + dim } else { dim } as usize;
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_reduce: dim out of range",
                },
            )));
        }

        let index_shape = self.tensor_shape(index)?;
        if index_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_reduce: index must be 1D",
                },
            )));
        }

        let src_shape = self.tensor_shape(source)?;
        if src_shape.len() != ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_reduce: source rank must match input rank",
                },
            )));
        }
        if src_shape[dim] != index_shape[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "index_reduce: source dim size must match index length",
                },
            )));
        }

        let dim_size = shape[dim];
        let idx_vals = self.tensor_values(index)?;
        let src_vals = self.tensor_values(source)?;
        let input_vals = self.tensor_values(input)?;

        let inner_stride: usize = shape[dim + 1..].iter().product();
        let outer_stride: usize = shape[dim..].iter().product();
        let outer_count: usize = shape[..dim].iter().product();
        let src_outer_stride: usize = src_shape[dim..].iter().product();

        let mut result = if include_self {
            input_vals.clone()
        } else {
            match reduce {
                "prod" => vec![1.0; input_vals.len()],
                "mean" | "amax" => vec![f64::NEG_INFINITY; input_vals.len()],
                "amin" => vec![f64::INFINITY; input_vals.len()],
                _ => {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_reduce: reduce must be prod, mean, amax, or amin",
                        },
                    )));
                }
            }
        };

        let mut counts: Vec<usize> = vec![0; input_vals.len()];

        for outer in 0..outer_count {
            for (src_dim_idx, &idx_f) in idx_vals.iter().enumerate() {
                let dst_dim_idx = idx_f as usize;
                if dst_dim_idx >= dim_size {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "index_reduce: index out of bounds",
                        },
                    )));
                }
                for inner in 0..inner_stride {
                    let src_idx = outer * src_outer_stride + src_dim_idx * inner_stride + inner;
                    let dst_idx = outer * outer_stride + dst_dim_idx * inner_stride + inner;
                    let src_val = src_vals[src_idx];
                    match reduce {
                        "prod" => result[dst_idx] *= src_val,
                        "mean" => {
                            if counts[dst_idx] == 0 && !include_self {
                                result[dst_idx] = src_val;
                            } else {
                                result[dst_idx] += src_val;
                            }
                            counts[dst_idx] += 1;
                        }
                        "amax" => result[dst_idx] = result[dst_idx].max(src_val),
                        "amin" => result[dst_idx] = result[dst_idx].min(src_val),
                        _ => unreachable!(),
                    }
                }
            }
        }

        if reduce == "mean" {
            for (i, &count) in counts.iter().enumerate() {
                if count > 0 {
                    let total = if include_self { count + 1 } else { count };
                    result[i] /= total as f64;
                }
            }
        }

        self.tensor_variable(result, shape, false)
    }

    pub fn tensor_values(&self, node: TensorNodeId) -> Result<Vec<f64>, AutogradError> {
        self.tensor_tape.values(node)
    }

    /// Return both the contiguous values and metadata for a tensor node.
    pub fn tensor_values_meta(
        &self,
        node: TensorNodeId,
    ) -> Result<(Vec<f64>, TensorMeta), AutogradError> {
        let values = self.tensor_tape.values(node)?;
        let meta = self.tensor_tape.tensor_meta(node)?.clone();
        Ok((values, meta))
    }

    /// In-place subtraction: target = target - other.
    pub fn tensor_sub_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_binary_compatibility(target, other)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let other_vals = self.tensor_tape.values(other)?;
                let new_values: Vec<f64> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a - b)
                    .collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let other_vals = self.tensor_tape.values_f32(other)?;
                let new_values: Vec<f32> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a - b)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation("sub_", target, Some(format!("other={}", other.0)));
        Ok(())
    }

    /// In-place addition: target = target + other.
    pub fn tensor_add_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_binary_compatibility(target, other)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let other_vals = self.tensor_tape.values(other)?;
                let new_values: Vec<f64> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a + b)
                    .collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let other_vals = self.tensor_tape.values_f32(other)?;
                let new_values: Vec<f32> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a + b)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation("add_", target, Some(format!("other={}", other.0)));
        Ok(())
    }

    /// In-place multiplication: target = target * other.
    pub fn tensor_mul_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_binary_compatibility(target, other)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let other_vals = self.tensor_tape.values(other)?;
                let new_values: Vec<f64> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a * b)
                    .collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let other_vals = self.tensor_tape.values_f32(other)?;
                let new_values: Vec<f32> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a * b)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation("mul_", target, Some(format!("other={}", other.0)));
        Ok(())
    }

    /// In-place division: target = target / other.
    pub fn tensor_div_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_binary_compatibility(target, other)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let other_vals = self.tensor_tape.values(other)?;
                let new_values: Vec<f64> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a / b)
                    .collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let other_vals = self.tensor_tape.values_f32(other)?;
                let new_values: Vec<f32> = target_vals
                    .iter()
                    .zip(other_vals.iter())
                    .map(|(a, b)| a / b)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation("div_", target, Some(format!("other={}", other.0)));
        Ok(())
    }

    /// In-place zero: target = zeros.
    pub fn tensor_zero_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let numel = self.tensor_numel(target)?;
        self.update_tensor_values_for_float(target, vec![0.0; numel], INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("zero_", target, None);
        Ok(())
    }

    /// In-place ones: target = ones.
    pub fn tensor_ones_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let numel = self.tensor_numel(target)?;
        self.update_tensor_values_for_float(target, vec![1.0; numel], INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("ones_", target, None);
        Ok(())
    }

    /// In-place Bernoulli: fill with 0 or 1 based on probability p.
    pub fn tensor_bernoulli_(&mut self, target: TensorNodeId, p: f64) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let numel = self.tensor_numel(target)?;
        let values: Vec<f64> = (0..numel)
            .map(|_| if self.rng.next_f64() < p { 1.0 } else { 0.0 })
            .collect();
        self.update_tensor_values_for_float(target, values, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("bernoulli_", target, Some(format!("p={p}")));
        Ok(())
    }

    /// Sample from Bernoulli distribution with element-wise probabilities.
    ///
    /// Equivalent to `torch.bernoulli(prob)`. Each output element is 1 with
    /// probability prob[i], 0 otherwise. Returns a new tensor with same shape.
    pub fn tensor_bernoulli(
        &mut self,
        prob: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(prob)?;
        let prob_vals = self.tensor_values(prob)?;
        let values: Vec<f64> = prob_vals
            .iter()
            .map(|&p| if self.rng.next_f64() < p { 1.0 } else { 0.0 })
            .collect();
        self.tensor_variable(values, shape, false)
    }

    /// In-place random: fill with uniform integers from [from, to).
    pub fn tensor_random_(
        &mut self,
        target: TensorNodeId,
        from: i64,
        to: i64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let numel = self.tensor_numel(target)?;
        let range = (to - from) as f64;
        let values: Vec<f64> = (0..numel)
            .map(|_| from as f64 + (self.rng.next_f64() * range).floor())
            .collect();
        self.update_tensor_values_for_float(target, values, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "random_",
            target,
            Some(format!("from={from} to={to}")),
        );
        Ok(())
    }

    /// In-place randint: fill with random integers in [low, high).
    pub fn tensor_randint_(
        &mut self,
        target: TensorNodeId,
        low: i64,
        high: i64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        if low >= high {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "randint_: low must be less than high",
                },
            )));
        }
        let numel = self.tensor_numel(target)?;
        let range = (high - low) as f64;
        let values: Vec<f64> = (0..numel)
            .map(|_| low as f64 + (self.rng.next_f64() * range).floor())
            .collect();
        self.update_tensor_values_for_float(target, values, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "randint_",
            target,
            Some(format!("low={low} high={high}")),
        );
        Ok(())
    }

    /// In-place fill: target = fill_value.
    pub fn tensor_fill_(
        &mut self,
        target: TensorNodeId,
        fill_value: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let numel = self.tensor_numel(target)?;
        self.update_tensor_values_for_float(target, vec![fill_value; numel], INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "fill_",
            target,
            Some(format!("fill_value={fill_value}")),
        );
        Ok(())
    }

    pub fn tensor_copy_(
        &mut self,
        target: TensorNodeId,
        source: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_shape = self.tensor_shape(target)?;
        let source_shape = self.tensor_shape(source)?;
        if target_shape != source_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: target_shape,
                    rhs: source_shape,
                },
            )));
        }
        let source_vals = self.tensor_values(source)?;
        self.update_tensor_values_for_float(target, source_vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("copy_", target, None);
        Ok(())
    }

    /// Check if tensor can be resized to match another tensor's shape.
    ///
    /// Equivalent to `torch.Tensor.resize_as_(other)`. In FrankenTorch,
    /// true in-place resize of the underlying storage is not supported.
    /// Resize tensor in-place to specified shape.
    /// FrankenTorch doesn't support true in-place resize; this validates shape matches
    /// (no-op) or returns an error. For shape changes, create a new tensor.
    pub fn tensor_resize_(
        &mut self,
        target: TensorNodeId,
        size: Vec<usize>,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_shape = self.tensor_shape(target)?;
        if target_shape == size {
            self.record_tensor_in_place_operation("resize_", target, None);
            return Ok(());
        }
        Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
            ft_dispatch::DispatchKeyError::IncompatibleSet {
                reason: "resize_: in-place resize not supported; create new tensor with desired shape",
            },
        )))
    }

    /// This function validates shapes match (no-op) or returns an error.
    ///
    /// For actual shape changes, create a new tensor with the desired
    /// shape and copy values as needed.
    pub fn tensor_resize_as_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let other_shape = self.tensor_shape(other)?;
        let target_shape = self.tensor_shape(target)?;
        if target_shape == other_shape {
            self.record_tensor_in_place_operation("resize_as_", target, None);
            return Ok(());
        }
        Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
            ft_dispatch::DispatchKeyError::IncompatibleSet {
                reason: "resize_as_: in-place resize not supported; create new tensor with desired shape",
            },
        )))
    }

    pub fn tensor_fill_diagonal_(
        &mut self,
        target: TensorNodeId,
        fill_value: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let shape = self.tensor_shape(target)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fill_diagonal_: input must be 2D",
                },
            )));
        }
        let (rows, cols) = (shape[0], shape[1]);
        let diag_len = rows.min(cols);
        let mut values = self.tensor_values(target)?;
        for i in 0..diag_len {
            values[i * cols + i] = fill_value;
        }
        self.update_tensor_values_for_float(target, values, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "fill_diagonal_",
            target,
            Some(format!("fill_value={fill_value}")),
        );
        Ok(())
    }

    /// In-place scalar multiplication: target = target * scalar.
    pub fn tensor_mul_scalar_(
        &mut self,
        target: TensorNodeId,
        scalar: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let new_values: Vec<f64> = target_vals.iter().map(|v| v * scalar).collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let scalar32 = scalar as f32;
                let new_values: Vec<f32> = target_vals.iter().map(|v| v * scalar32).collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation(
            "mul_scalar_",
            target,
            Some(format!("scalar={scalar}")),
        );
        Ok(())
    }

    /// In-place scalar addition: target = target + scalar.
    pub fn tensor_add_scalar_(
        &mut self,
        target: TensorNodeId,
        scalar: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let new_values: Vec<f64> = target_vals.iter().map(|v| v + scalar).collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let scalar32 = scalar as f32;
                let new_values: Vec<f32> = target_vals.iter().map(|v| v + scalar32).collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation(
            "add_scalar_",
            target,
            Some(format!("scalar={scalar}")),
        );
        Ok(())
    }

