    /// In-place nan_to_num: replace NaN with nan, +inf with posinf, -inf with neginf.
    pub fn tensor_nan_to_num_(
        &mut self,
        target: TensorNodeId,
        nan: f64,
        posinf: Option<f64>,
        neginf: Option<f64>,
    ) -> Result<(), AutogradError> {
        let meta = self.tensor_tape.tensor_meta(target)?.clone();
        let (default_posinf, default_neginf) = if meta.dtype() == DType::F32 {
            (f64::from(f32::MAX), f64::from(f32::MIN))
        } else {
            (f64::MAX, f64::MIN)
        };
        let posinf_val = posinf.unwrap_or(default_posinf);
        let neginf_val = neginf.unwrap_or(default_neginf);
        self.apply_tensor_unary_in_place(
            "nan_to_num_",
            target,
            Some(format!("nan={nan} posinf={posinf_val} neginf={neginf_val}")),
            |x| {
                if x.is_nan() {
                    nan
                } else if x == f64::INFINITY {
                    posinf_val
                } else if x == f64::NEG_INFINITY {
                    neginf_val
                } else {
                    x
                }
            },
        )
    }

    /// In-place softshrink: x - lambd if x > lambd, x + lambd if x < -lambd, else 0.
    ///
    /// Equivalent to `F.softshrink(tensor, lambd)` in PyTorch (no native in-place).
    pub fn tensor_softshrink_(
        &mut self,
        target: TensorNodeId,
        lambd: f64,
    ) -> Result<(), AutogradError> {
        self.apply_tensor_unary_in_place(
            "softshrink_",
            target,
            Some(format!("lambd={lambd}")),
            |x| {
                if x > lambd {
                    x - lambd
                } else if x < -lambd {
                    x + lambd
                } else {
                    0.0
                }
            },
        )
    }

    /// In-place hardshrink: x if |x| > lambd, else 0.
    ///
    /// Equivalent to `F.hardshrink(tensor, lambd)` in PyTorch (no native in-place).
    pub fn tensor_hardshrink_(
        &mut self,
        target: TensorNodeId,
        lambd: f64,
    ) -> Result<(), AutogradError> {
        self.apply_tensor_unary_in_place(
            "hardshrink_",
            target,
            Some(format!("lambd={lambd}")),
            |x| {
                if x.abs() > lambd { x } else { 0.0 }
            },
        )
    }

    /// In-place tanhshrink: x - tanh(x).
    ///
    /// Equivalent to `F.tanhshrink(tensor)` in PyTorch (no native in-place).
    pub fn tensor_tanhshrink_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.apply_tensor_unary_in_place("tanhshrink_", target, None, |x| x - x.tanh())
    }

    /// In-place softsign: x / (1 + |x|).
    pub fn tensor_softsign_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.apply_tensor_unary_in_place("softsign_", target, None, |x| x / (1.0 + x.abs()))
    }

    /// In-place logsigmoid: log(sigmoid(x)) = -softplus(-x).
    pub fn tensor_logsigmoid_(&mut self, target: TensorNodeId) -> Result<(), AutogradError> {
        self.apply_tensor_unary_in_place("logsigmoid_", target, None, |x| {
            if x > 0.0 {
                -(-x).ln_1p()
            } else {
                x - (1.0 + x.exp()).ln()
            }
        })
    }

    pub fn tensor_clamp_(
        &mut self,
        target: TensorNodeId,
        min_val: f64,
        max_val: f64,
    ) -> Result<(), AutogradError> {
        if min_val > max_val {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "tensor_clamp_ requires min_val <= max_val",
                },
            )));
        }
        self.apply_tensor_unary_in_place(
            "clamp_",
            target,
            Some(format!("min={min_val} max={max_val}")),
            |v| v.clamp(min_val, max_val),
        )
    }

    pub fn tensor_clamp_min_(
        &mut self,
        target: TensorNodeId,
        min_val: f64,
    ) -> Result<(), AutogradError> {
        self.tensor_clamp_(target, min_val, f64::INFINITY)
    }

    pub fn tensor_clamp_max_(
        &mut self,
        target: TensorNodeId,
        max_val: f64,
    ) -> Result<(), AutogradError> {
        self.tensor_clamp_(target, f64::NEG_INFINITY, max_val)
    }

    /// Alias for tensor_clamp_min_. Equivalent to `tensor.clip_(min=min_val)`.
    pub fn tensor_clip_min_(
        &mut self,
        target: TensorNodeId,
        min_val: f64,
    ) -> Result<(), AutogradError> {
        self.tensor_clamp_min_(target, min_val)
    }

    /// Alias for tensor_clamp_max_. Equivalent to `tensor.clip_(max=max_val)`.
    pub fn tensor_clip_max_(
        &mut self,
        target: TensorNodeId,
        max_val: f64,
    ) -> Result<(), AutogradError> {
        self.tensor_clamp_max_(target, max_val)
    }

    /// In-place masked fill: fills target tensor at positions where mask is non-zero.
    pub fn tensor_masked_fill_(
        &mut self,
        target: TensorNodeId,
        mask: TensorNodeId,
        value: f64,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let mask_vals = self.tensor_values(mask)?;
        if target_vals.len() != mask_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(mask)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(mask_vals.iter())
            .map(|(&t, &m)| if m != 0.0 { value } else { t })
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "masked_fill_",
            target,
            Some(format!("value={value}")),
        );
        Ok(())
    }

    /// In-place where: where condition is non-zero, take from `other`, else keep original.
    pub fn tensor_where_(
        &mut self,
        target: TensorNodeId,
        condition: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let cond_vals = self.tensor_values(condition)?;
        let other_vals = self.tensor_values(other)?;
        if target_vals.len() != cond_vals.len() || target_vals.len() != other_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(condition)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(cond_vals.iter())
            .zip(other_vals.iter())
            .map(|((&t, &c), &o)| if c != 0.0 { o } else { t })
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("where_", target, None);
        Ok(())
    }

