    pub fn backward(&mut self, root: NodeId) -> Result<BackwardReport, AutogradError> {
        let options = BackwardOptions::for_mode(self.mode());
        self.backward_with_options(root, options)
    }

    pub fn backward_with_options(
        &mut self,
        root: NodeId,
        options: BackwardOptions,
    ) -> Result<BackwardReport, AutogradError> {
        let report = self.tape.backward_with_options(root, options)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Backward,
            format!(
                "root={} backward_steps={} queue_pushes={} queue_pops={} max_queue_len={} reentrant_guard={}",
                root.0,
                report.steps.len(),
                report.telemetry.queue_pushes,
                report.telemetry.queue_pops,
                report.telemetry.max_queue_len,
                report.telemetry.reentrant_guard_triggered
            ),
        );
        Ok(report)
    }

    pub fn tensor_backward(
        &mut self,
        root: TensorNodeId,
    ) -> Result<TensorBackwardReport, AutogradError> {
        let options = BackwardOptions::for_mode(self.mode());
        self.tensor_backward_with_options(root, options)
    }

    pub fn tensor_backward_with_options(
        &mut self,
        root: TensorNodeId,
        options: BackwardOptions,
    ) -> Result<TensorBackwardReport, AutogradError> {
        let report = self.tensor_tape.backward_with_options(root, options)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Backward,
            format!(
                "tensor_root={} backward_steps={} queue_pushes={} queue_pops={} max_queue_len={} reentrant_guard={}",
                root.0,
                report.steps.len(),
                report.telemetry.queue_pushes,
                report.telemetry.queue_pops,
                report.telemetry.max_queue_len,
                report.telemetry.reentrant_guard_triggered
            ),
        );
        Ok(report)
    }

    #[must_use]
    pub fn gradient(&self, report: &BackwardReport, node: NodeId) -> Option<f64> {
        report.gradient(node)
    }

    #[must_use]
    pub fn tensor_gradient<'a>(
        &self,
        report: &'a TensorBackwardReport,
        node: TensorNodeId,
    ) -> Option<&'a [f64]> {
        report.gradient(node)
    }

    pub fn tensor_accumulated_gradient(
        &self,
        node: TensorNodeId,
    ) -> Result<Option<Vec<f64>>, AutogradError> {
        self.tensor_tape.tensor_accumulated_gradient_values(node)
    }

    pub fn tensor_grad(&self, node: TensorNodeId) -> Result<Option<Vec<f64>>, AutogradError> {
        self.tensor_accumulated_gradient(node)
    }

    pub fn tensor_zero_grad(&mut self, node: TensorNodeId) -> Result<(), AutogradError> {
        self.tensor_tape.zero_tensor_accumulated_gradient(node)
    }

    pub fn tensor_zero_grads(&mut self, nodes: &[TensorNodeId]) -> Result<(), AutogradError> {
        for node in nodes {
            self.tensor_tape.zero_tensor_accumulated_gradient(*node)?;
        }
        Ok(())
    }

    pub fn tensor_set_accumulated_gradient(
        &mut self,
        node: TensorNodeId,
        gradient: Vec<f64>,
    ) -> Result<(), AutogradError> {
        self.tensor_tape
            .set_tensor_accumulated_gradient(node, gradient)
    }

    /// Update a parameter's values directly, bypassing the leaf-grad in-place guard.
    ///
    /// This is the correct way for optimizers to update parameter values.
    /// In PyTorch, `param.data -= update` also bypasses the autograd guard.
    pub fn tensor_update_param_values(
        &mut self,
        param: TensorNodeId,
        new_values: Vec<f64>,
    ) -> Result<(), AutogradError> {
        self.update_tensor_values_for_float(param, new_values, PARAM_UPDATE_FLOAT_REASON)
    }

    // ── Gradient Clipping Utilities ────────────────────────────────────

    /// Clip the total gradient norm of a set of parameters.
    ///
    /// Equivalent to `torch.nn.utils.clip_grad_norm_(parameters, max_norm, norm_type)`.
    /// Scales all gradients so that the total norm does not exceed `max_norm`.
    /// Returns the total norm before clipping.
    pub fn clip_grad_norm_(
        &mut self,
        params: &[TensorNodeId],
        max_norm: f64,
        norm_type: f64,
    ) -> Result<f64, AutogradError> {
        // Compute total norm across all parameter gradients
        let mut total_norm = 0.0_f64;

        if norm_type == f64::INFINITY {
            // Max norm: find the largest absolute gradient value
            for &p in params {
                if let Some(grad) = self.tensor_accumulated_gradient(p)? {
                    for &g in &grad {
                        let abs_g = g.abs();
                        if abs_g > total_norm {
                            total_norm = abs_g;
                        }
                    }
                }
            }
        } else {
            // Lp norm
            for &p in params {
                if let Some(grad) = self.tensor_accumulated_gradient(p)? {
                    for &g in &grad {
                        total_norm += g.abs().powf(norm_type);
                    }
                }
            }
            total_norm = total_norm.powf(1.0 / norm_type);
        }

        // Scale gradients if total_norm exceeds max_norm
        let clip_coef = max_norm / (total_norm + 1e-6);
        if clip_coef < 1.0 {
            for &p in params {
                if let Some(grad) = self.tensor_accumulated_gradient(p)? {
                    let clipped: Vec<f64> = grad.iter().map(|&g| g * clip_coef).collect();
                    self.tensor_set_accumulated_gradient(p, clipped)?;
                }
            }
        }

        self.runtime.ledger_mut().record(
            EvidenceKind::Policy,
            format!(
                "clip_grad_norm_ total_norm={total_norm} max_norm={max_norm} norm_type={norm_type} clipped={}",
                clip_coef < 1.0
            ),
        );

        Ok(total_norm)
    }

    /// Clip individual gradient values to a specified range.
    ///
    /// Equivalent to `torch.nn.utils.clip_grad_value_(parameters, clip_value)`.
    /// Clamps all gradient values to `[-clip_value, clip_value]`.
    pub fn clip_grad_value_(
        &mut self,
        params: &[TensorNodeId],
        clip_value: f64,
    ) -> Result<(), AutogradError> {
        for &p in params {
            if let Some(grad) = self.tensor_accumulated_gradient(p)? {
                let clipped: Vec<f64> = grad
                    .iter()
                    .map(|&g| g.clamp(-clip_value, clip_value))
                    .collect();
                self.tensor_set_accumulated_gradient(p, clipped)?;
            }
        }

        self.runtime.ledger_mut().record(
            EvidenceKind::Policy,
            format!(
                "clip_grad_value_ clip_value={clip_value} params={}",
                params.len()
            ),
        );

        Ok(())
    }

    // ── Learning Rate Schedulers ───────────────────────────────────────

    /// Cosine annealing learning rate schedule.
    ///
    /// Decays learning rate following a cosine curve from base_lr to eta_min.
    /// lr = eta_min + (base_lr - eta_min) * (1 + cos(pi * t / T_max)) / 2
    ///
    /// Args:
    /// - base_lr: initial learning rate
    /// - step: current step/epoch
    /// - t_max: maximum number of steps in a cycle
    /// - eta_min: minimum learning rate (default 0.0)
    pub fn cosine_annealing_lr(&self, base_lr: f64, step: usize, t_max: usize, eta_min: f64) -> f64 {
        if t_max == 0 {
            return base_lr;
        }
        let t = (step % t_max) as f64;
        let t_max_f = t_max as f64;
        eta_min + (base_lr - eta_min) * (1.0 + (std::f64::consts::PI * t / t_max_f).cos()) / 2.0
    }

    /// Cosine annealing with warm restarts (SGDR).
    ///
    /// Similar to cosine_annealing_lr but with restarts every T_0 * T_mult^i epochs.
    ///
    /// Args:
    /// - base_lr: initial learning rate
    /// - step: current step/epoch
    /// - t_0: initial period length
    /// - t_mult: period multiplier after each restart
    /// - eta_min: minimum learning rate
    pub fn cosine_annealing_warm_restarts_lr(
        &self,
        base_lr: f64,
        step: usize,
        t_0: usize,
        t_mult: f64,
        eta_min: f64,
    ) -> f64 {
        if t_0 == 0 {
            return base_lr;
        }
        let mut t_cur = step;
        let mut t_i = t_0;
        while t_cur >= t_i {
            t_cur -= t_i;
            t_i = (t_i as f64 * t_mult).ceil() as usize;
        }
        let t_f = t_cur as f64 / t_i as f64;
        eta_min + (base_lr - eta_min) * (1.0 + (std::f64::consts::PI * t_f).cos()) / 2.0
    }

    /// Step learning rate decay.
    ///
    /// Decays learning rate by gamma every step_size epochs.
    /// lr = base_lr * gamma^(step // step_size)
    pub fn step_lr(&self, base_lr: f64, step: usize, step_size: usize, gamma: f64) -> f64 {
        if step_size == 0 {
            return base_lr;
        }
        base_lr * gamma.powi((step / step_size) as i32)
    }

    /// Multi-step learning rate decay.
    ///
    /// Decays by gamma when step reaches each milestone.
    pub fn multistep_lr(&self, base_lr: f64, step: usize, milestones: &[usize], gamma: f64) -> f64 {
        let count = milestones.iter().filter(|&&m| step >= m).count();
        base_lr * gamma.powi(count as i32)
    }

    /// Exponential learning rate decay.
    ///
    /// lr = base_lr * gamma^step
    pub fn exponential_lr(&self, base_lr: f64, step: usize, gamma: f64) -> f64 {
        base_lr * gamma.powi(step as i32)
    }

    /// Linear warmup schedule.
    ///
    /// Linearly increases from start_factor * base_lr to base_lr over warmup_steps.
    pub fn linear_warmup_lr(
        &self,
        base_lr: f64,
        step: usize,
        warmup_steps: usize,
        start_factor: f64,
    ) -> f64 {
        if warmup_steps == 0 || step >= warmup_steps {
            return base_lr;
        }
        let progress = step as f64 / warmup_steps as f64;
        base_lr * (start_factor + (1.0 - start_factor) * progress)
    }

    /// Polynomial learning rate decay.
    ///
    /// lr = (base_lr - end_lr) * (1 - step/total_steps)^power + end_lr
    pub fn polynomial_lr(
        &self,
        base_lr: f64,
        step: usize,
        total_steps: usize,
        power: f64,
        end_lr: f64,
    ) -> f64 {
        if total_steps == 0 || step >= total_steps {
            return end_lr;
        }
        let progress = step as f64 / total_steps as f64;
        (base_lr - end_lr) * (1.0 - progress).powf(power) + end_lr
    }

    /// One-cycle learning rate policy (Smith & Topin).
    ///
    /// Three phases:
    /// 1. Linear warmup from max_lr/div_factor to max_lr (pct_start of cycle)
    /// 2. Cosine annealing from max_lr to max_lr/div_factor (to 1-final_div_pct)
    /// 3. Linear decay to max_lr/(div_factor*final_div_factor)
    pub fn one_cycle_lr(
        &self,
        max_lr: f64,
        step: usize,
        total_steps: usize,
        pct_start: f64,
        div_factor: f64,
        final_div_factor: f64,
    ) -> f64 {
        if total_steps == 0 {
            return max_lr;
        }
        let initial_lr = max_lr / div_factor;
        let min_lr = initial_lr / final_div_factor;
        let pct = step as f64 / total_steps as f64;
        if pct < pct_start {
            let scale = pct / pct_start;
            initial_lr + (max_lr - initial_lr) * scale
        } else {
            let down_pct = (pct - pct_start) / (1.0 - pct_start);
            let cos_scale = (1.0 + (std::f64::consts::PI * down_pct).cos()) / 2.0;
            min_lr + (initial_lr - min_lr) * cos_scale
        }
    }

    // ── Weight Normalization Utilities ─────────────────────────────────

    /// Apply weight normalization to a weight tensor.
    ///
    /// Equivalent to `torch.nn.utils.weight_norm`.
    /// Reparametrizes weight as `w = g * (v / ||v||)` where g is a scalar
    /// and v is the original weight direction.
    ///
    /// Returns `(weight_g, weight_v)` where:
    /// - `weight_g`: scalar magnitude per output feature `[out_features]`
    /// - `weight_v`: unnormalized direction, same shape as weight
    pub fn weight_norm_decompose(
        &mut self,
        weight: TensorNodeId,
        dim: usize,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let shape = self.tensor_shape(weight)?;
        if dim >= shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "weight_norm_decompose: dim out of range",
                },
            )));
        }
        let v = weight;
        let g_shape = vec![shape[dim]];
        let g_vals = vec![1.0_f64; shape[dim]];
        let g = self.tensor_variable(g_vals, g_shape, true)?;
        Ok((g, v))
    }

    /// Compute the normalized weight from weight_norm parameters.
    ///
    /// Given `(g, v)` from `weight_norm_decompose`, computes `g * (v / ||v||)`.
    pub fn weight_norm_compute(
        &mut self,
        weight_g: TensorNodeId,
        weight_v: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let v_shape = self.tensor_shape(weight_v)?;
        if dim >= v_shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "weight_norm_compute: dim out of range",
                },
            )));
        }
        let dims_to_reduce: Vec<usize> = (0..v_shape.len()).filter(|&d| d != dim).collect();
        let mut norm_sq = weight_v;
        for &d in &dims_to_reduce {
            let sq = self.tensor_square(norm_sq)?;
            norm_sq = self.tensor_sum_dim(sq, d)?;
        }
        let norm = self.tensor_sqrt(norm_sq)?;
        let eps = 1e-12;
        let eps_tensor = self.full(self.tensor_shape(norm)?, eps, false)?;
        let norm_safe = self.tensor_add(norm, eps_tensor)?;
        let v_normalized = self.tensor_div(weight_v, norm_safe)?;
        let mut g_expanded = weight_g;
        for d in 0..v_shape.len() {
            if d != dim {
                g_expanded = self.tensor_unsqueeze(g_expanded, d)?;
            }
        }
        self.tensor_mul(g_expanded, v_normalized)
    }

    /// Apply spectral normalization to a weight tensor.
    ///
    /// Equivalent to `torch.nn.utils.spectral_norm`.
    /// Normalizes weight by its spectral norm (largest singular value).
    /// Uses power iteration to approximate the spectral norm.
    ///
    /// - `weight`: weight tensor to normalize
    /// - `n_power_iterations`: number of power iterations (default: 1)
    ///
    /// Returns normalized weight `w / sigma(w)`.
    pub fn spectral_norm(
        &mut self,
        weight: TensorNodeId,
        n_power_iterations: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(weight)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "spectral_norm: weight must be at least 2-D",
                },
            )));
        }
        let out_features = shape[0];
        let in_features: usize = shape[1..].iter().product();
        let w_flat = self.tensor_reshape(weight, vec![out_features, in_features])?;
        let mut u_data = vec![0.0_f64; out_features];
        for i in 0..out_features {
            u_data[i] = 1.0 / (out_features as f64).sqrt();
        }
        let mut u = self.tensor_variable(u_data, vec![out_features, 1], false)?;
        let w_t = self.tensor_transpose(w_flat, 0, 1)?;
        for _ in 0..n_power_iterations.max(1) {
            let v = self.tensor_matmul(w_t, u)?;
            let v_norm = self.tensor_norm(v, 2.0)?;
            let v_norm_shape = self.tensor_shape(v_norm)?;
            let eps = self.full(v_norm_shape, 1e-12, false)?;
            let v_norm_safe = self.tensor_add(v_norm, eps)?;
            let v_normalized = self.tensor_div(v, v_norm_safe)?;
            let u_new = self.tensor_matmul(w_flat, v_normalized)?;
            let u_norm = self.tensor_norm(u_new, 2.0)?;
            let u_norm_shape = self.tensor_shape(u_norm)?;
            let eps_u = self.full(u_norm_shape, 1e-12, false)?;
            let u_norm_safe = self.tensor_add(u_norm, eps_u)?;
            u = self.tensor_div(u_new, u_norm_safe)?;
        }
        let v_final = self.tensor_matmul(w_t, u)?;
        let v_norm_final = self.tensor_norm(v_final, 2.0)?;
        let v_norm_shape = self.tensor_shape(v_norm_final)?;
        let eps = self.full(v_norm_shape, 1e-12, false)?;
        let v_norm_safe = self.tensor_add(v_norm_final, eps)?;
        let v_normalized = self.tensor_div(v_final, v_norm_safe)?;
        let u_t = self.tensor_transpose(u, 0, 1)?;
        let wv = self.tensor_matmul(w_flat, v_normalized)?;
        let sigma_mat = self.tensor_matmul(u_t, wv)?;
        let sigma_vals = self.tensor_values(sigma_mat)?;
        let sigma_val = sigma_vals.first().copied().unwrap_or(1.0).max(1e-12);
        let sigma_tensor = self.full(shape.clone(), sigma_val, false)?;
        self.tensor_div(weight, sigma_tensor)
    }

    /// Flatten a list of parameter tensors into a single 1-D vector.
    ///
    /// Equivalent to `torch.nn.utils.convert_parameters.parameters_to_vector(parameters)`.
    /// Useful for optimization algorithms that work on flat parameter vectors.
    pub fn parameters_to_vector(
        &mut self,
        params: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if params.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "parameters_to_vector: empty parameter list",
                },
            )));
        }
        let mut all_vals = Vec::new();
        for &p in params {
            let vals = self.tensor_values(p)?;
            all_vals.extend(vals);
        }
        let total_len = all_vals.len();
        self.tensor_variable(all_vals, vec![total_len], false)
    }

    /// Unflatten a 1-D vector into parameter tensors.
    ///
    /// Equivalent to `torch.nn.utils.convert_parameters.vector_to_parameters(vec, parameters)`.
    /// Copies values from `vec` into `params` tensors in-place.
    pub fn vector_to_parameters(
        &mut self,
        vec: TensorNodeId,
        params: &[TensorNodeId],
    ) -> Result<(), AutogradError> {
        let vec_vals = self.tensor_values(vec)?;
        let mut offset = 0;
        for &p in params {
            let shape = self.tensor_shape(p)?;
            let numel: usize = shape.iter().product();
            if offset + numel > vec_vals.len() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "vector_to_parameters: vector too short for parameters",
                    },
                )));
            }
            let vals: Vec<f64> = vec_vals[offset..offset + numel].to_vec();
            self.tensor_tape.update_tensor_values(p, vals)?;
            offset += numel;
        }
        Ok(())
    }

    /// Compute the total number of elements in a list of parameters.
    ///
    /// Useful for pre-allocating vectors or checking sizes.
    pub fn count_parameters(&mut self, params: &[TensorNodeId]) -> Result<usize, AutogradError> {
        let mut total = 0;
        for &p in params {
            let shape = self.tensor_shape(p)?;
            let numel: usize = shape.iter().product();
            total += numel;
        }
        Ok(total)
    }

    /// Get shapes of all parameters as a vector.
    pub fn parameter_shapes(
        &mut self,
        params: &[TensorNodeId],
    ) -> Result<Vec<Vec<usize>>, AutogradError> {
        let mut shapes = Vec::with_capacity(params.len());
        for &p in params {
            shapes.push(self.tensor_shape(p)?);
        }
        Ok(shapes)
    }

    /// Fuse convolutional weights and batch normalization parameters.
    ///
    /// Equivalent to `torch.nn.utils.fuse_conv_bn_weights`.
    /// Computes fused weight and bias that absorb the BN transformation:
    ///   w_fused = w * (gamma / sqrt(running_var + eps))
    ///   b_fused = (bias - running_mean) * (gamma / sqrt(running_var + eps)) + beta
    ///
    /// Returns `(fused_weight, fused_bias)`.
    pub fn fuse_conv_bn_weights(
        &mut self,
        conv_weight: TensorNodeId,
        conv_bias: Option<TensorNodeId>,
        bn_running_mean: TensorNodeId,
        bn_running_var: TensorNodeId,
        bn_gamma: TensorNodeId,
        bn_beta: TensorNodeId,
        eps: f64,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let w_shape = self.tensor_shape(conv_weight)?;
        if w_shape.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fuse_conv_bn_weights: conv_weight must be at least 1-D",
                },
            )));
        }
        let out_channels = w_shape[0];
        let eps_tensor = self.full(vec![out_channels], eps, false)?;
        let std = self.tensor_add(bn_running_var, eps_tensor)?;
        let std = self.tensor_sqrt(std)?;
        let scale = self.tensor_div(bn_gamma, std)?;
        let mut scale_shape = vec![1usize; w_shape.len()];
        scale_shape[0] = out_channels;
        let scale_expanded = self.tensor_reshape(scale, scale_shape)?;
        let fused_weight = self.tensor_mul(conv_weight, scale_expanded)?;
        let bias = match conv_bias {
            Some(b) => b,
            None => self.tensor_zeros(vec![out_channels], false)?,
        };
        let shifted_bias = self.tensor_sub(bias, bn_running_mean)?;
        let scaled_bias = self.tensor_mul(shifted_bias, scale)?;
        let fused_bias = self.tensor_add(scaled_bias, bn_beta)?;
        Ok((fused_weight, fused_bias))
    }

    // ── Pruning Utilities ──────────────────────────────────────────────

    /// Create a pruning mask based on L1 magnitude.
    ///
    /// Equivalent to `torch.nn.utils.prune.l1_unstructured`.
    /// Returns a binary mask where `amount` fraction of smallest-magnitude weights are zeroed.
    ///
    /// - `tensor`: weight tensor to create mask for
    /// - `amount`: fraction of weights to prune (0.0 to 1.0)
    pub fn prune_l1_unstructured_mask(
        &mut self,
        tensor: TensorNodeId,
        amount: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if !(0.0..=1.0).contains(&amount) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "prune_l1_unstructured_mask: amount must be in [0, 1]",
                },
            )));
        }
        let vals = self.tensor_values(tensor)?;
        let shape = self.tensor_shape(tensor)?;
        let numel = vals.len();
        let num_to_prune = (numel as f64 * amount).round() as usize;
        if num_to_prune == 0 {
            return self.tensor_ones(shape, false);
        }
        if num_to_prune >= numel {
            return self.tensor_zeros(shape, false);
        }
        let mut indexed: Vec<(usize, f64)> = vals.iter().map(|&v| v.abs()).enumerate().collect();
        indexed.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));
        let mut mask = vec![1.0_f64; numel];
        for i in 0..num_to_prune {
            mask[indexed[i].0] = 0.0;
        }
        self.tensor_variable(mask, shape, false)
    }

    /// Create a random pruning mask.
    ///
    /// Equivalent to `torch.nn.utils.prune.random_unstructured`.
    /// Returns a binary mask with `amount` fraction of weights randomly zeroed.
    pub fn prune_random_unstructured_mask(
        &mut self,
        tensor: TensorNodeId,
        amount: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if !(0.0..=1.0).contains(&amount) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "prune_random_unstructured_mask: amount must be in [0, 1]",
                },
            )));
        }
        let shape = self.tensor_shape(tensor)?;
        let numel: usize = shape.iter().product();
        let rand_tensor = self.tensor_rand(shape.clone(), false)?;
        let rand_vals = self.tensor_values(rand_tensor)?;
        let mask: Vec<f64> = rand_vals.iter().map(|&v| if v >= amount { 1.0 } else { 0.0 }).collect();
        self.tensor_variable(mask, shape, false)
    }

    /// Apply a pruning mask to a tensor.
    ///
    /// Returns `tensor * mask`, zeroing out pruned weights.
    pub fn apply_pruning_mask(
        &mut self,
        tensor: TensorNodeId,
        mask: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_mul(tensor, mask)
    }

    /// Compute sparsity of a tensor (fraction of zeros).
    pub fn compute_sparsity(
        &mut self,
        tensor: TensorNodeId,
    ) -> Result<f64, AutogradError> {
        let vals = self.tensor_values(tensor)?;
        if vals.is_empty() {
            return Ok(0.0);
        }
        let num_zeros = vals.iter().filter(|&&v| v == 0.0).count();
        Ok(num_zeros as f64 / vals.len() as f64)
    }

    // ── RNN Sequence Utilities ─────────────────────────────────────────

    /// Pad a list of variable-length sequences with a given padding value.
    ///
    /// Equivalent to `torch.nn.utils.rnn.pad_sequence(sequences, batch_first, padding_value)`.
    /// Takes a list of sequences (each as TensorNodeId) and pads them to the same length.
    /// Returns a single tensor with shape:
    /// - `[max_len, batch_size, *]` if `batch_first=false`
    /// - `[batch_size, max_len, *]` if `batch_first=true`
    pub fn pad_sequence(
        &mut self,
        sequences: &[TensorNodeId],
        batch_first: bool,
        padding_value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if sequences.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pad_sequence: sequences list must not be empty",
                },
            )));
        }

        let shapes: Vec<_> = sequences
            .iter()
            .map(|&s| self.tensor_shape(s))
            .collect::<Result<_, _>>()?;

        let max_len = shapes.iter().map(|s| s[0]).max().unwrap_or(0);
        let batch_size = sequences.len();
        let trailing_shape: Vec<usize> = if shapes[0].len() > 1 {
            shapes[0][1..].to_vec()
        } else {
            vec![]
        };

        let trailing_numel: usize = trailing_shape.iter().product::<usize>().max(1);
        let total_numel = if batch_first {
            batch_size * max_len * trailing_numel
        } else {
            max_len * batch_size * trailing_numel
        };

        let mut padded = vec![padding_value; total_numel];

        for (b, (&seq, shape)) in sequences.iter().zip(shapes.iter()).enumerate() {
            let seq_len = shape[0];
            let seq_data = self.tensor_values(seq)?;

            for t in 0..seq_len {
                for f in 0..trailing_numel {
                    let src_idx = t * trailing_numel + f;
                    let dst_idx = if batch_first {
                        b * max_len * trailing_numel + t * trailing_numel + f
                    } else {
                        t * batch_size * trailing_numel + b * trailing_numel + f
                    };
                    if src_idx < seq_data.len() {
                        padded[dst_idx] = seq_data[src_idx];
                    }
                }
            }
        }

        let out_shape = if batch_first {
            let mut s = vec![batch_size, max_len];
            s.extend(&trailing_shape);
            s
        } else {
            let mut s = vec![max_len, batch_size];
            s.extend(&trailing_shape);
            s
        };

        self.tensor_variable(padded, out_shape, false)
    }

    /// Pack a list of variable-length sequences (already sorted by length, descending).
    ///
    /// Equivalent to `torch.nn.utils.rnn.pack_sequence(sequences, enforce_sorted)`.
    /// Returns a tuple of (packed_data, batch_sizes, sorted_indices, unsorted_indices).
    /// - `packed_data`: Flattened tensor containing all timesteps
    /// - `batch_sizes`: Number of sequences at each timestep
    /// - `sorted_indices`: Permutation used for sorting (if any)
    /// - `unsorted_indices`: Inverse permutation
    pub fn pack_sequence(
        &mut self,
        sequences: &[TensorNodeId],
        enforce_sorted: bool,
    ) -> Result<(TensorNodeId, Vec<usize>, Vec<usize>, Vec<usize>), AutogradError> {
        if sequences.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pack_sequence: sequences list must not be empty",
                },
            )));
        }

        let shapes: Vec<_> = sequences
            .iter()
            .map(|&s| self.tensor_shape(s))
            .collect::<Result<_, _>>()?;
        let lengths: Vec<usize> = shapes.iter().map(|s| s[0]).collect();

        let sorted_indices: Vec<usize> = if enforce_sorted {
            (0..lengths.len()).collect()
        } else {
            let mut idx: Vec<usize> = (0..lengths.len()).collect();
            idx.sort_by(|&a, &b| lengths[b].cmp(&lengths[a]));
            idx
        };

        let sorted_lengths: Vec<usize> = sorted_indices.iter().map(|&i| lengths[i]).collect();

        let max_len = sorted_lengths[0];
        let trailing_shape: Vec<usize> = if shapes[0].len() > 1 {
            shapes[0][1..].to_vec()
        } else {
            vec![]
        };
        let trailing_numel: usize = trailing_shape.iter().product::<usize>().max(1);

        let mut batch_sizes = Vec::with_capacity(max_len);
        for t in 0..max_len {
            let count = sorted_lengths.iter().filter(|&&len| len > t).count();
            batch_sizes.push(count);
        }

        let total_elements: usize = batch_sizes.iter().sum();
        let mut packed_data = Vec::with_capacity(total_elements * trailing_numel);

        for t in 0..max_len {
            for (b, &orig_idx) in sorted_indices.iter().enumerate() {
                if sorted_lengths[b] > t {
                    let seq_data = self.tensor_values(sequences[orig_idx])?;
                    for f in 0..trailing_numel {
                        let idx = t * trailing_numel + f;
                        if idx < seq_data.len() {
                            packed_data.push(seq_data[idx]);
                        }
                    }
                }
            }
        }

        let mut unsorted_indices = vec![0usize; sorted_indices.len()];
        for (sorted_pos, &orig_idx) in sorted_indices.iter().enumerate() {
            unsorted_indices[orig_idx] = sorted_pos;
        }

        let packed_shape = if trailing_shape.is_empty() {
            vec![packed_data.len()]
        } else {
            let mut s = vec![total_elements];
            s.extend(&trailing_shape);
            s
        };

        let packed_tensor = self.tensor_variable(packed_data, packed_shape, false)?;

        Ok((packed_tensor, batch_sizes, sorted_indices, unsorted_indices))
    }

    /// Pack a padded batch of sequences.
    ///
    /// Equivalent to `torch.nn.utils.rnn.pack_padded_sequence(input, lengths, batch_first, enforce_sorted)`.
    /// Takes a padded tensor and sequence lengths, returns packed representation.
    pub fn pack_padded_sequence(
        &mut self,
        input: TensorNodeId,
        lengths: &[usize],
        batch_first: bool,
        enforce_sorted: bool,
    ) -> Result<(TensorNodeId, Vec<usize>, Vec<usize>, Vec<usize>), AutogradError> {
        let shape = self.tensor_shape(input)?;
        let data = self.tensor_values(input)?;

        let (max_len, batch_size) = if batch_first {
            (shape[1], shape[0])
        } else {
            (shape[0], shape[1])
        };

        if lengths.len() != batch_size {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pack_padded_sequence: lengths count must equal batch_size",
                },
            )));
        }

        let trailing_shape: Vec<usize> = if shape.len() > 2 { shape[2..].to_vec() } else { vec![] };
        let trailing_numel: usize = trailing_shape.iter().product::<usize>().max(1);

        let sorted_indices: Vec<usize> = if enforce_sorted {
            (0..batch_size).collect()
        } else {
            let mut idx: Vec<usize> = (0..batch_size).collect();
            idx.sort_by(|&a, &b| lengths[b].cmp(&lengths[a]));
            idx
        };

        let sorted_lengths: Vec<usize> = sorted_indices.iter().map(|&i| lengths[i]).collect();

        let actual_max_len = *sorted_lengths.iter().max().unwrap_or(&0);
        let mut batch_sizes = Vec::with_capacity(actual_max_len);
        for t in 0..actual_max_len {
            let count = sorted_lengths.iter().filter(|&&len| len > t).count();
            batch_sizes.push(count);
        }

        let total_elements: usize = batch_sizes.iter().sum();
        let mut packed_data = Vec::with_capacity(total_elements * trailing_numel);

        for t in 0..actual_max_len {
            for (b, &orig_idx) in sorted_indices.iter().enumerate() {
                if sorted_lengths[b] > t {
                    for f in 0..trailing_numel {
                        let idx = if batch_first {
                            orig_idx * max_len * trailing_numel + t * trailing_numel + f
                        } else {
                            t * batch_size * trailing_numel + orig_idx * trailing_numel + f
                        };
                        if idx < data.len() {
                            packed_data.push(data[idx]);
                        }
                    }
                }
            }
        }

        let mut unsorted_indices = vec![0usize; sorted_indices.len()];
        for (sorted_pos, &orig_idx) in sorted_indices.iter().enumerate() {
            unsorted_indices[orig_idx] = sorted_pos;
        }

        let packed_shape = if trailing_shape.is_empty() {
            vec![packed_data.len()]
        } else {
            let mut s = vec![total_elements];
            s.extend(&trailing_shape);
            s
        };

        let packed_tensor = self.tensor_variable(packed_data, packed_shape, false)?;

        Ok((packed_tensor, batch_sizes, sorted_indices, unsorted_indices))
    }

    /// Unpack a packed sequence back to padded form.
    ///
    /// Equivalent to `torch.nn.utils.rnn.pad_packed_sequence(packed, batch_first, padding_value, total_length)`.
    /// Takes packed data and batch_sizes, returns (padded_tensor, lengths).
    pub fn pad_packed_sequence(
        &mut self,
        packed_data: TensorNodeId,
        batch_sizes: &[usize],
        batch_first: bool,
        padding_value: f64,
        total_length: Option<usize>,
    ) -> Result<(TensorNodeId, Vec<usize>), AutogradError> {
        let data = self.tensor_values(packed_data)?;
        let packed_shape = self.tensor_shape(packed_data)?;

        let trailing_shape: Vec<usize> = if packed_shape.len() > 1 {
            packed_shape[1..].to_vec()
        } else {
            vec![]
        };
        let trailing_numel: usize = trailing_shape.iter().product::<usize>().max(1);

        let max_len = total_length.unwrap_or(batch_sizes.len());
        let batch_size = *batch_sizes.first().unwrap_or(&0);

        let total_numel = if batch_first {
            batch_size * max_len * trailing_numel
        } else {
            max_len * batch_size * trailing_numel
        };

        let mut padded = vec![padding_value; total_numel];

        let mut lengths = vec![0usize; batch_size];
        for (t, &bs) in batch_sizes.iter().enumerate() {
            for b in 0..bs {
                if lengths[b] <= t {
                    lengths[b] = t + 1;
                }
            }
        }

        let mut data_idx = 0;
        for (t, &bs) in batch_sizes.iter().enumerate() {
            for b in 0..bs {
                for f in 0..trailing_numel {
                    let dst_idx = if batch_first {
                        b * max_len * trailing_numel + t * trailing_numel + f
                    } else {
                        t * batch_size * trailing_numel + b * trailing_numel + f
                    };
                    if data_idx < data.len() && dst_idx < padded.len() {
                        padded[dst_idx] = data[data_idx];
                    }
                    data_idx += 1;
                }
            }
        }

        let out_shape = if batch_first {
            let mut s = vec![batch_size, max_len];
            s.extend(&trailing_shape);
            s
        } else {
            let mut s = vec![max_len, batch_size];
            s.extend(&trailing_shape);
            s
        };

        let out_tensor = self.tensor_variable(padded, out_shape, false)?;

        Ok((out_tensor, lengths))
    }

    // ── RNN Cell Functions ─────────────────────────────────────────────

    /// Single step of a vanilla RNN cell with tanh activation.
    ///
    /// Equivalent to `torch.nn.RNNCell` with `nonlinearity='tanh'`.
    /// Computes: `h' = tanh(W_ih @ x + b_ih + W_hh @ h + b_hh)`
    pub fn rnn_tanh_cell(
        &mut self,
        input: TensorNodeId,
        hidden: TensorNodeId,
        w_ih: TensorNodeId,
        w_hh: TensorNodeId,
        b_ih: Option<TensorNodeId>,
        b_hh: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let igates = self.tensor_mm(input, w_ih)?;
        let hgates = self.tensor_mm(hidden, w_hh)?;
        let mut gates = self.tensor_add(igates, hgates)?;

        if let Some(bias_ih) = b_ih {
            gates = self.tensor_add(gates, bias_ih)?;
        }
        if let Some(bias_hh) = b_hh {
            gates = self.tensor_add(gates, bias_hh)?;
        }

        self.tensor_tanh(gates)
    }

    /// Single step of a vanilla RNN cell with ReLU activation.
    ///
    /// Equivalent to `torch.nn.RNNCell` with `nonlinearity='relu'`.
    /// Computes: `h' = relu(W_ih @ x + b_ih + W_hh @ h + b_hh)`
    pub fn rnn_relu_cell(
        &mut self,
        input: TensorNodeId,
        hidden: TensorNodeId,
        w_ih: TensorNodeId,
        w_hh: TensorNodeId,
        b_ih: Option<TensorNodeId>,
        b_hh: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let igates = self.tensor_mm(input, w_ih)?;
        let hgates = self.tensor_mm(hidden, w_hh)?;
        let mut gates = self.tensor_add(igates, hgates)?;

        if let Some(bias_ih) = b_ih {
            gates = self.tensor_add(gates, bias_ih)?;
        }
        if let Some(bias_hh) = b_hh {
            gates = self.tensor_add(gates, bias_hh)?;
        }

        self.tensor_relu(gates)
    }

    /// Single step of an LSTM cell.
    ///
    /// Equivalent to `torch.nn.LSTMCell`.
    /// Returns (h', c') tuple for the new hidden and cell states.
    pub fn lstm_cell(
        &mut self,
        input: TensorNodeId,
        hx: (TensorNodeId, TensorNodeId),
        w_ih: TensorNodeId,
        w_hh: TensorNodeId,
        b_ih: Option<TensorNodeId>,
        b_hh: Option<TensorNodeId>,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let (h, c) = hx;

        let mut gates = self.tensor_mm(input, w_ih)?;
        let hgates = self.tensor_mm(h, w_hh)?;
        gates = self.tensor_add(gates, hgates)?;

        if let Some(bias_ih) = b_ih {
            gates = self.tensor_add(gates, bias_ih)?;
        }
        if let Some(bias_hh) = b_hh {
            gates = self.tensor_add(gates, bias_hh)?;
        }

        let hidden_size = self.tensor_shape(h)?[self.tensor_shape(h)?.len() - 1];
        let gates_data = self.tensor_values(gates)?;
        let c_data = self.tensor_values(c)?;

        let batch_size = gates_data.len() / (4 * hidden_size);
        let mut new_h = Vec::with_capacity(batch_size * hidden_size);
        let mut new_c = Vec::with_capacity(batch_size * hidden_size);

        for b in 0..batch_size {
            for i in 0..hidden_size {
                let gate_base = b * 4 * hidden_size;
                let i_gate = gates_data[gate_base + i];
                let f_gate = gates_data[gate_base + hidden_size + i];
                let g_gate = gates_data[gate_base + 2 * hidden_size + i];
                let o_gate = gates_data[gate_base + 3 * hidden_size + i];

                let i_gate = 1.0 / (1.0 + (-i_gate).exp());
                let f_gate = 1.0 / (1.0 + (-f_gate).exp());
                let g_gate = g_gate.tanh();
                let o_gate = 1.0 / (1.0 + (-o_gate).exp());

                let c_idx = b * hidden_size + i;
                let c_val = f_gate * c_data[c_idx] + i_gate * g_gate;
                let h_val = o_gate * c_val.tanh();

                new_c.push(c_val);
                new_h.push(h_val);
            }
        }

        let h_shape = self.tensor_shape(h)?;
        let new_h_tensor = self.tensor_variable(new_h, h_shape.clone(), false)?;
        let new_c_tensor = self.tensor_variable(new_c, h_shape, false)?;

        Ok((new_h_tensor, new_c_tensor))
    }

    /// Single step of a GRU cell.
    ///
    /// Equivalent to `torch.nn.GRUCell`.
    /// Returns h' for the new hidden state.
    pub fn gru_cell(
        &mut self,
        input: TensorNodeId,
        hidden: TensorNodeId,
        w_ih: TensorNodeId,
        w_hh: TensorNodeId,
        b_ih: Option<TensorNodeId>,
        b_hh: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut gi = self.tensor_mm(input, w_ih)?;
        let mut gh = self.tensor_mm(hidden, w_hh)?;

        if let Some(bias_ih) = b_ih {
            gi = self.tensor_add(gi, bias_ih)?;
        }
        if let Some(bias_hh) = b_hh {
            gh = self.tensor_add(gh, bias_hh)?;
        }

        let hidden_size = self.tensor_shape(hidden)?[self.tensor_shape(hidden)?.len() - 1];
        let gi_data = self.tensor_values(gi)?;
        let gh_data = self.tensor_values(gh)?;
        let h_data = self.tensor_values(hidden)?;

        let batch_size = gi_data.len() / (3 * hidden_size);
        let mut new_h = Vec::with_capacity(batch_size * hidden_size);

        for b in 0..batch_size {
            for i in 0..hidden_size {
                let gi_base = b * 3 * hidden_size;
                let gh_base = b * 3 * hidden_size;

                let r_i = gi_data[gi_base + i];
                let z_i = gi_data[gi_base + hidden_size + i];
                let n_i = gi_data[gi_base + 2 * hidden_size + i];

                let r_h = gh_data[gh_base + i];
                let z_h = gh_data[gh_base + hidden_size + i];
                let n_h = gh_data[gh_base + 2 * hidden_size + i];

                let r = 1.0 / (1.0 + (-(r_i + r_h)).exp());
                let z = 1.0 / (1.0 + (-(z_i + z_h)).exp());
                let n = (n_i + r * n_h).tanh();

                let h_idx = b * hidden_size + i;
                let h_val = (1.0 - z) * n + z * h_data[h_idx];

                new_h.push(h_val);
            }
        }

        let h_shape = self.tensor_shape(hidden)?;
        self.tensor_variable(new_h, h_shape, false)
    }

    #[must_use]
    pub fn evidence(&self) -> &[EvidenceEntry] {
        self.runtime.ledger().entries()
    }

    #[must_use]
    pub fn evidence_len(&self) -> usize {
        self.runtime.ledger().len()
    }

    fn checked_shape_numel(
        shape: &[usize],
        overflow_reason: &'static str,
    ) -> Result<usize, AutogradError> {
        let mut product = 1usize;
        for dim in shape.iter().copied() {
            if dim == 0 {
                return Ok(0);
            }
            let Some(next) = product.checked_mul(dim) else {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: overflow_reason,
                    },
                )));
            };
            product = next;
        }
        Ok(product)
    }

    fn checked_mul(
        lhs: usize,
        rhs: usize,
        overflow_reason: &'static str,
    ) -> Result<usize, AutogradError> {
        lhs.checked_mul(rhs).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: overflow_reason,
                },
            ))
        })
    }

    fn checked_add(
        lhs: usize,
        rhs: usize,
        overflow_reason: &'static str,
    ) -> Result<usize, AutogradError> {
        lhs.checked_add(rhs).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: overflow_reason,
                },
            ))
        })
    }

    fn require_f64_tensor_storage(&self, input: TensorNodeId) -> Result<(), AutogradError> {
        let dtype = self.tensor_tape.tensor_meta(input)?.dtype();
        if dtype != DType::F64 {
            return Err(AutogradError::DenseTensor(
                ft_core::DenseTensorError::UnsupportedStorageAccess { dtype },
            ));
        }
        Ok(())
    }

    fn adaptive_avg_pool_window(
        output_index: usize,
        input_size: usize,
        output_size: usize,
        overflow_reason: &'static str,
    ) -> Result<(usize, usize), AutogradError> {
        let start_num = Self::checked_mul(output_index, input_size, overflow_reason)?;
        let start = start_num / output_size;
        let next_output_index = Self::checked_add(output_index, 1, overflow_reason)?;
        let end_num = Self::checked_mul(next_output_index, input_size, overflow_reason)?;
        let end = end_num.div_ceil(output_size);
        if end <= start {
            return Err(Self::incompatible_tensor_args(
                "adaptive_avg_pool: pooling window contains no input elements",
            ));
        }
        Ok((start, end))
    }

    fn checked_conv_transpose_output_dim(
        spec: ConvTransposeOutputDimSpec,
        errors: ConvTransposeOutputDimErrors,
    ) -> Result<usize, AutogradError> {
        let span = Self::checked_mul(spec.input - 1, spec.stride, errors.overflow)?;
        let base = Self::checked_add(span, spec.kernel, errors.overflow)?;
        let base = Self::checked_add(base, spec.output_padding, errors.overflow)?;
        let padding = Self::checked_mul(spec.padding, 2, errors.padding_overflow)?;
        if base <= padding {
            return Err(Self::incompatible_tensor_args(errors.underflow));
        }
        Ok(base - padding)
    }

    fn checked_square_numel(
        n: usize,
        overflow_reason: &'static str,
    ) -> Result<usize, AutogradError> {
        n.checked_mul(n).ok_or({
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: overflow_reason,
                },
            ))
        })
    }

    fn exact_integer_index_to_isize(
        value: f64,
        invalid_reason: &'static str,
    ) -> Result<isize, AutogradError> {
        if !value.is_finite() || value.trunc() != value {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        if value < isize::MIN as f64 || value > isize::MAX as f64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        let converted = value as isize;
        if converted as f64 != value {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        Ok(converted)
    }

    fn exact_nonnegative_index_to_usize(
        value: f64,
        invalid_reason: &'static str,
    ) -> Result<usize, AutogradError> {
        if !value.is_finite() || value < 0.0 || value.trunc() != value {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        if value > usize::MAX as f64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        let converted = value as usize;
        if converted as f64 != value {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: invalid_reason,
                },
            )));
        }
        Ok(converted)
    }

    fn update_tensor_values_for_float(
        &mut self,
        target: TensorNodeId,
        values: Vec<f64>,
        reason: &'static str,
    ) -> Result<(), AutogradError> {
        match self.tensor_tape.dtype(target)? {
            DType::F64 => self.tensor_tape.update_tensor_values(target, values),
            DType::F32 => {
                let values_f32: Vec<f32> = values.iter().map(|&v| v as f32).collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, values_f32)
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet { reason },
            ))),
        }
    }

    fn validate_tensor_in_place_binary_compatibility(
        &self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_meta = self.tensor_tape.tensor_meta(target)?;
        let other_meta = self.tensor_tape.tensor_meta(other)?;
        if target_meta.shape() != other_meta.shape() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: target_meta.shape().to_vec(),
                    rhs: other_meta.shape().to_vec(),
                },
            )));
        }
        if target_meta.dtype() != other_meta.dtype() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::Incompatible(TensorCompatError::DTypeMismatch {
                    lhs: target_meta.dtype(),
                    rhs: other_meta.dtype(),
                }),
            )));
        }
        if target_meta.device() != other_meta.device() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::Incompatible(TensorCompatError::DeviceMismatch {
                    lhs: target_meta.device(),
                    rhs: other_meta.device(),
                }),
            )));
        }
        Ok(())
    }

    fn validate_tensor_in_place_target(&self, target: TensorNodeId) -> Result<(), AutogradError> {
        if self.is_grad_enabled()
            && self.tensor_tape.tensor_is_leaf(target)?
            && self.tensor_tape.tensor_requires_grad(target)?
        {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "in-place mutation on leaf tensors that require grad is forbidden",
                },
            )));
        }
        Ok(())
    }

    fn apply_tensor_unary_in_place<F>(
        &mut self,
        op: &'static str,
        target: TensorNodeId,
        extra: Option<String>,
        transform: F,
    ) -> Result<(), AutogradError>
    where
        F: Fn(f64) -> f64,
    {
        self.validate_tensor_in_place_target(target)?;
        match self.tensor_tape.dtype(target)? {
            DType::F64 => {
                let target_vals = self.tensor_tape.values(target)?;
                let new_values: Vec<f64> = target_vals.into_iter().map(transform).collect();
                self.tensor_tape.update_tensor_values(target, new_values)?;
            }
            DType::F32 => {
                let target_vals = self.tensor_tape.values_f32(target)?;
                let new_values: Vec<f32> = target_vals
                    .into_iter()
                    .map(|v| transform(v as f64) as f32)
                    .collect();
                self.tensor_tape
                    .update_tensor_values_f32(target, new_values)?;
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: INPLACE_FLOAT_REASON,
                    },
                )));
            }
        }
        self.record_tensor_in_place_operation(op, target, extra);
        Ok(())
    }

    fn record_operation(&mut self, event: &OperationEvent) {
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!(
                "op={:?} lhs={} rhs={} out={} mode={:?} kernel={} key={:?} backend={:?} keyset=0x{:016x} fallback={}",
                event.op,
                event.lhs.0,
                event.rhs.0,
                event.out.0,
                event.decision.mode,
                event.decision.kernel,
                event.decision.selected_key,
                event.decision.backend_key,
                event.decision.keyset_bits,
                event.decision.fallback_used
            ),
        );
    }

