    // -------------------------------------------------------------------
    // Linear Algebra: LU Decomposition
    // -------------------------------------------------------------------

    /// Compute the LU factorization of a square matrix with partial pivoting.
    ///
    /// Returns `(lu_factor_node, pivot_indices)` where `lu_factor_node` is a
    /// tensor containing the packed LU matrix, and `pivot_indices` is a `Vec<usize>`
    /// of row pivot indices.
    ///
    /// The input must be a 2-D square tensor (n x n).
    pub fn tensor_lu_factor(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, Vec<usize>), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "lu_factor: autograd not supported (LU backward not yet implemented). Tracked under frankentorch-sn58.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let result = ft_kernel_cpu::lu_factor_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let n = result.n;
        let lu_node = self.tensor_variable(result.lu, vec![n, n], false)?;
        Ok((lu_node, result.pivots))
    }

    /// Compute the full LU decomposition: `P @ L @ U = A`.
    ///
    /// Returns `(P, L, U)` as three separate tensor nodes.
    /// - P: permutation matrix (n x n)
    /// - L: lower triangular with unit diagonal (n x n)
    /// - U: upper triangular (n x n)
    pub fn tensor_linalg_lu(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId, TensorNodeId), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_lu: autograd not supported (LU backward not yet implemented). Tracked under frankentorch-sn58.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let factor = ft_kernel_cpu::lu_factor_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let unpacked = ft_kernel_cpu::lu_unpack(&factor);
        let n = unpacked.n;
        let p_node = self.tensor_variable(unpacked.p, vec![n, n], false)?;
        let l_node = self.tensor_variable(unpacked.l, vec![n, n], false)?;
        let u_node = self.tensor_variable(unpacked.u, vec![n, n], false)?;
        Ok((p_node, l_node, u_node))
    }

    /// Solve `A * X = B` using a pre-computed LU factorization.
    ///
    /// `lu_packed` is the packed LU tensor from `tensor_lu_factor`.
    /// `pivots` is the pivot indices from `tensor_lu_factor`.
    /// `b` is the right-hand side tensor (shape [n] or [n, m]).
    ///
    /// Returns the solution tensor X.
    pub fn tensor_lu_solve(
        &mut self,
        lu_packed: TensorNodeId,
        pivots: &[usize],
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(lu_packed)? || self.tensor_requires_grad(b)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "lu_solve: autograd not supported (LU backward not yet implemented). Use tensor_linalg_solve for autograd-aware solve. Tracked under frankentorch-sn58.",
                },
            )));
        }
        let (lu_values, lu_meta) = self.tensor_values_meta(lu_packed)?;
        let lu_shape = lu_meta.shape();
        if lu_shape.len() != 2 || lu_shape[0] != lu_shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: lu_shape.to_vec(),
                    rhs: vec![lu_shape.len()],
                },
            )));
        }
        let n = lu_shape[0];
        let factor = ft_kernel_cpu::LuFactorResult {
            lu: lu_values,
            pivots: pivots.to_vec(),
            n,
        };

        let (b_values, b_meta) = self.tensor_values_meta(b)?;
        let b_shape = b_meta.shape().to_vec();
        let solution = ft_kernel_cpu::lu_solve_contiguous_f64(&factor, &b_values, &b_meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;

        self.tensor_variable(solution, b_shape, false)
    }

    /// Solve the linear system `A @ X = B` for X.
    ///
    /// Internally factorises A via LU decomposition then solves.
    /// A must be a square (n x n) tensor; B must be [n] or [n, m].
    /// Returns the solution tensor X with the same shape as B.
    pub fn tensor_linalg_solve(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose via tensor_linalg_inv + tensor_matmul so gradients
        // flow back to both A and B. Tracked under frankentorch-dlht.
        // Previous body called LU factor/solve kernels directly and
        // rebuilt a non-grad leaf, severing autograd through every
        // linear solve.
        //
        // Math: X = inv(A) @ B. The chain rule via inv backward
        // (-Y^T grad Y^T, frankentorch-frq7) and matmul backward
        // recovers the standard solve adjoint:
        //   dL/dB = A^{-T} dL/dX
        //   dL/dA = -A^{-T} dL/dX X^T
        // Trade-off: forward pass uses the explicit inverse instead
        // of LU solve — slightly less stable for ill-conditioned A,
        // but PyTorch's solve autograd uses the same inv-based path
        // for backward, so gradient correctness is identical.
        //
        // For batched B [n, m] this still works: matmul broadcasts
        // [n, n] @ [n, m] = [n, m]. For 1-D B [n], we reshape to
        // [n, 1] then squeeze to recover the [n] output shape.
        let b_shape = self.tensor_shape(b)?;
        let inv_a = self.tensor_linalg_inv(a)?;
        if b_shape.len() == 1 {
            let n = b_shape[0];
            let b_2d = self.tensor_reshape(b, vec![n, 1])?;
            let x_2d = self.tensor_matmul(inv_a, b_2d)?;
            self.tensor_reshape(x_2d, vec![n])
        } else {
            self.tensor_matmul(inv_a, b)
        }
    }

    /// Compute the Cholesky decomposition of a symmetric positive-definite matrix.
    ///
    /// Returns the lower triangular factor L such that A = L @ L^T.
    /// If `upper` is true, returns U such that A = U^T @ U.
    pub fn tensor_linalg_cholesky(
        &mut self,
        input: TensorNodeId,
        upper: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_meta = self.tensor_tape.tensor_meta(input)?.clone();
        if self.tensor_requires_grad(input)? {
            if input_meta.shape() == [1, 1] && input_meta.dtype() == DType::F64 {
                let out = self.tensor_apply_function(
                    &[input],
                    move |ctx, inputs| {
                        let values = inputs[0].0;
                        if values[0] <= 0.0 {
                            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                                ft_dispatch::DispatchKeyError::IncompatibleSet {
                                    reason: "linalg_cholesky: input is not positive definite",
                                },
                            )));
                        }
                        let factor = values[0].sqrt();
                        ctx.save_for_backward(vec![factor], vec![1, 1]);
                        Ok((vec![factor], vec![1, 1]))
                    },
                    move |ctx, grad_outputs| {
                        let factor = ctx.saved_tensors()[0][0];
                        Ok(vec![Some(vec![grad_outputs[0][0] / (2.0 * factor)])])
                    },
                )?;
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "linalg_cholesky input={} out={} upper={upper} (autograd 1x1)",
                        input.0, out.0
                    ),
                );
                return Ok(out);
            }
            // Cholesky backward is implementable but non-trivial
            // (involves the phi = lower(L^T L) tridiag formula).
            // Fail loud for now (parking-lot pattern matching pvfk
            // / 3v6e). Tracked under frankentorch-rl4g.
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_cholesky: autograd not supported (cholesky backward not yet implemented)",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let result = ft_kernel_cpu::cholesky_contiguous_f64(&values, &meta, upper)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let n = result.n;
        self.tensor_variable(result.factor, vec![n, n], false)
    }

    /// Alias for tensor_linalg_cholesky.
    ///
    /// Provided for parity with older PyTorch code using `torch.cholesky`.
    pub fn tensor_cholesky(
        &mut self,
        input: TensorNodeId,
        upper: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_cholesky(input, upper)
    }

    /// Solve A @ X = B given Cholesky factor L where A = L @ L^T.
    ///
    /// More efficient than general solve for symmetric positive-definite systems.
    /// `cholesky_factor` is the result of `tensor_linalg_cholesky`.
    /// B can be [n] or [n, m].
    pub fn tensor_cholesky_solve(
        &mut self,
        b: TensorNodeId,
        cholesky_factor: TensorNodeId,
        upper: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let factor_shape = self.tensor_shape(cholesky_factor)?;
        if factor_shape.len() != 2 || factor_shape[0] != factor_shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: factor_shape,
                    rhs: vec![2],
                },
            )));
        }

        // Compose through tensor_triangular_solve so the autograd
        // tape carries gradients through both b and the cholesky
        // factor. tensor_triangular_solve was made autograd-aware
        // under frankentorch-skpl.
        //
        // For A = L L^T (upper=false) solving A X = B:
        //   Y = L^{-1} B   = triangular_solve(L, B, upper=false)
        //   X = L^{-T} Y   = triangular_solve(L^T, Y, upper=true)
        //
        // For A = U^T U (upper=true):
        //   Y = U^{-T} B   = triangular_solve(U^T, B, upper=false)
        //   X = U^{-1} Y   = triangular_solve(U, Y, upper=true)
        //
        // Either way the inner triangle becomes upper after the
        // transpose. Tracked under frankentorch-tw0y.
        if upper {
            let u_t = self.tensor_transpose(cholesky_factor, 0, 1)?;
            let y = self.tensor_triangular_solve(u_t, b, false)?;
            self.tensor_triangular_solve(cholesky_factor, y, true)
        } else {
            let y = self.tensor_triangular_solve(cholesky_factor, b, false)?;
            let l_t = self.tensor_transpose(cholesky_factor, 0, 1)?;
            self.tensor_triangular_solve(l_t, y, true)
        }
    }

    /// Compute the matrix inverse.
    ///
    /// Returns A^-1 where A @ A^-1 = I. Errors if A is singular.
    ///
    /// Wraps the kernel inverse in a tensor_apply_function with the
    /// analytical backward
    ///     grad_A = -Y^T @ grad_Y @ Y^T   where Y = A^{-1}
    /// (standard matrix-calculus identity: dY = -A^{-1} dA A^{-1}).
    /// Saves Y for backward to avoid recomputing the inverse.
    /// Tracked under frankentorch-frq7 (child of frankentorch-tw0y).
    pub fn tensor_linalg_inv(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 || shape[0] != shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape.clone(),
                    rhs: vec![2],
                },
            )));
        }
        let n = shape[0];

        let out = self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, in_shape) = inputs[0];
                let meta = ft_core::TensorMeta::from_shape(
                    in_shape.to_vec(),
                    DType::F64,
                    ft_core::Device::Cpu,
                );
                let result = ft_kernel_cpu::inv_tensor_contiguous_f64(vals, &meta)
                    .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
                // Save Y (the inverse) for backward.
                ctx.save_for_backward(result.clone(), in_shape.to_vec());
                Ok((result, in_shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let y = &saved[0];
                if grad_y.len() != n * n || y.len() != n * n {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "linalg_inv backward: gradient or saved-Y shape mismatch",
                        },
                    )));
                }
                // grad_A = -Y^T @ grad_Y @ Y^T
                // First: tmp = Y^T @ grad_Y   (n×n)
                //   tmp[i,j] = sum_k Y[k,i] * grad_y[k,j]
                let mut tmp = vec![0.0_f64; n * n];
                for i in 0..n {
                    for j in 0..n {
                        let mut acc = 0.0_f64;
                        for k in 0..n {
                            acc += y[k * n + i] * grad_y[k * n + j];
                        }
                        tmp[i * n + j] = acc;
                    }
                }
                // Then: grad_a = -tmp @ Y^T
                //   grad_a[i,j] = -sum_k tmp[i,k] * Y[j,k]
                let mut grad_a = vec![0.0_f64; n * n];
                for i in 0..n {
                    for j in 0..n {
                        let mut acc = 0.0_f64;
                        for k in 0..n {
                            acc += tmp[i * n + k] * y[j * n + k];
                        }
                        grad_a[i * n + j] = -acc;
                    }
                }
                Ok(vec![Some(grad_a)])
            },
        )?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("linalg_inv input={} out={} (autograd)", input.0, out.0),
        );
        Ok(out)
    }

    /// Compute the matrix product of a sequence of matrices.
    ///
    /// Equivalent to `torch.linalg.multi_dot(tensors)`. Multiplies
    /// the matrices left-to-right. For optimal parenthesization of
    /// long chains, consider dynamic programming (not implemented
    /// here). Requires two or more tensors. First and last can be 1-D
    /// (treated as row/column vectors); middle matrices must be 2-D.
    pub fn tensor_linalg_multi_dot(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "multi_dot: need at least two tensors",
                },
            )));
        }
        let mut result = self.tensor_matmul(tensors[0], tensors[1])?;
        for t in &tensors[2..] {
            result = self.tensor_matmul(result, *t)?;
        }
        Ok(result)
    }

    /// Alias for `tensor_linalg_multi_dot`.
    pub fn tensor_chain_matmul(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_multi_dot(tensors)
    }

    /// Alias for `tensor_chain_matmul`. Equivalent to `torch.linalg.multi_dot`.
    pub fn tensor_multi_dot(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_multi_dot(tensors)
    }

    /// Solve a triangular linear system: A @ X = B.
    ///
    /// Equivalent to `torch.linalg.solve_triangular(A, B, upper)`.
    /// A must be a square triangular matrix.
    pub fn tensor_triangular_solve(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
        upper: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;

        if a_shape.len() != 2 || a_shape[0] != a_shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triangular_solve: A must be a square 2-D matrix",
                },
            )));
        }

        let n = a_shape[0];
        let nrhs = if b_shape.len() == 1 { 1 } else { b_shape[1] };

        if matches!(b_shape.len(), 1 | 2) && b_shape[0] != n {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "triangular_solve: B rows must match A dimension",
                },
            )));
        }

        // tensor_apply_function takes (forward, backward) closures.
        // The forward solves AX = B by direct substitution.
        // The backward applies the standard triangular-solve identity:
        //     grad_B = A^{-T} grad_X
        //     grad_A = -A^{-T} grad_X X^T   masked to A's triangle
        // We implement triangular_solve(A^T, grad_X, !upper) inline
        // for the grad_B leg, then outer-product with -X^T to get
        // grad_A and zero out the off-triangular half.
        // Tracked under frankentorch-skpl (child of frankentorch-tw0y).
        let b_shape_clone = b_shape.clone();
        let out = self.tensor_apply_function(
            &[a, b],
            move |ctx, inputs| {
                let (a_vals, a_in_shape) = inputs[0];
                let (b_vals, _b_in_shape) = inputs[1];
                let mut x = b_vals.to_vec();
                for col in 0..nrhs {
                    if upper {
                        for i in (0..n).rev() {
                            let diag = a_vals[i * n + i];
                            if diag.abs() < 1e-15 {
                                return Err(AutogradError::Dispatch(
                                    ft_dispatch::DispatchError::Key(
                                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                                            reason: "triangular_solve: singular triangular matrix",
                                        },
                                    ),
                                ));
                            }
                            let mut sum = x[i * nrhs + col];
                            for j in (i + 1)..n {
                                sum -= a_vals[i * n + j] * x[j * nrhs + col];
                            }
                            x[i * nrhs + col] = sum / diag;
                        }
                    } else {
                        for i in 0..n {
                            let diag = a_vals[i * n + i];
                            if diag.abs() < 1e-15 {
                                return Err(AutogradError::Dispatch(
                                    ft_dispatch::DispatchError::Key(
                                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                                            reason: "triangular_solve: singular triangular matrix",
                                        },
                                    ),
                                ));
                            }
                            let mut sum = x[i * nrhs + col];
                            for j in 0..i {
                                sum -= a_vals[i * n + j] * x[j * nrhs + col];
                            }
                            x[i * nrhs + col] = sum / diag;
                        }
                    }
                }
                // Save A (for the backward triangular_solve(A^T, ..)) and
                // X (for the outer product in grad_A).
                ctx.save_for_backward(a_vals.to_vec(), a_in_shape.to_vec());
                ctx.save_for_backward(x.clone(), b_shape_clone.clone());
                Ok((x, b_shape_clone.clone()))
            },
            move |ctx, grad_outputs| {
                let grad_x = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let a_vals = &saved[0];
                let x_vals = &saved[1];

                // Step 1: grad_B = A^{-T} grad_X = triangular_solve(A^T, grad_X, !upper).
                // We perform the substitution directly on a transposed
                // view of A (i.e. swap (i, j) → (j, i) in indexing).
                // The triangle flips: solving with A^T treats the
                // upper-tri part of A as the lower-tri part of A^T.
                let mut grad_b = grad_x.to_vec();
                let solve_upper = !upper;
                for col in 0..nrhs {
                    if solve_upper {
                        for i in (0..n).rev() {
                            // diag of A^T is same as diag of A
                            let diag = a_vals[i * n + i];
                            // a_T[i,j] = a[j,i]; relevant for j > i
                            let mut sum = grad_b[i * nrhs + col];
                            for j in (i + 1)..n {
                                sum -= a_vals[j * n + i] * grad_b[j * nrhs + col];
                            }
                            grad_b[i * nrhs + col] = sum / diag;
                        }
                    } else {
                        for i in 0..n {
                            let diag = a_vals[i * n + i];
                            let mut sum = grad_b[i * nrhs + col];
                            for j in 0..i {
                                sum -= a_vals[j * n + i] * grad_b[j * nrhs + col];
                            }
                            grad_b[i * nrhs + col] = sum / diag;
                        }
                    }
                }

                // Step 2: grad_A = -grad_B @ X^T   masked to A's triangle.
                // grad_A[i,k] = -sum_j grad_B[i,j] * X[k,j]
                let mut grad_a = vec![0.0_f64; n * n];
                for i in 0..n {
                    for k in 0..n {
                        // Mask: keep only the triangle that A has.
                        let in_triangle = if upper { k >= i } else { k <= i };
                        if !in_triangle {
                            continue;
                        }
                        let mut acc = 0.0_f64;
                        for j in 0..nrhs {
                            acc += grad_b[i * nrhs + j] * x_vals[k * nrhs + j];
                        }
                        grad_a[i * n + k] = -acc;
                    }
                }

                Ok(vec![Some(grad_a), Some(grad_b)])
            },
        )?;
        Ok(out)
    }

    /// Compute the inverse of a symmetric positive-definite matrix via Cholesky.
    ///
    /// Equivalent to `torch.cholesky_inverse(L, upper)`.
    /// More numerically stable than general inverse for SPD matrices.
    pub fn tensor_cholesky_inverse(
        &mut self,
        cholesky_factor: TensorNodeId,
        upper: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(cholesky_factor)?;
        if shape.len() != 2 || shape[0] != shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cholesky_inverse: input must be square 2-D",
                },
            )));
        }
        let n = shape[0];
        // Solve L @ L^T @ X = I using cholesky_solve
        let identity = self.eye(n, false)?;
        self.tensor_cholesky_solve(identity, cholesky_factor, upper)
    }

    /// Compute a matrix norm (Frobenius or nuclear).
    ///
    /// Equivalent to `torch.linalg.matrix_norm(input, ord)`.
    /// Supported ords: "fro" (Frobenius, default), 1 (max col sum), -1 (min col sum),
    /// inf (max row sum), -inf (min row sum).
    pub fn tensor_matrix_norm(
        &mut self,
        input: TensorNodeId,
        ord: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-oitu).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }

        // Compose through autograd primitives so gradients flow to
        // the input. Previously the body extracted tensor_values,
        // computed the norm in plain f64, and rebuilt a
        // requires_grad=false leaf — silently severing the autograd
        // tape on tracked inputs. Same severed-autograd pattern as
        // the cov / corrcoef / mode / quantile family fixed under
        // frankentorch-1tax. Tracked under frankentorch-i4rd.
        //
        // The sum-of-row-or-column-abs paths reduce to a 1-D vector
        // and then take a scalar max/min. tensor_max_dim / min_dim
        // along the only dim of a 1-D tensor returns a 0-D scalar
        // (and discards the argmax index — gradient flows through
        // the values branch only). For shape parity with the previous
        // contract (output shape [1]), reshape via tensor_unsqueeze
        // at the end.
        let result = match ord {
            "fro" => {
                let sq = self.tensor_mul(input, input)?;
                let sum_sq = self.tensor_sum(sq)?;
                self.tensor_sqrt(sum_sq)?
            }
            "1" | "inf" | "-1" | "-inf" => {
                let reduce_dim: usize = if ord == "1" || ord == "-1" {
                    // ||A||_1 = max_j sum_i |A_ij|; sum over rows (dim=0).
                    0
                } else {
                    // ||A||_inf = max_i sum_j |A_ij|; sum over cols (dim=1).
                    1
                };
                let take_max = ord == "1" || ord == "inf";
                let abs_a = self.tensor_abs(input)?;
                let sums = self.tensor_sum_dim(abs_a, reduce_dim)?;
                let (reduced, _argidx) = if take_max {
                    self.tensor_max_dim(sums, 0)?
                } else {
                    self.tensor_min_dim(sums, 0)?
                };
                reduced
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "matrix_norm: unsupported ord (use fro, 1, -1, inf, -inf)",
                    },
                )));
            }
        };

        // Previous contract was a 1-D shape [1] output. tensor_sum
        // and tensor_max_dim along the only dim both yield a 0-D
        // scalar (shape [] or [1] — depends on the kernel), so
        // promote / preserve shape via reshape. We use unsqueeze if
        // the reduction left a 0-D scalar.
        let result_shape = self.tensor_shape(result)?;
        if result_shape.is_empty() {
            self.tensor_unsqueeze(result, 0)
        } else if result_shape == [1] {
            Ok(result)
        } else {
            // Defensive: reshape to [1].
            self.tensor_reshape(result, vec![1])
        }
    }

    /// Alias for tensor_matrix_norm.
    ///
    /// Equivalent to `torch.linalg.matrix_norm(input, ord)`.
    pub fn tensor_linalg_matrix_norm(
        &mut self,
        input: TensorNodeId,
        ord: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_matrix_norm(input, ord)
    }

    /// Frobenius norm of a matrix.
    ///
    /// Equivalent to `torch.linalg.norm(input, 'fro')`.
    /// The Frobenius norm is sqrt(sum of squared elements).
    pub fn tensor_frobenius_norm(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_matrix_norm(input, "fro")
    }

    /// Nuclear norm (trace norm) of a matrix.
    ///
    /// Equivalent to `torch.linalg.norm(input, 'nuc')`.
    /// The nuclear norm is the sum of singular values.
    pub fn tensor_nuclear_norm(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_matrix_norm(input, "nuc")
    }

    /// Scatter values into positions indicated by a mask.
    ///
    /// Equivalent to `torch.Tensor.masked_scatter_(mask, source)`.
    /// Copies elements from `source` into positions where `mask` is non-zero.
    pub fn tensor_masked_scatter(
        &mut self,
        input: TensorNodeId,
        mask: TensorNodeId,
        source: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose tensor_masked_scatter through autograd-aware
        // primitives so the backward pass actually flows through both
        // `input` (at the un-masked positions) and `source` (at the
        // first n_true source slots). The previous body extracted
        // values and rebuilt a requires_grad=false leaf — same
        // severed-autograd pattern recently fixed in
        // index_add / index_copy / index_fill / Scatter / ScatterAdd
        // / IndexPut.
        //
        // Strategy:
        //   1. Walk the (non-tracked) mask values to compute, for
        //      each flat position i, the source slot index that
        //      masked_scatter would copy from there: it's the prefix
        //      sum of the mask, minus one. Where mask[i] == 0 we set
        //      a *valid* sentinel index (clamped to [0, src_len-1]
        //      or 0 when src_len == 0 and there are no true masks)
        //      so the gather below stays in-bounds; tensor_where
        //      below masks those positions out.
        //   2. tensor_reshape `source` to a flat 1-D view (autograd
        //      flows through reshape).
        //   3. tensor_gather(source_flat, 0, prefix_clamped_node) →
        //      a tensor of the same shape as input where each slot
        //      holds the source value that masked_scatter would put
        //      there if the mask was true. Gather's backward
        //      scatter_adds gradient back to source at the gathered
        //      positions — which are exactly the first n_true source
        //      slots, with each used exactly once.
        //   4. tensor_where(mask, scattered, input). Where's
        //      backward routes the incoming gradient to scattered
        //      at mask==1 slots and to input at mask==0 slots — the
        //      analytical adjoint of masked_scatter.
        //
        // For mask==0 positions, the gather index is irrelevant
        // (always masked out by where), but we still need the index
        // to be in-bounds. We pick `src_len-1` (or 0 if src_len==0
        // and n_true==0) so gather succeeds; the corresponding slot
        // in `scattered` is then discarded by where, and gather's
        // backward correctly accumulates 0 into source at those
        // positions because grad_scattered = 0 at mask==0 slots.
        // Validate dtype + device + shape contracts up-front, BEFORE
        // any fast path. The slow path delegates these checks to
        // tensor_where (cond / x / y must match dtype + device +
        // shape) and to tensor_gather (source dtype propagates
        // through reshape -> gather -> scattered). If the n_true == 0
        // fast path returns input directly without these checks,
        // mask/source mismatches would be silently accepted, making
        // validation data-dependent on mask contents (closes
        // frankentorch-zdpm).
        let input_dtype = self.tensor_tape.dtype(input)?;
        let mask_dtype = self.tensor_tape.dtype(mask)?;
        let source_dtype = self.tensor_tape.dtype(source)?;
        if mask_dtype != input_dtype || source_dtype != input_dtype {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "masked_scatter requires input, mask, and source to share dtype",
                },
            )));
        }
        let input_device = self.tensor_tape.tensor(input)?.meta().device();
        let mask_device = self.tensor_tape.tensor(mask)?.meta().device();
        let source_device = self.tensor_tape.tensor(source)?.meta().device();
        if mask_device != input_device || source_device != input_device {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "masked_scatter requires input, mask, and source to be on the same device",
                },
            )));
        }

        let mask_vals = self.tensor_tape.values(mask)?;
        let shape = self.tensor_shape(input)?;
        let input_numel =
            Self::checked_shape_numel(&shape, "masked_scatter: input shape volume overflow")?;
        if input_numel != mask_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "masked_scatter: input and mask must have same number of elements",
                },
            )));
        }

        let source_shape = self.tensor_shape(source)?;
        let source_numel = Self::checked_shape_numel(
            &source_shape,
            "masked_scatter: source shape volume overflow",
        )?;

        let n_true = mask_vals.iter().filter(|&&m| m != 0.0).count();
        if n_true > source_numel {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "masked_scatter: source doesn't have enough elements",
                },
            )));
        }

        // Empty-source fast path: source is shape-empty so its
        // gradient contract collapses to a zero-length vector that
        // cannot have come from anywhere — the autograd backward
        // produces nothing for it regardless. n_true must be 0 here
        // (validated above), so the output equals input. No gather
        // is needed and source has nothing to thread through the
        // graph.
        if source_numel == 0 {
            // n_true is provably 0 here (otherwise the size check
            // would have errored), so output == input.
            debug_assert_eq!(n_true, 0);
            return Ok(input);
        }

        // Non-empty source: thread source through the graph via the
        // gather + where composition below in BOTH n_true == 0 and
        // n_true > 0 cases. When n_true == 0, every prefix slot is
        // the safe sentinel `source_numel - 1`; gather still copies
        // those values into `scattered`, but tensor_where's all-false
        // mask discards them so the forward output equals input bit-
        // for-bit. The backward then correctly zeros source's
        // gradient (gather backward of an all-zero grad_scattered),
        // which the previous fast-path-returns-input shortcut would
        // have left as None — closes frankentorch-c4tx.
        //
        // Build the gather index: source_numel >= 1 here, so the
        // safe sentinel index 0..source_numel is in-bounds.
        let mut prefix_idx = Vec::with_capacity(input_numel);
        let mut count: usize = 0;
        let safe_off_index = source_numel - 1;
        #[allow(clippy::cast_precision_loss)]
        for &m in &mask_vals {
            if m != 0.0 {
                prefix_idx.push(count as f64);
                count += 1;
            } else {
                prefix_idx.push(safe_off_index as f64);
            }
        }

        let prefix_node = self
            .tensor_tape
            .leaf(prefix_idx, vec![input_numel], false)?;
        let source_flat = self.tensor_reshape(source, vec![source_numel])?;
        let scattered_flat = self.tensor_gather(source_flat, 0, prefix_node)?;
        let scattered = self.tensor_reshape(scattered_flat, shape.clone())?;
        self.tensor_where(mask, scattered, input)
    }

    /// Compute A^n via binary exponentiation.
    ///
    /// n > 0: repeated squaring. n = 0: identity. n < 0: inv(A)^|n|.
    pub fn tensor_matrix_power(
        &mut self,
        input: TensorNodeId,
        n: i32,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 || shape[0] != shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape,
                    rhs: vec![2],
                },
            )));
        }
        let dim = shape[0];

        if n == 0 {
            return self.eye(dim, false);
        }

        // For negative n, invert first
        let base = if n < 0 {
            self.tensor_linalg_inv(input)?
        } else {
            input
        };

        let mut exp = n.unsigned_abs();
        let mut result = self.eye(dim, false)?;
        let mut current = base;

        while exp > 0 {
            if exp & 1 == 1 {
                result = self.tensor_matmul(result, current)?;
            }
            exp >>= 1;
            if exp > 0 {
                current = self.tensor_matmul(current, current)?;
            }
        }

        Ok(result)
    }

    /// Matrix exponential: exp(A).
    ///
    /// Uses scaling-and-squaring with Padé [6/6] approximation.
    /// NOT element-wise exp — this is the matrix exponential.
    pub fn tensor_matrix_exp(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (values, meta) = self.tensor_values_meta(input)?;
        let result = ft_kernel_cpu::matrix_exp_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let shape = meta.shape().to_vec();
        self.tensor_variable(result, shape, false)
    }

    /// Eigendecomposition of a symmetric matrix: A = V @ diag(λ) @ V^T.
    ///
    /// Returns `(eigenvalues, eigenvectors)` where eigenvalues are sorted ascending
    /// and eigenvectors are the columns of V (orthonormal).
    pub fn tensor_linalg_eigh(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_eigh: autograd not supported (eigendecomposition backward not yet implemented). Tracked under frankentorch-rl4g.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let result = ft_kernel_cpu::eigh_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let n = result.n;
        let evals = self.tensor_variable(result.eigenvalues, vec![n], false)?;
        let evecs = self.tensor_variable(result.eigenvectors, vec![n, n], false)?;
        Ok((evals, evecs))
    }

    /// Compute just the eigenvalues of a symmetric matrix (sorted ascending).
    pub fn tensor_linalg_eigvalsh(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_eigvalsh: autograd not supported (eigenvalue backward not yet implemented). Tracked under frankentorch-rl4g.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let n = meta.shape()[0];
        let evals = ft_kernel_cpu::eigvalsh_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        self.tensor_variable(evals, vec![n], false)
    }

    /// Alias for `tensor_linalg_eigh`. Equivalent to deprecated `torch.eigh`.
    pub fn tensor_eigh(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        self.tensor_linalg_eigh(input)
    }

    /// Alias for `tensor_linalg_eigvalsh`. Equivalent to `torch.eigvalsh`.
    pub fn tensor_eigvalsh(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_eigvalsh(input)
    }

    /// Compute the SVD: A = U @ diag(S) @ Vh.
    ///
    /// If `full_matrices` is true, U is (m x m) and Vh is (n x n).
    /// If false (reduced), U is (m x k) and Vh is (k x n) where k = min(m,n).
    /// S is always a 1D tensor of singular values sorted descending.
    pub fn tensor_linalg_svd(
        &mut self,
        input: TensorNodeId,
        full_matrices: bool,
    ) -> Result<(TensorNodeId, TensorNodeId, TensorNodeId), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_svd: autograd not supported (SVD backward not yet implemented). Tracked under frankentorch-rl4g.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let result = ft_kernel_cpu::svd_contiguous_f64(&values, &meta, full_matrices)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let m = result.m;
        let n = result.n;
        let k = result.k;
        let u_cols = if full_matrices { m } else { k };
        let vh_rows = if full_matrices { n } else { k };
        let u_node = self.tensor_variable(result.u, vec![m, u_cols], false)?;
        let s_node = self.tensor_variable(result.s, vec![k], false)?;
        let vh_node = self.tensor_variable(result.vh, vec![vh_rows, n], false)?;
        Ok((u_node, s_node, vh_node))
    }

    /// Alias for `tensor_linalg_svd`. Equivalent to deprecated `torch.svd`.
    ///
    /// Note: PyTorch's deprecated torch.svd returns (U, S, V) where V is
    /// the transpose of Vh. This alias returns the same as linalg_svd:
    /// (U, S, Vh). For the deprecated behavior, transpose the third output.
    pub fn tensor_svd(
        &mut self,
        input: TensorNodeId,
        full_matrices: bool,
    ) -> Result<(TensorNodeId, TensorNodeId, TensorNodeId), AutogradError> {
        self.tensor_linalg_svd(input, full_matrices)
    }

    /// Compute just the singular values of a matrix.
    ///
    /// Returns a 1D tensor of singular values sorted descending.
    pub fn tensor_linalg_svdvals(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_svdvals: autograd not supported (SVD backward not yet implemented). Tracked under frankentorch-rl4g.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let input_shape = meta.shape();
        let k = input_shape[0].min(input_shape[1]);
        let s = ft_kernel_cpu::svdvals_contiguous_f64(&values, &meta)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        self.tensor_variable(s, vec![k], false)
    }

    /// Alias for `tensor_linalg_svdvals`. Equivalent to `torch.svdvals`.
    pub fn tensor_svdvals(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_svdvals(input)
    }

    /// Compute the numerical rank of a matrix.
    ///
    /// Equivalent to `torch.linalg.matrix_rank(input, tol)`. Counts the number
    /// of singular values above the tolerance threshold.
    ///
    /// If `tol` is None, uses the default tolerance:
    ///     `tol = max(m, n) * eps * max_singular_value`
    /// where eps is machine epsilon (~2.2e-16 for f64).
    ///
    /// Returns a scalar tensor (0-D) containing the rank. Does not support
    /// autograd (rank is discrete).
    pub fn tensor_matrix_rank(
        &mut self,
        input: TensorNodeId,
        tol: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "matrix_rank: input must be a 2D matrix",
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];
        let s_id = self.tensor_linalg_svdvals(input)?;
        let s_vals = self.tensor_values(s_id)?;
        let max_s = s_vals.iter().cloned().fold(0.0_f64, f64::max);
        let actual_tol = tol.unwrap_or_else(|| {
            let eps = f64::EPSILON;
            (m.max(n) as f64) * eps * max_s
        });
        let rank = s_vals.iter().filter(|&&v| v > actual_tol).count() as f64;
        self.tensor_variable(vec![rank], vec![], false)
    }

    /// Compute the determinant of a square matrix.
    ///
    /// Returns a 0-D tensor that participates in the autograd graph
    /// (matches `torch.linalg.det`). Backward via Jacobi's formula:
    ///     grad_A = grad_out * det(A) * (A^{-1})^T
    /// Singular A → backward emits zeros (gradient undefined).
    /// Tracked under frankentorch-pvfk.
    pub fn tensor_linalg_det(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 || shape[0] != shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape.clone(),
                    rhs: vec![2],
                },
            )));
        }
        let n = shape[0];
        self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, in_shape) = inputs[0];
                let meta = ft_core::TensorMeta::from_shape(
                    in_shape.to_vec(),
                    DType::F64,
                    ft_core::Device::Cpu,
                );
                let result = ft_kernel_cpu::det_contiguous_f64(vals, &meta)
                    .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
                ctx.save_for_backward(vals.to_vec(), in_shape.to_vec());
                Ok((vec![result.det], vec![]))
            },
            move |ctx, grad_outputs| {
                let g = grad_outputs[0];
                if g.len() != 1 {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "linalg_det backward: expected 0-D upstream gradient",
                        },
                    )));
                }
                let saved = ctx.saved_tensors();
                let a = &saved[0];
                if a.len() != n * n {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "linalg_det backward: saved A shape mismatch",
                        },
                    )));
                }
                let meta =
                    ft_core::TensorMeta::from_shape(vec![n, n], DType::F64, ft_core::Device::Cpu);
                let det_result = ft_kernel_cpu::det_contiguous_f64(a, &meta)
                    .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
                let inv_a = match ft_kernel_cpu::inv_tensor_contiguous_f64(a, &meta) {
                    Ok(inv) => inv,
                    Err(_) => {
                        return Ok(vec![Some(vec![0.0; n * n])]);
                    }
                };
                let scale = g[0] * det_result.det;
                let mut grad_a = vec![0.0_f64; n * n];
                for i in 0..n {
                    for j in 0..n {
                        grad_a[i * n + j] = scale * inv_a[j * n + i];
                    }
                }
                Ok(vec![Some(grad_a)])
            },
        )
    }

    pub fn tensor_det(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_det(input)
    }

    /// Compute sign and log-absolute-determinant of a square matrix.
    ///
    /// Returns `(sign, logabsdet)` as 0-D tensors where
    /// `det(A) = sign * exp(logabsdet)`. More numerically stable than
    /// `det` for large matrices. Sign is non-differentiable (constant
    /// in {-1, 0, 1}); logabsdet participates in the autograd graph.
    /// Backward of logabsdet via Jacobi's formula:
    ///     grad_A = grad_logabsdet * (A^{-1})^T
    /// Singular A → backward emits zeros. Tracked under frankentorch-pvfk.
    pub fn tensor_linalg_slogdet(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 || shape[0] != shape[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: shape.clone(),
                    rhs: vec![2],
                },
            )));
        }
        let n = shape[0];

        // Compute sign once via the kernel, return as a non-grad 0-D tensor.
        let sign_val = {
            let (vals, meta) = self.tensor_values_meta(input)?;
            let result = ft_kernel_cpu::slogdet_contiguous_f64(&vals, &meta)
                .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
            result.sign
        };
        let sign_id = self.tensor_variable(vec![sign_val], vec![], false)?;

        let logabsdet_id = self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, in_shape) = inputs[0];
                let meta = ft_core::TensorMeta::from_shape(
                    in_shape.to_vec(),
                    DType::F64,
                    ft_core::Device::Cpu,
                );
                let result = ft_kernel_cpu::slogdet_contiguous_f64(vals, &meta)
                    .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
                ctx.save_for_backward(vals.to_vec(), in_shape.to_vec());
                Ok((vec![result.logabsdet], vec![]))
            },
            move |ctx, grad_outputs| {
                let g = grad_outputs[0];
                if g.len() != 1 {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "linalg_slogdet backward: expected 0-D upstream gradient",
                        },
                    )));
                }
                let saved = ctx.saved_tensors();
                let a = &saved[0];
                if a.len() != n * n {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "linalg_slogdet backward: saved A shape mismatch",
                        },
                    )));
                }
                let meta =
                    ft_core::TensorMeta::from_shape(vec![n, n], DType::F64, ft_core::Device::Cpu);
                let inv_a = match ft_kernel_cpu::inv_tensor_contiguous_f64(a, &meta) {
                    Ok(inv) => inv,
                    Err(_) => {
                        return Ok(vec![Some(vec![0.0; n * n])]);
                    }
                };
                let scale = g[0];
                let mut grad_a = vec![0.0_f64; n * n];
                for i in 0..n {
                    for j in 0..n {
                        grad_a[i * n + j] = scale * inv_a[j * n + i];
                    }
                }
                Ok(vec![Some(grad_a)])
            },
        )?;

        Ok((sign_id, logabsdet_id))
    }

    /// Alias for `tensor_linalg_slogdet`.
    ///
    /// Equivalent to `torch.slogdet(input)`.
    pub fn tensor_slogdet(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        self.tensor_linalg_slogdet(input)
    }

    /// Compute the log-determinant of a square matrix.
    ///
    /// Equivalent to `torch.logdet(input)`. Returns `log(|det(A)|)`.
    /// This is the second element of `slogdet` and is more numerically
    /// stable than `log(det(A))` for large matrices. Returns `-inf`
    /// for singular matrices (det = 0).
    pub fn tensor_logdet(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let (_sign, logabsdet) = self.tensor_linalg_slogdet(input)?;
        Ok(logabsdet)
    }

    /// Compute the Moore-Penrose pseudoinverse via SVD.
    ///
    /// Equivalent to `torch.linalg.pinv(input)`.
    /// For a matrix A with SVD `A = U @ diag(S) @ V^T`, the pseudoinverse is
    /// `A+ = V @ diag(1/S) @ U^T` (with small singular values zeroed).
    /// `torch.pinverse(input)` parity alias for
    /// `tensor_linalg_pinv`. torch's legacy pinverse name is
    /// distinct from torch.linalg.pinv (still in wide use in
    /// older PyTorch codebases). Tracked under frankentorch-36op.
    pub fn tensor_pinverse(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_pinv(input)
    }

    pub fn tensor_linalg_pinv(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware path for full-rank A (frankentorch-d3gs):
        //   m >= n (full column rank): A^+ = (A^T A)^{-1} A^T
        //   m <= n (full row rank):    A^+ = A^T (A A^T)^{-1}
        // Both compose through tensor_transpose + tensor_matmul +
        // tensor_linalg_inv — all autograd-aware after recent fixes.
        // The SVD-based path below stays for non-grad inputs to
        // continue handling rank-deficient cases correctly. If A is
        // rank-deficient and requires_grad, the inv inside the normal
        // equations will error loud (matches torch.linalg.pinv when
        // gradient mode is on without ridge regularization).
        if self.tensor_requires_grad(input)? {
            let shape_check = self.tensor_shape(input)?;
            if shape_check.len() != 2 {
                // Migrate to InvalidDimension (frankentorch-pyl0).
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                    ft_kernel_cpu::KernelError::InvalidDimension {
                        dim: shape_check.len(),
                        ndim: 2,
                    },
                )));
            }
            let m = shape_check[0];
            let n = shape_check[1];
            let a_t = self.tensor_transpose(input, 0, 1)?;
            return if m >= n {
                // tall: A^+ = (A^T A)^{-1} A^T
                let ata = self.tensor_matmul(a_t, input)?;
                let inv_ata = self.tensor_linalg_inv(ata)?;
                self.tensor_matmul(inv_ata, a_t)
            } else {
                // wide: A^+ = A^T (A A^T)^{-1}
                let aat = self.tensor_matmul(input, a_t)?;
                let inv_aat = self.tensor_linalg_inv(aat)?;
                self.tensor_matmul(a_t, inv_aat)
            };
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-pyl0).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }
        let m = shape[0];
        let n = shape[1];

        // SVD: A = U @ diag(S) @ Vh
        let (u_id, s_id, vh_id) = self.tensor_linalg_svd(input, false)?;
        let s_vals = self.tensor_values(s_id)?;

        // Threshold: singular values below eps * max(S) * max(m,n) are treated as zero
        let max_s = s_vals.iter().cloned().fold(0.0f64, f64::max);
        let eps = f64::EPSILON * (m.max(n) as f64) * max_s;

        let k = s_vals.len();
        let s_inv: Vec<f64> = s_vals
            .iter()
            .map(|&s| if s > eps { 1.0 / s } else { 0.0 })
            .collect();

        // Build pinv = Vh^T @ diag(s_inv) @ U^T
        // Vh is [k, n], Vh^T is [n, k]
        let vh_t = self.tensor_transpose(vh_id, 0, 1)?;
        // U is [m, k], U^T is [k, m]
        let u_t = self.tensor_transpose(u_id, 0, 1)?;

        // Scale columns of Vh^T by s_inv: Vh^T @ diag(s_inv) = element-wise multiply
        let s_inv_tensor = self.tensor_variable(s_inv, vec![1, k], false)?;
        let s_inv_expanded = self.tensor_expand(s_inv_tensor, vec![n, k])?;
        let vh_t_scaled = self.tensor_mul(vh_t, s_inv_expanded)?;

        // Final: vh_t_scaled @ u_t = [n, k] @ [k, m] = [n, m]
        self.tensor_matmul(vh_t_scaled, u_t)
    }

    pub fn tensor_pinv(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_pinv(input)
    }

    /// Compute the least-squares solution to a linear matrix equation.
    ///
    /// Equivalent to `torch.linalg.lstsq(A, B)`. Computes the solution `X`
    /// that minimizes `||AX - B||_2` for an m×n matrix A and m×k matrix B.
    ///
    /// Returns only the solution X (n×k matrix). For the full output
    /// (residuals, rank, singular values), use SVD-based decomposition.
    ///
    /// Implementation: uses pseudo-inverse `X = pinv(A) @ B`.
    pub fn tensor_lstsq(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape.len() != 2 || b_shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "lstsq: A and B must be 2D matrices",
                },
            )));
        }
        if a_shape[0] != b_shape[0] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "lstsq: A and B must have the same number of rows",
                },
            )));
        }
        let a_pinv = self.tensor_pinv(a)?;
        self.tensor_matmul(a_pinv, b)
    }

    /// Return the k-th smallest element of a 1-D tensor.
    ///
    /// Equivalent to `torch.kthvalue(input, k)`.
    /// Returns `(value, index)` where value is the k-th smallest element
    /// and index is its position in the input (1-indexed k, 0-indexed index).
    pub fn tensor_kthvalue(
        &mut self,
        input: TensorNodeId,
        k: usize,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 1 {
            // Migrate to InvalidDimension (frankentorch-oitu).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 1,
                },
            )));
        }
        let vals = self.tensor_values(input)?;
        if k == 0 || k > vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "kthvalue: k must be in [1, input.size(0)]",
                },
            )));
        }

        // Sort indices by value to find rank-k position; the routing
        // index is non-differentiable but the value branch routes
        // grad_value back to that single input position. Tracked
        // under frankentorch-0juq.
        let mut indices: Vec<usize> = (0..vals.len()).collect();
        indices.sort_by(|&a, &b| vals[a].total_cmp(&vals[b]));
        let idx = indices[k - 1];
        let n = vals.len();

        let value = self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _shape) = inputs[0];
                Ok((vec![vals[idx]], vec![1]))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; n];
                grad_in[idx] = g[0];
                Ok(vec![Some(grad_in)])
            },
        )?;
        let index = self.tensor_variable(vec![idx as f64], vec![1], false)?;
        Ok((value, index))
    }

    /// Compute vector norm along a dimension.
    ///
    /// Equivalent to `torch.linalg.vector_norm(input, ord=2, dim=None)`.
    /// Supports ord: 0, 1, 2, inf, -inf, and any positive float.
    pub fn tensor_linalg_vector_norm(
        &mut self,
        input: TensorNodeId,
        ord: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose via autograd-aware primitives so gradients flow back
        // to the input. Tracked under frankentorch-4yh9. Previous body
        // extracted tensor_values and rebuilt a non-grad leaf,
        // silently severing autograd through every vector_norm call
        // (used in normalization layers, regularization, gradient
        // clipping, etc).
        let shape = self.tensor_shape(input)?;
        let numel = Self::checked_shape_numel(&shape, "vector_norm: input shape volume overflow")?;
        if numel == 0 {
            // Empty input: every norm is 0 by convention, but tracked
            // empty tensors must still keep a tape edge so backward
            // yields an empty gradient rather than failing on a fresh
            // non-grad zero leaf. Tracked under frankentorch-ivel.
            return self.tensor_apply_function(
                &[input],
                |_ctx, _inputs| Ok((vec![0.0], vec![1])),
                |_ctx, _grad_outputs| Ok(vec![Some(Vec::new())]),
            );
        }
        // Flatten so the reduction has a single axis.
        let flat = self.tensor_reshape(input, vec![numel])?;
        let abs_x = self.tensor_abs(flat)?;

        if ord == 0.0 {
            // L0 norm is non-differentiable (integer count of nonzeros).
            // Fail loud when caller asked for gradients; otherwise
            // fall back to the f64 path.
            if self.tensor_requires_grad(input)? {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "vector_norm(ord=0): autograd not supported (integer count of nonzeros is not differentiable)",
                    },
                )));
            }
            let vals = self.tensor_values(input)?;
            #[allow(clippy::cast_precision_loss)]
            let count = vals.iter().filter(|&&v| v != 0.0).count() as f64;
            return self.tensor_variable(vec![count], vec![1], false);
        }
        if ord == f64::INFINITY {
            // L_inf = max(|x|). tensor_max_dim returns (vals, idx).
            let (m, _) = self.tensor_max_dim(abs_x, 0)?;
            // Result has shape [1] already after dim-0 reduction
            // because input was 1-D — but let's normalize via reshape
            // to match the legacy [1] shape contract.
            let m_shape = self.tensor_shape(m)?;
            return if m_shape == vec![1] {
                Ok(m)
            } else {
                self.tensor_reshape(m, vec![1])
            };
        }
        if ord == f64::NEG_INFINITY {
            let (m, _) = self.tensor_min_dim(abs_x, 0)?;
            let m_shape = self.tensor_shape(m)?;
            return if m_shape == vec![1] {
                Ok(m)
            } else {
                self.tensor_reshape(m, vec![1])
            };
        }
        // General p: (sum_i |x_i|^p)^(1/p).
        let pow_p = self.tensor_pow(abs_x, ord)?;
        let summed = self.tensor_sum(pow_p)?;
        // tensor_sum returns shape [1]; tensor_pow accepts that.
        self.tensor_pow(summed, 1.0 / ord)
    }

    /// Compute the least-squares solution to a linear system A @ X = B.
    ///
    /// Equivalent to `torch.linalg.lstsq(A, B)`.
    /// Returns the solution X that minimizes ||A @ X - B||_2.
    /// A is (m, n), B is (m,) or (m, k). Returns X of shape (n,) or (n, k).
    pub fn tensor_linalg_lstsq(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;

        if a_shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-oitu).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: a_shape.len(),
                    ndim: 2,
                },
            )));
        }

        // Autograd-aware path for full-rank A (frankentorch-ea99):
        // X = A^+ @ B where A^+ = pinv(A). pinv was made autograd-
        // aware via the normal-equation formulation (frankentorch-d3gs);
        // composing matmul on top delivers gradients to both A and B.
        // The SVD path below stays for non-grad inputs to continue
        // handling rank-deficient cases.
        if self.tensor_requires_grad(a)? || self.tensor_requires_grad(b)? {
            let pinv = self.tensor_linalg_pinv(a)?;
            return if b_shape.len() == 1 {
                let n_dim = a_shape[1];
                let n_rhs = a_shape[0];
                let b_2d = self.tensor_reshape(b, vec![n_rhs, 1])?;
                let x_2d = self.tensor_matmul(pinv, b_2d)?;
                self.tensor_reshape(x_2d, vec![n_dim])
            } else {
                self.tensor_matmul(pinv, b)
            };
        }

        let m = a_shape[0];
        let n = a_shape[1];

        // Solve via SVD: X = V @ diag(1/sigma) @ U^T @ B (pseudoinverse approach)
        let (u, s, vt) = self.tensor_linalg_svd(a, false)?;
        let u_vals = self.tensor_values(u)?;
        let s_vals = self.tensor_values(s)?;
        let vt_vals = self.tensor_values(vt)?;
        let b_vals = self.tensor_values(b)?;

        let k = m.min(n); // number of singular values

        let nrhs = if b_shape.len() == 1 { 1 } else { b_shape[1] };

        // Compute U^T @ B -> (k, nrhs)
        let u_shape = self.tensor_shape(u)?;
        let u_cols = u_shape[1]; // k in reduced mode

        let mut utb = vec![0.0; u_cols * nrhs];
        for i in 0..u_cols {
            for j in 0..nrhs {
                let mut sum = 0.0;
                for r in 0..m {
                    let b_val = if b_shape.len() == 1 {
                        b_vals[r]
                    } else {
                        b_vals[r * nrhs + j]
                    };
                    sum += u_vals[r * u_cols + i] * b_val;
                }
                utb[i * nrhs + j] = sum;
            }
        }

        // Apply diag(1/sigma): divide each row i by s[i] (skip near-zero singular values)
        let eps = 1e-15 * s_vals.iter().cloned().fold(0.0_f64, f64::max);
        for i in 0..k {
            let inv_s = if s_vals[i].abs() > eps {
                1.0 / s_vals[i]
            } else {
                0.0
            };
            for j in 0..nrhs {
                utb[i * nrhs + j] *= inv_s;
            }
        }

        // Compute V @ (diag(1/s) @ U^T @ B) -> (n, nrhs)
        let vt_shape = self.tensor_shape(vt)?;
        let vt_rows = vt_shape[0]; // n in reduced mode

        let mut result = vec![0.0; n * nrhs];
        for i in 0..n {
            for j in 0..nrhs {
                let mut sum = 0.0;
                for r in 0..vt_rows.min(k) {
                    sum += vt_vals[r * n + i] * utb[r * nrhs + j];
                }
                result[i * nrhs + j] = sum;
            }
        }

        let out_shape = if b_shape.len() == 1 {
            vec![n]
        } else {
            vec![n, nrhs]
        };
        self.tensor_variable(result, out_shape, false)
    }

    /// Compute the condition number of a matrix.
    ///
    /// Equivalent to `torch.linalg.cond(A, p)`.
    /// For p=2 (default), uses the ratio of largest to smallest singular value.
    /// For p=1 or p=inf, uses norm(A) * norm(inv(A)).
    pub fn tensor_linalg_cond(
        &mut self,
        input: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-pyl0).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }

        // Compose via autograd-aware primitives so gradients flow back
        // to the input matrix. Tracked under frankentorch-dsif. The
        // previous body extracted intermediate scalar values from the
        // svdvals/norm tensors and rebuilt non-grad leaves, severing
        // autograd through every condition-number computation in a
        // training loop.
        if p == 2.0 || p == -2.0 {
            // SVD-based: cond = sigma_max / sigma_min (or reciprocal for p=-2).
            // tensor_linalg_svdvals itself does not currently backward
            // through the SVD (the kernel returns a non-grad leaf),
            // so even though tensor_narrow + tensor_div compose
            // through autograd downstream, the input gradient is still
            // severed at the svdvals boundary. Fail loud when the
            // caller asked for gradients via requires_grad — this
            // matches the parking-lot pattern used for det/slogdet
            // (frankentorch-pvfk) and stft/istft autograd guards.
            if self.tensor_requires_grad(input)? {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "linalg_cond(p=±2): autograd not supported (tensor_linalg_svdvals severs the tape); use p=1, p=-inf, p=inf, or p='fro' for gradient-aware paths",
                    },
                )));
            }
            // svdvals returns a 1-D tensor of length min(m,n) sorted
            // descending; extract first/last elements via tensor_narrow.
            let s = self.tensor_linalg_svdvals(input)?;
            let s_shape = self.tensor_shape(s)?;
            if s_shape.is_empty() || s_shape[0] == 0 {
                // Empty matrix — autograd is not meaningful here.
                return self.tensor_variable(vec![f64::NAN], vec![1], false);
            }
            let n = s_shape[0];
            let sigma_max = self.tensor_narrow(s, 0, 0, 1)?; // [1]
            let sigma_min = self.tensor_narrow(s, 0, n - 1, 1)?; // [1]
            if p == 2.0 {
                self.tensor_div(sigma_max, sigma_min)
            } else {
                self.tensor_div(sigma_min, sigma_max)
            }
        } else {
            // For other norms: cond(A) = norm(A, p) * norm(inv(A), p).
            // tensor_matrix_norm and tensor_linalg_inv are both
            // autograd-aware; just multiply the two norm tensors
            // directly instead of extracting f64 scalars.
            let ord = if p == f64::INFINITY {
                "inf"
            } else if p == f64::NEG_INFINITY {
                "-inf"
            } else if p == 1.0 {
                "1"
            } else {
                "fro"
            };
            let norm_a = self.tensor_matrix_norm(input, ord)?;
            let inv = self.tensor_linalg_inv(input)?;
            let norm_inv = self.tensor_matrix_norm(inv, ord)?;
            self.tensor_mul(norm_a, norm_inv)
        }
    }

    /// Compute the numerical rank of a matrix.
    ///
    /// Equivalent to `torch.linalg.matrix_rank(A, tol)`.
    /// Uses SVD and counts singular values above the tolerance threshold.
    pub fn tensor_linalg_matrix_rank(
        &mut self,
        input: TensorNodeId,
        tol: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            // Migrate to InvalidDimension (frankentorch-pyl0).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension {
                    dim: shape.len(),
                    ndim: 2,
                },
            )));
        }

        let s = self.tensor_linalg_svdvals(input)?;
        let s_vals = self.tensor_values(s)?;

        let threshold = match tol {
            Some(t) => t,
            None => {
                // Default: max(m, n) * eps * sigma_max
                let (m, n) = (shape[0], shape[1]);
                let sigma_max = s_vals.first().copied().unwrap_or(0.0);
                m.max(n) as f64 * f64::EPSILON * sigma_max
            }
        };

        let rank = s_vals.iter().filter(|&&sv| sv > threshold).count();
        self.tensor_variable(vec![rank as f64], vec![1], false)
    }

    /// Compute the QR decomposition: `A = Q @ R`.
    ///
    /// Returns `(Q, R)` as two separate tensor nodes.
    /// - If `reduced` is true: Q is (m x k), R is (k x n) where k = min(m, n).
    /// - If `reduced` is false: Q is (m x m), R is (m x n).
    pub fn tensor_linalg_qr(
        &mut self,
        input: TensorNodeId,
        reduced: bool,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "linalg_qr: autograd not supported (QR backward not yet implemented). Tracked under frankentorch-rl4g.",
                },
            )));
        }
        let (values, meta) = self.tensor_values_meta(input)?;
        let input_m = meta.shape()[0];
        let result = ft_kernel_cpu::qr_contiguous_f64(&values, &meta, reduced)
            .map_err(|e| AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(e)))?;
        let q_node = self.tensor_variable(result.q, vec![input_m, result.m], false)?;
        let r_node = self.tensor_variable(result.r, vec![result.m, result.n], false)?;
        Ok((q_node, r_node))
    }

    /// Alias for `tensor_linalg_qr`. Equivalent to deprecated `torch.qr`.
    pub fn tensor_qr(
        &mut self,
        input: TensorNodeId,
        some: bool,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        self.tensor_linalg_qr(input, some)
    }

    /// Compute the LU factorization of a square matrix.
    ///
    /// Equivalent to `torch.linalg.lu_factor`. Returns `(LU, pivots)` where:
    /// - LU: packed LU factorization (n x n)
    /// - pivots: pivot indices as an i64 tensor of shape [n]
    ///
    /// This is the `linalg`-prefixed version that returns pivots as a tensor
    /// for PyTorch API compatibility. Use `tensor_lu_factor` if you prefer
    /// pivots as a `Vec<usize>`.
    pub fn tensor_linalg_lu_factor(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let (lu_node, pivots_vec) = self.tensor_lu_factor(input)?;
        let n = pivots_vec.len();
        let pivots_f64: Vec<f64> = pivots_vec.iter().map(|&p| p as f64).collect();
        let pivots_node = self.tensor_variable(pivots_f64, vec![n], false)?;
        Ok((lu_node, pivots_node))
    }

    /// Compute the LU factorization with info output.
    ///
    /// Equivalent to `torch.linalg.lu_factor_ex`. Returns `(LU, pivots, info)`:
    /// - LU: packed LU factorization (n x n)
    /// - pivots: pivot indices as an i64 tensor of shape [n]
    /// - info: scalar tensor (0 if successful, otherwise indicates error)
    pub fn tensor_linalg_lu_factor_ex(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId, TensorNodeId), AutogradError> {
        let (lu_node, pivots_node) = self.tensor_linalg_lu_factor(input)?;
        let info_node = self.tensor_variable(vec![0.0], vec![1], false)?;
        Ok((lu_node, pivots_node, info_node))
    }

    /// Solve a linear system using pre-computed LU factorization.
    ///
    /// Equivalent to `torch.linalg.lu_solve`. Takes:
    /// - LU: packed LU factorization from `tensor_linalg_lu_factor`
    /// - pivots: pivot indices tensor from `tensor_linalg_lu_factor`
    /// - B: right-hand side tensor (shape [n] or [n, m])
    ///
    /// Returns the solution X such that A @ X = B.
    pub fn tensor_linalg_lu_solve(
        &mut self,
        lu: TensorNodeId,
        pivots: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let pivots_vals = self.tensor_values(pivots)?;
        let pivots_usize: Vec<usize> = pivots_vals.iter().map(|&p| p as usize).collect();
        self.tensor_lu_solve(lu, &pivots_usize, b)
    }

    /// Cross product of two 3-element vectors.
    ///
    /// Alias for `tensor_cross` to match `torch.linalg.cross`.
    pub fn tensor_linalg_cross(
        &mut self,
        input: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_cross(input, other)
    }

    /// Compute the dot product of batches of vectors.
    ///
    /// Alias for `tensor_vecdot` to match `torch.linalg.vecdot`.
    pub fn tensor_linalg_vecdot(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_vecdot(x, y)
    }

    // ── fft — FFT Helper Functions ─────────────────────────────────────────

    /// Shift the zero-frequency component to the center of the spectrum.
    ///
    /// Equivalent to `torch.fft.fftshift`. Rolls each dimension by half its size.
    /// If `dim` is None, shifts all dimensions.
    pub fn tensor_fft_fftshift(
        &mut self,
        input: TensorNodeId,
        dim: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let dims: Vec<usize> = match dim {
            Some(d) => d.to_vec(),
            None => (0..ndim).collect(),
        };
        let mut result = input;
        for &d in &dims {
            if d >= ndim {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "fft_fftshift: dimension out of range",
                    },
                )));
            }
            let shift = (shape[d] / 2) as i64;
            result = self.tensor_roll(result, shift, d)?;
        }
        Ok(result)
    }

    /// Inverse of `tensor_fft_fftshift`.
    ///
    /// Equivalent to `torch.fft.ifftshift`. For odd-length dimensions,
    /// this is NOT the same as fftshift.
    pub fn tensor_fft_ifftshift(
        &mut self,
        input: TensorNodeId,
        dim: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let dims: Vec<usize> = match dim {
            Some(d) => d.to_vec(),
            None => (0..ndim).collect(),
        };
        let mut result = input;
        for &d in &dims {
            if d >= ndim {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "fft_ifftshift: dimension out of range",
                    },
                )));
            }
            let shift = -(((shape[d] + 1) / 2) as i64);
            result = self.tensor_roll(result, shift, d)?;
        }
        Ok(result)
    }

    /// Return the Discrete Fourier Transform sample frequencies.
    ///
    /// Equivalent to `torch.fft.fftfreq(n, d)`.
    /// Returns frequencies in cycles per unit spacing: `[0, 1, ..., n/2-1, -n/2, ..., -1] / (n*d)`.
    pub fn tensor_fft_fftfreq(
        &mut self,
        n: usize,
        d: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if n == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft_fftfreq: n must be > 0",
                },
            )));
        }
        let scale = 1.0 / (n as f64 * d);
        let mut values = Vec::with_capacity(n);
        let half = (n + 1) / 2;
        for i in 0..half {
            values.push(i as f64 * scale);
        }
        for i in half..n {
            values.push((i as isize - n as isize) as f64 * scale);
        }
        self.tensor_variable(values, vec![n], false)
    }

    /// Return the Discrete Fourier Transform sample frequencies for real input.
    ///
    /// Equivalent to `torch.fft.rfftfreq(n, d)`.
    /// Returns frequencies: `[0, 1, ..., n//2] / (n*d)` (length n//2 + 1).
    pub fn tensor_fft_rfftfreq(
        &mut self,
        n: usize,
        d: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if n == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft_rfftfreq: n must be > 0",
                },
            )));
        }
        let scale = 1.0 / (n as f64 * d);
        let out_len = n / 2 + 1;
        let values: Vec<f64> = (0..out_len).map(|i| i as f64 * scale).collect();
        self.tensor_variable(values, vec![out_len], false)
    }

    // ── Signal Processing — Window Functions ───────────────────────────────

    /// Create a Hann window of size `window_length`.
    ///
    /// Equivalent to `torch.hann_window(window_length, periodic)`.
    /// The window is symmetric if `periodic=false`, periodic if `true`.
    pub fn tensor_hann_window(
        &mut self,
        window_length: usize,
        periodic: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if window_length == 0 {
            return self.tensor_variable(vec![], vec![0], false);
        }
        if window_length == 1 {
            return self.tensor_variable(vec![1.0], vec![1], false);
        }
        let n = if periodic {
            window_length
        } else {
            window_length - 1
        };
        let values: Vec<f64> = (0..window_length)
            .map(|i| {
                let cos_val = (2.0 * std::f64::consts::PI * i as f64 / n as f64).cos();
                0.5 * (1.0 - cos_val)
            })
            .collect();
        self.tensor_variable(values, vec![window_length], false)
    }

    /// Create a Hamming window of size `window_length`.
    ///
    /// Equivalent to `torch.hamming_window(window_length, periodic, alpha, beta)`.
    /// Default alpha=0.54, beta=0.46 for standard Hamming window.
    pub fn tensor_hamming_window(
        &mut self,
        window_length: usize,
        periodic: bool,
        alpha: f64,
        beta: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if window_length == 0 {
            return self.tensor_variable(vec![], vec![0], false);
        }
        if window_length == 1 {
            return self.tensor_variable(vec![1.0], vec![1], false);
        }
        let n = if periodic {
            window_length
        } else {
            window_length - 1
        };
        let values: Vec<f64> = (0..window_length)
            .map(|i| {
                let cos_val = (2.0 * std::f64::consts::PI * i as f64 / n as f64).cos();
                alpha - beta * cos_val
            })
            .collect();
        self.tensor_variable(values, vec![window_length], false)
    }

    /// Create a Blackman window of size `window_length`.
    ///
    /// Equivalent to `torch.blackman_window(window_length, periodic)`.
    pub fn tensor_blackman_window(
        &mut self,
        window_length: usize,
        periodic: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if window_length == 0 {
            return self.tensor_variable(vec![], vec![0], false);
        }
        if window_length == 1 {
            return self.tensor_variable(vec![1.0], vec![1], false);
        }
        let n = if periodic {
            window_length
        } else {
            window_length - 1
        };
        let a0 = 0.42;
        let a1 = 0.5;
        let a2 = 0.08;
        let values: Vec<f64> = (0..window_length)
            .map(|i| {
                let x = i as f64 / n as f64;
                let cos1 = (2.0 * std::f64::consts::PI * x).cos();
                let cos2 = (4.0 * std::f64::consts::PI * x).cos();
                a0 - a1 * cos1 + a2 * cos2
            })
            .collect();
        self.tensor_variable(values, vec![window_length], false)
    }

    /// Create a Bartlett window of size `window_length`.
    ///
    /// Equivalent to `torch.bartlett_window(window_length, periodic)`.
    pub fn tensor_bartlett_window(
        &mut self,
        window_length: usize,
        periodic: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if window_length == 0 {
            return self.tensor_variable(vec![], vec![0], false);
        }
        if window_length == 1 {
            return self.tensor_variable(vec![1.0], vec![1], false);
        }
        let n = if periodic {
            window_length
        } else {
            window_length - 1
        };
        let half = n as f64 / 2.0;
        let values: Vec<f64> = (0..window_length)
            .map(|i| 1.0 - ((i as f64 - half) / half).abs())
            .collect();
        self.tensor_variable(values, vec![window_length], false)
    }

    /// Create a Kaiser window of size `window_length`.
    ///
    /// Equivalent to `torch.kaiser_window(window_length, periodic, beta)`.
    /// Uses modified Bessel function I0.
    pub fn tensor_kaiser_window(
        &mut self,
        window_length: usize,
        periodic: bool,
        beta: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if window_length == 0 {
            return self.tensor_variable(vec![], vec![0], false);
        }
        if window_length == 1 {
            return self.tensor_variable(vec![1.0], vec![1], false);
        }
        let n = if periodic {
            window_length as f64
        } else {
            (window_length - 1) as f64
        };
        let denom = Self::bessel_i0(beta);
        let values: Vec<f64> = (0..window_length)
            .map(|i| {
                let x = 2.0 * i as f64 / n - 1.0;
                let arg = beta * (1.0 - x * x).sqrt();
                Self::bessel_i0(arg) / denom
            })
            .collect();
        self.tensor_variable(values, vec![window_length], false)
    }

    /// Modified Bessel function of the first kind, order 0.
    fn bessel_i0(x: f64) -> f64 {
        let ax = x.abs();
        if ax < 3.75 {
            let y = (x / 3.75).powi(2);
            1.0 + y
                * (3.5156229 + y * (3.0899424 + y * (1.2067492 + y * (0.2659732 + y * (0.0360768 + y * 0.0045813)))))
        } else {
            let y = 3.75 / ax;
            (ax.exp() / ax.sqrt())
                * (0.39894228
                    + y * (0.01328592
                        + y * (0.00225319
                            + y * (-0.00157565
                                + y * (0.00916281
                                    + y * (-0.02057706 + y * (0.02635537 + y * (-0.01647633 + y * 0.00392377))))))))
        }
    }

    fn _compute_strides(shape: &[usize]) -> Vec<usize> {
        let ndim = shape.len();
        let mut strides = vec![0usize; ndim];
        if ndim > 0 {
            strides[ndim - 1] = 1;
            for d in (0..ndim - 1).rev() {
                strides[d] = strides[d + 1] * shape[d + 1];
            }
        }
        strides
    }

    // ── nn.init — Parameter Initialization Functions ───────────────────
    //
    // These functions modify tensor values in-place for parameter initialization.
    // Unlike regular in-place ops, they bypass the requires_grad leaf validation
    // because initialization is meant to set parameter values before training.
    // This mirrors PyTorch's nn.init which uses @torch.no_grad() internally.

    /// Compute (fan_in, fan_out) for a tensor based on its shape.
    ///
    /// For 2-D tensors (Linear): fan_in = shape[1], fan_out = shape[0].
    /// For N-D tensors (Conv): fan_in = shape[1] * prod(shape[2:]),
    ///                         fan_out = shape[0] * prod(shape[2:]).
    pub fn calculate_fan_in_and_fan_out(
        &self,
        tensor: TensorNodeId,
    ) -> Result<(usize, usize), AutogradError> {
        let shape = self.tensor_shape(tensor)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "calculate_fan_in_and_fan_out requires at least 2 dimensions",
                },
            )));
        }
        let receptive_field = Self::checked_shape_numel(
            &shape[2..],
            "calculate_fan_in_and_fan_out: receptive field overflow",
        )?;
        let fan_in = Self::checked_mul(
            shape[1],
            receptive_field,
            "calculate_fan_in_and_fan_out: fan_in overflow",
        )?;
        let fan_out = Self::checked_mul(
            shape[0],
            receptive_field,
            "calculate_fan_in_and_fan_out: fan_out overflow",
        )?;
        Ok((fan_in, fan_out))
    }

    /// Fill tensor with values drawn from uniform distribution U(a, b).
    pub fn init_uniform_(
        &mut self,
        tensor: TensorNodeId,
        a: f64,
        b: f64,
    ) -> Result<(), AutogradError> {
        let numel = self.tensor_numel(tensor)?;
        let values: Vec<f64> = (0..numel)
            .map(|_| a + (b - a) * self.rng.next_f64())
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_uniform_",
            tensor,
            Some(format!("a={a} b={b}")),
        );
        Ok(())
    }

    /// Fill tensor with values drawn from normal distribution N(mean, std^2).
    pub fn init_normal_(
        &mut self,
        tensor: TensorNodeId,
        mean: f64,
        std: f64,
    ) -> Result<(), AutogradError> {
        let numel = self.tensor_numel(tensor)?;
        let values: Vec<f64> = (0..numel)
            .map(|_| mean + std * self.rng.next_normal())
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_normal_",
            tensor,
            Some(format!("mean={mean} std={std}")),
        );
        Ok(())
    }

    pub fn tensor_uniform_(
        &mut self,
        tensor: TensorNodeId,
        low: f64,
        high: f64,
    ) -> Result<(), AutogradError> {
        self.init_uniform_(tensor, low, high)
    }

    pub fn tensor_normal_(
        &mut self,
        tensor: TensorNodeId,
        mean: f64,
        std: f64,
    ) -> Result<(), AutogradError> {
        self.init_normal_(tensor, mean, std)
    }

    /// Fill tensor with exponentially distributed random values.
    ///
    /// Equivalent to `torch.Tensor.exponential_(lambd)`.
    /// Samples from Exp(lambda) with PDF: lambda * exp(-lambda * x)
    pub fn tensor_exponential_(
        &mut self,
        tensor: TensorNodeId,
        lambd: f64,
    ) -> Result<(), AutogradError> {
        if lambd <= 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "exponential_: lambda must be positive",
                },
            )));
        }
        let numel = self.tensor_numel(tensor)?;
        // Inverse CDF: -ln(1-U)/lambda, but use -ln(U)/lambda since U is uniform
        let values: Vec<f64> = (0..numel)
            .map(|_| -self.rng.next_f64().ln() / lambd)
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "exponential_",
            tensor,
            Some(format!("lambd={lambd}")),
        );
        Ok(())
    }

    /// Fill tensor with log-normally distributed random values.
    ///
    /// Equivalent to `torch.Tensor.log_normal_(mean, std)`.
    /// If X ~ N(mean, std^2), then exp(X) ~ LogNormal(mean, std).
    pub fn tensor_log_normal_(
        &mut self,
        tensor: TensorNodeId,
        mean: f64,
        std: f64,
    ) -> Result<(), AutogradError> {
        if std <= 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "log_normal_: std must be positive",
                },
            )));
        }
        let numel = self.tensor_numel(tensor)?;
        let values: Vec<f64> = (0..numel)
            .map(|_| (mean + std * self.rng.next_normal()).exp())
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "log_normal_",
            tensor,
            Some(format!("mean={mean} std={std}")),
        );
        Ok(())
    }

    /// Fill tensor with Cauchy-distributed random values.
    ///
    /// Equivalent to `torch.Tensor.cauchy_(median, sigma)`.
    /// Uses inverse CDF: median + sigma * tan(pi * (U - 0.5))
    pub fn tensor_cauchy_(
        &mut self,
        tensor: TensorNodeId,
        median: f64,
        sigma: f64,
    ) -> Result<(), AutogradError> {
        if sigma <= 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cauchy_: sigma must be positive",
                },
            )));
        }
        let numel = self.tensor_numel(tensor)?;
        let values: Vec<f64> = (0..numel)
            .map(|_| {
                let u = self.rng.next_f64();
                median + sigma * (std::f64::consts::PI * (u - 0.5)).tan()
            })
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "cauchy_",
            tensor,
            Some(format!("median={median} sigma={sigma}")),
        );
        Ok(())
    }

    /// Fill tensor with geometrically distributed random values.
    ///
    /// Equivalent to `torch.Tensor.geometric_(p)`.
    /// Number of Bernoulli trials until first success.
    pub fn tensor_geometric_(&mut self, tensor: TensorNodeId, p: f64) -> Result<(), AutogradError> {
        if p <= 0.0 || p > 1.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "geometric_: p must be in (0, 1]",
                },
            )));
        }
        let numel = self.tensor_numel(tensor)?;
        // Inverse CDF: ceil(ln(1-U) / ln(1-p))
        let log_1_minus_p = (1.0 - p).ln();
        let values: Vec<f64> = (0..numel)
            .map(|_| {
                let u = self.rng.next_f64();
                ((1.0 - u).ln() / log_1_minus_p).ceil()
            })
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("geometric_", tensor, Some(format!("p={p}")));
        Ok(())
    }

    /// Fill tensor with Poisson-distributed random values.
    ///
    /// Equivalent to `torch.poisson(input)` where each element is drawn
    /// from Poisson(lambda). Uses Knuth's algorithm for small lambda.
    pub fn tensor_poisson_(
        &mut self,
        tensor: TensorNodeId,
        lambd: f64,
    ) -> Result<(), AutogradError> {
        if lambd < 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "poisson_: lambda must be non-negative",
                },
            )));
        }
        let numel = self.tensor_numel(tensor)?;
        let l = (-lambd).exp();
        let values: Vec<f64> = (0..numel)
            .map(|_| {
                if lambd == 0.0 {
                    return 0.0;
                }
                // Knuth algorithm for Poisson sampling
                let mut k = 0i64;
                let mut p = 1.0;
                loop {
                    k += 1;
                    p *= self.rng.next_f64();
                    if p <= l {
                        break;
                    }
                }
                (k - 1) as f64
            })
            .collect();
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("poisson_", tensor, Some(format!("lambd={lambd}")));
        Ok(())
    }

    /// Sample from Poisson distribution with element-wise rates.
    ///
    /// Equivalent to `torch.poisson(rate)`. Each output element is sampled
    /// from Poisson(rate[i]). Returns a new tensor with same shape as rate.
    pub fn tensor_poisson(
        &mut self,
        rate: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(rate)?;
        let rate_vals = self.tensor_values(rate)?;
        let values: Vec<f64> = rate_vals
            .iter()
            .map(|&lambd| {
                if lambd < 0.0 {
                    return f64::NAN;
                }
                if lambd == 0.0 {
                    return 0.0;
                }
                let l = (-lambd).exp();
                let mut k = 0i64;
                let mut p = 1.0;
                loop {
                    k += 1;
                    p *= self.rng.next_f64();
                    if p <= l {
                        break;
                    }
                }
                (k - 1) as f64
            })
            .collect();
        self.tensor_variable(values, shape, false)
    }

    /// Fill tensor with a constant value.
    pub fn init_constant_(&mut self, tensor: TensorNodeId, val: f64) -> Result<(), AutogradError> {
        let numel = self.tensor_numel(tensor)?;
        let values = vec![val; numel];
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("init_constant_", tensor, Some(format!("val={val}")));
        Ok(())
    }

    /// Fill tensor with ones.
    pub fn init_ones_(&mut self, tensor: TensorNodeId) -> Result<(), AutogradError> {
        self.init_constant_(tensor, 1.0)
    }

    /// Fill tensor with zeros.
    pub fn init_zeros_(&mut self, tensor: TensorNodeId) -> Result<(), AutogradError> {
        self.init_constant_(tensor, 0.0)
    }

    /// Fill a 2-D tensor with the identity matrix.
    pub fn init_eye_(&mut self, tensor: TensorNodeId) -> Result<(), AutogradError> {
        let shape = self.tensor_shape(tensor)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_eye_ requires a 2-D tensor",
                },
            )));
        }
        let rows = shape[0];
        let cols = shape[1];
        let numel = rows * cols;
        let mut values = vec![0.0; numel];
        let min_dim = rows.min(cols);
        for i in 0..min_dim {
            values[i * cols + i] = 1.0;
        }
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("init_eye_", tensor, None);
        Ok(())
    }

    /// Fill a {3,4,5}-D tensor with the Dirac delta function.
    ///
    /// For Conv weight tensors: sets input channel == output channel filters to identity.
    pub fn init_dirac_(
        &mut self,
        tensor: TensorNodeId,
        groups: usize,
    ) -> Result<(), AutogradError> {
        let shape = self.tensor_shape(tensor)?;
        let ndim = shape.len();
        if !(3..=5).contains(&ndim) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_dirac_ requires a 3-D, 4-D, or 5-D tensor",
                },
            )));
        }
        let out_channels = shape[0];
        let in_channels = shape[1];
        if groups == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_dirac_ requires groups > 0",
                },
            )));
        }
        if out_channels % groups != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_dirac_ requires groups to evenly divide out_channels",
                },
            )));
        }
        let out_channels_per_group = out_channels / groups;
        let min_dim = out_channels_per_group.min(in_channels);
        let numel = Self::checked_shape_numel(&shape, "init_dirac_: shape volume overflow")?;
        let mut values = vec![0.0; numel];
        let spatial: Vec<usize> = shape[2..].to_vec();
        let spatial_numel =
            Self::checked_shape_numel(&spatial, "init_dirac_: spatial shape overflow")?;

        for g in 0..groups {
            for d in 0..min_dim {
                let oc = g * out_channels_per_group + d;
                let ic = d;
                // Center index in each spatial dimension
                let mut center_offset = 0usize;
                let mut stride = 1usize;
                for &s in spatial.iter().rev() {
                    let offset =
                        Self::checked_mul(s / 2, stride, "init_dirac_: center offset overflow")?;
                    center_offset = center_offset.checked_add(offset).ok_or({
                        AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "init_dirac_: center offset overflow",
                            },
                        ))
                    })?;
                    stride = Self::checked_mul(stride, s, "init_dirac_: spatial stride overflow")?;
                }
                let channel_stride = Self::checked_mul(
                    in_channels,
                    spatial_numel,
                    "init_dirac_: spatial span overflow",
                )?;
                let base =
                    Self::checked_mul(oc, channel_stride, "init_dirac_: flat index overflow")?;
                let ic_offset =
                    Self::checked_mul(ic, spatial_numel, "init_dirac_: flat index overflow")?;
                let flat_idx = base
                    .checked_add(ic_offset)
                    .and_then(|value| value.checked_add(center_offset))
                    .ok_or({
                        AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "init_dirac_: flat index overflow",
                            },
                        ))
                    })?;
                if flat_idx < numel {
                    values[flat_idx] = 1.0;
                }
            }
        }
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_dirac_",
            tensor,
            Some(format!("groups={groups}")),
        );
        Ok(())
    }

    /// Xavier (Glorot) uniform initialization.
    ///
    /// Fills with values from U(-a, a) where a = gain * sqrt(6 / (fan_in + fan_out)).
    pub fn init_xavier_uniform_(
        &mut self,
        tensor: TensorNodeId,
        gain: f64,
    ) -> Result<(), AutogradError> {
        let (fan_in, fan_out) = self.calculate_fan_in_and_fan_out(tensor)?;
        let a = gain * (6.0 / (fan_in + fan_out) as f64).sqrt();
        self.init_uniform_(tensor, -a, a)
    }

    /// Xavier (Glorot) normal initialization.
    ///
    /// Fills with values from N(0, std^2) where std = gain * sqrt(2 / (fan_in + fan_out)).
    pub fn init_xavier_normal_(
        &mut self,
        tensor: TensorNodeId,
        gain: f64,
    ) -> Result<(), AutogradError> {
        let (fan_in, fan_out) = self.calculate_fan_in_and_fan_out(tensor)?;
        let std = gain * (2.0 / (fan_in + fan_out) as f64).sqrt();
        self.init_normal_(tensor, 0.0, std)
    }

    /// Compute gain for a given nonlinearity.
    ///
    /// Returns the recommended gain factor for the given activation function.
    #[must_use]
    pub fn calculate_gain(nonlinearity: &str, param: f64) -> f64 {
        match nonlinearity {
            "linear" | "conv1d" | "conv2d" | "conv3d" | "conv_transpose1d" | "conv_transpose2d"
            | "conv_transpose3d" | "sigmoid" => 1.0,
            "tanh" => 5.0 / 3.0,
            "relu" => 2.0_f64.sqrt(),
            "leaky_relu" => (2.0 / (1.0 + param * param)).sqrt(),
            "selu" => 0.75,
            _ => 1.0,
        }
    }

    /// Kaiming (He) uniform initialization.
    ///
    /// Fills with values from U(-bound, bound) where bound = sqrt(3) * gain / sqrt(fan).
    /// `mode` is "fan_in" or "fan_out". `nonlinearity` determines the gain.
    pub fn init_kaiming_uniform_(
        &mut self,
        tensor: TensorNodeId,
        a: f64,
        mode: &str,
        nonlinearity: &str,
    ) -> Result<(), AutogradError> {
        let (fan_in, fan_out) = self.calculate_fan_in_and_fan_out(tensor)?;
        let fan = match mode {
            "fan_in" => fan_in,
            "fan_out" => fan_out,
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "init_kaiming_uniform_ mode must be 'fan_in' or 'fan_out'",
                    },
                )));
            }
        };
        let gain = Self::calculate_gain(nonlinearity, a);
        let std = gain / (fan as f64).sqrt();
        let bound = 3.0_f64.sqrt() * std;
        self.init_uniform_(tensor, -bound, bound)
    }

    /// Kaiming (He) normal initialization.
    ///
    /// Fills with values from N(0, std^2) where std = gain / sqrt(fan).
    /// `mode` is "fan_in" or "fan_out". `nonlinearity` determines the gain.
    pub fn init_kaiming_normal_(
        &mut self,
        tensor: TensorNodeId,
        a: f64,
        mode: &str,
        nonlinearity: &str,
    ) -> Result<(), AutogradError> {
        let (fan_in, fan_out) = self.calculate_fan_in_and_fan_out(tensor)?;
        let fan = match mode {
            "fan_in" => fan_in,
            "fan_out" => fan_out,
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "init_kaiming_normal_ mode must be 'fan_in' or 'fan_out'",
                    },
                )));
            }
        };
        let gain = Self::calculate_gain(nonlinearity, a);
        let std = gain / (fan as f64).sqrt();
        self.init_normal_(tensor, 0.0, std)
    }

    /// LeCun uniform initialization (for SELU activations).
    ///
    /// Fills with U(-bound, bound) where bound = sqrt(3 / fan_in).
    /// Recommended for SELU activation networks.
    pub fn init_lecun_uniform_(
        &mut self,
        tensor: TensorNodeId,
    ) -> Result<(), AutogradError> {
        let (fan_in, _) = self.calculate_fan_in_and_fan_out(tensor)?;
        let bound = (3.0 / fan_in as f64).sqrt();
        self.init_uniform_(tensor, -bound, bound)
    }

    /// LeCun normal initialization (for SELU activations).
    ///
    /// Fills with N(0, 1/fan_in). Recommended for SELU activation networks.
    pub fn init_lecun_normal_(
        &mut self,
        tensor: TensorNodeId,
    ) -> Result<(), AutogradError> {
        let (fan_in, _) = self.calculate_fan_in_and_fan_out(tensor)?;
        let std = (1.0 / fan_in as f64).sqrt();
        self.init_normal_(tensor, 0.0, std)
    }

    /// Orthogonal initialization using QR decomposition.
    ///
    /// Fills a 2-D tensor with a (semi-)orthogonal matrix. For non-square tensors,
    /// uses reduced QR decomposition.
    pub fn init_orthogonal_(
        &mut self,
        tensor: TensorNodeId,
        gain: f64,
    ) -> Result<(), AutogradError> {
        let shape = self.tensor_shape(tensor)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_orthogonal_ requires at least 2 dimensions",
                },
            )));
        }
        let rows = shape[0];
        let cols =
            Self::checked_shape_numel(&shape[1..], "init_orthogonal_: column shape overflow")?;

        // Generate a random matrix and compute QR
        let flat_shape = if rows >= cols {
            vec![rows, cols]
        } else {
            vec![cols, rows]
        };
        let random_mat = self.randn(flat_shape.clone(), false)?;
        let (q_node, r_node) = self.tensor_linalg_qr(random_mat, true)?;

        // Fix sign: make diagonal of R positive (ensures unique Q)
        let r_values = self.tensor_values(r_node)?;
        let q_values = self.tensor_values(q_node)?;
        let k = flat_shape[1]; // min(rows, cols) after our arrangement
        let n_cols_q = k;

        let mut q_fixed = q_values.clone();
        for j in 0..k {
            let r_diag = r_values[j * k + j]; // R is k x k (or k x cols)
            if r_diag < 0.0 {
                // Negate column j of Q
                for i in 0..flat_shape[0] {
                    q_fixed[i * n_cols_q + j] = -q_fixed[i * n_cols_q + j];
                }
            }
        }

        // If rows < cols, transpose Q
        let final_values = if rows < cols {
            let transposed_len =
                Self::checked_mul(rows, cols, "init_orthogonal_: transpose buffer overflow")?;
            let mut transposed = vec![0.0; transposed_len];
            for i in 0..cols {
                for j in 0..rows {
                    transposed[j * cols + i] = q_fixed[i * rows + j];
                }
            }
            transposed
        } else {
            q_fixed
        };

        // Apply gain and reshape to original tensor shape
        let numel = Self::checked_shape_numel(&shape, "init_orthogonal_: shape volume overflow")?;
        let scaled: Vec<f64> = final_values[..numel].iter().map(|&v| v * gain).collect();
        self.update_tensor_values_for_float(tensor, scaled, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_orthogonal_",
            tensor,
            Some(format!("gain={gain}")),
        );
        Ok(())
    }

    /// Sparse initialization: fill tensor with normally distributed non-zero entries.
    ///
    /// Each column has a fraction `(1 - sparsity)` of non-zero entries.
    pub fn init_sparse_(
        &mut self,
        tensor: TensorNodeId,
        sparsity: f64,
        std: f64,
    ) -> Result<(), AutogradError> {
        let shape = self.tensor_shape(tensor)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_sparse_ requires a 2-D tensor",
                },
            )));
        }
        if !(0.0..1.0).contains(&sparsity) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "init_sparse_ requires sparsity in [0, 1)",
                },
            )));
        }
        let rows = shape[0];
        let cols = shape[1];
        let num_zeros_per_col = (sparsity * rows as f64).ceil() as usize;
        let num_zeros_per_col = num_zeros_per_col.min(rows);
        let numel = Self::checked_mul(rows, cols, "init_sparse_: shape volume overflow")?;
        let mut values = vec![0.0; numel];

        // Fill with normal values, then zero out `num_zeros_per_col` entries per column
        for j in 0..cols {
            // Generate normal values for this column
            let mut col_values: Vec<f64> =
                (0..rows).map(|_| std * self.rng.next_normal()).collect();

            // Generate random indices to zero out using Fisher-Yates partial shuffle
            let mut indices: Vec<usize> = (0..rows).collect();
            for k in 0..num_zeros_per_col {
                let swap_idx = k + (self.rng.next_u64() as usize % (rows - k));
                indices.swap(k, swap_idx);
            }
            for &idx in &indices[..num_zeros_per_col] {
                col_values[idx] = 0.0;
            }

            for (i, &val) in col_values.iter().enumerate() {
                values[i * cols + j] = val;
            }
        }

        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_sparse_",
            tensor,
            Some(format!("sparsity={sparsity} std={std}")),
        );
        Ok(())
    }

    /// Initialize tensor with truncated normal distribution.
    ///
    /// Samples from N(mean, std^2) but values are clipped to [a, b] and
    /// resampled until within bounds. Common in vision transformers (ViT).
    /// Default bounds are [-2, 2] standard deviations from mean.
    pub fn init_trunc_normal_(
        &mut self,
        tensor: TensorNodeId,
        mean: f64,
        std: f64,
        a: f64,
        b: f64,
    ) -> Result<(), AutogradError> {
        if std <= 0.0 {
            return Err(Self::incompatible_tensor_args(
                "init_trunc_normal_: std must be positive",
            ));
        }
        if a >= b {
            return Err(Self::incompatible_tensor_args(
                "init_trunc_normal_: a must be less than b",
            ));
        }
        let numel = self.tensor_numel(tensor)?;
        let mut values = Vec::with_capacity(numel);
        for _ in 0..numel {
            let mut sample;
            loop {
                sample = mean + std * self.rng.next_normal();
                if sample >= a && sample <= b {
                    break;
                }
            }
            values.push(sample);
        }
        self.update_tensor_values_for_float(tensor, values, INIT_FLOAT_REASON)?;
        self.record_tensor_in_place_operation(
            "init_trunc_normal_",
            tensor,
            Some(format!("mean={mean} std={std} a={a} b={b}")),
        );
        Ok(())
    }

    // ── nan_to_num ──────────────────────────────────────────────────────
    /// Replace NaN, positive infinity, and negative infinity with specified values.
    ///
    /// Equivalent to `torch.nan_to_num(input, nan=0.0, posinf=None, neginf=None)`.
    /// When `posinf`/`neginf` are `None`, they default to the largest/smallest
    /// finite representable value for the input dtype.
    pub fn tensor_nan_to_num(
        &mut self,
        input: TensorNodeId,
        nan: f64,
        posinf: Option<f64>,
        neginf: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        let meta = self.tensor_tape.tensor_meta(input)?.clone();
        let out = match meta.dtype() {
            DType::F64 | DType::F32 => {
                // Autograd-aware path (frankentorch-vlp6 / lczj).
                // Compose through tensor_eq + tensor_isnan +
                // tensor_where so gradients flow through non-replaced
                // finite positions and are zero at NaN/±inf positions
                // where the value is replaced by a constant. PyTorch's
                // nan_to_num backward has the same behavior.
                //
                // Order: replace +inf, then -inf, then NaN. The eq
                // checks for ±inf return false against NaN
                // (NaN != anything in IEEE 754), so NaN passes
                // through unchanged until the final isnan pass
                // catches it. Without this order, an isnan-first
                // approach would still work but the eq passes would
                // consume any NaN-replaced value as a finite number
                // and double-process it.
                let (default_posinf, default_neginf) = if meta.dtype() == DType::F32 {
                    (f64::from(f32::MAX), f64::from(f32::MIN))
                } else {
                    (f64::MAX, f64::MIN)
                };
                let posinf_val = posinf.unwrap_or(default_posinf);
                let neginf_val = neginf.unwrap_or(default_neginf);

                let nan_const = self.full_like(input, nan, false)?;
                let posinf_const = self.full_like(input, posinf_val, false)?;
                let neginf_const = self.full_like(input, neginf_val, false)?;
                let posinf_compare = self.full_like(input, f64::INFINITY, false)?;
                let neginf_compare = self.full_like(input, f64::NEG_INFINITY, false)?;

                let is_posinf = self.tensor_eq(input, posinf_compare)?;
                let after_posinf = self.tensor_where(is_posinf, posinf_const, input)?;
                let is_neginf = self.tensor_eq(after_posinf, neginf_compare)?;
                let after_neginf = self.tensor_where(is_neginf, neginf_const, after_posinf)?;
                let is_nan = self.tensor_isnan(after_neginf)?;
                let out = self.tensor_where(is_nan, nan_const, after_neginf)?;

                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "nan_to_num input={} out={} dtype={:?} nan={nan} posinf={posinf_val} neginf={neginf_val} (autograd)",
                        input.0,
                        out.0,
                        meta.dtype()
                    ),
                );
                out
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: NAN_TO_NUM_FLOAT_REASON,
                    },
                )));
            }
        };
        Ok(out)
    }

    // ── logaddexp ───────────────────────────────────────────────────────
    /// Numerically stable `log(exp(a) + exp(b))`.
    ///
    /// Equivalent to `torch.logaddexp(input, other)`.
    /// Autograd-tracked: composed from existing tracked ops.
    pub fn tensor_logaddexp(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let (a_vals, a_meta) = {
            let t = self.tensor_tape.tensor(a)?;
            (t.storage()?.to_vec(), t.meta().clone())
        };
        let (b_vals, b_shape) = {
            let t = self.tensor_tape.tensor(b)?;
            (t.storage()?.to_vec(), t.meta().shape().to_vec())
        };
        if a_meta.shape() != b_shape.as_slice() {
            // Migrate to ShapeMismatch (frankentorch-c991).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_meta.shape().to_vec(),
                    rhs: b_shape,
                },
            )));
        }
        if a_vals
            .iter()
            .chain(b_vals.iter())
            .any(|value| !value.is_finite())
        {
            let out = self.tensor_logaddexp_custom(a, b, false)?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!("logaddexp a={} b={} out={} nonfinite=true", a.0, b.0, out.0),
            );
            return Ok(out);
        }

        // max(a, b) + log(exp(a - max(a,b)) + exp(b - max(a,b)))
        // = max(a,b) + log1p(exp(-|a - b|))
        let m = self.tensor_max(a, b)?;
        let a_shifted = self.tensor_sub(a, m)?;
        let b_shifted = self.tensor_sub(b, m)?;
        let exp_a = self.tensor_exp(a_shifted)?;
        let exp_b = self.tensor_exp(b_shifted)?;
        let sum_exp = self.tensor_add(exp_a, exp_b)?;
        let log_sum = self.tensor_log(sum_exp)?;
        self.tensor_add(m, log_sum)
    }

    // ── logaddexp2 ──────────────────────────────────────────────────────
    /// Numerically stable `log2(2^a + 2^b)`.
    ///
    /// Equivalent to `torch.logaddexp2(input, other)`.
    pub fn tensor_logaddexp2(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        // Direct computation: log2(2^a + 2^b)
        // = max(a,b) + log2(2^(a-max) + 2^(b-max))
        // = max(a,b) + log2(exp2(a-max) + exp2(b-max))
        let a_shape = {
            let t = self.tensor_tape.tensor(a)?;
            t.meta().shape().to_vec()
        };
        let b_shape = {
            let t = self.tensor_tape.tensor(b)?;
            t.meta().shape().to_vec()
        };

        if a_shape != b_shape {
            // Migrate to ShapeMismatch (frankentorch-c991).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: a_shape,
                    rhs: b_shape,
                },
            )));
        }

        let out = self.tensor_logaddexp_custom(a, b, true)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("logaddexp2 a={} b={} out={}", a.0, b.0, out.0),
        );
        Ok(out)
    }

    /// In-place logaddexp: target = log(exp(target) + exp(other)).
    pub fn tensor_logaddexp_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let other_vals = self.tensor_values(other)?;
        if target_vals.len() != other_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(other)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(other_vals.iter())
            .map(|(&a, &b)| Self::stable_logaddexp_value(a, b))
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("logaddexp_", target, None);
        Ok(())
    }

    /// In-place logaddexp2: target = log2(2^target + 2^other).
    pub fn tensor_logaddexp2_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let other_vals = self.tensor_values(other)?;
        if target_vals.len() != other_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(other)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(other_vals.iter())
            .map(|(&a, &b)| Self::stable_logaddexp2_value(a, b))
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("logaddexp2_", target, None);
        Ok(())
    }

    fn stable_logaddexp_value(a: f64, b: f64) -> f64 {
        if a.is_nan() || b.is_nan() {
            return f64::NAN;
        }
        let m = a.max(b);
        if m.is_infinite() {
            return m;
        }
        m + ((a - m).exp() + (b - m).exp()).ln()
    }

    fn stable_logaddexp2_value(a: f64, b: f64) -> f64 {
        if a.is_nan() || b.is_nan() {
            return f64::NAN;
        }
        let m = a.max(b);
        if m.is_infinite() {
            return m;
        }
        m + (2.0_f64.powf(a - m) + 2.0_f64.powf(b - m)).log2()
    }

    fn logaddexp_backward_weight(input: f64, output: f64, base2: bool) -> f64 {
        if base2 {
            2.0_f64.powf(input - output)
        } else {
            (input - output).exp()
        }
    }

    fn tensor_logaddexp_custom(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
        base2: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_apply_function(
            &[a, b],
            move |ctx, inputs| {
                let (a_vals, a_shape) = inputs[0];
                let (b_vals, b_shape) = inputs[1];
                if a_shape != b_shape {
                    // Migrate to ShapeMismatch (frankentorch-c991).
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                        ft_kernel_cpu::KernelError::ShapeMismatch {
                            lhs: a_shape.to_vec(),
                            rhs: b_shape.to_vec(),
                        },
                    )));
                }
                ctx.save_for_backward(a_vals.to_vec(), a_shape.to_vec());
                ctx.save_for_backward(b_vals.to_vec(), b_shape.to_vec());
                let values = a_vals
                    .iter()
                    .zip(b_vals.iter())
                    .map(|(&ai, &bi)| {
                        if base2 {
                            Self::stable_logaddexp2_value(ai, bi)
                        } else {
                            Self::stable_logaddexp_value(ai, bi)
                        }
                    })
                    .collect::<Vec<_>>();
                Ok((values, a_shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let grad_out = grad_outputs[0];
                let a_vals = &ctx.saved_tensors()[0];
                let b_vals = &ctx.saved_tensors()[1];
                if grad_out.len() != a_vals.len() || a_vals.len() != b_vals.len() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "logaddexp backward: incoming gradient length mismatch",
                        },
                    )));
                }
                let mut grad_a = Vec::with_capacity(a_vals.len());
                let mut grad_b = Vec::with_capacity(b_vals.len());
                for ((&ai, &bi), &go) in a_vals.iter().zip(b_vals.iter()).zip(grad_out.iter()) {
                    let out = if base2 {
                        Self::stable_logaddexp2_value(ai, bi)
                    } else {
                        Self::stable_logaddexp_value(ai, bi)
                    };
                    grad_a.push(go * Self::logaddexp_backward_weight(ai, out, base2));
                    grad_b.push(go * Self::logaddexp_backward_weight(bi, out, base2));
                }
                let needs_grad = ctx.needs_input_grad();
                Ok(vec![
                    needs_grad[0].then_some(grad_a),
                    needs_grad[1].then_some(grad_b),
                ])
            },
        )
    }

    // ── xlogy ───────────────────────────────────────────────────────────
    /// Compute `x * log(y)` with the convention that `0 * log(y) = 0`.
    ///
    /// Equivalent to `torch.xlogy(input, other)` / `torch.special.xlogy`.
    ///
    /// Composes through tensor_log + tensor_mul + tensor_eq +
    /// tensor_where so the autograd tape carries gradients through
    /// both x and y. Previously this extracted tensor_values and
    /// rebuilt a requires_grad=false leaf, severing the tape on
    /// tracked inputs (same severed-autograd pattern recently fixed
    /// across the activation / index_* / scatter_* family). Tracked
    /// under frankentorch-1tax.
    ///
    /// The `0 * log(y) = 0` convention is implemented via
    /// `where(x == 0, 0, x * log(y))` — when x is exactly 0, the
    /// output is 0 even if log(y) is -inf or NaN. tensor_where
    /// blocks gradients through the masked-out branch automatically.
    pub fn tensor_xlogy(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let x_shape = self.tensor_shape(x)?;
        let y_shape = self.tensor_shape(y)?;
        if x_shape != y_shape {
            // Migrate to ShapeMismatch (frankentorch-c991).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: x_shape,
                    rhs: y_shape,
                },
            )));
        }
        let log_y = self.tensor_log(y)?;
        let prod = self.tensor_mul(x, log_y)?;
        // Single zeros tensor shared between the eq mask and the
        // where-true branch (frankentorch-rbhb).
        let zeros = self.full(x_shape, 0.0, false)?;
        let mask_x_zero = self.tensor_eq(x, zeros)?;
        // xlogy(0, y) short-circuits to 0 ONLY when y is not NaN. scipy
        // and torch both leave xlogy(0, NaN) = 0*log(NaN) = NaN, so the
        // mask is (x == 0 && !isnan(y)), mirroring tensor_xlog1py
        // (frankentorch-duf7). tensor_isnan emits exact 0.0/1.0, so
        // (isnan_y == 0) is the bit-exact boolean negation.
        let isnan_y = self.tensor_isnan(y)?;
        let not_isnan_y = self.tensor_eq(isnan_y, zeros)?;
        let mask = self.tensor_mul(mask_x_zero, not_isnan_y)?;
        let out = self.tensor_where(mask, zeros, prod)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("xlogy x={} y={} out={}", x.0, y.0, out.0),
        );
        Ok(out)
    }

    /// Alias for `tensor_xlogy`. Equivalent to `torch.special.xlogy`.
    pub fn tensor_special_xlogy(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_xlogy(x, y)
    }

    /// In-place xlogy: target = target * log(other), with 0 * log(y) = 0 when y is not NaN.
    pub fn tensor_xlogy_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let target_vals = self.tensor_values(target)?;
        let other_vals = self.tensor_values(other)?;
        if target_vals.len() != other_vals.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::ShapeMismatch {
                    lhs: self.tensor_shape(target)?,
                    rhs: self.tensor_shape(other)?,
                },
            )));
        }
        let result: Vec<f64> = target_vals
            .iter()
            .zip(other_vals.iter())
            .map(|(&x, &y)| {
                if x == 0.0 && !y.is_nan() {
                    0.0
                } else {
                    x * y.ln()
                }
            })
            .collect();
        self.update_tensor_values_for_float(target, result, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("xlogy_", target, None);
        Ok(())
    }

    /// In-place xlog1py: target = target * log(1 + other).
    ///
    /// Equivalent to `torch.Tensor.xlog1py_(target, other)`.
    /// Special case: 0 * log(1 + y) = 0 regardless of y (even if y == -1).
    pub fn tensor_xlog1py_(
        &mut self,
        target: TensorNodeId,
        other: TensorNodeId,
    ) -> Result<(), AutogradError> {
        self.validate_tensor_in_place_target(target)?;
        let result = self.tensor_xlog1py(target, other)?;
        let result_vals = self.tensor_values(result)?;
        self.update_tensor_values_for_float(target, result_vals, INPLACE_FLOAT_REASON)?;
        self.record_tensor_in_place_operation("xlog1py_", target, None);
        Ok(())
    }

    // ── torch.special functions ──────────────────────────────────────────

    /// Element-wise sigmoid (expit) function: 1 / (1 + exp(-x)).
    ///
    /// Equivalent to `torch.special.expit(input)`.
    pub fn tensor_expit(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        // expit is identical to sigmoid
        self.tensor_sigmoid(input)
    }

    /// Element-wise logit function: log(x / (1 - x)).
    ///
    /// Equivalent to `torch.special.logit(input, eps)`.
    /// Values are clamped to [eps, 1 - eps] if eps is provided.
    ///
    /// Composes through tensor_clamp / tensor_sub / tensor_div /
    /// tensor_log so the autograd tape carries gradients through the
    /// input. Previously this extracted tensor_values and rebuilt a
    /// requires_grad=false leaf, severing the tape silently — same
    /// pattern recently fixed across the activation / index_* /
    /// scatter_* family. Tracked under frankentorch-1tax.
    pub fn tensor_logit(
        &mut self,
        input: TensorNodeId,
        eps: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let clamped = if let Some(e) = eps {
            self.tensor_clamp(input, e, 1.0 - e)?
        } else {
            input
        };
        // 1 - x via a constant tensor + tensor_sub. Using
        // tensor_sub_scalar would also work; the explicit
        // construction keeps autograd tracking on `clamped`.
        let ones = self.full(shape, 1.0, false)?;
        let one_minus_x = self.tensor_sub(ones, clamped)?;
        let ratio = self.tensor_div(clamped, one_minus_x)?;
        let out = self.tensor_log(ratio)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("logit in={} out={}", input.0, out.0),
        );
        Ok(out)
    }

    /// Alias for tensor_logit for torch.special.logit parity.
    ///
    /// Tracked under frankentorch-hcy0.
    pub fn tensor_special_logit(
        &mut self,
        input: TensorNodeId,
        eps: Option<f64>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_logit(input, eps)
    }

    /// Alias for tensor_sigmoid for torch.special.expit parity.
    ///
    /// expit(x) = sigmoid(x) = 1 / (1 + exp(-x))
    /// Tracked under frankentorch-hcy0.
    pub fn tensor_special_expit(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_sigmoid(input)
    }

    /// Alias for tensor_exp2 for torch.special.exp2 parity.
    ///
