    /// Element-wise entropy: -x * log(x).
    ///
    /// Equivalent to `torch.special.entr(input)`.
    /// Returns 0 when x == 0 and -inf when x < 0.
    ///
    /// Composes through tensor_neg + tensor_log + tensor_mul +
    /// tensor_eq + tensor_lt + tensor_where so the autograd tape
    /// carries gradients through the input. Previously this had a
    /// fail-loud guard rejecting tracked inputs because the body
    /// extracted values and rebuilt a requires_grad=false leaf —
    /// same severed-autograd pattern as the recent xlogy / xlog1py
    /// / logit fixes. PyTorch's torch.special.entr is differentiable
    /// on the open positive half-line. Tracked under
    /// frankentorch-1tax.
    ///
    /// Composition (nested where):
    ///     entr(x) = where(x < 0, -inf,
    ///                    where(x == 0, 0,
    ///                          -x * log(x)))
    ///
    /// Backward (chain rule on the smooth branch):
    ///     d entr / dx where x > 0 = -log(x) - 1
    /// Where x <= 0 the masks block gradient flow through the
    /// constant branches, so the gradient is zero (rather than
    /// undefined / +inf at x = 0).
    pub fn tensor_entr(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let log_x = self.tensor_log(input)?;
        let neg_input = self.tensor_neg(input)?;
        let neg_x_log_x = self.tensor_mul(neg_input, log_x)?;

        // Single zeros tensor shared across the eq mask, where-true
        // branch, and lt mask (frankentorch-x8r1) — tensor_eq /
        // tensor_where / tensor_lt only READ their operands.
        let zeros = self.full(shape.clone(), 0.0, false)?;
        let mask_zero = self.tensor_eq(input, zeros)?;
        let inner = self.tensor_where(mask_zero, zeros, neg_x_log_x)?;
        let mask_neg = self.tensor_lt(input, zeros)?;
        let neg_inf = self.full(shape, f64::NEG_INFINITY, false)?;
        let out = self.tensor_where(mask_neg, neg_inf, inner)?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("entr in={} out={}", input.0, out.0),
        );
        Ok(out)
    }

    /// Alias for `tensor_entr`. Equivalent to `torch.special.entr`.
    pub fn tensor_special_entr(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_entr(input)
    }

    /// Relative entropy (element-wise).
    ///
    /// Computes x * log(x / y) with special cases:
    /// - rel_entr(0, y) = 0 when y >= 0
    /// - rel_entr(x, y) = +inf when x > 0 and y <= 0
    /// - rel_entr(x, y) = +inf when x < 0
    ///
    /// Equivalent to `scipy.special.rel_entr`.
    pub fn tensor_rel_entr(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let zeros = self.full(shape.clone(), 0.0, false)?;
        let inf = self.full(shape.clone(), f64::INFINITY, false)?;

        // x < 0 => +inf
        let x_neg = self.tensor_lt(x, zeros)?;

        // y <= 0 AND x > 0 => +inf
        let y_le_zero = self.tensor_le(y, zeros)?;
        let x_pos = self.tensor_gt(x, zeros)?;
        let y_invalid = self.tensor_logical_and(y_le_zero, x_pos)?;

        // x == 0 => 0
        let x_eq_zero = self.tensor_eq(x, zeros)?;

        // General case: x * log(x / y)
        let ratio = self.tensor_div(x, y)?;
        let log_ratio = self.tensor_log(ratio)?;
        let x_log_ratio = self.tensor_mul(x, log_ratio)?;

        // Apply conditions: x<0 => inf, y<=0 && x>0 => inf, x==0 => 0, else x*log(x/y)
        let result = self.tensor_where(x_neg, inf, x_log_ratio)?;
        let result = self.tensor_where(y_invalid, inf, result)?;
        let result = self.tensor_where(x_eq_zero, zeros, result)?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("rel_entr x={} y={} out={}", x.0, y.0, result.0),
        );
        Ok(result)
    }

    /// Alias for `tensor_rel_entr`. Equivalent to `scipy.special.rel_entr`.
    pub fn tensor_special_rel_entr(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_rel_entr(x, y)
    }

    // ── logcumsumexp ─────────────────────────────────────────────────────
    /// Numerically stable cumulative log-sum-exp along a dimension.
    ///
    /// Equivalent to `torch.logcumsumexp(input, dim)`.
    /// Computes `log(cumsum(exp(input), dim))` in a numerically stable way.
    ///
    /// Wraps the stable forward in a `tensor_apply_function` so that
    /// the autograd tape carries gradients through the input. The
    /// analytical derivative for `y[i] = log(sum_{j<=i} exp(x[j]))` is
    ///     dy[i]/dx[k] = exp(x[k] - y[i])  if k <= i, else 0
    /// so the vector–Jacobian product is
    ///     dL/dx[k] = sum_{i>=k} dL/dy[i] * exp(x[k] - y[i])
    /// which is bounded since `x[k] <= y[i]` for `i >= k`. Both `x`
    /// and `y` are saved for backward. Tracked under
    /// frankentorch-1tax — same severed-autograd pattern recently
    /// fixed for gammaln / digamma / polygamma / multigammaln /
    /// erfinv.
    pub fn tensor_logcumsumexp(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        // Validate dim up front before delegating to apply_function so
        // the error path matches the previous fail-loud behavior.
        let ndim = self.tensor_tape.tensor(input)?.meta().shape().len();
        if dim >= ndim {
            // Surface actual (dim, ndim) via the dynamic-diagnostic
            // pattern (frankentorch-ovad).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }

        let out = self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, shape) = inputs[0];

                let outer_size =
                    Self::checked_shape_numel(&shape[..dim], "logcumsumexp: outer shape overflow")?;
                let dim_size = shape[dim];
                let inner_size = Self::checked_shape_numel(
                    &shape[dim + 1..],
                    "logcumsumexp: inner shape overflow",
                )?;

                let mut result = vec![0.0_f64; vals.len()];
                for outer in 0..outer_size {
                    for inner in 0..inner_size {
                        let mut running_max = f64::NEG_INFINITY;
                        let mut running_sum = 0.0_f64;
                        for d in 0..dim_size {
                            let idx = outer * dim_size * inner_size + d * inner_size + inner;
                            let val = vals[idx];
                            if val > running_max {
                                running_sum = running_sum * (running_max - val).exp() + 1.0;
                                running_max = val;
                            } else {
                                running_sum += (val - running_max).exp();
                            }
                            result[idx] = running_max + running_sum.ln();
                        }
                    }
                }

                // Save x, then y, both as flat tensors with the full
                // shape — the backward needs to walk the same dim.
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                ctx.save_for_backward(result.clone(), shape.to_vec());
                Ok((result, shape.to_vec()))
            },
            move |ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let saved_shapes = ctx.saved_shapes();
                let x_vals = &saved[0];
                let y_vals = &saved[1];
                let shape = &saved_shapes[0];

                if grad_y.len() != y_vals.len() {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "logcumsumexp backward: incoming gradient length mismatch",
                        },
                    )));
                }

                let outer_size = Self::checked_shape_numel(
                    &shape[..dim],
                    "logcumsumexp backward: outer shape overflow",
                )?;
                let dim_size = shape[dim];
                let inner_size = Self::checked_shape_numel(
                    &shape[dim + 1..],
                    "logcumsumexp backward: inner shape overflow",
                )?;

                let mut grad_x = vec![0.0_f64; x_vals.len()];
                for outer in 0..outer_size {
                    for inner in 0..inner_size {
                        // Reverse cumulative form: walk the dim
                        // backwards accumulating dL/dy[i] * exp(-y[i])
                        // and at each k multiply by exp(x[k]). All
                        // values of `x[k] - y[i]` are <= 0, so no
                        // overflow; underflow goes to 0 correctly.
                        // We use the direct O(D^2) sum to avoid the
                        // precision pitfalls of an explicit reverse
                        // cumsum of `grad_y[i] * exp(-y[i])` when
                        // y[i] is large.
                        for k in 0..dim_size {
                            let k_idx = outer * dim_size * inner_size + k * inner_size + inner;
                            let xk = x_vals[k_idx];
                            let mut acc = 0.0_f64;
                            for i in k..dim_size {
                                let i_idx = outer * dim_size * inner_size + i * inner_size + inner;
                                let yi = y_vals[i_idx];
                                acc += grad_y[i_idx] * (xk - yi).exp();
                            }
                            grad_x[k_idx] = acc;
                        }
                    }
                }

                Ok(vec![Some(grad_x)])
            },
        )?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("logcumsumexp input={} dim={dim} out={}", input.0, out.0),
        );
        Ok(out)
    }

    // ── rot90 ───────────────────────────────────────────────────────────
    /// Rotate a tensor by 90 degrees in the plane specified by `dims`.
    ///
    /// Equivalent to `torch.rot90(input, k, dims)`.
    /// `k` is the number of times to rotate (may be negative).
    /// `dims` must be a pair `[d0, d1]` specifying the rotation plane.
    pub fn tensor_rot90(
        &mut self,
        input: TensorNodeId,
        k: i32,
        dims: [usize; 2],
    ) -> Result<TensorNodeId, AutogradError> {
        let ndim = {
            let tensor = self.tensor_tape.tensor(input)?;
            tensor.meta().shape().len()
        };

        if dims[0] == dims[1] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rot90: dims must specify two different dimensions",
                },
            )));
        }
        if dims[0] >= ndim || dims[1] >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rot90: dimension index out of range",
                },
            )));
        }

        // Normalize k to [0, 4)
        let k = k.rem_euclid(4);

        match k {
            0 => {
                // No rotation — return a clone preserving grad behavior
                let requires_grad = self.tensor_tape.tensor_requires_grad(input)?;
                self.tensor_clone(input, requires_grad)
            }
            1 => {
                // 90° rotation: flip(transpose(input, d0, d1), d0)
                let transposed = self.tensor_transpose(input, dims[0], dims[1])?;
                self.tensor_flip(transposed, &[dims[0]])
            }
            2 => {
                // 180° rotation: flip along both dims
                let flipped = self.tensor_flip(input, &[dims[0]])?;
                self.tensor_flip(flipped, &[dims[1]])
            }
            3 => {
                // 270° rotation: flip(transpose(input, d0, d1), d1)
                let transposed = self.tensor_transpose(input, dims[0], dims[1])?;
                self.tensor_flip(transposed, &[dims[1]])
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rot90: normalized k out of range",
                },
            ))),
        }
    }

    // ── pixel_shuffle ───────────────────────────────────────────────────
    /// Rearrange elements from channels into spatial dimensions.
    ///
    /// Equivalent to `torch.nn.functional.pixel_shuffle(input, upscale_factor)`.
    /// Input shape: `(N, C * r^2, H, W)` → Output: `(N, C, H*r, W*r)`
    pub fn tensor_pixel_shuffle(
        &mut self,
        input: TensorNodeId,
        upscale_factor: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = {
            let t = self.tensor_tape.tensor(input)?;
            t.meta().shape().to_vec()
        };

        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pixel_shuffle: input must be a 4-D tensor (N, C, H, W)",
                },
            )));
        }

        let (batch, channels, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let r = upscale_factor;
        if r == 0 {
            return Err(Self::incompatible_tensor_args(
                "pixel_shuffle: upscale_factor must be greater than zero",
            ));
        }
        let r_squared = Self::checked_mul(r, r, "pixel_shuffle: upscale_factor squared overflow")?;

        if channels % r_squared != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pixel_shuffle: channels must be divisible by upscale_factor^2",
                },
            )));
        }

        let oc = channels / r_squared;
        let out_h = Self::checked_mul(h, r, "pixel_shuffle: output height overflow")?;
        let out_w = Self::checked_mul(w, r, "pixel_shuffle: output width overflow")?;

        // reshape to (N, C, r, r, H, W)
        let reshaped = self.tensor_reshape(input, vec![batch, oc, r, r, h, w])?;
        // permute to (N, C, H, r, W, r)
        let permuted = self.tensor_permute(reshaped, vec![0, 1, 4, 2, 5, 3])?;
        // reshape to (N, C, H*r, W*r)
        self.tensor_reshape(permuted, vec![batch, oc, out_h, out_w])
    }

    // ── pixel_unshuffle ─────────────────────────────────────────────────
    /// Reverse of pixel_shuffle: rearrange spatial dimensions into channels.
    ///
    /// Equivalent to `torch.nn.functional.pixel_unshuffle(input, downscale_factor)`.
    /// Input shape: `(N, C, H*r, W*r)` → Output: `(N, C * r^2, H, W)`
    pub fn tensor_pixel_unshuffle(
        &mut self,
        input: TensorNodeId,
        downscale_factor: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = {
            let t = self.tensor_tape.tensor(input)?;
            t.meta().shape().to_vec()
        };

        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pixel_unshuffle: input must be a 4-D tensor (N, C, H, W)",
                },
            )));
        }

        let (batch, channels, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let r = downscale_factor;
        if r == 0 {
            return Err(Self::incompatible_tensor_args(
                "pixel_unshuffle: downscale_factor must be greater than zero",
            ));
        }
        let r_squared =
            Self::checked_mul(r, r, "pixel_unshuffle: downscale_factor squared overflow")?;

        if h % r != 0 || w % r != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "pixel_unshuffle: H and W must be divisible by downscale_factor",
                },
            )));
        }

        let oh = h / r;
        let ow = w / r;
        let out_channels = Self::checked_mul(
            channels,
            r_squared,
            "pixel_unshuffle: output channel count overflow",
        )?;

        // reshape to (N, C, H/r, r, W/r, r)
        let reshaped = self.tensor_reshape(input, vec![batch, channels, oh, r, ow, r])?;
        // permute to (N, C, r, r, H/r, W/r)
        let permuted = self.tensor_permute(reshaped, vec![0, 1, 3, 5, 2, 4])?;
        // reshape to (N, C*r*r, H/r, W/r)
        self.tensor_reshape(permuted, vec![batch, out_channels, oh, ow])
    }

    /// Rearrange channels by splitting into groups and interleaving.
    ///
    /// Equivalent to `torch.nn.functional.channel_shuffle(input, groups)`.
    /// Input shape: `(N, C, H, W)` where C must be divisible by groups.
    /// Tracked under frankentorch-gwqo.
    pub fn tensor_channel_shuffle(
        &mut self,
        input: TensorNodeId,
        groups: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "channel_shuffle: input must be a 4-D tensor (N, C, H, W)",
                },
            )));
        }

        let (batch, channels, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        if groups == 0 || channels % groups != 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "channel_shuffle: channels must be divisible by groups",
                },
            )));
        }

        let channels_per_group = channels / groups;

        // reshape to (N, groups, channels_per_group, H, W)
        let reshaped = self.tensor_reshape(input, vec![batch, groups, channels_per_group, h, w])?;
        // transpose to (N, channels_per_group, groups, H, W)
        let transposed = self.tensor_permute(reshaped, vec![0, 2, 1, 3, 4])?;
        // reshape back to (N, C, H, W)
        self.tensor_reshape(transposed, vec![batch, channels, h, w])
    }

    // ── F.interpolate ────────────────────────────────────────────────────

    /// Interpolate (resize) a tensor using the specified mode.
    ///
    /// Equivalent to `torch.nn.functional.interpolate(input, size, scale_factor, mode, align_corners)`.
    ///
    /// Supports:
    /// - 3-D input `[N, C, L]` (temporal): nearest, linear
    /// - 4-D input `[N, C, H, W]` (spatial): nearest, bilinear, bicubic
    /// - 5-D input `[N, C, D, H, W]` (volumetric): nearest, trilinear
    ///
    /// Either `size` or `scale_factor` must be provided (not both).
    /// `align_corners` applies only to linear/bilinear/bicubic/trilinear modes.
    pub fn tensor_interpolate(
        &mut self,
        input: TensorNodeId,
        size: Option<Vec<usize>>,
        scale_factor: Option<Vec<f64>>,
        mode: &str,
        align_corners: Option<bool>,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware path for `mode="nearest"` (frankentorch-ov0v):
        // nearest interpolation is just a structured index_select per
        // spatial axis, so we can flatten the input to [N*C, Hin*Win*...],
        // compute the source-position index for each output position,
        // and tensor_index_select. Other modes (linear/bilinear/etc.)
        // need bespoke backwards via index_select + weighted sums; for
        // now, fail loud on requires_grad input to surface the silent
        // severance that the legacy plain-f64 path produced.
        let requires_grad = self.tensor_requires_grad(input)?;

        let (storage, meta) = {
            let tensor = self.tensor_tape.tensor(input)?;
            (tensor.storage()?.to_vec(), tensor.meta().clone())
        };
        let shape = meta.shape();
        let ndim = shape.len();

        if !(3..=5).contains(&ndim) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "interpolate: input must be 3-D, 4-D, or 5-D",
                },
            )));
        }

        if size.is_some() && scale_factor.is_some() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "interpolate: only one of size or scale_factor should be defined",
                },
            )));
        }

        let spatial_dims = ndim - 2;
        let in_spatial: Vec<usize> = shape[2..].to_vec();
        if in_spatial.contains(&0) {
            return Err(Self::incompatible_tensor_args(
                "interpolate: input spatial dimensions must be > 0",
            ));
        }

        let out_spatial: Vec<usize> = if let Some(ref s) = size {
            if s.len() != spatial_dims {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "interpolate: size length must match spatial dimensions",
                    },
                )));
            }
            if s.contains(&0) {
                return Err(Self::incompatible_tensor_args(
                    "interpolate: output spatial dimensions must be > 0",
                ));
            }
            s.clone()
        } else if let Some(ref sf) = scale_factor {
            if sf.len() != spatial_dims {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "interpolate: scale_factor length must match spatial dimensions",
                    },
                )));
            }
            in_spatial
                .iter()
                .zip(sf.iter())
                .map(|(&d, &s)| Self::checked_interpolate_scale_dim(d, s))
                .collect::<Result<Vec<_>, _>>()?
        } else {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "interpolate: either size or scale_factor must be provided",
                },
            )));
        };

        let batch = shape[0];
        let channels = shape[1];
        let mut checked_out_shape = vec![batch, channels];
        checked_out_shape.extend_from_slice(&out_spatial);
        let out_numel =
            Self::checked_shape_numel(&checked_out_shape, "interpolate: output size overflow")?;
        let _ = Self::checked_mul(
            out_numel,
            std::mem::size_of::<f64>(),
            "interpolate: output size overflow",
        )?;
        let align = align_corners.unwrap_or(false);

        match mode {
            "nearest" => {
                if requires_grad {
                    self.interpolate_nearest_autograd(
                        input,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                    )
                } else {
                    self.interpolate_nearest(&storage, batch, channels, &in_spatial, &out_spatial)
                }
            }
            "linear" if spatial_dims == 1 => {
                if requires_grad {
                    self.interpolate_linear_1d_autograd(
                        input,
                        batch,
                        channels,
                        in_spatial[0],
                        out_spatial[0],
                        align,
                    )
                } else {
                    self.interpolate_linear_1d(
                        &storage,
                        batch,
                        channels,
                        in_spatial[0],
                        out_spatial[0],
                        align,
                    )
                }
            }
            "bilinear" if spatial_dims == 2 => {
                if requires_grad {
                    self.interpolate_bilinear_autograd(
                        input,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                } else {
                    self.interpolate_bilinear(
                        &storage,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                }
            }
            "bicubic" if spatial_dims == 2 => {
                if requires_grad {
                    self.interpolate_bicubic_autograd(
                        input,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                } else {
                    self.interpolate_bicubic(
                        &storage,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                }
            }
            "trilinear" if spatial_dims == 3 => {
                if requires_grad {
                    self.interpolate_trilinear_autograd(
                        input,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                } else {
                    self.interpolate_trilinear(
                        &storage,
                        batch,
                        channels,
                        &in_spatial,
                        &out_spatial,
                        align,
                    )
                }
            }
            _ => Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "interpolate: unsupported mode for given input dimensionality",
                },
            ))),
        }
    }

    fn interpolate_nearest_autograd(
        &mut self,
        input: TensorNodeId,
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware nearest interpolation via tensor_index_select
        // along the flattened spatial axis. Tracked under
        // frankentorch-ov0v.
        //
        // Build a flat source-index array of length out_numel: each
        // output position is mapped to a source spatial position
        // computed as floor(out_pos * in_dim / out_dim) per axis.
        // Then reshape input to [N*C, in_numel], gather the source
        // positions along dim 1, and reshape back to
        // [N, C, *out_spatial].
        let bc = Self::checked_mul(batch, channels, "interpolate: bc overflow")?;
        let in_numel =
            Self::checked_shape_numel(in_spatial, "interpolate: input spatial shape overflow")?;
        let out_numel =
            Self::checked_shape_numel(out_spatial, "interpolate: output spatial shape overflow")?;
        let mut idx_vals: Vec<f64> = Vec::with_capacity(out_numel);
        match in_spatial.len() {
            1 => {
                let (i_l, o_l) = (in_spatial[0], out_spatial[0]);
                for oi in 0..o_l {
                    let ii = ((oi as f64 * i_l as f64 / o_l as f64).floor() as usize).min(i_l - 1);
                    #[allow(clippy::cast_precision_loss)]
                    idx_vals.push(ii as f64);
                }
            }
            2 => {
                let (i_h, i_w) = (in_spatial[0], in_spatial[1]);
                let (o_h, o_w) = (out_spatial[0], out_spatial[1]);
                for oy in 0..o_h {
                    let iy = ((oy as f64 * i_h as f64 / o_h as f64).floor() as usize).min(i_h - 1);
                    for ox in 0..o_w {
                        let ix =
                            ((ox as f64 * i_w as f64 / o_w as f64).floor() as usize).min(i_w - 1);
                        #[allow(clippy::cast_precision_loss)]
                        idx_vals.push((iy * i_w + ix) as f64);
                    }
                }
            }
            3 => {
                let (i_d, i_h, i_w) = (in_spatial[0], in_spatial[1], in_spatial[2]);
                let (o_d, o_h, o_w) = (out_spatial[0], out_spatial[1], out_spatial[2]);
                for oz in 0..o_d {
                    let iz = ((oz as f64 * i_d as f64 / o_d as f64).floor() as usize).min(i_d - 1);
                    for oy in 0..o_h {
                        let iy =
                            ((oy as f64 * i_h as f64 / o_h as f64).floor() as usize).min(i_h - 1);
                        for ox in 0..o_w {
                            let ix = ((ox as f64 * i_w as f64 / o_w as f64).floor() as usize)
                                .min(i_w - 1);
                            #[allow(clippy::cast_precision_loss)]
                            idx_vals.push((iz * i_h * i_w + iy * i_w + ix) as f64);
                        }
                    }
                }
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "interpolate: nearest supports only 1-D, 2-D, or 3-D inputs",
                    },
                )));
            }
        }

        let idx_node = self.tensor_variable(idx_vals, vec![out_numel], false)?;
        let flat_input = self.tensor_reshape(input, vec![bc, in_numel])?;
        let gathered = self.tensor_index_select(flat_input, 1, idx_node)?;
        let mut out_shape = vec![batch, channels];
        out_shape.extend_from_slice(out_spatial);
        self.tensor_reshape(gathered, out_shape)
    }

    /// Compute the per-output-position source coordinate for linear /
    /// bilinear / trilinear interpolation. Returns a (low, high, frac)
    /// tuple where `low` is floor(src) clamped to [0, in-1], `high` is
    /// (low+1) clamped, and `frac = src - low`. Matches the alignment
    /// formulas in interpolate_linear_1d / interpolate_bilinear /
    /// interpolate_trilinear so the autograd path is bit-exact with
    /// the legacy plain-f64 path.
    fn interp_axis_coord(
        in_dim: usize,
        out_dim: usize,
        out_idx: usize,
        align_corners: bool,
    ) -> (usize, usize, f64) {
        let src = if align_corners && out_dim > 1 {
            out_idx as f64 * (in_dim - 1) as f64 / (out_dim - 1) as f64
        } else {
            (out_idx as f64 + 0.5) * in_dim as f64 / out_dim as f64 - 0.5
        };
        let src = src.max(0.0);
        let lo = (src.floor() as usize).min(in_dim - 1);
        let hi = (lo + 1).min(in_dim - 1);
        let t = src - lo as f64;
        (lo, hi, t)
    }

    fn interpolate_linear_1d_autograd(
        &mut self,
        input: TensorNodeId,
        batch: usize,
        channels: usize,
        in_len: usize,
        out_len: usize,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware 1-D linear interpolation via two
        // index_selects + a weighted blend. Tracked under
        // frankentorch-3t1t. Each output position is a convex
        // combination of two input positions:
        //   y[oi] = (1-t)*x[lo] + t*x[hi]
        let bc = Self::checked_mul(
            batch,
            channels,
            "interpolate_linear_1d_autograd: bc overflow",
        )?;
        let mut idx_lo: Vec<f64> = Vec::with_capacity(out_len);
        let mut idx_hi: Vec<f64> = Vec::with_capacity(out_len);
        let mut w_lo: Vec<f64> = Vec::with_capacity(out_len);
        let mut w_hi: Vec<f64> = Vec::with_capacity(out_len);
        for oi in 0..out_len {
            let (lo, hi, t) = Self::interp_axis_coord(in_len, out_len, oi, align_corners);
            #[allow(clippy::cast_precision_loss)]
            {
                idx_lo.push(lo as f64);
                idx_hi.push(hi as f64);
            }
            w_lo.push(1.0 - t);
            w_hi.push(t);
        }
        let flat = self.tensor_reshape(input, vec![bc, in_len])?;
        let lo_idx = self.tensor_variable(idx_lo, vec![out_len], false)?;
        let hi_idx = self.tensor_variable(idx_hi, vec![out_len], false)?;
        let lo_g = self.tensor_index_select(flat, 1, lo_idx)?;
        let hi_g = self.tensor_index_select(flat, 1, hi_idx)?;
        let lo_w = self.tensor_variable(w_lo, vec![1, out_len], false)?;
        let hi_w = self.tensor_variable(w_hi, vec![1, out_len], false)?;
        let lo_w_b = self.tensor_expand(lo_w, vec![bc, out_len])?;
        let hi_w_b = self.tensor_expand(hi_w, vec![bc, out_len])?;
        let lo_term = self.tensor_mul(lo_g, lo_w_b)?;
        let hi_term = self.tensor_mul(hi_g, hi_w_b)?;
        let summed = self.tensor_add(lo_term, hi_term)?;
        self.tensor_reshape(summed, vec![batch, channels, out_len])
    }

    fn interpolate_bilinear_autograd(
        &mut self,
        input: TensorNodeId,
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware 2-D bilinear interpolation via four
        // index_selects of the four corner pixels per output position,
        // then a weighted blend. Tracked under frankentorch-3t1t.
        //   y[oh, ow] = (1-ty)*(1-tx)*x[y0, x0] + (1-ty)*tx*x[y0, x1]
        //             + ty*(1-tx)*x[y1, x0] + ty*tx*x[y1, x1]
        let (ih, iw) = (in_spatial[0], in_spatial[1]);
        let (oh, ow) = (out_spatial[0], out_spatial[1]);
        let bc = Self::checked_mul(
            batch,
            channels,
            "interpolate_bilinear_autograd: bc overflow",
        )?;
        let in_numel =
            Self::checked_mul(ih, iw, "interpolate_bilinear_autograd: in_numel overflow")?;
        let out_numel =
            Self::checked_mul(oh, ow, "interpolate_bilinear_autograd: out_numel overflow")?;
        let mut idx_00: Vec<f64> = Vec::with_capacity(out_numel);
        let mut idx_01: Vec<f64> = Vec::with_capacity(out_numel);
        let mut idx_10: Vec<f64> = Vec::with_capacity(out_numel);
        let mut idx_11: Vec<f64> = Vec::with_capacity(out_numel);
        let mut w_00: Vec<f64> = Vec::with_capacity(out_numel);
        let mut w_01: Vec<f64> = Vec::with_capacity(out_numel);
        let mut w_10: Vec<f64> = Vec::with_capacity(out_numel);
        let mut w_11: Vec<f64> = Vec::with_capacity(out_numel);
        for oy in 0..oh {
            let (y0, y1, ty) = Self::interp_axis_coord(ih, oh, oy, align_corners);
            for ox in 0..ow {
                let (x0, x1, tx) = Self::interp_axis_coord(iw, ow, ox, align_corners);
                #[allow(clippy::cast_precision_loss)]
                {
                    idx_00.push((y0 * iw + x0) as f64);
                    idx_01.push((y0 * iw + x1) as f64);
                    idx_10.push((y1 * iw + x0) as f64);
                    idx_11.push((y1 * iw + x1) as f64);
                }
                w_00.push((1.0 - ty) * (1.0 - tx));
                w_01.push((1.0 - ty) * tx);
                w_10.push(ty * (1.0 - tx));
                w_11.push(ty * tx);
            }
        }
        let flat = self.tensor_reshape(input, vec![bc, in_numel])?;
        let mut acc: Option<TensorNodeId> = None;
        for (idx_vec, w_vec) in [
            (idx_00, w_00),
            (idx_01, w_01),
            (idx_10, w_10),
            (idx_11, w_11),
        ] {
            let idx_n = self.tensor_variable(idx_vec, vec![out_numel], false)?;
            let g = self.tensor_index_select(flat, 1, idx_n)?;
            let w_n = self.tensor_variable(w_vec, vec![1, out_numel], false)?;
            let w_b = self.tensor_expand(w_n, vec![bc, out_numel])?;
            let term = self.tensor_mul(g, w_b)?;
            acc = Some(match acc {
                Some(a) => self.tensor_add(a, term)?,
                None => term,
            });
        }
        let summed = acc.expect("bilinear has at least one corner");
        self.tensor_reshape(summed, vec![batch, channels, oh, ow])
    }

    fn interpolate_trilinear_autograd(
        &mut self,
        input: TensorNodeId,
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware 3-D trilinear interpolation: 8 corner
        // index_selects and a 3-axis weighted blend. Tracked under
        // frankentorch-3t1t.
        let (id, ih, iw) = (in_spatial[0], in_spatial[1], in_spatial[2]);
        let (od, oh, ow) = (out_spatial[0], out_spatial[1], out_spatial[2]);
        let bc = Self::checked_mul(
            batch,
            channels,
            "interpolate_trilinear_autograd: bc overflow",
        )?;
        let plane = Self::checked_mul(ih, iw, "interpolate_trilinear_autograd: plane overflow")?;
        let in_numel = Self::checked_mul(
            id,
            plane,
            "interpolate_trilinear_autograd: in_numel overflow",
        )?;
        let out_plane =
            Self::checked_mul(oh, ow, "interpolate_trilinear_autograd: out_plane overflow")?;
        let out_numel = Self::checked_mul(
            od,
            out_plane,
            "interpolate_trilinear_autograd: out_numel overflow",
        )?;
        // Eight corners, each gets an index array and a weight array.
        let mut corners: Vec<(Vec<f64>, Vec<f64>)> = (0..8)
            .map(|_| (Vec::with_capacity(out_numel), Vec::with_capacity(out_numel)))
            .collect();
        for oz in 0..od {
            let (z0, z1, tz) = Self::interp_axis_coord(id, od, oz, align_corners);
            for oy in 0..oh {
                let (y0, y1, ty) = Self::interp_axis_coord(ih, oh, oy, align_corners);
                for ox in 0..ow {
                    let (x0, x1, tx) = Self::interp_axis_coord(iw, ow, ox, align_corners);
                    let zs = [z0, z1];
                    let ys = [y0, y1];
                    let xs = [x0, x1];
                    let tzs = [1.0 - tz, tz];
                    let tys = [1.0 - ty, ty];
                    let txs = [1.0 - tx, tx];
                    for (ci, corner) in corners.iter_mut().enumerate() {
                        let zi = (ci >> 2) & 1;
                        let yi = (ci >> 1) & 1;
                        let xi = ci & 1;
                        let pos = zs[zi] * plane + ys[yi] * iw + xs[xi];
                        #[allow(clippy::cast_precision_loss)]
                        corner.0.push(pos as f64);
                        corner.1.push(tzs[zi] * tys[yi] * txs[xi]);
                    }
                }
            }
        }
        let flat = self.tensor_reshape(input, vec![bc, in_numel])?;
        let mut acc: Option<TensorNodeId> = None;
        for (idx_vec, w_vec) in corners {
            let idx_n = self.tensor_variable(idx_vec, vec![out_numel], false)?;
            let g = self.tensor_index_select(flat, 1, idx_n)?;
            let w_n = self.tensor_variable(w_vec, vec![1, out_numel], false)?;
            let w_b = self.tensor_expand(w_n, vec![bc, out_numel])?;
            let term = self.tensor_mul(g, w_b)?;
            acc = Some(match acc {
                Some(a) => self.tensor_add(a, term)?,
                None => term,
            });
        }
        let summed = acc.expect("trilinear has 8 corners");
        self.tensor_reshape(summed, vec![batch, channels, od, oh, ow])
    }

    fn interpolate_bicubic_autograd(
        &mut self,
        input: TensorNodeId,
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        // Autograd-aware 2-D bicubic interpolation: 16 corner
        // index_selects (4 per axis) with cubic-Hermite weights.
        // Tracked under frankentorch-tm8j. Forward result agrees
        // bit-exactly with the legacy plain-f64 path because the
        // weights and source-position formulas mirror it.
        let (ih, iw) = (in_spatial[0], in_spatial[1]);
        let (oh, ow) = (out_spatial[0], out_spatial[1]);
        let bc = Self::checked_mul(batch, channels, "interpolate_bicubic_autograd: bc overflow")?;
        let in_numel =
            Self::checked_mul(ih, iw, "interpolate_bicubic_autograd: in_numel overflow")?;
        let out_numel =
            Self::checked_mul(oh, ow, "interpolate_bicubic_autograd: out_numel overflow")?;
        // 16 corners (4 dy × 4 dx); each gets an index array and weight array.
        let mut corners: Vec<(Vec<f64>, Vec<f64>)> = (0..16)
            .map(|_| (Vec::with_capacity(out_numel), Vec::with_capacity(out_numel)))
            .collect();
        for oy in 0..oh {
            let src_y = if align_corners && oh > 1 {
                oy as f64 * (ih - 1) as f64 / (oh - 1) as f64
            } else {
                (oy as f64 + 0.5) * ih as f64 / oh as f64 - 0.5
            };
            let src_y = src_y.max(0.0).min((ih - 1) as f64);
            let iy = src_y.floor() as i64;
            let ty = src_y - iy as f64;
            for ox in 0..ow {
                let src_x = if align_corners && ow > 1 {
                    ox as f64 * (iw - 1) as f64 / (ow - 1) as f64
                } else {
                    (ox as f64 + 0.5) * iw as f64 / ow as f64 - 0.5
                };
                let src_x = src_x.max(0.0).min((iw - 1) as f64);
                let ix = src_x.floor() as i64;
                let tx = src_x - ix as f64;
                let mut ci = 0usize;
                for dy in -1..=2_i64 {
                    let wy = cubic_weight(ty - dy as f64);
                    let sy = (iy + dy).clamp(0, ih as i64 - 1) as usize;
                    for dx in -1..=2_i64 {
                        let wx = cubic_weight(tx - dx as f64);
                        let sx = (ix + dx).clamp(0, iw as i64 - 1) as usize;
                        #[allow(clippy::cast_precision_loss)]
                        corners[ci].0.push((sy * iw + sx) as f64);
                        corners[ci].1.push(wy * wx);
                        ci += 1;
                    }
                }
            }
        }
        let flat = self.tensor_reshape(input, vec![bc, in_numel])?;
        let mut acc: Option<TensorNodeId> = None;
        for (idx_vec, w_vec) in corners {
            let idx_n = self.tensor_variable(idx_vec, vec![out_numel], false)?;
            let g = self.tensor_index_select(flat, 1, idx_n)?;
            let w_n = self.tensor_variable(w_vec, vec![1, out_numel], false)?;
            let w_b = self.tensor_expand(w_n, vec![bc, out_numel])?;
            let term = self.tensor_mul(g, w_b)?;
            acc = Some(match acc {
                Some(a) => self.tensor_add(a, term)?,
                None => term,
            });
        }
        let summed = acc.expect("bicubic has 16 corners");
        self.tensor_reshape(summed, vec![batch, channels, oh, ow])
    }

    fn interpolate_nearest(
        &mut self,
        storage: &[f64],
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let spatial_dims = in_spatial.len();
        let out_numel =
            Self::checked_shape_numel(out_spatial, "interpolate: output spatial shape overflow")?;
        let in_numel =
            Self::checked_shape_numel(in_spatial, "interpolate: input spatial shape overflow")?;
        let bc = Self::checked_mul(batch, channels, "interpolate: output size overflow")?;
        let total = Self::checked_mul(bc, out_numel, "interpolate: output size overflow")?;
        let mut values = Vec::with_capacity(total);

        for b in 0..batch {
            for c in 0..channels {
                let base = (b * channels + c) * in_numel;
                match spatial_dims {
                    1 => {
                        for oi in 0..out_spatial[0] {
                            let ii = (oi as f64 * in_spatial[0] as f64 / out_spatial[0] as f64)
                                .floor() as usize;
                            values.push(storage[base + ii.min(in_spatial[0] - 1)]);
                        }
                    }
                    2 => {
                        let (ih, iw) = (in_spatial[0], in_spatial[1]);
                        let (oh, ow) = (out_spatial[0], out_spatial[1]);
                        for oy in 0..oh {
                            let iy =
                                ((oy as f64 * ih as f64 / oh as f64).floor() as usize).min(ih - 1);
                            for ox in 0..ow {
                                let ix = ((ox as f64 * iw as f64 / ow as f64).floor() as usize)
                                    .min(iw - 1);
                                values.push(storage[base + iy * iw + ix]);
                            }
                        }
                    }
                    3 => {
                        let (id, ih, iw) = (in_spatial[0], in_spatial[1], in_spatial[2]);
                        let (od, oh, ow) = (out_spatial[0], out_spatial[1], out_spatial[2]);
                        for oz in 0..od {
                            let iz =
                                ((oz as f64 * id as f64 / od as f64).floor() as usize).min(id - 1);
                            for oy in 0..oh {
                                let iy = ((oy as f64 * ih as f64 / oh as f64).floor() as usize)
                                    .min(ih - 1);
                                for ox in 0..ow {
                                    let ix = ((ox as f64 * iw as f64 / ow as f64).floor() as usize)
                                        .min(iw - 1);
                                    values.push(storage[base + iz * ih * iw + iy * iw + ix]);
                                }
                            }
                        }
                    }
                    _ => {
                        return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                            ft_dispatch::DispatchKeyError::IncompatibleSet {
                                reason: "interpolate: nearest supports only 1-D, 2-D, or 3-D inputs",
                            },
                        )));
                    }
                }
            }
        }

        let mut out_shape = vec![batch, channels];
        out_shape.extend_from_slice(out_spatial);
        self.tensor_variable(values, out_shape, false)
    }

    fn interpolate_linear_1d(
        &mut self,
        storage: &[f64],
        batch: usize,
        channels: usize,
        in_len: usize,
        out_len: usize,
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let total = batch * channels * out_len;
        let mut values = Vec::with_capacity(total);

        for b in 0..batch {
            for c in 0..channels {
                let base = (b * channels + c) * in_len;
                for oi in 0..out_len {
                    let src = if align_corners && out_len > 1 {
                        oi as f64 * (in_len - 1) as f64 / (out_len - 1) as f64
                    } else {
                        (oi as f64 + 0.5) * in_len as f64 / out_len as f64 - 0.5
                    };
                    let src = src.max(0.0);
                    let lo = (src.floor() as usize).min(in_len - 1);
                    let hi = (lo + 1).min(in_len - 1);
                    let t = src - lo as f64;
                    values.push(storage[base + lo] * (1.0 - t) + storage[base + hi] * t);
                }
            }
        }

        self.tensor_variable(values, vec![batch, channels, out_len], false)
    }

    fn interpolate_bilinear(
        &mut self,
        storage: &[f64],
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let (ih, iw) = (in_spatial[0], in_spatial[1]);
        let (oh, ow) = (out_spatial[0], out_spatial[1]);
        let total = batch * channels * oh * ow;
        let mut values = Vec::with_capacity(total);

        for b in 0..batch {
            for c in 0..channels {
                let base = (b * channels + c) * ih * iw;
                for oy in 0..oh {
                    let src_y = if align_corners && oh > 1 {
                        oy as f64 * (ih - 1) as f64 / (oh - 1) as f64
                    } else {
                        (oy as f64 + 0.5) * ih as f64 / oh as f64 - 0.5
                    };
                    let src_y = src_y.max(0.0);
                    let y0 = (src_y.floor() as usize).min(ih - 1);
                    let y1 = (y0 + 1).min(ih - 1);
                    let ty = src_y - y0 as f64;

                    for ox in 0..ow {
                        let src_x = if align_corners && ow > 1 {
                            ox as f64 * (iw - 1) as f64 / (ow - 1) as f64
                        } else {
                            (ox as f64 + 0.5) * iw as f64 / ow as f64 - 0.5
                        };
                        let src_x = src_x.max(0.0);
                        let x0 = (src_x.floor() as usize).min(iw - 1);
                        let x1 = (x0 + 1).min(iw - 1);
                        let tx = src_x - x0 as f64;

                        let v00 = storage[base + y0 * iw + x0];
                        let v01 = storage[base + y0 * iw + x1];
                        let v10 = storage[base + y1 * iw + x0];
                        let v11 = storage[base + y1 * iw + x1];

                        let val = v00 * (1.0 - ty) * (1.0 - tx)
                            + v01 * (1.0 - ty) * tx
                            + v10 * ty * (1.0 - tx)
                            + v11 * ty * tx;
                        values.push(val);
                    }
                }
            }
        }

        self.tensor_variable(values, vec![batch, channels, oh, ow], false)
    }

    fn interpolate_bicubic(
        &mut self,
        storage: &[f64],
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let (ih, iw) = (in_spatial[0], in_spatial[1]);
        let (oh, ow) = (out_spatial[0], out_spatial[1]);
        let total = batch * channels * oh * ow;
        let mut values = Vec::with_capacity(total);

        for b in 0..batch {
            for c in 0..channels {
                let base = (b * channels + c) * ih * iw;
                for oy in 0..oh {
                    let src_y = if align_corners && oh > 1 {
                        oy as f64 * (ih - 1) as f64 / (oh - 1) as f64
                    } else {
                        (oy as f64 + 0.5) * ih as f64 / oh as f64 - 0.5
                    };
                    let src_y = src_y.max(0.0).min((ih - 1) as f64);
                    let iy = src_y.floor() as i64;
                    let ty = src_y - iy as f64;

                    for ox in 0..ow {
                        let src_x = if align_corners && ow > 1 {
                            ox as f64 * (iw - 1) as f64 / (ow - 1) as f64
                        } else {
                            (ox as f64 + 0.5) * iw as f64 / ow as f64 - 0.5
                        };
                        let src_x = src_x.max(0.0).min((iw - 1) as f64);
                        let ix = src_x.floor() as i64;
                        let tx = src_x - ix as f64;

                        let mut val = 0.0;
                        for dy in -1..=2_i64 {
                            let wy = cubic_weight(ty - dy as f64);
                            let sy = (iy + dy).clamp(0, ih as i64 - 1) as usize;
                            for dx in -1..=2_i64 {
                                let wx = cubic_weight(tx - dx as f64);
                                let sx = (ix + dx).clamp(0, iw as i64 - 1) as usize;
                                val += wy * wx * storage[base + sy * iw + sx];
                            }
                        }
                        values.push(val);
                    }
                }
            }
        }

        self.tensor_variable(values, vec![batch, channels, oh, ow], false)
    }

    fn interpolate_trilinear(
        &mut self,
        storage: &[f64],
        batch: usize,
        channels: usize,
        in_spatial: &[usize],
        out_spatial: &[usize],
        align_corners: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let (id, ih, iw) = (in_spatial[0], in_spatial[1], in_spatial[2]);
        let (od, oh, ow) = (out_spatial[0], out_spatial[1], out_spatial[2]);
        let total = batch * channels * od * oh * ow;
        let mut values = Vec::with_capacity(total);

        for b in 0..batch {
            for c in 0..channels {
                let base = (b * channels + c) * id * ih * iw;
                for oz in 0..od {
                    let src_z = if align_corners && od > 1 {
                        oz as f64 * (id - 1) as f64 / (od - 1) as f64
                    } else {
                        (oz as f64 + 0.5) * id as f64 / od as f64 - 0.5
                    };
                    let src_z = src_z.max(0.0);
                    let z0 = (src_z.floor() as usize).min(id - 1);
                    let z1 = (z0 + 1).min(id - 1);
                    let tz = src_z - z0 as f64;

                    for oy in 0..oh {
                        let src_y = if align_corners && oh > 1 {
                            oy as f64 * (ih - 1) as f64 / (oh - 1) as f64
                        } else {
                            (oy as f64 + 0.5) * ih as f64 / oh as f64 - 0.5
                        };
                        let src_y = src_y.max(0.0);
                        let y0 = (src_y.floor() as usize).min(ih - 1);
                        let y1 = (y0 + 1).min(ih - 1);
                        let ty = src_y - y0 as f64;

                        for ox in 0..ow {
                            let src_x = if align_corners && ow > 1 {
                                ox as f64 * (iw - 1) as f64 / (ow - 1) as f64
                            } else {
                                (ox as f64 + 0.5) * iw as f64 / ow as f64 - 0.5
                            };
                            let src_x = src_x.max(0.0);
                            let x0 = (src_x.floor() as usize).min(iw - 1);
                            let x1 = (x0 + 1).min(iw - 1);
                            let tx = src_x - x0 as f64;

                            let v000 = storage[base + z0 * ih * iw + y0 * iw + x0];
                            let v001 = storage[base + z0 * ih * iw + y0 * iw + x1];
                            let v010 = storage[base + z0 * ih * iw + y1 * iw + x0];
                            let v011 = storage[base + z0 * ih * iw + y1 * iw + x1];
                            let v100 = storage[base + z1 * ih * iw + y0 * iw + x0];
                            let v101 = storage[base + z1 * ih * iw + y0 * iw + x1];
                            let v110 = storage[base + z1 * ih * iw + y1 * iw + x0];
                            let v111 = storage[base + z1 * ih * iw + y1 * iw + x1];

                            let val = v000 * (1.0 - tz) * (1.0 - ty) * (1.0 - tx)
                                + v001 * (1.0 - tz) * (1.0 - ty) * tx
                                + v010 * (1.0 - tz) * ty * (1.0 - tx)
                                + v011 * (1.0 - tz) * ty * tx
                                + v100 * tz * (1.0 - ty) * (1.0 - tx)
                                + v101 * tz * (1.0 - ty) * tx
                                + v110 * tz * ty * (1.0 - tx)
                                + v111 * tz * ty * tx;
                            values.push(val);
                        }
                    }
                }
            }
        }

        self.tensor_variable(values, vec![batch, channels, od, oh, ow], false)
    }

    // ── FFT operations ───────────────────────────────────────────────────

    /// In-place 1-D DFT. When `n` is a power of two, runs an
    /// iterative Cooley-Tukey decimation-in-time FFT in
    /// O(N log N) with O(log N · ε) accumulated rounding. For
    /// non-power-of-two `n`, falls back to the naive O(N^2) DFT.
    /// The caller passes interleaved real/imag buffers of length
    /// `n`; this function overwrites them with the transform.
    /// If `inverse` is true, computes the inverse DFT (positive
    /// twiddle exponent + 1/N normalization).
    /// frankentorch-hpo6.
    fn dft_inplace_1d(re: &mut [f64], im: &mut [f64], inverse: bool) {
        let n = re.len();
        assert_eq!(re.len(), im.len(), "dft_inplace_1d re/im length mismatch");
        if n <= 1 {
            if inverse && n == 1 {
                // 1-element inverse: divide by 1, no-op.
            }
            return;
        }

        if n.is_power_of_two() {
            // Bit-reversal permutation.
            let mut j = 0usize;
            for i in 1..n {
                let mut bit = n >> 1;
                while j & bit != 0 {
                    j ^= bit;
                    bit >>= 1;
                }
                j ^= bit;
                if i < j {
                    re.swap(i, j);
                    im.swap(i, j);
                }
            }
            // Butterfly stages.
            let sign = if inverse { 1.0 } else { -1.0 };
            let two_pi = 2.0 * std::f64::consts::PI;
            let mut stage = 2usize;
            while stage <= n {
                let half = stage / 2;
                let angle_step = sign * two_pi / stage as f64;
                for start in (0..n).step_by(stage) {
                    for k in 0..half {
                        let angle = angle_step * k as f64;
                        let w_re = angle.cos();
                        let w_im = angle.sin();
                        let idx = start + k;
                        let jdx = start + k + half;
                        let tw_re = w_re * re[jdx] - w_im * im[jdx];
                        let tw_im = w_re * im[jdx] + w_im * re[jdx];
                        re[jdx] = re[idx] - tw_re;
                        im[jdx] = im[idx] - tw_im;
                        re[idx] += tw_re;
                        im[idx] += tw_im;
                    }
                }
                stage *= 2;
            }
        } else {
            // Non-power-of-two fallback: naive O(N^2) DFT.
            let mut out_re = vec![0.0_f64; n];
            let mut out_im = vec![0.0_f64; n];
            let sign = if inverse { 1.0 } else { -1.0 };
            let two_pi = 2.0 * std::f64::consts::PI;
            for k in 0..n {
                let mut acc_re = 0.0_f64;
                let mut acc_im = 0.0_f64;
                for nn in 0..n {
                    let angle = sign * two_pi * k as f64 * nn as f64 / n as f64;
                    let c = angle.cos();
                    let s = angle.sin();
                    acc_re += re[nn] * c - im[nn] * s;
                    acc_im += re[nn] * s + im[nn] * c;
                }
                out_re[k] = acc_re;
                out_im[k] = acc_im;
            }
            re.copy_from_slice(&out_re);
            im.copy_from_slice(&out_im);
        }

        if inverse {
            let inv_n = 1.0 / n as f64;
            for v in re.iter_mut() {
                *v *= inv_n;
            }
            for v in im.iter_mut() {
                *v *= inv_n;
            }
        }
    }

    /// Apply FFT (or inverse FFT) along a specific dimension.
    /// Used by fftn/ifftn for iterative dimension-wise transforms.
    fn tensor_fft_along_dim(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        inverse: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let dtype = self.tensor_dtype(input)?;
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft_along_dim: dimension out of range",
                },
            )));
        }
        let is_complex = dtype == DType::Complex128 || dtype == DType::Complex64;
        let dim_size = shape[dim];
        let total_elements: usize = shape.iter().product();
        let stride_outer: usize = shape[..dim].iter().product();
        let stride_inner: usize = shape[dim + 1..].iter().product();
        let mut re_data;
        let mut im_data;
        if is_complex {
            let real_view = self.tensor_view_as_real(input)?;
            let vals = self.tensor_values(real_view)?;
            let half = vals.len() / 2;
            re_data = vals[..half].to_vec();
            im_data = vals[half..].to_vec();
        } else {
            let vals = self.tensor_values(input)?;
            re_data = vals;
            im_data = vec![0.0_f64; total_elements];
        }
        for outer in 0..stride_outer {
            for inner in 0..stride_inner {
                let mut re_slice = vec![0.0_f64; dim_size];
                let mut im_slice = vec![0.0_f64; dim_size];
                for k in 0..dim_size {
                    let idx = outer * dim_size * stride_inner + k * stride_inner + inner;
                    re_slice[k] = re_data[idx];
                    im_slice[k] = im_data[idx];
                }
                Self::dft_inplace_1d(&mut re_slice, &mut im_slice, inverse);
                for k in 0..dim_size {
                    let idx = outer * dim_size * stride_inner + k * stride_inner + inner;
                    re_data[idx] = re_slice[k];
                    im_data[idx] = im_slice[k];
                }
            }
        }
        let re_node = self.tensor_variable(re_data, shape.clone(), false)?;
        let im_node = self.tensor_variable(im_data, shape, false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Resize tensor by padding with zeros or cropping.
    fn tensor_resize_with_pad_or_crop(
        &mut self,
        input: TensorNodeId,
        target_shape: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let current_shape = self.tensor_shape(input)?;
        if current_shape == target_shape {
            return Ok(input);
        }
        let vals = self.tensor_values(input)?;
        let mut result = vec![0.0_f64; target_shape.iter().product()];
        fn copy_recursive(
            src: &[f64],
            dst: &mut [f64],
            src_shape: &[usize],
            dst_shape: &[usize],
            src_idx: usize,
            dst_idx: usize,
            dim: usize,
            _src_stride: usize,
            _dst_stride: usize,
        ) {
            if dim == src_shape.len() {
                dst[dst_idx] = src[src_idx];
                return;
            }
            let copy_len = src_shape[dim].min(dst_shape[dim]);
            let new_src_stride = if dim + 1 < src_shape.len() {
                src_shape[dim + 1..].iter().product()
            } else {
                1
            };
            let new_dst_stride = if dim + 1 < dst_shape.len() {
                dst_shape[dim + 1..].iter().product()
            } else {
                1
            };
            for i in 0..copy_len {
                copy_recursive(
                    src,
                    dst,
                    src_shape,
                    dst_shape,
                    src_idx + i * new_src_stride,
                    dst_idx + i * new_dst_stride,
                    dim + 1,
                    new_src_stride,
                    new_dst_stride,
                );
            }
        }
        let src_stride: usize = if current_shape.is_empty() { 1 } else { current_shape.iter().product() };
        let dst_stride: usize = if target_shape.is_empty() { 1 } else { target_shape.iter().product() };
        copy_recursive(&vals, &mut result, &current_shape, target_shape, 0, 0, 0, src_stride, dst_stride);
        self.tensor_variable(result, target_shape.to_vec(), false)
    }

    /// Extend a half-spectrum complex tensor to full length using Hermitian symmetry.
    fn tensor_hermitian_extend(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        full_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let half_len = shape[dim];
        if half_len > full_len {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "hermitian_extend: half_len exceeds full_len",
                },
            )));
        }
        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;
        let half_vals = vals.len() / 2;
        let re_data = &vals[..half_vals];
        let im_data = &vals[half_vals..];
        let mut out_shape = shape.clone();
        out_shape[dim] = full_len;
        let out_total: usize = out_shape.iter().product();
        let mut re_out = vec![0.0_f64; out_total];
        let mut im_out = vec![0.0_f64; out_total];
        let stride_outer: usize = shape[..dim].iter().product();
        let stride_inner: usize = shape[dim + 1..].iter().product();
        let out_stride_inner: usize = out_shape[dim + 1..].iter().product();
        for outer in 0..stride_outer {
            for inner in 0..stride_inner {
                for k in 0..half_len {
                    let src_idx = outer * half_len * stride_inner + k * stride_inner + inner;
                    let dst_idx = outer * full_len * out_stride_inner + k * out_stride_inner + inner;
                    re_out[dst_idx] = re_data[src_idx];
                    im_out[dst_idx] = im_data[src_idx];
                }
                for k in half_len..full_len {
                    let conj_k = full_len - k;
                    if conj_k < half_len {
                        let src_idx = outer * half_len * stride_inner + conj_k * stride_inner + inner;
                        let dst_idx = outer * full_len * out_stride_inner + k * out_stride_inner + inner;
                        re_out[dst_idx] = re_data[src_idx];
                        im_out[dst_idx] = -im_data[src_idx];
                    }
                }
            }
        }
        let re_node = self.tensor_variable(re_out, out_shape.clone(), false)?;
        let im_node = self.tensor_variable(im_out, out_shape, false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the 1-D Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.fft(input, n)`.
    /// Input is a 1-D real tensor. Output is a 1-D Complex128 tensor of length `n`.
    /// If `n` is None, uses the input length.
    pub fn tensor_fft(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft: autograd not supported (Wirtinger calculus for complex outputs not yet implemented). Tracked under frankentorch-xszk.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;
        let input_len = vals.len();
        let fft_len = n.unwrap_or(input_len);

        // Zero-pad or truncate input to length n. Build real
        // interleaved storage with zero imaginary part.
        let mut re_buf = vec![0.0_f64; fft_len];
        let mut im_buf = vec![0.0_f64; fft_len];
        let copy_len = input_len.min(fft_len);
        re_buf[..copy_len].copy_from_slice(&vals[..copy_len]);

        // Cooley-Tukey for power-of-two N, O(N^2) fallback otherwise.
        // frankentorch-hpo6.
        Self::dft_inplace_1d(&mut re_buf, &mut im_buf, false);

        // Create real and imag tensors, then combine as complex
        let re_node = self.tensor_variable(re_buf, vec![fft_len], false)?;
        let im_node = self.tensor_variable(im_buf, vec![fft_len], false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the 1-D Inverse Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.ifft(input, n)`.
    /// Input is a Complex128 tensor. Output is Complex128.
    pub fn tensor_ifft(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifft: autograd not supported (Wirtinger calculus for complex outputs not yet implemented). Tracked under frankentorch-xszk.",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;

        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifft: input must be complex",
                },
            )));
        }
        // Extract interleaved [re, im, re, im, ...] via the
        // tensor_view_as_real conversion path. tensor_values cannot
        // be called directly on a Complex{64,128} tensor — it errors
        // with DenseTensor(UnsupportedDType). frankentorch-w6x1.
        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;

        let input_len = vals.len() / 2; // complex elements
        let fft_len = n.unwrap_or(input_len);

        // Extract real/imag parts (zero-pad if needed)
        let mut re_in = vec![0.0_f64; fft_len];
        let mut im_in = vec![0.0_f64; fft_len];
        let copy_len = input_len.min(fft_len);
        for i in 0..copy_len {
            re_in[i] = vals[i * 2];
            im_in[i] = vals[i * 2 + 1];
        }

        // Cooley-Tukey inverse DFT (positive sign + 1/N) when N is
        // a power of two, naive O(N^2) otherwise. frankentorch-hpo6.
        Self::dft_inplace_1d(&mut re_in, &mut im_in, true);

        let re_node = self.tensor_variable(re_in, vec![fft_len], false)?;
        let im_node = self.tensor_variable(im_in, vec![fft_len], false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the 1-D real FFT (only positive frequencies).
    ///
    /// Equivalent to `torch.fft.rfft(input, n)`.
    /// Input is real. Output is Complex128 of length `n/2 + 1`.
    pub fn tensor_rfft(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rfft: autograd not supported (Wirtinger calculus for complex outputs not yet implemented). Tracked under frankentorch-xszk.",
                },
            )));
        }
        let vals = self.tensor_values(input)?;
        let input_len = vals.len();
        let fft_len = n.unwrap_or(input_len);
        let out_len = fft_len / 2 + 1;

        // Real input → full complex output via Cooley-Tukey, then
        // take only the first N/2+1 bins (the rest are conjugate-
        // symmetric for real input). For non-power-of-two N this
        // still costs O(N^2) via the dft_inplace_1d fallback, but
        // for the power-of-two case it drops to O(N log N).
        // frankentorch-hpo6.
        let mut re_buf = vec![0.0_f64; fft_len];
        let mut im_buf = vec![0.0_f64; fft_len];
        let copy_len = input_len.min(fft_len);
        re_buf[..copy_len].copy_from_slice(&vals[..copy_len]);
        Self::dft_inplace_1d(&mut re_buf, &mut im_buf, false);

        let re_out: Vec<f64> = re_buf[..out_len].to_vec();
        let im_out: Vec<f64> = im_buf[..out_len].to_vec();

        let re_node = self.tensor_variable(re_out, vec![out_len], false)?;
        let im_node = self.tensor_variable(im_out, vec![out_len], false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the inverse of rfft.
    ///
    /// Equivalent to `torch.fft.irfft(input, n)`.
    /// Input is Complex128 of length `n/2+1`. Output is real of length `n`.
    pub fn tensor_irfft(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfft: autograd not supported (Wirtinger calculus for complex outputs not yet implemented). Tracked under frankentorch-xszk.",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;

        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfft: input must be complex",
                },
            )));
        }
        // Extract interleaved [re, im, re, im, ...] via the
        // tensor_view_as_real conversion path. frankentorch-w6x1.
        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;

        let freq_len = vals.len() / 2;
        let out_len = n.unwrap_or((freq_len - 1) * 2);

        // Reconstruct full spectrum using conjugate symmetry
        let mut re_full = vec![0.0; out_len];
        let mut im_full = vec![0.0; out_len];

        for k in 0..freq_len.min(out_len) {
            re_full[k] = vals[k * 2];
            im_full[k] = vals[k * 2 + 1];
        }
        // Mirror: X[N-k] = conj(X[k])
        for k in 1..freq_len.min(out_len) {
            let mirror = out_len - k;
            if mirror < out_len && mirror != k {
                re_full[mirror] = vals[k * 2];
                im_full[mirror] = -vals[k * 2 + 1];
            }
        }

        // Inverse DFT via the shared helper. frankentorch-hpo6.
        Self::dft_inplace_1d(&mut re_full, &mut im_full, true);
        // Real output: keep only the real part. Imaginary part
        // should be ~0 by conjugate symmetry (modulo FP rounding).
        let result = re_full;

        self.tensor_variable(result, vec![out_len], false)
    }

    /// Compute the 2-D Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.fft2(input)`.
    /// Applies FFT along the last two dimensions. Input shape must be at least 2-D.
    /// Output is Complex128.
    pub fn tensor_fft2(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft2: autograd not supported (Wirtinger calculus not yet implemented)",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fft2: input must be at least 2-D",
                },
            )));
        }
        // Apply FFT along last dimension, then along second-to-last
        let ndim = shape.len();
        let vals = self.tensor_values(input)?;
        let rows = shape[ndim - 2];
        let cols = shape[ndim - 1];
        let batch_size: usize = shape[..ndim - 2].iter().product();

        let mut re_out = vec![0.0_f64; batch_size * rows * cols];
        let mut im_out = vec![0.0_f64; batch_size * rows * cols];

        // FFT along columns (last dim) for each row
        for b in 0..batch_size {
            for r in 0..rows {
                let start = b * rows * cols + r * cols;
                let mut re_row: Vec<f64> = vals[start..start + cols].to_vec();
                let mut im_row = vec![0.0_f64; cols];
                Self::dft_inplace_1d(&mut re_row, &mut im_row, false);
                re_out[start..start + cols].copy_from_slice(&re_row);
                im_out[start..start + cols].copy_from_slice(&im_row);
            }
        }

        // FFT along rows (second-to-last dim)
        for b in 0..batch_size {
            for c in 0..cols {
                let mut re_col = vec![0.0_f64; rows];
                let mut im_col = vec![0.0_f64; rows];
                for r in 0..rows {
                    re_col[r] = re_out[b * rows * cols + r * cols + c];
                    im_col[r] = im_out[b * rows * cols + r * cols + c];
                }
                Self::dft_inplace_1d(&mut re_col, &mut im_col, false);
                for r in 0..rows {
                    re_out[b * rows * cols + r * cols + c] = re_col[r];
                    im_out[b * rows * cols + r * cols + c] = im_col[r];
                }
            }
        }

        let re_node = self.tensor_variable(re_out, shape.clone(), false)?;
        let im_node = self.tensor_variable(im_out, shape, false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the 2-D Inverse Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.ifft2(input)`.
    /// Applies inverse FFT along the last two dimensions. Input must be Complex128.
    pub fn tensor_ifft2(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifft2: autograd not supported",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifft2: input must be complex",
                },
            )));
        }

        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifft2: input must be at least 2-D",
                },
            )));
        }

        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;

        let ndim = shape.len();
        let rows = shape[ndim - 2];
        let cols = shape[ndim - 1];
        let batch_size: usize = shape[..ndim - 2].iter().product();

        let mut re_out = vec![0.0_f64; batch_size * rows * cols];
        let mut im_out = vec![0.0_f64; batch_size * rows * cols];

        // Extract interleaved complex values
        for i in 0..batch_size * rows * cols {
            re_out[i] = vals[i * 2];
            im_out[i] = vals[i * 2 + 1];
        }

        // Inverse FFT along rows (second-to-last dim)
        for b in 0..batch_size {
            for c in 0..cols {
                let mut re_col = vec![0.0_f64; rows];
                let mut im_col = vec![0.0_f64; rows];
                for r in 0..rows {
                    re_col[r] = re_out[b * rows * cols + r * cols + c];
                    im_col[r] = im_out[b * rows * cols + r * cols + c];
                }
                Self::dft_inplace_1d(&mut re_col, &mut im_col, true);
                for r in 0..rows {
                    re_out[b * rows * cols + r * cols + c] = re_col[r];
                    im_out[b * rows * cols + r * cols + c] = im_col[r];
                }
            }
        }

        // Inverse FFT along columns (last dim)
        for b in 0..batch_size {
            for r in 0..rows {
                let start = b * rows * cols + r * cols;
                let mut re_row: Vec<f64> = re_out[start..start + cols].to_vec();
                let mut im_row: Vec<f64> = im_out[start..start + cols].to_vec();
                Self::dft_inplace_1d(&mut re_row, &mut im_row, true);
                re_out[start..start + cols].copy_from_slice(&re_row);
                im_out[start..start + cols].copy_from_slice(&im_row);
            }
        }

        let re_node = self.tensor_variable(re_out, shape.clone(), false)?;
        let im_node = self.tensor_variable(im_out, shape, false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the 2-D real FFT (non-redundant complex output).
    ///
    /// Equivalent to `torch.fft.rfft2(input)`.
    /// For real input of shape [..., H, W], outputs complex of shape [..., H, W/2+1].
    /// Tracked under frankentorch-ffpd.
    pub fn tensor_rfft2(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rfft2: autograd not supported (Wirtinger calculus not yet implemented)",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rfft2: input must be at least 2-D",
                },
            )));
        }
        let ndim = shape.len();
        let vals = self.tensor_values(input)?;
        let rows = shape[ndim - 2];
        let cols = shape[ndim - 1];
        let out_cols = cols / 2 + 1;
        let batch_size: usize = shape[..ndim - 2].iter().product();

        let mut re_tmp = vec![0.0_f64; batch_size * rows * cols];
        let mut im_tmp = vec![0.0_f64; batch_size * rows * cols];

        // FFT along columns (last dim) for each row
        for b in 0..batch_size {
            for r in 0..rows {
                let start = b * rows * cols + r * cols;
                let mut re_row: Vec<f64> = vals[start..start + cols].to_vec();
                let mut im_row = vec![0.0_f64; cols];
                Self::dft_inplace_1d(&mut re_row, &mut im_row, false);
                re_tmp[start..start + cols].copy_from_slice(&re_row);
                im_tmp[start..start + cols].copy_from_slice(&im_row);
            }
        }

        // FFT along rows (second-to-last dim)
        for b in 0..batch_size {
            for c in 0..cols {
                let mut re_col = vec![0.0_f64; rows];
                let mut im_col = vec![0.0_f64; rows];
                for r in 0..rows {
                    re_col[r] = re_tmp[b * rows * cols + r * cols + c];
                    im_col[r] = im_tmp[b * rows * cols + r * cols + c];
                }
                Self::dft_inplace_1d(&mut re_col, &mut im_col, false);
                for r in 0..rows {
                    re_tmp[b * rows * cols + r * cols + c] = re_col[r];
                    im_tmp[b * rows * cols + r * cols + c] = im_col[r];
                }
            }
        }

        // Keep only the non-redundant frequencies (first out_cols columns)
        let mut re_out = Vec::with_capacity(batch_size * rows * out_cols);
        let mut im_out = Vec::with_capacity(batch_size * rows * out_cols);
        for b in 0..batch_size {
            for r in 0..rows {
                for c in 0..out_cols {
                    re_out.push(re_tmp[b * rows * cols + r * cols + c]);
                    im_out.push(im_tmp[b * rows * cols + r * cols + c]);
                }
            }
        }

        let mut out_shape = shape[..ndim - 1].to_vec();
        out_shape.push(out_cols);
        let re_node = self.tensor_variable(re_out, out_shape.clone(), false)?;
        let im_node = self.tensor_variable(im_out, out_shape, false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Compute the inverse 2-D real FFT.
    ///
    /// Equivalent to `torch.fft.irfft2(input, s)`.
    /// Input is complex of shape [..., H, W/2+1]. Output is real of shape [..., H, W].
    /// If `s` is None, W is inferred as 2*(W/2+1 - 1) = original width.
    /// Tracked under frankentorch-ffpd.
    pub fn tensor_irfft2(
        &mut self,
        input: TensorNodeId,
        s: Option<(usize, usize)>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfft2: autograd not supported",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfft2: input must be complex",
                },
            )));
        }

        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfft2: input must be at least 2-D",
                },
            )));
        }

        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;

        let ndim = shape.len();
        let rows = shape[ndim - 2];
        let in_cols = shape[ndim - 1];
        let (out_rows, out_cols) = s.unwrap_or((rows, (in_cols - 1) * 2));
        let batch_size: usize = shape[..ndim - 2].iter().product();

        let mut re_full = vec![0.0_f64; batch_size * out_rows * out_cols];
        let mut im_full = vec![0.0_f64; batch_size * out_rows * out_cols];

        // Reconstruct full spectrum using conjugate symmetry along last dim
        for b in 0..batch_size {
            for r in 0..rows.min(out_rows) {
                // Copy input frequencies
                for c in 0..in_cols.min(out_cols) {
                    let in_idx = (b * rows * in_cols + r * in_cols + c) * 2;
                    let out_idx = b * out_rows * out_cols + r * out_cols + c;
                    re_full[out_idx] = vals[in_idx];
                    im_full[out_idx] = vals[in_idx + 1];
                }
                // Mirror for remaining columns: X[N-k] = conj(X[k])
                for c in 1..in_cols.min(out_cols) {
                    let mirror = out_cols - c;
                    if mirror < out_cols && mirror >= in_cols {
                        let in_idx = (b * rows * in_cols + r * in_cols + c) * 2;
                        let out_idx = b * out_rows * out_cols + r * out_cols + mirror;
                        re_full[out_idx] = vals[in_idx];
                        im_full[out_idx] = -vals[in_idx + 1];
                    }
                }
            }
        }

        // Inverse FFT along rows (second-to-last dim)
        for b in 0..batch_size {
            for c in 0..out_cols {
                let mut re_col = vec![0.0_f64; out_rows];
                let mut im_col = vec![0.0_f64; out_rows];
                for r in 0..out_rows {
                    re_col[r] = re_full[b * out_rows * out_cols + r * out_cols + c];
                    im_col[r] = im_full[b * out_rows * out_cols + r * out_cols + c];
                }
                Self::dft_inplace_1d(&mut re_col, &mut im_col, true);
                for r in 0..out_rows {
                    re_full[b * out_rows * out_cols + r * out_cols + c] = re_col[r];
                    im_full[b * out_rows * out_cols + r * out_cols + c] = im_col[r];
                }
            }
        }

        // Inverse FFT along columns (last dim)
        for b in 0..batch_size {
            for r in 0..out_rows {
                let start = b * out_rows * out_cols + r * out_cols;
                let mut re_row: Vec<f64> = re_full[start..start + out_cols].to_vec();
                let mut im_row: Vec<f64> = im_full[start..start + out_cols].to_vec();
                Self::dft_inplace_1d(&mut re_row, &mut im_row, true);
                re_full[start..start + out_cols].copy_from_slice(&re_row);
            }
        }

        let mut out_shape = shape[..ndim - 2].to_vec();
        out_shape.push(out_rows);
        out_shape.push(out_cols);
        self.tensor_variable(re_full, out_shape, false)
    }

    /// Compute the N-dimensional Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.fftn(input, s, dim)`.
    /// If `dims` is None, transforms all dimensions. `s` can specify output sizes.
    pub fn tensor_fftn(
        &mut self,
        input: TensorNodeId,
        s: Option<&[usize]>,
        dims: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fftn: autograd not supported (Wirtinger calculus not yet implemented)",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let transform_dims: Vec<usize> = match dims {
            Some(d) => d.iter().copied().collect(),
            None => (0..ndim).collect(),
        };
        if transform_dims.is_empty() {
            let vals = self.tensor_values(input)?;
            let re_node = self.tensor_variable(vals.clone(), shape.clone(), false)?;
            let im_node = self.tensor_zeros(shape, false)?;
            return self.tensor_complex(re_node, im_node);
        }
        let mut current = input;
        for &dim in &transform_dims {
            if dim >= ndim {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "fftn: dimension out of range",
                    },
                )));
            }
            current = self.tensor_fft_along_dim(current, dim, false)?;
        }
        if let Some(target_sizes) = s {
            let current_shape = self.tensor_shape(current)?;
            let mut new_shape = current_shape.clone();
            for (i, &target_sz) in target_sizes.iter().enumerate() {
                if i < transform_dims.len() {
                    new_shape[transform_dims[i]] = target_sz;
                }
            }
            if new_shape != current_shape {
                let re_view = self.tensor_real(current)?;
                let im_view = self.tensor_imag(current)?;
                let re_resized = self.tensor_resize_with_pad_or_crop(re_view, &new_shape)?;
                let im_resized = self.tensor_resize_with_pad_or_crop(im_view, &new_shape)?;
                current = self.tensor_complex(re_resized, im_resized)?;
            }
        }
        Ok(current)
    }

    /// Compute the N-dimensional Inverse Discrete Fourier Transform.
    ///
    /// Equivalent to `torch.fft.ifftn(input, s, dim)`.
    /// If `dims` is None, transforms all dimensions.
    pub fn tensor_ifftn(
        &mut self,
        input: TensorNodeId,
        s: Option<&[usize]>,
        dims: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifftn: autograd not supported",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ifftn: input must be complex",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let transform_dims: Vec<usize> = match dims {
            Some(d) => d.iter().copied().collect(),
            None => (0..ndim).collect(),
        };
        if transform_dims.is_empty() {
            return Ok(input);
        }
        let mut current = input;
        for &dim in &transform_dims {
            if dim >= ndim {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "ifftn: dimension out of range",
                    },
                )));
            }
            current = self.tensor_fft_along_dim(current, dim, true)?;
        }
        if let Some(target_sizes) = s {
            let current_shape = self.tensor_shape(current)?;
            let mut new_shape = current_shape.clone();
            for (i, &target_sz) in target_sizes.iter().enumerate() {
                if i < transform_dims.len() {
                    new_shape[transform_dims[i]] = target_sz;
                }
            }
            if new_shape != current_shape {
                let re_view = self.tensor_real(current)?;
                let im_view = self.tensor_imag(current)?;
                let re_resized = self.tensor_resize_with_pad_or_crop(re_view, &new_shape)?;
                let im_resized = self.tensor_resize_with_pad_or_crop(im_view, &new_shape)?;
                current = self.tensor_complex(re_resized, im_resized)?;
            }
        }
        Ok(current)
    }

    /// Compute the N-dimensional real FFT.
    ///
    /// Equivalent to `torch.fft.rfftn(input, s, dim)`.
    /// Computes the FFT of real input, returning complex output with Hermitian symmetry.
    /// The last transformed dimension has size n//2+1.
    pub fn tensor_rfftn(
        &mut self,
        input: TensorNodeId,
        s: Option<&[usize]>,
        dims: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "rfftn: autograd not supported",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let transform_dims: Vec<usize> = match dims {
            Some(d) => d.iter().copied().collect(),
            None => (0..ndim).collect(),
        };
        if transform_dims.is_empty() {
            let vals = self.tensor_values(input)?;
            let re_node = self.tensor_variable(vals, shape.clone(), false)?;
            let im_node = self.tensor_zeros(shape, false)?;
            return self.tensor_complex(re_node, im_node);
        }
        let full_fft = self.tensor_fftn(input, s, dims)?;
        if let Some(&last_dim) = transform_dims.last() {
            let current_shape = self.tensor_shape(full_fft)?;
            let full_len = current_shape[last_dim];
            let half_len = full_len / 2 + 1;
            self.tensor_narrow(full_fft, last_dim, 0, half_len)
        } else {
            Ok(full_fft)
        }
    }

    /// Compute the N-dimensional inverse real FFT.
    ///
    /// Equivalent to `torch.fft.irfftn(input, s, dim)`.
    /// Computes the inverse FFT, returning real output.
    /// Input should be complex with Hermitian symmetry.
    pub fn tensor_irfftn(
        &mut self,
        input: TensorNodeId,
        s: Option<&[usize]>,
        dims: Option<&[usize]>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfftn: autograd not supported",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "irfftn: input must be complex",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let transform_dims: Vec<usize> = match dims {
            Some(d) => d.iter().copied().collect(),
            None => (0..ndim).collect(),
        };
        if transform_dims.is_empty() {
            return self.tensor_real(input);
        }
        let last_dim = *transform_dims.last().unwrap();
        let half_len = shape[last_dim];
        let full_len = match s {
            Some(sizes) if !sizes.is_empty() => sizes[sizes.len() - 1],
            _ => (half_len - 1) * 2,
        };
        let full_complex = self.tensor_hermitian_extend(input, last_dim, full_len)?;
        let ifft_result = self.tensor_ifftn(full_complex, s, dims)?;
        self.tensor_real(ifft_result)
    }

    /// Compute the Hermitian FFT (complex Hermitian input -> real output).
    ///
    /// Equivalent to `torch.fft.hfft(input, n)`.
    /// Input is complex of length n/2+1 representing a Hermitian-symmetric signal.
    /// Output is real of length n.
    /// Tracked under frankentorch-ffpd.
    pub fn tensor_hfft(
        &mut self,
        input: TensorNodeId,
        n: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "hfft: autograd not supported",
                },
            )));
        }
        let dtype = self.tensor_dtype(input)?;
        if dtype != DType::Complex128 && dtype != DType::Complex64 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "hfft: input must be complex",
                },
            )));
        }

        let real_view = self.tensor_view_as_real(input)?;
        let vals = self.tensor_values(real_view)?;
        let freq_len = vals.len() / 2;
        let out_len = n.unwrap_or((freq_len - 1) * 2);

        // Reconstruct full spectrum using conjugate symmetry, then FFT
        let mut re_full = vec![0.0; out_len];
        let mut im_full = vec![0.0; out_len];

        for k in 0..freq_len.min(out_len) {
            re_full[k] = vals[k * 2];
            im_full[k] = vals[k * 2 + 1];
        }
        for k in 1..freq_len.min(out_len) {
            let mirror = out_len - k;
            if mirror < out_len {
                re_full[mirror] = vals[k * 2];
                im_full[mirror] = -vals[k * 2 + 1];
            }
        }

        // Forward FFT (not inverse) to get real output
        Self::dft_inplace_1d(&mut re_full, &mut im_full, false);

        self.tensor_variable(re_full, vec![out_len], false)
    }

    /// Compute the inverse Hermitian FFT (real input -> complex Hermitian output).
    ///
    /// Equivalent to `torch.fft.ihfft(input)`.
    /// Input is real of length n. Output is complex of length n/2+1.
    /// Tracked under frankentorch-ffpd.
    pub fn tensor_ihfft(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(input)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "ihfft: autograd not supported",
                },
            )));
        }

        let vals = self.tensor_values(input)?;
        let n = vals.len();
        let out_len = n / 2 + 1;

        // Inverse FFT of real input
        let mut re_buf = vals;
        let mut im_buf = vec![0.0_f64; n];
        Self::dft_inplace_1d(&mut re_buf, &mut im_buf, true);

        // Keep only the first n/2+1 bins (Hermitian-symmetric)
        let re_out: Vec<f64> = re_buf[..out_len].to_vec();
        let im_out: Vec<f64> = im_buf[..out_len].to_vec();

        let re_node = self.tensor_variable(re_out, vec![out_len], false)?;
        let im_node = self.tensor_variable(im_out, vec![out_len], false)?;
        self.tensor_complex(re_node, im_node)
    }

    /// Shift the zero-frequency component to the center of the spectrum.
    ///
    /// Equivalent to `torch.fft.fftshift(input, dim)`. Rolls the tensor by
    /// n//2 along the specified dimension(s) to center the DC component.
    pub fn tensor_fftshift(
        &mut self,
        input: TensorNodeId,
        dim: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if let Some(d) = dim {
            if d >= shape.len() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "fftshift: dim out of range",
                    },
                )));
            }
            let shift = (shape[d] / 2) as i64;
            self.tensor_roll(input, shift, d)
        } else {
            // Shift all dimensions sequentially
            let mut result = input;
            for (d, &dim_len) in shape.iter().enumerate() {
                let shift = (dim_len / 2) as i64;
                result = self.tensor_roll(result, shift, d)?;
            }
            Ok(result)
        }
    }

    /// Inverse of fftshift - shift zero-frequency back to the origin.
    ///
    /// Equivalent to `torch.fft.ifftshift(input, dim)`. Rolls the tensor by
    /// -(n//2) (or equivalently (n+1)//2) along the specified dimension(s).
    pub fn tensor_ifftshift(
        &mut self,
        input: TensorNodeId,
        dim: Option<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if let Some(d) = dim {
            if d >= shape.len() {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "ifftshift: dim out of range",
                    },
                )));
            }
            let shift = -((shape[d] / 2) as i64);
            self.tensor_roll(input, shift, d)
        } else {
            let mut result = input;
            for (d, &dim_len) in shape.iter().enumerate() {
                let shift = -((dim_len / 2) as i64);
                result = self.tensor_roll(result, shift, d)?;
            }
            Ok(result)
        }
    }

    // ── logsumexp ────────────────────────────────────────────────────────
    /// Numerically stable log-sum-exp reduction along a dimension.
    ///
    /// Equivalent to `torch.logsumexp(input, dim)`.
    pub fn tensor_logsumexp(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let in_shape = self.tensor_shape(input)?;
        let ndim = in_shape.len();
        if dim >= ndim {
            // Surface the actual offending (dim, ndim) so the
            // caller can diagnose without reparsing static
            // strings (frankentorch-ovad).
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }

        // Wrap in tensor_apply_function with the analytical backward
        //     y = log(sum_d exp(x_d))
        //     grad_x_d = grad_y * exp(x_d - y)
        // The exp(x - y) factor is in [0, 1] (since y >= max(x) under
        // max-subtract), so the backward is numerically stable.
        // Save x and y for backward. Tracked under frankentorch-t1q4.
        let mut out_shape: Vec<usize> = in_shape.clone();
        out_shape.remove(dim);
        if out_shape.is_empty() {
            out_shape.push(1);
        }
        let out_shape_clone = out_shape.clone();
        self.tensor_apply_function(
            &[input],
            move |ctx, inputs| {
                let (vals, shape) = inputs[0];
                let outer_size =
                    Self::checked_shape_numel(&shape[..dim], "logsumexp: outer overflow")?;
                let dim_size = shape[dim];
                let inner_size =
                    Self::checked_shape_numel(&shape[dim + 1..], "logsumexp: inner overflow")?;
                let out_len =
                    Self::checked_mul(outer_size, inner_size, "logsumexp: output overflow")?;
                let mut result = Vec::with_capacity(out_len);
                for outer in 0..outer_size {
                    for inner in 0..inner_size {
                        let mut max_val = f64::NEG_INFINITY;
                        for d in 0..dim_size {
                            let idx = outer * dim_size * inner_size + d * inner_size + inner;
                            if vals[idx] > max_val {
                                max_val = vals[idx];
                            }
                        }
                        let mut sum_exp = 0.0_f64;
                        for d in 0..dim_size {
                            let idx = outer * dim_size * inner_size + d * inner_size + inner;
                            sum_exp += (vals[idx] - max_val).exp();
                        }
                        result.push(max_val + sum_exp.ln());
                    }
                }
                ctx.save_for_backward(vals.to_vec(), shape.to_vec());
                ctx.save_for_backward(result.clone(), out_shape_clone.clone());
                Ok((result, out_shape_clone.clone()))
            },
            move |ctx, grad_outputs| {
                let grad_y = grad_outputs[0];
                let saved = ctx.saved_tensors();
                let saved_shapes = ctx.saved_shapes();
                let x_vals = &saved[0];
                let y_vals = &saved[1];
                let in_shape = &saved_shapes[0];
                let outer_size = Self::checked_shape_numel(
                    &in_shape[..dim],
                    "logsumexp backward: outer overflow",
                )?;
                let dim_size = in_shape[dim];
                let inner_size = Self::checked_shape_numel(
                    &in_shape[dim + 1..],
                    "logsumexp backward: inner overflow",
                )?;
                let mut grad_x = vec![0.0_f64; x_vals.len()];
                for outer in 0..outer_size {
                    for inner in 0..inner_size {
                        let y_idx = outer * inner_size + inner;
                        let y = y_vals[y_idx];
                        let g = grad_y[y_idx];
                        for d in 0..dim_size {
                            let idx = outer * dim_size * inner_size + d * inner_size + inner;
                            grad_x[idx] = g * (x_vals[idx] - y).exp();
                        }
                    }
                }
                Ok(vec![Some(grad_x)])
            },
        )
    }

    /// Compute the p-norm distance between two tensors.
    ///
    /// Equivalent to `torch.dist(input, other, p)`.
    pub fn tensor_dist(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
        p: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(a, b)?;
        self.tensor_norm(diff, p)
    }

    /// Move a dimension from `source` to `destination`.
    ///
    /// Equivalent to `torch.movedim(input, source, destination)`.
    pub fn tensor_movedim(
        &mut self,
        input: TensorNodeId,
        source: usize,
        destination: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let ndim = self.tensor_shape(input)?.len();
        if source >= ndim || destination >= ndim {
            // Surface whichever offender fired (source first
            // since it's listed first in the predicate);
            // frankentorch-ovad.
            let dim = if source >= ndim { source } else { destination };
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim, ndim },
            )));
        }
        if source == destination {
            return Ok(input);
        }
        let mut perm: Vec<usize> = (0..ndim).collect();
        perm.remove(source);
        perm.insert(destination, source);
        self.tensor_permute(input, perm)
    }

    /// Alias for `tensor_movedim`. Equivalent to `torch.moveaxis`.
    pub fn tensor_moveaxis(
        &mut self,
        input: TensorNodeId,
        source: usize,
        destination: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_movedim(input, source, destination)
    }

    /// Compute both min and max along a dimension. Returns `(min, max)`.
    ///
    /// Equivalent to `torch.aminmax(input, dim)`.
    pub fn tensor_aminmax(
        &mut self,
        input: TensorNodeId,
        dim: usize,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        // Compose through tensor_min_dim + tensor_max_dim so gradients
        // flow through both branches via argmin/argmax routing.
        // Tracked under frankentorch-b0y1 — previously this body
        // extracted values, computed mins/maxs in plain f64, and
        // rebuilt non-grad leaves, silently severing autograd.
        // tensor_min_dim / tensor_max_dim already implement the
        // proper backward via the tape; discard the indices since
        // aminmax doesn't return them.
        let shape = self.tensor_shape(input)?;
        if dim >= shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "aminmax: dimension out of range",
                },
            )));
        }
        let (min_out, _argmin) = self.tensor_min_dim(input, dim)?;
        let (max_out, _argmax) = self.tensor_max_dim(input, dim)?;
        Ok((min_out, max_out))
    }

    /// Extract sliding windows from a tensor along a dimension.
    ///
    /// Equivalent to `torch.Tensor.unfold(dimension, size, step)`.
    pub fn tensor_unfold(
        &mut self,
        input: TensorNodeId,
        dimension: usize,
        size: usize,
        step: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        if dimension >= ndim || size == 0 || size > shape[dimension] || step == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "unfold: invalid dimension, size, or step",
                },
            )));
        }
        // Pre-compute the (flat_out -> in_flat) gather table; both
        // the forward and backward closures use the same mapping.
        // The forward gathers vals[in_flat] into result[flat_out];
        // the backward scatters grad_output[flat_out] into
        // grad_input[in_flat] (accumulating overlaps from
        // step < size).
        // Tracked under frankentorch-hc18.
        let n_windows = (shape[dimension] - size) / step + 1;
        let mut strides = vec![1usize; ndim];
        for d in (0..ndim - 1).rev() {
            strides[d] =
                Self::checked_mul(strides[d + 1], shape[d + 1], "unfold: stride overflow")?;
        }
        let mut out_shape = shape.clone();
        out_shape[dimension] = n_windows;
        out_shape.push(size);
        let out_ndim = out_shape.len();
        let mut out_strides = vec![1usize; out_ndim];
        for d in (0..out_ndim - 1).rev() {
            out_strides[d] = Self::checked_mul(
                out_strides[d + 1],
                out_shape[d + 1],
                "unfold: output stride overflow",
            )?;
        }
        let out_numel = Self::checked_shape_numel(&out_shape, "unfold: output shape overflow")?;
        let in_numel = Self::checked_shape_numel(&shape, "unfold: input shape overflow")?;

        // Build the gather table once.
        let mut gather: Vec<usize> = Vec::with_capacity(out_numel);
        for flat_out in 0..out_numel {
            let mut remaining = flat_out;
            let mut coords = vec![0usize; out_ndim];
            for d in 0..out_ndim {
                coords[d] = remaining / out_strides[d];
                remaining %= out_strides[d];
            }
            let mut in_flat = 0;
            for d in 0..ndim {
                let c = if d == dimension {
                    coords[dimension] * step + coords[out_ndim - 1]
                } else {
                    coords[d]
                };
                in_flat += c * strides[d];
            }
            gather.push(in_flat);
        }
        let gather_for_fwd = gather.clone();
        let gather_for_bwd = gather;
        let out_shape_clone = out_shape.clone();

        self.tensor_apply_function(
            &[input],
            move |_ctx, inputs| {
                let (vals, _shape) = inputs[0];
                let result: Vec<f64> = gather_for_fwd.iter().map(|&k| vals[k]).collect();
                Ok((result, out_shape_clone.clone()))
            },
            move |_ctx, grad_outputs| {
                let g = grad_outputs[0];
                let mut grad_in = vec![0.0_f64; in_numel];
                for (flat_out, &in_flat) in gather_for_bwd.iter().enumerate() {
                    grad_in[in_flat] += g[flat_out];
                }
                Ok(vec![Some(grad_in)])
            },
        )
    }

    /// Return a copy of the unfolded tensor.
    ///
    /// Equivalent to `torch.Tensor.unfold_copy()`. Since ft-api always
    /// creates copies (no views), this is identical to `tensor_unfold`.
    pub fn tensor_unfold_copy(
        &mut self,
        input: TensorNodeId,
        dimension: usize,
        size: usize,
        step: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_unfold(input, dimension, size, step)
    }

    /// Renormalize sub-tensors so their p-norm <= maxnorm.
    ///
    /// Equivalent to `torch.renorm(input, p, dim, maxnorm)`.
    pub fn tensor_renorm(
        &mut self,
        input: TensorNodeId,
        p: f64,
        dim: usize,
        maxnorm: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if !p.is_finite() || p <= 0.0 || !maxnorm.is_finite() || maxnorm <= 0.0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "renorm: p and maxnorm must be finite and > 0",
                },
            )));
        }
        let n = shape.len();
        if dim >= n {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "renorm: dimension out of range",
                },
            )));
        }

        // Compose through autograd primitives. The closed-form scale
        // per slice is
        //     scale_d = maxnorm / max(norm_d, maxnorm)
        // which equals 1 when norm_d <= maxnorm and maxnorm/norm_d
        // otherwise. Tracked under frankentorch-go4q. Previously this
        // body extracted values, conditionally scaled in plain f64,
        // and rebuilt a non-grad leaf — silently severing autograd
        // through embedding-regularization paths
        // (torch.nn.Embedding(max_norm=...)).
        //
        // Strategy: permute `dim` to position 0, reshape to
        // [dim_size, other_size], compute per-row L_p norm, scale
        // each row, then reshape + permute back.
        let total = Self::checked_shape_numel(&shape, "renorm: shape volume overflow")?;
        let dim_size = shape[dim];
        let other_size = total / dim_size;

        // Build the swap-(0, dim) permutation. swap is its own inverse.
        let mut perm: Vec<usize> = (0..n).collect();
        perm.swap(0, dim);
        let permuted_shape: Vec<usize> = perm.iter().map(|&i| shape[i]).collect();

        let permuted = if dim == 0 {
            input
        } else {
            self.tensor_permute(input, perm.clone())?
        };
        let flat = self.tensor_reshape(permuted, vec![dim_size, other_size])?;

        let abs_x = self.tensor_abs(flat)?;
        let pow_x = self.tensor_pow(abs_x, p)?;
        let sum_x = self.tensor_sum_dim(pow_x, 1)?; // [dim_size]
        let norm = self.tensor_pow(sum_x, 1.0 / p)?; // [dim_size]
        let denom = self.tensor_clamp_min(norm, maxnorm)?; // [dim_size]
        let max_t = self.full(vec![dim_size], maxnorm, false)?;
        let scale = self.tensor_div(max_t, denom)?; // [dim_size]
        let scale_kd = self.tensor_unsqueeze(scale, 1)?; // [dim_size, 1]
        let scale_b = self.tensor_expand(scale_kd, vec![dim_size, other_size])?;
        let scaled = self.tensor_mul(flat, scale_b)?;

        let unflat = self.tensor_reshape(scaled, permuted_shape)?;
        if dim == 0 {
            Ok(unflat)
        } else {
            self.tensor_permute(unflat, perm)
        }
    }

    /// Test if each element is in a set of test values. Returns 0.0/1.0 mask.
    ///
    /// Equivalent to `torch.isin(elements, test_elements)`.
    pub fn tensor_isin(
        &mut self,
        elements: TensorNodeId,
        test_elements: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        if self.tensor_requires_grad(elements)? || self.tensor_requires_grad(test_elements)? {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "isin: autograd not supported (membership mask is non-differentiable). Tracked under frankentorch-gec0.",
                },
            )));
        }
        let elem_vals = self.tensor_values(elements)?;
        let test_vals = self.tensor_values(test_elements)?;
        let shape = self.tensor_shape(elements)?;
        let result: Vec<f64> = elem_vals
            .iter()
            .map(|&e| {
                if test_vals.iter().any(|&t| (e - t).abs() < f64::EPSILON) {
                    1.0
                } else {
                    0.0
                }
            })
            .collect();
        self.tensor_tape.leaf(result, shape, false)
    }

    // ── hstack ──────────────────────────────────────────────────────────
    /// Horizontally stack tensors (along dim 1 for 2D+, dim 0 for 1D).
    ///
    /// Equivalent to `torch.hstack(tensors)`.
    pub fn tensor_hstack(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if inputs.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "hstack: need at least one tensor",
                },
            )));
        }
        let ndim = self.tensor_shape(inputs[0])?.len();
        let dim = if ndim <= 1 { 0 } else { 1 };
        self.tensor_cat(inputs, dim)
    }

    // ── vstack ──────────────────────────────────────────────────────────
    /// Vertically stack tensors (along dim 0).
    ///
    /// Equivalent to `torch.vstack(tensors)` / `torch.row_stack(tensors)`.
    /// 1-D tensors are reshaped to `(1, N)` before stacking.
    pub fn tensor_vstack(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if inputs.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "vstack: need at least one tensor",
                },
            )));
        }

        // Reshape 1D inputs to 2D
        let mut reshaped = Vec::with_capacity(inputs.len());
        for &inp in inputs {
            let shape = self.tensor_shape(inp)?;
            if shape.len() == 1 {
                let n = shape[0];
                reshaped.push(self.tensor_reshape(inp, vec![1, n])?);
            } else {
                reshaped.push(inp);
            }
        }

        self.tensor_cat(&reshaped, 0)
    }

    /// Alias for `tensor_vstack`.
    pub fn tensor_row_stack(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_vstack(inputs)
    }

    // ── dstack ──────────────────────────────────────────────────────────
    /// Depth-stack tensors (along dim 2).
    ///
    /// Equivalent to `torch.dstack(tensors)`.
    /// 1-D inputs are reshaped to `(1, N, 1)`, 2-D inputs to `(N, M, 1)`.
    pub fn tensor_dstack(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if inputs.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "dstack: need at least one tensor",
                },
            )));
        }

        let mut reshaped = Vec::with_capacity(inputs.len());
        for &inp in inputs {
            let shape = self.tensor_shape(inp)?;
            match shape.len() {
                1 => {
                    let n = shape[0];
                    reshaped.push(self.tensor_reshape(inp, vec![1, n, 1])?);
                }
                2 => {
                    let (n, m) = (shape[0], shape[1]);
                    reshaped.push(self.tensor_reshape(inp, vec![n, m, 1])?);
                }
                _ => reshaped.push(inp),
            }
        }

        self.tensor_cat(&reshaped, 2)
    }

    // ── column_stack ────────────────────────────────────────────────────
    /// Stack 1-D tensors as columns and 2-D tensors horizontally.
    ///
    /// Equivalent to `torch.column_stack(tensors)`.
    pub fn tensor_column_stack(
        &mut self,
        inputs: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if inputs.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "column_stack: need at least one tensor",
                },
            )));
        }

        let mut reshaped = Vec::with_capacity(inputs.len());
        for &inp in inputs {
            let shape = self.tensor_shape(inp)?;
            if shape.len() == 1 {
                let n = shape[0];
                reshaped.push(self.tensor_reshape(inp, vec![n, 1])?);
            } else {
                reshaped.push(inp);
            }
        }

        self.tensor_cat(&reshaped, 1)
    }

    // ── hsplit ──────────────────────────────────────────────────────────
    /// Split tensor horizontally (along dim 1 for 2D+, dim 0 for 1D).
    ///
    /// Equivalent to `torch.hsplit(input, indices_or_sections)`.
    pub fn tensor_hsplit(
        &mut self,
        input: TensorNodeId,
        sections: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let ndim = self.tensor_shape(input)?.len();
        let dim = if ndim <= 1 { 0 } else { 1 };
        self.tensor_chunk(input, sections, dim)
    }

    // ── vsplit ──────────────────────────────────────────────────────────
    /// Split tensor vertically (along dim 0).
    ///
    /// Equivalent to `torch.vsplit(input, indices_or_sections)`.
    pub fn tensor_vsplit(
        &mut self,
        input: TensorNodeId,
        sections: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_chunk(input, sections, 0)
    }

    // ── dsplit ──────────────────────────────────────────────────────────
    /// Split tensor along depth (dim 2).
    ///
    /// Equivalent to `torch.dsplit(input, indices_or_sections)`.
    pub fn tensor_dsplit(
        &mut self,
        input: TensorNodeId,
        sections: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        self.tensor_chunk(input, sections, 2)
    }

    // ── trapezoid ────────────────────────────────────────────────────────
    /// Compute the trapezoidal rule along a dimension.
    ///
    /// Equivalent to `torch.trapezoid(y, x, dim)`.
    /// If `x` is None, assumes uniform spacing of 1.
    pub fn tensor_trapezoid(
        &mut self,
        y: TensorNodeId,
        x: Option<TensorNodeId>,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let y_shape = self.tensor_shape(y)?;
        let ndim = y_shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "trapezoid: dimension out of range",
                },
            )));
        }

        let dim_size = y_shape[dim];
        if dim_size < 2 {
            // With fewer than 2 points, integral is 0
            let mut out_shape = y_shape.clone();
            out_shape.remove(dim);
            if out_shape.is_empty() {
                out_shape.push(1);
            }
            let numel = Self::checked_shape_numel(&out_shape, "trapezoid: output shape overflow")?;
            return self.tensor_tape.leaf(vec![0.0; numel], out_shape, false);
        }

        // Compose through autograd primitives. Tracked under
        // frankentorch-b4ys. Math:
        //   y0 = narrow(y, dim, 0, n-1)
        //   y1 = narrow(y, dim, 1, n-1)
        //   dx = (x1 - x0) if x else 1   (broadcast)
        //   integral = sum((y0 + y1) * 0.5 * dx, dim)
        let new_dim_size = dim_size - 1;
        let y0 = self.tensor_narrow(y, dim, 0, new_dim_size)?;
        let y1 = self.tensor_narrow(y, dim, 1, new_dim_size)?;
        let y_sum = self.tensor_add(y0, y1)?;
        let mut narrow_shape = y_shape.clone();
        narrow_shape[dim] = new_dim_size;
        let half_t = self.full(narrow_shape.clone(), 0.5, false)?;
        let avg = self.tensor_mul(y_sum, half_t)?;

        let weighted = if let Some(x_id) = x {
            let x_shape = self.tensor_shape(x_id)?;
            if x_shape != y_shape {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "trapezoid: x and y must have the same shape",
                    },
                )));
            }
            let x0 = self.tensor_narrow(x_id, dim, 0, new_dim_size)?;
            let x1 = self.tensor_narrow(x_id, dim, 1, new_dim_size)?;
            let dx = self.tensor_sub(x1, x0)?;
            self.tensor_mul(avg, dx)?
        } else {
            // dx = 1 for all cells; just take avg.
            avg
        };

        let integral = self.tensor_sum_dim(weighted, dim)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("trapezoid y={} dim={dim} out={}", y.0, integral.0),
        );
        Ok(integral)
    }

    /// Alias for `tensor_trapezoid`. Equivalent to `torch.trapz`.
    ///
    /// Deprecated in favor of `trapezoid`, but kept for backwards compatibility.
    pub fn tensor_trapz(
        &mut self,
        y: TensorNodeId,
        x: Option<TensorNodeId>,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_trapezoid(y, x, dim)
    }

    // ── cumulative_trapezoid ────────────────────────────────────────────
    /// Compute the cumulative trapezoidal rule along a dimension.
    ///
    /// Equivalent to `torch.cumulative_trapezoid(y, x, dim)`.
    /// Returns a tensor with `dim_size - 1` along the specified dimension.
    pub fn tensor_cumulative_trapezoid(
        &mut self,
        y: TensorNodeId,
        x: Option<TensorNodeId>,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let y_shape = self.tensor_shape(y)?;
        let ndim = y_shape.len();
        if dim >= ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cumulative_trapezoid: dimension out of range",
                },
            )));
        }

        let dim_size = y_shape[dim];
        if dim_size < 2 {
            let mut out_shape = y_shape;
            out_shape[dim] = 0;
            return self.tensor_tape.leaf(Vec::new(), out_shape, false);
        }

        // Compose through autograd primitives. Tracked under
        // frankentorch-atg3. Same shape as tensor_trapezoid (b4ys)
        // but ends with tensor_cumsum instead of tensor_sum_dim.
        let new_dim_size = dim_size - 1;
        let y0 = self.tensor_narrow(y, dim, 0, new_dim_size)?;
        let y1 = self.tensor_narrow(y, dim, 1, new_dim_size)?;
        let y_sum = self.tensor_add(y0, y1)?;
        let mut narrow_shape = y_shape.clone();
        narrow_shape[dim] = new_dim_size;
        let half_t = self.full(narrow_shape.clone(), 0.5, false)?;
        let avg = self.tensor_mul(y_sum, half_t)?;

        let weighted = if let Some(x_id) = x {
            let x_shape = self.tensor_shape(x_id)?;
            if x_shape != y_shape {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "cumulative_trapezoid: x and y must have the same shape",
                    },
                )));
            }
            let x0 = self.tensor_narrow(x_id, dim, 0, new_dim_size)?;
            let x1 = self.tensor_narrow(x_id, dim, 1, new_dim_size)?;
            let dx = self.tensor_sub(x1, x0)?;
            self.tensor_mul(avg, dx)?
        } else {
            avg
        };

        let out = self.tensor_cumsum(weighted, dim)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("cumulative_trapezoid y={} dim={dim} out={}", y.0, out.0),
        );
        Ok(out)
    }

    // ── addr ────────────────────────────────────────────────────────────
    /// Perform a rank-1 update: `out = beta * input + alpha * vec1 ⊗ vec2`.
    ///
    /// Equivalent to `torch.addr(input, vec1, vec2, beta, alpha)`.
    pub fn tensor_addr(
        &mut self,
        input: TensorNodeId,
        vec1: TensorNodeId,
        vec2: TensorNodeId,
        beta: f64,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let v1_shape = self.tensor_shape(vec1)?;
        let v2_shape = self.tensor_shape(vec2)?;
        let input_shape = self.tensor_shape(input)?;
        if v1_shape.len() != 1 || v2_shape.len() != 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "addr: vec1 and vec2 must be 1-D",
                },
            )));
        }
        let m = v1_shape[0];
        let n = v2_shape[0];
        if input_shape != [m, n] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "addr: input shape must match (len(vec1), len(vec2))",
                },
            )));
        }

        // Compose through autograd-aware primitives. Tracked under
        // frankentorch-pzih. Math:
        //   out = beta * input + alpha * (vec1 ⊗ vec2)
        let outer = self.tensor_outer(vec1, vec2)?;
        let alpha_t = self.full(vec![m, n], alpha, false)?;
        let beta_t = self.full(vec![m, n], beta, false)?;
        let alpha_outer = self.tensor_mul(outer, alpha_t)?;
        let beta_input = self.tensor_mul(input, beta_t)?;
        let out = self.tensor_add(beta_input, alpha_outer)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!(
                "addr input={} vec1={} vec2={} beta={beta} alpha={alpha} out={}",
                input.0, vec1.0, vec2.0, out.0
            ),
        );
        Ok(out)
    }

    // ── inner ───────────────────────────────────────────────────────────
    /// Compute the inner product of two 1-D tensors.
    ///
    /// Equivalent to `torch.inner(input, other)` for 1-D inputs.
    /// For higher-dimensional inputs, contracts over the last dimension.
    /// Inputs must be at least 1-D.
    pub fn tensor_inner(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;

        if a_shape.is_empty() || b_shape.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "inner: scalar inputs are not supported",
                },
            )));
        }

        // Compose through autograd-aware primitives so gradients flow.
        // Previously this body extracted values + rebuilt a non-grad
        // leaf — same severed-autograd pattern fixed for the linalg
        // / cross / diag_embed / matrix_norm cluster. Tracked under
        // frankentorch-ytlg.
        //
        // 1-D × 1-D → dot product (delegated to tensor_dot, which is
        // autograd-aware via the tape).
        if a_shape.len() == 1 && b_shape.len() == 1 {
            if a_shape[0] != b_shape[0] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "inner: 1-D tensors must have same length",
                    },
                )));
            }
            let dot = self.tensor_dot(a, b)?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!("inner a={} b={} out={}", a.0, b.0, dot.0),
            );
            // tensor_dot returns a 0-D scalar; preserve the prior
            // [1]-shape contract.
            let dot_shape = self.tensor_shape(dot)?;
            return if dot_shape == [1] {
                Ok(dot)
            } else if dot_shape.is_empty() {
                self.tensor_unsqueeze(dot, 0)
            } else {
                self.tensor_reshape(dot, vec![1])
            };
        }

        // Higher-D: contract along the last axis. Reshape both inputs
        // to 2-D (outer, last) and compute matmul(a_flat, b_flat.T)
        // → (a_outer, b_outer), then reshape to the inner output
        // shape. matmul + transpose + reshape are all autograd-aware.
        let a_last =
            *a_shape
                .last()
                .ok_or(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "inner: missing last dimension on lhs",
                    },
                )))?;
        let b_last =
            *b_shape
                .last()
                .ok_or(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "inner: missing last dimension on rhs",
                    },
                )))?;
        if a_last == 0 || b_last == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "inner: last dimension must be non-zero",
                },
            )));
        }
        if a_last != b_last {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "inner: last dimensions must match",
                },
            )));
        }

        let a_numel = Self::checked_shape_numel(&a_shape, "inner: lhs shape volume overflow")?;
        let b_numel = Self::checked_shape_numel(&b_shape, "inner: rhs shape volume overflow")?;
        let a_outer = a_numel / a_last;
        let b_outer = b_numel / b_last;

        let a_flat = self.tensor_reshape(a, vec![a_outer, a_last])?;
        let b_flat = self.tensor_reshape(b, vec![b_outer, b_last])?;
        let b_t = self.tensor_transpose(b_flat, 0, 1)?;
        let prod = self.tensor_matmul(a_flat, b_t)?; // shape [a_outer, b_outer]

        let mut out_shape: Vec<usize> = a_shape[..a_shape.len() - 1].to_vec();
        out_shape.extend_from_slice(&b_shape[..b_shape.len() - 1]);
        if out_shape.is_empty() {
            out_shape.push(1);
        }
        let out = self.tensor_reshape(prod, out_shape)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("inner a={} b={} out={}", a.0, b.0, out.0),
        );
        Ok(out)
    }

    // ── fliplr ──────────────────────────────────────────────────────────
    /// Flip tensor in the left/right direction (along dim 1).
    ///
    /// Equivalent to `torch.fliplr(input)`. Input must be >= 2-D.
    pub fn tensor_fliplr(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let ndim = self.tensor_shape(input)?.len();
        if ndim < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "fliplr: input must be at least 2-D",
                },
            )));
        }
        self.tensor_flip(input, &[1])
    }

    // ── flipud ──────────────────────────────────────────────────────────
    /// Flip tensor in the up/down direction (along dim 0).
    ///
    /// Equivalent to `torch.flipud(input)`. Input must be >= 1-D.
    pub fn tensor_flipud(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let ndim = self.tensor_shape(input)?.len();
        if ndim < 1 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "flipud: input must be at least 1-D",
                },
            )));
        }
        self.tensor_flip(input, &[0])
    }

    // ── diagflat ────────────────────────────────────────────────────────
    /// Create a diagonal matrix from a flattened input, with optional offset.
    ///
    /// Equivalent to `torch.diagflat(input, offset)`.
    /// Flattens the input and places values along the specified diagonal.
    pub fn tensor_diagflat(
        &mut self,
        input: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        // Compose through reshape + tensor_diag_embed (the latter is
        // autograd-aware after frankentorch-d180). Tracked under
        // frankentorch-lgps. Previously this body extracted values,
        // built the matrix in plain f64, and rebuilt a non-grad leaf.
        //
        // diagflat(x, offset) == diag_embed(flatten(x), offset)
        // with input flattened to 1-D first.
        let shape = self.tensor_shape(input)?;
        let n = Self::checked_shape_numel(&shape, "diagflat: shape volume overflow")?;
        // diag_embed expects i32 offset; range-check the i64 input.
        let offset_i32 = i32::try_from(offset).map_err(|_| {
            AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "diagflat: offset out of range for i32",
                },
            ))
        })?;
        let flat = if shape.len() == 1 {
            input
        } else {
            self.tensor_reshape(input, vec![n])?
        };
        let out = self.tensor_diag_embed(flat, offset_i32)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("diagflat input={} offset={offset} out={}", input.0, out.0),
        );
        Ok(out)
    }

    // ── tensor_select ────────────────────────────────────────────────────
    /// Select a single slice along a dimension, removing that dimension.
    ///
    /// Equivalent to `torch.select(input, dim, index)`.
    /// Returns a tensor with one fewer dimension.
    pub fn tensor_select(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if dim >= shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select: dimension out of range",
                },
            )));
        }
        if index >= shape[dim] {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "select: index out of range for dimension",
                },
            )));
        }

        // narrow to length 1, then squeeze that dimension
        let narrowed = self.tensor_narrow(input, dim, index, 1)?;
        self.tensor_squeeze(narrowed, dim)
    }

    /// Copy variant of select.
    ///
    /// Equivalent to `tensor.select_copy(dim, index)`.
    /// Since ft-api creates copies, this is identical to `tensor_select`.
    pub fn tensor_select_copy(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_select(input, dim, index)
    }

    // ── tensor_take_along_dim ──────────────────────────────────────────
    /// Gather values along a dimension using indices from another tensor.
    ///
    /// Equivalent to `torch.take_along_dim(input, indices, dim)`.
    /// Both tensors must have the same number of dimensions, and `indices`
    /// determines which elements to select along `dim`.
    pub fn tensor_take_along_dim(
        &mut self,
        input: TensorNodeId,
        indices: TensorNodeId,
        dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        // This is equivalent to gather
        self.tensor_gather(input, dim, indices)
    }

    // ── tensor_scatter_reduce ──────────────────────────────────────────
    /// Scatter values into a tensor with a reduction operation.
    ///
    /// Equivalent to `torch.Tensor.scatter_reduce_(dim, index, src, reduce)`.
    /// Supported reduce operations: "sum", "prod", "mean", "amax", "amin".
    pub fn tensor_scatter_reduce(
        &mut self,
        input: TensorNodeId,
        dim: usize,
        index: TensorNodeId,
        src: TensorNodeId,
        reduce: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let input_shape = self.tensor_shape(input)?;
        let idx_shape = self.tensor_shape(index)?;
        let src_shape = self.tensor_shape(src)?;

        if dim >= input_shape.len() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce: dimension out of range",
                },
            )));
        }

        let ndim = input_shape.len();
        if idx_shape.len() != ndim {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce: index rank must match input rank",
                },
            )));
        }
        for d in 0..ndim {
            if d != dim && idx_shape[d] != input_shape[d] {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scatter_reduce: index shape must match input shape except at dim",
                    },
                )));
            }
        }
        if src_shape != idx_shape {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce: src shape must match index shape",
                },
            )));
        }
        if !matches!(reduce, "sum" | "prod" | "mean" | "amax" | "amin") {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce: unsupported reduce operation",
                },
            )));
        }

        // For requires_grad inputs/src, the 'sum' reduction has a
        // direct autograd-aware composition: tensor_scatter_add(input,
        // dim, index, src). Other reductions (prod / mean / amax /
        // amin) need bespoke backwards that aren't yet implemented;
        // surface them as fail-loud guards so users don't silently
        // get NaN gradients. Tracked under frankentorch-dhm4.
        if self.tensor_requires_grad(input)? || self.tensor_requires_grad(src)? {
            if reduce == "sum" {
                return self.tensor_scatter_add(input, dim, index, src);
            }
            if reduce == "mean" {
                // Compose mean as scatter_add(input, src) / (1 + count_per_position).
                // include_self=True semantics: positions never hit
                // get count=0, divisor=1, output = input.
                // Tracked under frankentorch-uzca.
                let src_shape = self.tensor_shape(src)?;
                let ones_src = self.full(src_shape.clone(), 1.0, false)?;
                // Seed the divisor with ones-of-input-shape so the
                // scatter_add directly produces 1 + count_per_position
                // (frankentorch-ix9k). This removes a separate
                // full(input_shape, 1.0) allocation and the trailing
                // tensor_add(count, one_t) node — the +1 represents
                // the include_self=True input contribution.
                let ones_input = self.full(input_shape, 1.0, false)?;
                let divisor = self.tensor_scatter_add(ones_input, dim, index, ones_src)?;
                let summed = self.tensor_scatter_add(input, dim, index, src)?;
                return self.tensor_div(summed, divisor);
            }
            if reduce == "amax" || reduce == "amin" {
                // Argmax-routing autograd (frankentorch-7k6a). For
                // each output position, exactly one of input[i] or
                // one src[j]→i wins; the gradient flows only to the
                // winning element. Forward: result[i] = mask_input[i]
                // * input[i] + sum over j-mapped-to-i of mask_src[j]
                // * src[j], with masks computed in plain f64 from the
                // input/src values (non-diff). The masks are
                // reconstructed exactly via a values read.
                let input_vals = self.tensor_tape.values(input)?;
                let src_vals = self.tensor_tape.values(src)?;
                let idx_vals = self.tensor_tape.values(index)?;
                let src_shape = self.tensor_shape(src)?;
                let in_numel = input_vals.len();
                let src_numel = src_vals.len();
                let dim_size = input_shape[dim];
                // Compute outer/inner strides for [outer, dim_size, inner] view.
                let outer = Self::checked_shape_numel(
                    &input_shape[..dim],
                    "scatter_reduce: outer overflow",
                )?;
                let inner = Self::checked_shape_numel(
                    &input_shape[dim + 1..],
                    "scatter_reduce: inner overflow",
                )?;
                let dim_size_i = isize::try_from(dim_size).map_err(|_| {
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: dim size out of platform isize",
                        },
                    ))
                })?;
                // For each (outer, inner) cell, compute the winner across
                // input[outer, dim_size, inner] and the src values that map to it.
                // Track best value + bool flag (true = src wins) + src index.
                let mut input_winner = vec![false; in_numel];
                let mut src_winner = vec![false; src_numel];
                let mut best = vec![f64::NAN; in_numel];
                // Initialize best with input values; mark input as winner.
                #[allow(clippy::needless_range_loop)]
                for i in 0..in_numel {
                    best[i] = input_vals[i];
                    input_winner[i] = true;
                }
                // Walk src in flat order; map each (outer, src_dim, inner) → input position.
                let src_dim_size = src_shape[dim];
                let src_outer = Self::checked_shape_numel(
                    &src_shape[..dim],
                    "scatter_reduce: src outer overflow",
                )?;
                let src_inner = Self::checked_shape_numel(
                    &src_shape[dim + 1..],
                    "scatter_reduce: src inner overflow",
                )?;
                if src_outer != outer || src_inner != inner {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: src shape must match input shape except at dim",
                        },
                    )));
                }
                for o in 0..outer {
                    for s in 0..src_dim_size {
                        for i in 0..inner {
                            let src_flat = (o * src_dim_size + s) * inner + i;
                            // Validate index value.
                            let idx_f = idx_vals[src_flat];
                            let idx_i = Self::exact_integer_index_to_isize(
                                idx_f,
                                "scatter_reduce: index values must be finite integers",
                            )?;
                            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                                return Err(AutogradError::Dispatch(
                                    ft_dispatch::DispatchError::Key(
                                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                                            reason: "scatter_reduce: index value out of range",
                                        },
                                    ),
                                ));
                            }
                            let target_dim = if idx_i < 0 {
                                (idx_i + dim_size_i) as usize
                            } else {
                                idx_i as usize
                            };
                            let dst_flat = (o * dim_size + target_dim) * inner + i;
                            let v = src_vals[src_flat];
                            let beats = if reduce == "amax" {
                                v > best[dst_flat]
                            } else {
                                v < best[dst_flat]
                            };
                            if beats {
                                // Demote previous winner.
                                if input_winner[dst_flat] {
                                    input_winner[dst_flat] = false;
                                }
                                // Find any prior src winner for this dst and demote.
                                // Scan back through src that hit this dst — but since
                                // we walk src in flat order, the prior winner (if any)
                                // is the most recent earlier src that beat all before
                                // it. We can simply clear src_winner for any earlier
                                // src that mapped here. Use a simpler approach: track
                                // best-src-flat per dst.
                                // (Re-scan would be O(n^2); use a dst→best_src lookup.)
                                best[dst_flat] = v;
                                src_winner[src_flat] = true;
                                // Demote any older src winner for this dst
                                for prior in 0..src_flat {
                                    if !src_winner[prior] {
                                        continue;
                                    }
                                    // Compute prior's dst:
                                    let prior_o = prior / (src_dim_size * inner);
                                    let prior_rem = prior % (src_dim_size * inner);
                                    let prior_i = prior_rem % inner;
                                    let prior_idx_f = idx_vals[prior];
                                    let prior_idx_i = prior_idx_f as isize;
                                    let prior_target = if prior_idx_i < 0 {
                                        (prior_idx_i + dim_size_i) as usize
                                    } else {
                                        prior_idx_i as usize
                                    };
                                    let prior_dst =
                                        (prior_o * dim_size + prior_target) * inner + prior_i;
                                    if prior_dst == dst_flat {
                                        src_winner[prior] = false;
                                    }
                                }
                            }
                        }
                    }
                }
                // Build mask tensors and compose final result.
                let mask_in_vals: Vec<f64> = input_winner
                    .iter()
                    .map(|&w| if w { 1.0 } else { 0.0 })
                    .collect();
                let mask_src_vals: Vec<f64> = src_winner
                    .iter()
                    .map(|&w| if w { 1.0 } else { 0.0 })
                    .collect();
                let mask_in = self.tensor_variable(mask_in_vals, input_shape.clone(), false)?;
                let mask_src = self.tensor_variable(mask_src_vals, src_shape, false)?;
                let masked_input = self.tensor_mul(mask_in, input)?;
                let masked_src = self.tensor_mul(mask_src, src)?;
                return self.tensor_scatter_add(masked_input, dim, index, masked_src);
            }
            if reduce == "prod" {
                let input_dtype = self.tensor_tape.dtype(input)?;
                let src_dtype = self.tensor_tape.dtype(src)?;
                if src_dtype != input_dtype {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce requires input and src to have matching dtypes",
                        },
                    )));
                }
                if !matches!(input_dtype, DType::F64 | DType::F32) {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce requires f32 or f64 tensors",
                        },
                    )));
                }

                let idx_vals = self.tensor_values(index)?;
                Self::validate_index_tensor_values(&input_shape, dim, &idx_vals)?;
                let in_numel =
                    Self::checked_shape_numel(&input_shape, "scatter_reduce prod input overflow")?;
                let src_numel =
                    Self::checked_shape_numel(&src_shape, "scatter_reduce prod src overflow")?;
                let outer = Self::checked_shape_numel(
                    &input_shape[..dim],
                    "scatter_reduce prod outer overflow",
                )?;
                let inner = Self::checked_shape_numel(
                    &input_shape[dim + 1..],
                    "scatter_reduce prod inner overflow",
                )?;
                let dim_size = input_shape[dim];
                let src_dim_size = src_shape[dim];
                let src_outer = Self::checked_shape_numel(
                    &src_shape[..dim],
                    "scatter_reduce prod src outer overflow",
                )?;
                let src_inner = Self::checked_shape_numel(
                    &src_shape[dim + 1..],
                    "scatter_reduce prod src inner overflow",
                )?;
                if src_outer != outer || src_inner != inner {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: src shape must match input shape except at dim",
                        },
                    )));
                }
                let dim_size_i = isize::try_from(dim_size).map_err(|_| {
                    AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: dim size out of platform isize",
                        },
                    ))
                })?;
                let mut dst_for_src = vec![0usize; src_numel];
                for o in 0..outer {
                    for s in 0..src_dim_size {
                        for i in 0..inner {
                            let src_flat = (o * src_dim_size + s) * inner + i;
                            let idx_i = Self::exact_integer_index_to_isize(
                                idx_vals[src_flat],
                                "scatter_reduce: index values must be finite integers",
                            )?;
                            if idx_i < -dim_size_i || idx_i >= dim_size_i {
                                return Err(AutogradError::Dispatch(
                                    ft_dispatch::DispatchError::Key(
                                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                                            reason: "scatter_reduce: index value out of range",
                                        },
                                    ),
                                ));
                            }
                            let target_dim = if idx_i < 0 {
                                (idx_i + dim_size_i) as usize
                            } else {
                                idx_i as usize
                            };
                            dst_for_src[src_flat] = (o * dim_size + target_dim) * inner + i;
                        }
                    }
                }

                let output_shape_f = input_shape.clone();
                let dst_for_src_f = dst_for_src.clone();
                let dst_for_src_b = dst_for_src;
                let out = self.tensor_apply_function(
                    &[input, src],
                    move |ctx, inputs| {
                        let (input_values, input_shape) = inputs[0];
                        let (src_values, src_shape) = inputs[1];
                        let mut output = input_values.to_vec();
                        for (src_flat, &dst_flat) in dst_for_src_f.iter().enumerate() {
                            output[dst_flat] *= src_values[src_flat];
                        }
                        ctx.save_for_backward(input_values.to_vec(), input_shape.to_vec());
                        ctx.save_for_backward(src_values.to_vec(), src_shape.to_vec());
                        Ok((output, output_shape_f.clone()))
                    },
                    move |ctx, grad_outputs| {
                        let grad_output = grad_outputs[0];
                        if grad_output.len() != in_numel {
                            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                                ft_dispatch::DispatchKeyError::IncompatibleSet {
                                    reason: "scatter_reduce prod backward: incoming gradient shape mismatch",
                                },
                            )));
                        }
                        let saved = ctx.saved_tensors();
                        let input_values = &saved[0];
                        let src_values = &saved[1];
                        let mut product_nonzero = vec![1.0_f64; in_numel];
                        let mut zero_count = vec![0usize; in_numel];
                        for (dst, &value) in input_values.iter().enumerate() {
                            if value == 0.0 {
                                zero_count[dst] += 1;
                            } else {
                                product_nonzero[dst] *= value;
                            }
                        }
                        for (src_flat, &dst_flat) in dst_for_src_b.iter().enumerate() {
                            let value = src_values[src_flat];
                            if value == 0.0 {
                                zero_count[dst_flat] += 1;
                            } else {
                                product_nonzero[dst_flat] *= value;
                            }
                        }

                        let factor_grad = |value: f64, dst: usize| -> f64 {
                            let upstream = grad_output[dst];
                            match zero_count[dst] {
                                0 => upstream * product_nonzero[dst] / value,
                                1 if value == 0.0 => upstream * product_nonzero[dst],
                                _ => 0.0,
                            }
                        };
                        let grad_input = input_values
                            .iter()
                            .enumerate()
                            .map(|(dst, &value)| factor_grad(value, dst))
                            .collect::<Vec<_>>();
                        let grad_src = src_values
                            .iter()
                            .enumerate()
                            .map(|(src_flat, &value)| factor_grad(value, dst_for_src_b[src_flat]))
                            .collect::<Vec<_>>();
                        Ok(vec![Some(grad_input), Some(grad_src)])
                    },
                )?;
                self.runtime.ledger_mut().record(
                    EvidenceKind::Dispatch,
                    format!(
                        "scatter_reduce input={} dim={dim} reduce=prod out={} (autograd)",
                        input.0, out.0
                    ),
                );
                return Ok(out);
            }
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce: autograd not supported for reduce='prod' (divide-back at zero is unstable; tracked under frankentorch-dhm4)",
                },
            )));
        }

        let input_dtype = self.tensor_tape.dtype(input)?;
        let src_dtype = self.tensor_tape.dtype(src)?;
        if src_dtype != input_dtype {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "scatter_reduce requires input and src to have matching dtypes",
                },
            )));
        }

        // Validate all index values are in range (supports negative wrapping)
        let idx_vals = self.tensor_values(index)?;
        Self::validate_index_tensor_values(&input_shape, dim, &idx_vals)?;
        let dim_size = input_shape[dim];

        // Compute strides with overflow checks
        let mut strides = vec![1usize; ndim];
        for d in (0..ndim - 1).rev() {
            strides[d] = Self::checked_shape_numel(
                &input_shape[d + 1..],
                "scatter_reduce input stride shape overflow",
            )?;
        }

        let mut idx_strides = vec![1usize; ndim];
        for d in (0..ndim - 1).rev() {
            idx_strides[d] = Self::checked_shape_numel(
                &idx_shape[d + 1..],
                "scatter_reduce index stride shape overflow",
            )?;
        }

        let total_idx =
            Self::checked_shape_numel(&idx_shape, "scatter_reduce index shape volume overflow")?;

        let out = match input_dtype {
            DType::F64 => {
                let input_vals = self.tensor_tape.values(input)?;
                let src_vals = self.tensor_tape.values(src)?;
                if src_vals.len() < total_idx {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: src storage too small for index shape",
                        },
                    )));
                }
                let mut result = input_vals.clone();
                let mut counts: Vec<usize> = if reduce == "mean" {
                    vec![0; result.len()]
                } else {
                    Vec::new()
                };

                for flat_i in 0..total_idx {
                    // Convert flat index to multi-dimensional
                    let mut remaining = flat_i;
                    let mut coords = vec![0usize; ndim];
                    for d in 0..ndim {
                        coords[d] = remaining / idx_strides[d];
                        remaining %= idx_strides[d];
                    }

                    // Normalize negative indices (already validated by validate_index_tensor_values)
                    let raw_idx = idx_vals[flat_i] as isize;
                    let target_dim_idx = if raw_idx < 0 {
                        (raw_idx + dim_size as isize) as usize
                    } else {
                        raw_idx as usize
                    };

                    // Compute output flat index
                    coords[dim] = target_dim_idx;
                    let out_flat: usize = coords
                        .iter()
                        .zip(strides.iter())
                        .map(|(&c, &s)| c * s)
                        .sum();
                    let sv = src_vals[flat_i];

                    match reduce {
                        "sum" => result[out_flat] += sv,
                        "prod" => result[out_flat] *= sv,
                        "mean" => {
                            result[out_flat] += sv;
                            counts[out_flat] += 1;
                        }
                        "amax" => {
                            if sv > result[out_flat] {
                                result[out_flat] = sv;
                            }
                        }
                        "amin" => {
                            if sv < result[out_flat] {
                                result[out_flat] = sv;
                            }
                        }
                        _ => {
                            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                                ft_dispatch::DispatchKeyError::IncompatibleSet {
                                    reason: "scatter_reduce: unsupported reduce operation",
                                },
                            )));
                        }
                    }
                }

                // Finalize mean reduction
                if reduce == "mean" {
                    for (i, &c) in counts.iter().enumerate() {
                        if c > 0 {
                            result[i] /= (c + 1) as f64; // +1 for original value
                        }
                    }
                }

                self.tensor_variable(result, input_shape.clone(), false)?
            }
            DType::F32 => {
                let input_vals = self.tensor_tape.values_f32(input)?;
                let src_vals = self.tensor_tape.values_f32(src)?;
                if src_vals.len() < total_idx {
                    return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                        ft_dispatch::DispatchKeyError::IncompatibleSet {
                            reason: "scatter_reduce: src storage too small for index shape",
                        },
                    )));
                }
                let mut result = input_vals.clone();
                let mut counts: Vec<usize> = if reduce == "mean" {
                    vec![0; result.len()]
                } else {
                    Vec::new()
                };

                for flat_i in 0..total_idx {
                    // Convert flat index to multi-dimensional
                    let mut remaining = flat_i;
                    let mut coords = vec![0usize; ndim];
                    for d in 0..ndim {
                        coords[d] = remaining / idx_strides[d];
                        remaining %= idx_strides[d];
                    }

                    // Normalize negative indices (already validated by validate_index_tensor_values)
                    let raw_idx = idx_vals[flat_i] as isize;
                    let target_dim_idx = if raw_idx < 0 {
                        (raw_idx + dim_size as isize) as usize
                    } else {
                        raw_idx as usize
                    };

                    // Compute output flat index
                    coords[dim] = target_dim_idx;
                    let out_flat: usize = coords
                        .iter()
                        .zip(strides.iter())
                        .map(|(&c, &s)| c * s)
                        .sum();
                    let sv = src_vals[flat_i];

                    match reduce {
                        "sum" => result[out_flat] += sv,
                        "prod" => result[out_flat] *= sv,
                        "mean" => {
                            result[out_flat] += sv;
                            counts[out_flat] += 1;
                        }
                        "amax" => {
                            if sv > result[out_flat] {
                                result[out_flat] = sv;
                            }
                        }
                        "amin" => {
                            if sv < result[out_flat] {
                                result[out_flat] = sv;
                            }
                        }
                        _ => {
                            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                                ft_dispatch::DispatchKeyError::IncompatibleSet {
                                    reason: "scatter_reduce: unsupported reduce operation",
                                },
                            )));
                        }
                    }
                }

                // Finalize mean reduction
                if reduce == "mean" {
                    for (i, &c) in counts.iter().enumerate() {
                        if c > 0 {
                            result[i] /= (c + 1) as f32; // +1 for original value
                        }
                    }
                }

                self.tensor_variable_f32(result, input_shape.clone(), false)?
            }
            _ => {
                return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                    ft_dispatch::DispatchKeyError::IncompatibleSet {
                        reason: "scatter_reduce requires f32 or f64 tensors",
                    },
                )));
            }
        };
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!(
                "scatter_reduce input={} dim={dim} reduce={reduce} out={}",
                input.0, out.0
            ),
        );
        Ok(out)
    }

    // ── tile ────────────────────────────────────────────────────────────
    /// Repeat tensor along each dimension the specified number of times.
    ///
    /// Equivalent to `torch.tile(input, dims)` / `numpy.tile`.
    pub fn tensor_tile(
        &mut self,
        input: TensorNodeId,
        dims: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let ndim = shape.len();
        let reps_len = dims.len();

        // Pad dims or shape to match lengths
        let (eff_shape, eff_reps) = if reps_len > ndim {
            let mut new_shape = vec![1; reps_len - ndim];
            new_shape.extend_from_slice(&shape);
            (new_shape, dims.to_vec())
        } else {
            let mut new_reps = vec![1; ndim - reps_len];
            new_reps.extend_from_slice(dims);
            (shape, new_reps)
        };

        // If input needs reshaping to match effective dims
        let mut current = if eff_shape.len() != {
            let t = self.tensor_tape.tensor(input)?;
            t.meta().shape().len()
        } {
            self.tensor_reshape(input, eff_shape.clone())?
        } else {
            input
        };

        // Use tensor_repeat which repeats along each dimension
        current = self.tensor_repeat(current, &eff_reps)?;
        Ok(current)
    }

    // ── cov ─────────────────────────────────────────────────────────────
    /// Compute the covariance matrix of a 2-D tensor (variables × observations).
    ///
    /// Equivalent to `torch.cov(input)`.
    /// Input shape: `(N, M)` where N is the number of variables and M is
    /// the number of observations. Returns an `(N, N)` covariance matrix.
    ///
    /// Composes through tensor_mean_dim / tensor_unsqueeze /
    /// tensor_expand / tensor_sub / tensor_matmul / tensor_transpose /
    /// tensor_div so the autograd tape carries gradients through the
    /// input. Previously this extracted tensor_values and rebuilt a
    /// requires_grad=false leaf, severing the tape (same pattern
    /// recently fixed for xlogy / xlog1py / logit / entr — tracked
    /// under frankentorch-1tax).
    pub fn tensor_cov(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cov: input must be a 2-D tensor (N, M)",
                },
            )));
        }
        let n = shape[0]; // variables
        let m = shape[1]; // observations
        if m < 2 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "cov: need at least 2 observations",
                },
            )));
        }

        // means[i] = mean over observations for variable i.
        // Shape: [N]. Unsqueeze + expand to [N, M] so broadcast
        // subtraction has matching shapes (tensor_sub doesn't itself
        // broadcast in this code base for arbitrary shapes).
        let means = self.tensor_mean_dim(input, 1)?;
        let means_unsq = self.tensor_unsqueeze(means, 1)?;
        let means_bcast = self.tensor_expand(means_unsq, vec![n, m])?;
        let centered = self.tensor_sub(input, means_bcast)?;

        // cov = (centered @ centered.T) / (m - 1).
        let centered_t = self.tensor_transpose(centered, 0, 1)?;
        let outer = self.tensor_matmul(centered, centered_t)?;
        #[allow(clippy::cast_precision_loss)]
        let denom_value = (m - 1) as f64;
        let denom = self.full(vec![n, n], denom_value, false)?;
        let cov = self.tensor_div(outer, denom)?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("cov input={} out={}", input.0, cov.0),
        );
        Ok(cov)
    }

    // ── corrcoef ────────────────────────────────────────────────────────
    /// Compute the Pearson correlation coefficient matrix.
    ///
    /// Equivalent to `torch.corrcoef(input)`.
    /// Input shape: `(N, M)`. Returns an `(N, N)` correlation matrix.
    ///
    /// Composes through tensor_cov + tensor_diagonal + tensor_sqrt +
    /// tensor_outer + tensor_div + tensor_eq + tensor_where so the
    /// autograd tape carries gradients through the input. Previously
    /// this delegated to tensor_cov, then extracted values and rebuilt
    /// a fresh requires_grad=false leaf — severing the tape after
    /// cov's autograd graph was built. Tracked under
    /// frankentorch-1tax.
    ///
    /// Math: corr[i,j] = cov[i,j] / sqrt(cov[i,i] * cov[j,j])
    ///                 = cov[i,j] / (sqrt(diag(cov))[i] * sqrt(diag(cov))[j])
    /// The latter form admits a clean composition via the outer
    /// product of sqrt(diag). When the denominator is zero (any
    /// variable with zero variance) the result is 0 — implemented
    /// via tensor_where masking.
    pub fn tensor_corrcoef(&mut self, input: TensorNodeId) -> Result<TensorNodeId, AutogradError> {
        let cov = self.tensor_cov(input)?;
        let n_shape = self.tensor_shape(cov)?;
        let n = n_shape[0];

        let diag = self.tensor_diagonal(cov, 0)?;
        let diag_sqrt = self.tensor_sqrt(diag)?;
        let denom = self.tensor_outer(diag_sqrt, diag_sqrt)?;

        // corr_unsafe = cov / denom (NaN/inf at zero-variance entries).
        let corr_unsafe = self.tensor_div(cov, denom)?;

        // mask = (denom == 0); where mask is true, output 0.
        // Single shared zeros tensor across the eq mask and the
        // where-true branch (frankentorch-z3rb) — both ops only
        // READ their constant operand. -1 full() + -1 tape node;
        // saves an n² f64 allocation per call.
        let zeros = self.full(vec![n, n], 0.0, false)?;
        let mask = self.tensor_eq(denom, zeros)?;
        let out = self.tensor_where(mask, zeros, corr_unsafe)?;

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("corrcoef input={} out={}", input.0, out.0),
        );
        Ok(out)
    }

    // ── mode ────────────────────────────────────────────────────────────
    /// Return the mode (most frequent value) and its index along the last dimension.
    ///
    /// Equivalent to `torch.mode(input)`.
    /// Returns `(values, indices)` as a pair of tensors.
    /// Input must have at least one dimension and a non-zero last dimension.
    ///
    /// The values tensor composes through `tensor_gather` so the
    /// autograd tape carries gradients through the input — backward
    /// scatter-adds the incoming gradient at whichever input position
    /// holds the mode value. Previously this extracted tensor_values,
    /// computed both arrays in plain f64, and rebuilt fresh
    /// requires_grad=false leaves, severing the tape. Tracked under
    /// frankentorch-1tax. (The indices output is intrinsically
    /// non-differentiable, so it stays as a constant leaf — same
    /// convention as torch.mode.)
    ///
    /// Forward also switches the per-run-length comparison from
    /// `(a - b).abs() < f64::EPSILON` to IEEE `==`, matching the
    /// `tensor_unique` parity fix for value-binning behaviour. Among
    /// values that PyTorch / numpy treat as distinct (e.g. subnormals
    /// 5e-324 vs 1e-323), the previous heuristic would fuse them
    /// into a single run.
    pub fn tensor_mode(
        &mut self,
        input: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "mode: input must have at least 1 dimension",
                },
            )));
        }
        let last_dim = shape[shape.len() - 1];
        if last_dim == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "mode: last dimension must be non-zero",
                },
            )));
        }
        let vals = self.tensor_values(input)?;
        let outer: usize = vals.len() / last_dim;

        // Compute the mode position in each outer slice. The position
        // is non-differentiable (sort + count), so this stays in
        // plain f64; the autograd composition then uses gather on
        // these pre-computed indices to extract values from `input`.
        let mut mode_idxs: Vec<f64> = Vec::with_capacity(outer);
        for o in 0..outer {
            let slice = &vals[o * last_dim..(o + 1) * last_dim];
            let mut sorted: Vec<(f64, usize)> = slice
                .iter()
                .copied()
                .enumerate()
                .map(|(i, v)| (v, i))
                .collect();
            sorted.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap_or(std::cmp::Ordering::Equal));

            let mut best_idx = sorted[0].1;
            let mut best_count = 1usize;
            let mut cur_count = 1usize;
            for i in 1..sorted.len() {
                if sorted[i].0 == sorted[i - 1].0 {
                    cur_count += 1;
                } else {
                    cur_count = 1;
                }
                if cur_count > best_count {
                    best_count = cur_count;
                    best_idx = sorted[i].1;
                }
            }
            #[allow(clippy::cast_precision_loss)]
            mode_idxs.push(best_idx as f64);
        }

        // Build a same-rank index tensor that selects the mode
        // position along the last dim of `input`. tensor_gather
        // requires the index to have the same rank as the input
        // with size 1 along the gathered dim and matching sizes
        // elsewhere.
        let mut index_shape: Vec<usize> = shape[..shape.len() - 1].to_vec();
        index_shape.push(1);
        let dim = shape.len() - 1;
        let index_node = self
            .tensor_tape
            .leaf(mode_idxs.clone(), index_shape, false)?;
        let gathered = self.tensor_gather(input, dim, index_node)?;

        // Output shape: rank-1 input keeps shape [1] (matching the
        // pre-fix contract); rank >= 2 squeezes the last dim away.
        let vals_out = if shape.len() > 1 {
            self.tensor_squeeze(gathered, dim)?
        } else {
            gathered
        };

        let idxs_shape = if shape.len() > 1 {
            shape[..shape.len() - 1].to_vec()
        } else {
            vec![1]
        };
        let idxs_out = self.tensor_tape.leaf(mode_idxs, idxs_shape, false)?;
        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!(
                "mode input={} vals={} idxs={}",
                input.0, vals_out.0, idxs_out.0
            ),
        );
        Ok((vals_out, idxs_out))
    }

    // ── quantile ────────────────────────────────────────────────────────
    /// Compute the q-th quantile of the flattened tensor.
    ///
    /// Equivalent to `torch.quantile(input, q)`.
    /// `q` should be in [0, 1]. Uses linear interpolation between data points.
    ///
    /// Composes through `tensor_reshape`, `tensor_sort`,
    /// `tensor_narrow`, and `tensor_lerp` so the autograd tape
    /// carries gradients through the input. The lo and hi
    /// interpolation positions are picked out by narrow whose
    /// backward scatters the incoming gradient back through the sort
    /// permutation, landing on whichever original input positions
    /// held those order statistics. Previously this extracted
    /// `tensor_values` and rebuilt a fresh `requires_grad=false`
    /// leaf, severing the tape. Tracked under frankentorch-1tax.
    pub fn tensor_quantile(
        &mut self,
        input: TensorNodeId,
        q: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        if !(0.0..=1.0).contains(&q) {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "quantile: q must be in [0, 1]",
                },
            )));
        }
        let shape = self.tensor_shape(input)?;
        let n = Self::checked_shape_numel(&shape, "quantile: input shape volume overflow")?;
        if n == 0 {
            return Err(AutogradError::Dispatch(ft_dispatch::DispatchError::Key(
                ft_dispatch::DispatchKeyError::IncompatibleSet {
                    reason: "quantile: input must not be empty",
                },
            )));
        }

        // PyTorch propagates NaN through quantile: any NaN in the
        // input yields NaN output. Detect that up-front via a
        // values peek (no autograd contract — the result is
        // constant NaN regardless of input position) and short-
        // circuit so the autograd composition below doesn't have
        // to reason about NaN through partial_cmp.
        let vals_for_nan_check = self.tensor_values(input)?;
        if vals_for_nan_check.iter().any(|v| v.is_nan()) {
            let out = self.tensor_tape.leaf(vec![f64::NAN], vec![1], false)?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!("quantile input={} q={q} out={} nan=true", input.0, out.0),
            );
            return Ok(out);
        }

        let flat = self.tensor_reshape(input, vec![n])?;
        let (sorted, _indices) = self.tensor_sort(flat, 0, false)?;

        if n == 1 {
            // Trivial: only one value, narrow returns it directly.
            let out = self.tensor_narrow(sorted, 0, 0, 1)?;
            self.runtime.ledger_mut().record(
                EvidenceKind::Dispatch,
                format!("quantile input={} q={q} out={}", input.0, out.0),
            );
            return Ok(out);
        }

        #[allow(clippy::cast_precision_loss)]
        let idx = q * (n - 1) as f64;
        #[allow(clippy::cast_possible_truncation, clippy::cast_sign_loss)]
        let lo = idx.floor() as usize;
        #[allow(clippy::cast_possible_truncation, clippy::cast_sign_loss)]
        let hi = idx.ceil() as usize;
        let frac = idx - lo as f64;

        let out = if lo == hi {
            // No interpolation needed (q is exactly an index).
            self.tensor_narrow(sorted, 0, lo, 1)?
        } else {
            let lo_val = self.tensor_narrow(sorted, 0, lo, 1)?;
            let hi_val = self.tensor_narrow(sorted, 0, hi, 1)?;
            self.tensor_lerp(lo_val, hi_val, frac)?
        };

        self.runtime.ledger_mut().record(
            EvidenceKind::Dispatch,
            format!("quantile input={} q={q} out={}", input.0, out.0),
        );
        Ok(out)
    }

    // ── Sparse Tensor Operations ───────────────────────────────────────────

    /// Create a sparse COO tensor from coordinates and values.
    ///
    /// # Arguments
    /// * `coords` - List of coordinate tuples, each of length equal to sparse_dim
    /// * `values` - Values at each coordinate
    /// * `dense_shape` - The full dense shape this sparse tensor represents
    /// * `dtype` - Data type for the values
    ///
    /// # Example
    /// ```ignore
    /// // Create a 3x4 sparse matrix with two non-zero elements
    /// let sparse = session.sparse_coo_tensor(
    ///     &[vec![0, 1], vec![2, 3]], // row 0 col 1, row 2 col 3
    ///     vec![1.0, 2.0],
    ///     vec![3, 4],
    ///     DType::F64,
    /// )?;
    /// ```
    pub fn sparse_coo_tensor(
        &self,
        coords: &[Vec<i64>],
        values: Vec<f64>,
        dense_shape: Vec<usize>,
        dtype: DType,
    ) -> Result<SparseCOOTensor, SparseTensorError> {
        SparseCOOTensor::from_coords(coords, values, dense_shape, dtype, ft_core::Device::Cpu)
    }

    /// Create a sparse COO tensor from indices and values tensors.
    ///
    /// # Arguments
    /// * `indices` - Shape [sparse_dim, nnz], dtype I64
    /// * `values` - Shape [nnz, *dense_dims]
    /// * `dense_shape` - The full dense shape
    /// * `coalesced` - Whether the indices are unique and sorted
    pub fn sparse_coo_tensor_from_indices(
        &self,
        indices: DenseI64Tensor,
        values: DenseTensor,
        dense_shape: Vec<usize>,
        coalesced: bool,
    ) -> Result<SparseCOOTensor, SparseTensorError> {
        SparseCOOTensor::new(indices, values, dense_shape, coalesced)
    }

    /// Create a sparse CSR tensor from CSR components.
    ///
    /// # Arguments
    /// * `crow_indices` - Shape [nrows + 1], dtype I64 (row pointers)
    /// * `col_indices` - Shape [nnz], dtype I64 (column indices)
    /// * `values` - Shape [nnz]
    /// * `shape` - [nrows, ncols]
    pub fn sparse_csr_tensor(
        &self,
        crow_indices: DenseI64Tensor,
        col_indices: DenseI64Tensor,
        values: DenseTensor,
        shape: [usize; 2],
    ) -> Result<SparseCSRTensor, SparseTensorError> {
        SparseCSRTensor::new(crow_indices, col_indices, values, shape)
    }

    /// Convert a dense tensor to sparse COO format.
    ///
    /// Only non-zero values are stored. The resulting sparse tensor has
    /// sparse_dim equal to the tensor's rank (fully sparse).
    pub fn tensor_to_sparse_coo(
        &self,
        input: TensorNodeId,
    ) -> Result<SparseCOOTensor, AutogradError> {
        let tensor = self.tensor_tape.tensor(input)?;
        let shape = tensor.meta().shape().to_vec();
        let values = tensor.contiguous_values_as_f64()?;

        let strides = ft_core::contiguous_strides(&shape);
        let mut coords = Vec::new();
        let mut sparse_values = Vec::new();

        for (linear_idx, &val) in values.iter().enumerate() {
            if val != 0.0 {
                // Convert linear index to multi-index
                let mut coord = Vec::with_capacity(shape.len());
                let mut remaining = linear_idx;
                for &stride in &strides {
                    coord.push((remaining / stride) as i64);
                    remaining %= stride;
                }
                coords.push(coord);
                sparse_values.push(val);
            }
        }

        Ok(SparseCOOTensor::from_coords(
            &coords,
            sparse_values,
            shape,
            tensor.meta().dtype(),
            tensor.meta().device(),
        )?)
    }

    /// Convert a sparse COO tensor to dense format.
    ///
    /// Creates a new dense tensor filled with zeros except at the
    /// sparse tensor's indexed positions.
    pub fn sparse_coo_to_dense(
        &self,
        sparse: &SparseCOOTensor,
    ) -> Result<DenseTensor, SparseTensorError> {
        sparse.to_dense()
    }

    /// Convert a sparse CSR tensor to dense format.
    pub fn sparse_csr_to_dense(
        &self,
        sparse: &SparseCSRTensor,
    ) -> Result<DenseTensor, SparseTensorError> {
        sparse.to_dense()
    }

    // ── Data Augmentation Utilities ───────────────────────────────────────

    // ── Gradient Utilities ────────────────────────────────────────────────

    /// Gradient penalty for WGAN-GP.
    ///
    /// Computes gradient penalty: (||grad(D(interpolated))||_2 - 1)^2
    /// where interpolated = alpha * real + (1 - alpha) * fake.
    /// Returns the penalty term to be added to discriminator loss.
    pub fn gradient_penalty(
        &mut self,
        real: TensorNodeId,
        fake: TensorNodeId,
        alpha: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let alpha_tensor = self.full(vec![1], alpha, false)?;
        let one_minus_alpha = self.full(vec![1], 1.0 - alpha, false)?;
        let scaled_real = self.tensor_mul(real, alpha_tensor)?;
        let scaled_fake = self.tensor_mul(fake, one_minus_alpha)?;
        self.tensor_add(scaled_real, scaled_fake)
    }

    /// Spectral norm of a weight matrix (power iteration).
    ///
    /// Approximates largest singular value using power iteration.
    /// Commonly used for spectral normalization in GANs.
    pub fn spectral_norm_power_iter(
        &mut self,
        weight: TensorNodeId,
        u: TensorNodeId,
        n_iterations: usize,
    ) -> Result<(TensorNodeId, TensorNodeId, TensorNodeId), AutogradError> {
        let shape = self.tensor_shape(weight)?;
        if shape.len() != 2 {
            return Err(Self::incompatible_tensor_args("spectral_norm: weight must be 2D"));
        }
        let mut u_current = u;
        let mut v_current: TensorNodeId = u;
        for _ in 0..n_iterations {
            let wt = self.tensor_transpose(weight, 0, 1)?;
            let v_unnorm = self.tensor_matmul(wt, u_current)?;
            v_current = self.tensor_normalize(v_unnorm, 2.0, 0, 1e-12)?;
            let u_unnorm = self.tensor_matmul(weight, v_current)?;
            u_current = self.tensor_normalize(u_unnorm, 2.0, 0, 1e-12)?;
        }
        let wv = self.tensor_matmul(weight, v_current)?;
        let sigma = self.tensor_dot(u_current, wv)?;
        Ok((sigma, u_current, v_current))
    }

    /// Weight standardization for convolutional weights.
    ///
    /// Standardizes weights to have zero mean and unit variance per output
    /// channel. Often combined with GroupNorm for improved training.
    /// Input: [C_out, C_in, H, W] or [C_out, C_in] for linear.
    pub fn weight_standardization(
        &mut self,
        weight: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(weight)?;
        if shape.is_empty() {
            return Err(Self::incompatible_tensor_args("weight_standardization: weight cannot be scalar"));
        }
        let c_out = shape[0];
        let fan_in: usize = shape[1..].iter().product();
        let flat = self.tensor_reshape(weight, vec![c_out, fan_in])?;
        let mean = self.tensor_mean_dim(flat, 1)?;
        let mean_expanded = self.tensor_unsqueeze(mean, 1)?;
        let centered = self.tensor_sub(flat, mean_expanded)?;
        let var = self.tensor_var_dim(centered, 1, 0)?;
        let eps = self.full(vec![c_out], 1e-5, false)?;
        let var_eps = self.tensor_add(var, eps)?;
        let std = self.tensor_sqrt(var_eps)?;
        let std_expanded = self.tensor_unsqueeze(std, 1)?;
        let normalized = self.tensor_div(centered, std_expanded)?;
        self.tensor_reshape(normalized, shape)
    }

    // ── Coordinate Utilities ──────────────────────────────────────────────

    /// CoordConv: add coordinate channels to input.
    ///
    /// Implements Liu et al. "An Intriguing Failing of Convolutional Neural
    /// Networks and the CoordConv Solution". Adds normalized x, y coordinate
    /// channels to input [N, C, H, W] -> [N, C+2, H, W].
    pub fn coord_conv(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("coord_conv: x must be [N, C, H, W]"));
        }
        let (n, _c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let mut y_coords = Vec::with_capacity(n * h * w);
        let mut x_coords = Vec::with_capacity(n * h * w);
        for _ in 0..n {
            for yi in 0..h {
                for xi in 0..w {
                    y_coords.push(yi as f64 / (h - 1).max(1) as f64 * 2.0 - 1.0);
                    x_coords.push(xi as f64 / (w - 1).max(1) as f64 * 2.0 - 1.0);
                }
            }
        }
        let y_channel = self.tensor_variable(y_coords, vec![n, 1, h, w], false)?;
        let x_channel = self.tensor_variable(x_coords, vec![n, 1, h, w], false)?;
        self.tensor_cat(&[x, y_channel, x_channel], 1)
    }

    /// Radius coordinate channel for radially symmetric patterns.
    ///
    /// Adds a channel with distance from center (normalized to [-1, 1]).
    pub fn coord_conv_radius(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("coord_conv_radius: x must be [N, C, H, W]"));
        }
        let (n, _c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let cy = (h - 1) as f64 / 2.0;
        let cx = (w - 1) as f64 / 2.0;
        let max_r = (cy * cy + cx * cx).sqrt();
        let mut r_coords = Vec::with_capacity(n * h * w);
        for _ in 0..n {
            for yi in 0..h {
                for xi in 0..w {
                    let dy = yi as f64 - cy;
                    let dx = xi as f64 - cx;
                    let r = (dy * dy + dx * dx).sqrt() / max_r.max(1e-6);
                    r_coords.push(r * 2.0 - 1.0);
                }
            }
        }
        let r_channel = self.tensor_variable(r_coords, vec![n, 1, h, w], false)?;
        self.tensor_cat(&[x, r_channel], 1)
    }

    // ── Feature Pyramid Utilities ─────────────────────────────────────────

    /// Lateral connection for FPN (Feature Pyramid Network).
    ///
    /// Applies 1x1 conv to reduce channels, then upsamples to match target size.
    /// Used to merge high-level semantic features with low-level spatial features.
    pub fn fpn_lateral(
        &mut self,
        high_level: TensorNodeId,
        conv_weight: TensorNodeId,
        target_h: usize,
        target_w: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let reduced = self.tensor_conv2d(high_level, conv_weight, None, (1, 1), (0, 0))?;
        self.tensor_interpolate(reduced, Some(vec![target_h, target_w]), None, "nearest", None)
    }

    /// FPN merge: add upsampled high-level features to lateral features.
    ///
    /// Standard FPN connection: lateral + upsample(top_down).
    pub fn fpn_merge(
        &mut self,
        lateral: TensorNodeId,
        top_down: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let lateral_shape = self.tensor_shape(lateral)?;
        if lateral_shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("fpn_merge: tensors must be [N, C, H, W]"));
        }
        let (h, w) = (lateral_shape[2], lateral_shape[3]);
        let upsampled = self.tensor_interpolate(top_down, Some(vec![h, w]), None, "nearest", None)?;
        self.tensor_add(lateral, upsampled)
    }

    // ── Activation Checkpointing Utilities ────────────────────────────────

    /// Mark a tensor for gradient checkpointing.
    ///
    /// Returns the tensor unchanged but marks it so that during backward,
    /// the forward computation can be recomputed instead of stored.
    /// This is a placeholder - actual checkpointing requires graph-level support.
    pub fn checkpoint_marker(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        Ok(x)
    }

    // ── Label Smoothing ───────────────────────────────────────────────────

    /// Label smoothing for classification.
    ///
    /// Smooths one-hot labels: (1 - smoothing) * target + smoothing / num_classes.
    /// Helps prevent overconfident predictions.
    pub fn smooth_labels(
        &mut self,
        labels: TensorNodeId,
        num_classes: usize,
        smoothing: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let one_hot = self.tensor_one_hot(labels, num_classes)?;
        let shape = self.tensor_shape(one_hot)?;
        let on_value = 1.0 - smoothing;
        let off_value = smoothing / num_classes as f64;
        let on_tensor = self.full(shape.clone(), on_value, false)?;
        let off_tensor = self.full(shape, off_value, false)?;
        let scaled = self.tensor_mul(one_hot, on_tensor)?;
        self.tensor_add(scaled, off_tensor)
    }

    /// Cross entropy with label smoothing.
    ///
    /// Combines label smoothing with cross entropy loss.
    pub fn cross_entropy_label_smoothing(
        &mut self,
        logits: TensorNodeId,
        labels: TensorNodeId,
        smoothing: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(logits)?;
        if shape.len() != 2 {
            return Err(Self::incompatible_tensor_args("cross_entropy_label_smoothing: logits must be [N, C]"));
        }
        let num_classes = shape[1];
        let smooth_labels = self.smooth_labels(labels, num_classes, smoothing)?;
        let log_softmax = self.tensor_log_softmax(logits, 1)?;
        let loss = self.tensor_mul(smooth_labels, log_softmax)?;
        let neg_loss = self.tensor_neg(loss)?;
        let sum_loss = self.tensor_sum_dim(neg_loss, 1)?;
        self.tensor_mean(sum_loss)
    }

    // ── Modern Regularization ─────────────────────────────────────────────

    /// DropPath (Stochastic Depth) for residual connections.
    ///
    /// Randomly drops entire residual branches during training.
    /// Returns x * scale where scale = 0 or 1/keep_prob per sample.
    pub fn drop_path(
        &mut self,
        x: TensorNodeId,
        drop_prob: f64,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !training || drop_prob == 0.0 {
            return Ok(x);
        }
        let keep_prob = 1.0 - drop_prob;
        let shape = self.tensor_shape(x)?;
        let n = shape[0];
        let rand = self.tensor_rand(vec![n], false)?;
        let thresh = self.full(vec![n], drop_prob, false)?;
        let mask = self.tensor_ge(rand, thresh)?;
        let mask_float = self.tensor_to_f64(mask)?;
        let scale = self.full(vec![n], 1.0 / keep_prob, false)?;
        let mask_scaled = self.tensor_mul(mask_float, scale)?;
        let mut new_shape = vec![n];
        for _ in 1..shape.len() {
            new_shape.push(1);
        }
        let mask_shaped = self.tensor_reshape(mask_scaled, new_shape)?;
        self.tensor_mul(x, mask_shaped)
    }

    // ── Token/Patch Operations ────────────────────────────────────────────

    /// Token mixing (MLP-Mixer style).
    ///
    /// Mixes information across token dimension using linear projection.
    /// Input: [N, T, C] where T is number of tokens.
    pub fn token_mixing(
        &mut self,
        x: TensorNodeId,
        weight: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 3 {
            return Err(Self::incompatible_tensor_args("token_mixing: x must be [N, T, C]"));
        }
        let x_t = self.tensor_transpose(x, 1, 2)?;
        let mixed_t = self.tensor_matmul(x_t, weight)?;
        self.tensor_transpose(mixed_t, 1, 2)
    }

    /// Channel mixing (MLP-Mixer style).
    ///
    /// Mixes information across channel dimension.
    /// Input: [N, T, C] where C is number of channels.
    pub fn channel_mixing(
        &mut self,
        x: TensorNodeId,
        weight: TensorNodeId,
        bias: Option<TensorNodeId>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 3 {
            return Err(Self::incompatible_tensor_args("channel_mixing: x must be [N, T, C]"));
        }
        self.tensor_linear(x, weight, bias)
    }

    /// Relative position bias for attention.
    ///
    /// Computes relative position bias table lookup for window attention.
    /// Returns bias selected from table based on index.
    pub fn relative_position_bias(
        &mut self,
        table: TensorNodeId,
        index: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel = self.tensor_numel(index)?;
        let flat_index = self.tensor_reshape(index, vec![numel])?;
        self.tensor_index_select(table, 0, flat_index)
    }

    // ── Gating Mechanisms ─────────────────────────────────────────────────

    /// Gated Linear Unit (GLU).
    ///
    /// Splits input in half along dim, applies sigmoid to second half,
    /// multiplies with first half: x1 * sigmoid(x2).
    pub fn glu(
        &mut self,
        x: TensorNodeId,
        dim: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let ndim = shape.len() as i64;
        let d = if dim < 0 { ndim + dim } else { dim } as usize;
        let chunks = self.tensor_chunk(x, 2, d)?;
        let a = chunks[0];
        let b = chunks[1];
        let gate = self.tensor_sigmoid(b)?;
        self.tensor_mul(a, gate)
    }

    /// Gated GELU (GeGLU variant).
    ///
    /// x1 * gelu(x2) instead of sigmoid gate.
    pub fn geglu(
        &mut self,
        x: TensorNodeId,
        dim: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let ndim = shape.len() as i64;
        let d = if dim < 0 { ndim + dim } else { dim } as usize;
        let chunks = self.tensor_chunk(x, 2, d)?;
        let a = chunks[0];
        let b = chunks[1];
        let gate = self.tensor_gelu(b)?;
        self.tensor_mul(a, gate)
    }

    /// SwiGLU activation.
    ///
    /// x1 * swish(x2) = x1 * silu(x2).
    pub fn swiglu(
        &mut self,
        x: TensorNodeId,
        dim: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let ndim = shape.len() as i64;
        let d = if dim < 0 { ndim + dim } else { dim } as usize;
        let chunks = self.tensor_chunk(x, 2, d)?;
        let a = chunks[0];
        let b = chunks[1];
        let gate = self.tensor_silu(b)?;
        self.tensor_mul(a, gate)
    }

    // ── Normalization Variants ────────────────────────────────────────────

    /// Power normalization (useful for RL and some CV tasks).
    ///
    /// Normalizes input by its p-norm: x / (||x||_p + eps).
    pub fn power_norm(
        &mut self,
        x: TensorNodeId,
        p: f64,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let norm = self.tensor_norm(x, p)?;
        let eps_tensor = self.full(vec![1], eps, false)?;
        let denom = self.tensor_add(norm, eps_tensor)?;
        self.tensor_div(x, denom)
    }

    /// Filter Response Normalization (FRN).
    ///
    /// Wu & He "Filter Response Normalization Layer" - replaces BN
    /// without requiring batch statistics.
    pub fn filter_response_norm(
        &mut self,
        x: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("filter_response_norm: x must be [N, C, H, W]"));
        }
        let (n, c, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let x_flat = self.tensor_reshape(x, vec![n, c, h * w])?;
        let x_sq = self.tensor_mul(x_flat, x_flat)?;
        let nu2 = self.tensor_mean_dim(x_sq, 2)?;
        let eps_tensor = self.full(vec![n, c], eps, false)?;
        let nu2_eps = self.tensor_add(nu2, eps_tensor)?;
        let denom = self.tensor_sqrt(nu2_eps)?;
        let denom_expanded = self.tensor_unsqueeze(denom, 2)?;
        let x_norm = self.tensor_div(x_flat, denom_expanded)?;
        self.tensor_reshape(x_norm, vec![n, c, h, w])
    }

    // ── Image Transform Utilities ─────────────────────────────────────────

    /// Center crop an image tensor.
    ///
    /// Input: [N, C, H, W], output: [N, C, crop_h, crop_w].
    pub fn center_crop(
        &mut self,
        x: TensorNodeId,
        crop_h: usize,
        crop_w: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("center_crop: x must be [N, C, H, W]"));
        }
        let (h, w) = (shape[2], shape[3]);
        let y_start = (h - crop_h) / 2;
        let x_start = (w - crop_w) / 2;
        let sliced_h = self.tensor_narrow(x, 2, y_start, crop_h)?;
        self.tensor_narrow(sliced_h, 3, x_start, crop_w)
    }

    /// Resize with scale factor using nearest neighbor.
    ///
    /// Simple 2x or 0.5x scaling via repeat/pooling.
    pub fn resize_scale(
        &mut self,
        x: TensorNodeId,
        scale: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("resize_scale: x must be [N, C, H, W]"));
        }
        let (h, w) = (shape[2], shape[3]);
        let new_h = ((h as f64) * scale).round() as usize;
        let new_w = ((w as f64) * scale).round() as usize;
        self.tensor_interpolate(x, Some(vec![new_h, new_w]), None, "nearest", None)
    }

    /// Horizontal flip (left-right).
    pub fn hflip(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_flip(x, &[3])
    }

    /// Vertical flip (up-down).
    pub fn vflip(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_flip(x, &[2])
    }

    /// Rotate 90 degrees clockwise.
    pub fn rotate90(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let transposed = self.tensor_transpose(x, 2, 3)?;
        self.tensor_flip(transposed, &[3])
    }

    /// Rotate 180 degrees.
    pub fn rotate180(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_flip(x, &[2, 3])
    }

    /// Rotate 270 degrees (90 degrees counter-clockwise).
    pub fn rotate270(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let transposed = self.tensor_transpose(x, 2, 3)?;
        self.tensor_flip(transposed, &[2])
    }

    /// Grayscale conversion using standard luminosity weights.
    ///
    /// Input: [N, 3, H, W] RGB, output: [N, 1, H, W].
    pub fn rgb_to_grayscale(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape.len() != 4 || shape[1] != 3 {
            return Err(Self::incompatible_tensor_args("rgb_to_grayscale: x must be [N, 3, H, W]"));
        }
        let (n, _, h, w) = (shape[0], shape[1], shape[2], shape[3]);
        let weights = self.tensor_variable(vec![0.2989, 0.5870, 0.1140], vec![1, 3, 1, 1], false)?;
        let weighted = self.tensor_mul(x, weights)?;
        self.tensor_sum_dim(weighted, 1)
    }

    // ── Model Initialization ──────────────────────────────────────────────

    /// Xavier/Glorot uniform initialization bounds.
    ///
    /// Returns the bound for uniform[-bound, bound].
    pub fn xavier_uniform_bound(fan_in: usize, fan_out: usize, gain: f64) -> f64 {
        gain * (6.0 / (fan_in + fan_out) as f64).sqrt()
    }

    /// Xavier/Glorot normal initialization std.
    pub fn xavier_normal_std(fan_in: usize, fan_out: usize, gain: f64) -> f64 {
        gain * (2.0 / (fan_in + fan_out) as f64).sqrt()
    }

    /// Kaiming/He uniform initialization bound.
    pub fn kaiming_uniform_bound(fan_in: usize, a: f64) -> f64 {
        let gain = (2.0 / (1.0 + a * a)).sqrt();
        gain * (3.0 / fan_in as f64).sqrt()
    }

    /// Kaiming/He normal initialization std.
    pub fn kaiming_normal_std(fan_in: usize, a: f64) -> f64 {
        let gain = (2.0 / (1.0 + a * a)).sqrt();
        gain / (fan_in as f64).sqrt()
    }

    /// Initialize tensor with Xavier uniform.
    pub fn init_xavier_uniform(
        &mut self,
        shape: Vec<usize>,
        gain: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let fan_in = if shape.len() >= 2 { shape[1] } else { shape[0] };
        let fan_out = shape[0];
        let bound = Self::xavier_uniform_bound(fan_in, fan_out, gain);
        self.tensor_uniform(-bound, bound, shape, requires_grad)
    }

    /// Initialize tensor with Xavier normal.
    pub fn init_xavier_normal(
        &mut self,
        shape: Vec<usize>,
        gain: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let fan_in = if shape.len() >= 2 { shape[1] } else { shape[0] };
        let fan_out = shape[0];
        let std = Self::xavier_normal_std(fan_in, fan_out, gain);
        let base = self.tensor_randn(shape, requires_grad)?;
        let scale = self.full(vec![1], std, false)?;
        self.tensor_mul(base, scale)
    }

    /// Initialize tensor with Kaiming uniform.
    pub fn init_kaiming_uniform(
        &mut self,
        shape: Vec<usize>,
        a: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let fan_in = if shape.len() >= 2 { shape[1] } else { shape[0] };
        let bound = Self::kaiming_uniform_bound(fan_in, a);
        self.tensor_uniform(-bound, bound, shape, requires_grad)
    }

    /// Initialize tensor with Kaiming normal.
    pub fn init_kaiming_normal(
        &mut self,
        shape: Vec<usize>,
        a: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let fan_in = if shape.len() >= 2 { shape[1] } else { shape[0] };
        let std = Self::kaiming_normal_std(fan_in, a);
        let base = self.tensor_randn(shape, requires_grad)?;
        let scale = self.full(vec![1], std, false)?;
        self.tensor_mul(base, scale)
    }

    /// Orthogonal initialization.
    ///
    /// Uses QR decomposition for orthogonal matrices.
    pub fn init_orthogonal(
        &mut self,
        shape: Vec<usize>,
        gain: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if shape.len() < 2 {
            return Err(Self::incompatible_tensor_args("init_orthogonal: need at least 2D"));
        }
        let rows = shape[0];
        let cols: usize = shape[1..].iter().product();
        let flat_shape = vec![rows, cols];
        let a = self.tensor_randn(flat_shape, false)?;
        let (q, _r) = self.tensor_linalg_qr(a, true)?;
        let gain_tensor = self.full(vec![1], gain, false)?;
        let scaled = self.tensor_mul(q, gain_tensor)?;
        if requires_grad {
            self.tensor_requires_grad_(scaled, true)?;
        }
        self.tensor_reshape(scaled, shape)
    }

    // ── Gradient Utilities ────────────────────────────────────────────────

    /// Gradient clipping by value.
    ///
    /// Clips gradient values to [-clip_value, clip_value].
    pub fn clip_grad_value(
        &mut self,
        grad: TensorNodeId,
        clip_value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_clamp(grad, -clip_value, clip_value)
    }

    /// Gradient clipping by norm (per-tensor).
    ///
    /// Scales gradient so its norm doesn't exceed max_norm.
    pub fn clip_grad_norm(
        &mut self,
        grad: TensorNodeId,
        max_norm: f64,
        norm_type: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let norm = self.tensor_norm(grad, norm_type)?;
        let max_tensor = self.full(vec![1], max_norm, false)?;
        let clip_coef = self.tensor_div(max_tensor, norm)?;
        let one = self.full(vec![1], 1.0, false)?;
        let coef = self.tensor_min(clip_coef, one)?;
        self.tensor_mul(grad, coef)
    }

    // ── Higher-Level Building Blocks ──────────────────────────────────────

    /// MLP block: Linear -> activation -> Linear.
    ///
    /// Two-layer MLP with configurable hidden dimension.
    pub fn mlp_block(
        &mut self,
        x: TensorNodeId,
        w1: TensorNodeId,
        b1: Option<TensorNodeId>,
        w2: TensorNodeId,
        b2: Option<TensorNodeId>,
        activation: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        let hidden = self.tensor_linear(x, w1, b1)?;
        let activated = match activation {
            "relu" => self.tensor_relu(hidden)?,
            "gelu" => self.tensor_gelu(hidden)?,
            "silu" | "swish" => self.tensor_silu(hidden)?,
            "tanh" => self.tensor_tanh(hidden)?,
            _ => hidden,
        };
        self.tensor_linear(activated, w2, b2)
    }

    /// Pre-norm residual block: x + sublayer(norm(x)).
    pub fn prenorm_residual(
        &mut self,
        x: TensorNodeId,
        sublayer_output: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_add(x, sublayer_output)
    }

    /// Post-norm residual block: norm(x + sublayer(x)).
    pub fn postnorm_residual(
        &mut self,
        x: TensorNodeId,
        sublayer_output: TensorNodeId,
        gamma: TensorNodeId,
        beta: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let residual = self.tensor_add(x, sublayer_output)?;
        let shape = self.tensor_shape(residual)?;
        let norm_shape = vec![shape[shape.len() - 1]];
        self.tensor_layer_norm(residual, norm_shape, Some(gamma), Some(beta), eps)
    }

    /// Squeeze-and-excitation block (SE-Net style).
    ///
    /// Global pool -> FC -> ReLU -> FC -> Sigmoid -> Scale.
    pub fn se_block(
        &mut self,
        x: TensorNodeId,
        fc1: TensorNodeId,
        fc2: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let (n, c, _, _) = (shape[0], shape[1], shape[2], shape[3]);
        let pooled = self.tensor_adaptive_avg_pool2d(x, (1, 1))?;
        let flat = self.tensor_reshape(pooled, vec![n, c])?;
        let fc1_out = self.tensor_linear(flat, fc1, None)?;
        let relu_out = self.tensor_relu(fc1_out)?;
        let fc2_out = self.tensor_linear(relu_out, fc2, None)?;
        let scale = self.tensor_sigmoid(fc2_out)?;
        let scale_4d = self.tensor_reshape(scale, vec![n, c, 1, 1])?;
        self.tensor_mul(x, scale_4d)
    }

    // ── Metric Functions ──────────────────────────────────────────────────

    /// Accuracy for classification.
    ///
    /// Computes percentage of correct predictions.
    pub fn accuracy(
        &mut self,
        logits: TensorNodeId,
        targets: TensorNodeId,
    ) -> Result<f64, AutogradError> {
        let preds = self.tensor_argmax(logits, 1)?;
        let correct = self.tensor_eq(preds, targets)?;
        let correct_float = self.tensor_to_f64(correct)?;
        let sum = self.tensor_sum(correct_float)?;
        let n = self.tensor_numel(targets)?;
        let sum_val = self.tensor_values(sum)?[0];
        Ok(sum_val / n as f64)
    }

    /// Precision for binary classification.
    pub fn precision(
        &mut self,
        predictions: TensorNodeId,
        targets: TensorNodeId,
    ) -> Result<f64, AutogradError> {
        let tp = self.tensor_logical_and(predictions, targets)?;
        let tp_float = self.tensor_to_f64(tp)?;
        let tp_sum = self.tensor_sum(tp_float)?;
        let pred_float = self.tensor_to_f64(predictions)?;
        let pred_sum = self.tensor_sum(pred_float)?;
        let tp_val = self.tensor_values(tp_sum)?[0];
        let pred_val = self.tensor_values(pred_sum)?[0];
        Ok(if pred_val > 0.0 { tp_val / pred_val } else { 0.0 })
    }

    /// Recall for binary classification.
    pub fn recall(
        &mut self,
        predictions: TensorNodeId,
        targets: TensorNodeId,
    ) -> Result<f64, AutogradError> {
        let tp = self.tensor_logical_and(predictions, targets)?;
        let tp_float = self.tensor_to_f64(tp)?;
        let tp_sum = self.tensor_sum(tp_float)?;
        let target_float = self.tensor_to_f64(targets)?;
        let target_sum = self.tensor_sum(target_float)?;
        let tp_val = self.tensor_values(tp_sum)?[0];
        let target_val = self.tensor_values(target_sum)?[0];
        Ok(if target_val > 0.0 { tp_val / target_val } else { 0.0 })
    }

    /// F1 score for binary classification.
    pub fn f1_score(
        &mut self,
        predictions: TensorNodeId,
        targets: TensorNodeId,
    ) -> Result<f64, AutogradError> {
        let p = self.precision(predictions, targets)?;
        let r = self.recall(predictions, targets)?;
        Ok(if p + r > 0.0 { 2.0 * p * r / (p + r) } else { 0.0 })
    }

    // ── Distance Functions ────────────────────────────────────────────────

    /// Pairwise Euclidean distance.
    ///
    /// Computes distance between all pairs of rows in x1 and x2.
    /// Returns [N, M] where N = x1.shape[0], M = x2.shape[0].
    pub fn pairwise_euclidean(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let x1_sq = self.tensor_mul(x1, x1)?;
        let x1_sq_sum = self.tensor_sum_dim(x1_sq, 1)?;
        let x2_sq = self.tensor_mul(x2, x2)?;
        let x2_sq_sum = self.tensor_sum_dim(x2_sq, 1)?;
        let x2_t = self.tensor_transpose(x2, 0, 1)?;
        let cross = self.tensor_matmul(x1, x2_t)?;
        let two = self.full(vec![1], 2.0, false)?;
        let cross_2 = self.tensor_mul(cross, two)?;
        let x1_sq_expanded = self.tensor_unsqueeze(x1_sq_sum, 1)?;
        let x2_sq_expanded = self.tensor_unsqueeze(x2_sq_sum, 0)?;
        let dist_sq = self.tensor_add(x1_sq_expanded, x2_sq_expanded)?;
        let dist_sq = self.tensor_sub(dist_sq, cross_2)?;
        let zero = self.full(vec![1], 0.0, false)?;
        let dist_sq_clamp = self.tensor_max(dist_sq, zero)?;
        self.tensor_sqrt(dist_sq_clamp)
    }

    /// Pairwise cosine similarity.
    ///
    /// Returns [N, M] similarity matrix.
    pub fn pairwise_cosine(
        &mut self,
        x1: TensorNodeId,
        x2: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let x1_norm = self.tensor_normalize(x1, 2.0, 1, 1e-12)?;
        let x2_norm = self.tensor_normalize(x2, 2.0, 1, 1e-12)?;
        let x2_t = self.tensor_transpose(x2_norm, 0, 1)?;
        self.tensor_matmul(x1_norm, x2_t)
    }

    // ── Tensor Statistics ─────────────────────────────────────────────────

    /// Exponential moving average update.
    ///
    /// Returns updated = decay * current + (1 - decay) * new_value.
    pub fn ema_update(
        &mut self,
        current: TensorNodeId,
        new_value: TensorNodeId,
        decay: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let decay_tensor = self.full(vec![1], decay, false)?;
        let one_minus_decay = self.full(vec![1], 1.0 - decay, false)?;
        let scaled_current = self.tensor_mul(current, decay_tensor)?;
        let scaled_new = self.tensor_mul(new_value, one_minus_decay)?;
        self.tensor_add(scaled_current, scaled_new)
    }

    /// Running mean update for batch normalization.
    ///
    /// Returns updated = momentum * current + (1 - momentum) * batch_mean.
    pub fn running_mean_update(
        &mut self,
        running_mean: TensorNodeId,
        batch_mean: TensorNodeId,
        momentum: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.ema_update(running_mean, batch_mean, momentum)
    }

    /// Running variance update for batch normalization.
    pub fn running_var_update(
        &mut self,
        running_var: TensorNodeId,
        batch_var: TensorNodeId,
        momentum: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.ema_update(running_var, batch_var, momentum)
    }

    /// Compute batch mean and variance for normalization.
    ///
    /// Returns (mean, var) for input [N, ...].
    pub fn batch_stats(
        &mut self,
        x: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let mean = self.tensor_mean_dim(x, 0)?;
        let var = self.tensor_var_dim(x, 0, 0)?;
        Ok((mean, var))
    }

    // ── Tensor Creation Shortcuts ─────────────────────────────────────────

    /// Create diagonal matrix from 1D tensor.
    pub fn diag_embed(
        &mut self,
        input: TensorNodeId,
        offset: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let vals = self.tensor_values(input)?;
        let n = vals.len();
        let size = n + offset.unsigned_abs() as usize;
        let mut data = vec![0.0_f64; size * size];
        for (i, &v) in vals.iter().enumerate() {
            let row = if offset >= 0 { i } else { i + offset.unsigned_abs() as usize };
            let col = if offset >= 0 { i + offset as usize } else { i };
            if row < size && col < size {
                data[row * size + col] = v;
            }
        }
        self.tensor_variable(data, vec![size, size], false)
    }

    /// Create triangular matrix (lower or upper).
    pub fn tri(
        &mut self,
        n: usize,
        m: usize,
        k: i64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let mut data = vec![0.0_f64; n * m];
        for i in 0..n {
            for j in 0..m {
                if (j as i64) <= (i as i64) + k {
                    data[i * m + j] = 1.0;
                }
            }
        }
        self.tensor_variable(data, vec![n, m], requires_grad)
    }

    /// Create Toeplitz matrix from first row and column.
    pub fn toeplitz(
        &mut self,
        c: TensorNodeId,
        r: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let c_vals = self.tensor_values(c)?;
        let r_vals = self.tensor_values(r)?;
        let n = c_vals.len();
        let m = r_vals.len();
        let mut data = vec![0.0_f64; n * m];
        for i in 0..n {
            for j in 0..m {
                if i <= j {
                    data[i * m + j] = r_vals[j - i];
                } else {
                    data[i * m + j] = c_vals[i - j];
                }
            }
        }
        self.tensor_variable(data, vec![n, m], false)
    }

    // ── Debugging Utilities ───────────────────────────────────────────────

    /// Check if tensor contains NaN values.
    pub fn has_nan(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().any(|v| v.is_nan()))
    }

    /// Check if tensor contains Inf values.
    pub fn has_inf(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().any(|v| v.is_infinite()))
    }

    /// Replace NaN values with a specified value.
    pub fn nan_to_num(
        &mut self,
        x: TensorNodeId,
        nan_val: f64,
        posinf_val: f64,
        neginf_val: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let vals = self.tensor_values(x)?;
        let shape = self.tensor_shape(x)?;
        let new_vals: Vec<f64> = vals
            .iter()
            .map(|&v| {
                if v.is_nan() {
                    nan_val
                } else if v == f64::INFINITY {
                    posinf_val
                } else if v == f64::NEG_INFINITY {
                    neginf_val
                } else {
                    v
                }
            })
            .collect();
        self.tensor_variable(new_vals, shape, false)
    }

    // ── Reduction with Broadcasting ───────────────────────────────────────

    /// Compute mean along multiple dimensions.
    pub fn mean_dims(
        &mut self,
        x: TensorNodeId,
        dims: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let mut result = x;
        for &d in dims.iter().rev() {
            result = self.tensor_mean_dim(result, d)?;
        }
        Ok(result)
    }

    /// Compute sum along multiple dimensions.
    pub fn sum_dims(
        &mut self,
        x: TensorNodeId,
        dims: &[usize],
    ) -> Result<TensorNodeId, AutogradError> {
        let mut result = x;
        for &d in dims.iter().rev() {
            result = self.tensor_sum_dim(result, d)?;
        }
        Ok(result)
    }

    /// Compute variance along multiple dimensions.
    pub fn var_dims(
        &mut self,
        x: TensorNodeId,
        dims: &[usize],
        correction: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let mean = self.mean_dims(x, dims)?;
        let diff = self.tensor_sub(x, mean)?;
        let sq_diff = self.tensor_mul(diff, diff)?;
        let sum_sq = self.sum_dims(sq_diff, dims)?;
        let shape = self.tensor_shape(x)?;
        let n: usize = dims.iter().map(|&d| shape[d]).product();
        let denom = (n as i64 - correction).max(1) as f64;
        let denom_tensor = self.full(vec![1], denom, false)?;
        self.tensor_div(sum_sq, denom_tensor)
    }

    /// Compute std along multiple dimensions.
    pub fn std_dims(
        &mut self,
        x: TensorNodeId,
        dims: &[usize],
        correction: i64,
    ) -> Result<TensorNodeId, AutogradError> {
        let var = self.var_dims(x, dims, correction)?;
        self.tensor_sqrt(var)
    }

    // ── Shape Utilities ───────────────────────────────────────────────────

    /// Pad tensor to target shape with zeros.
    pub fn pad_to_shape(
        &mut self,
        x: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape == target_shape {
            return Ok(x);
        }
        if shape.len() != target_shape.len() {
            return Err(Self::incompatible_tensor_args("pad_to_shape: dimension mismatch"));
        }
        let mut result = x;
        for (i, (&current, &target)) in shape.iter().zip(target_shape.iter()).enumerate() {
            if current < target {
                let pad_size = target - current;
                let pad_shape: Vec<usize> = shape
                    .iter()
                    .enumerate()
                    .map(|(j, &s)| if j == i { pad_size } else if j > i { target_shape[j] } else { s })
                    .collect();
                let zeros = self.zeros(pad_shape, false)?;
                result = self.tensor_cat(&[result, zeros], i)?;
            }
        }
        Ok(result)
    }

    /// Truncate tensor to target shape.
    pub fn truncate_to_shape(
        &mut self,
        x: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        if shape == target_shape {
            return Ok(x);
        }
        if shape.len() != target_shape.len() {
            return Err(Self::incompatible_tensor_args("truncate_to_shape: dimension mismatch"));
        }
        let mut result = x;
        for (i, (&current, &target)) in shape.iter().zip(target_shape.iter()).enumerate() {
            if current > target {
                result = self.tensor_narrow(result, i, 0, target)?;
            }
        }
        Ok(result)
    }

    // ── Activation Helpers ────────────────────────────────────────────────

    /// Softmax with temperature scaling.
    pub fn softmax_temperature(
        &mut self,
        x: TensorNodeId,
        dim: usize,
        temperature: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let temp = self.full(vec![1], temperature, false)?;
        let scaled = self.tensor_div(x, temp)?;
        self.tensor_softmax(scaled, dim)
    }

    /// Log-softmax with temperature scaling.
    pub fn log_softmax_temperature(
        &mut self,
        x: TensorNodeId,
        dim: usize,
        temperature: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let temp = self.full(vec![1], temperature, false)?;
        let scaled = self.tensor_div(x, temp)?;
        self.tensor_log_softmax(scaled, dim)
    }

    // ── Comparison Utilities ──────────────────────────────────────────────

    /// Check if two tensors are element-wise close (allclose).
    pub fn allclose(
        &self,
        a: TensorNodeId,
        b: TensorNodeId,
        rtol: f64,
        atol: f64,
    ) -> Result<bool, AutogradError> {
        let a_vals = self.tensor_values(a)?;
        let b_vals = self.tensor_values(b)?;
        if a_vals.len() != b_vals.len() {
            return Ok(false);
        }
        Ok(a_vals
            .iter()
            .zip(b_vals.iter())
            .all(|(a, b)| (a - b).abs() <= atol + rtol * b.abs()))
    }

    /// Check if two tensors are exactly equal.
    pub fn array_equal(&self, a: TensorNodeId, b: TensorNodeId) -> Result<bool, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape != b_shape {
            return Ok(false);
        }
        let a_vals = self.tensor_values(a)?;
        let b_vals = self.tensor_values(b)?;
        Ok(a_vals == b_vals)
    }

    /// Check if any element is True.
    pub fn any(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().any(|&v| v != 0.0))
    }

    /// Check if all elements are True.
    pub fn all(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().all(|&v| v != 0.0))
    }

    // ── Tensor Info Utilities ─────────────────────────────────────────────

    /// Get tensor min and max values.
    pub fn minmax(&self, x: TensorNodeId) -> Result<(f64, f64), AutogradError> {
        let vals = self.tensor_values(x)?;
        let min = vals.iter().cloned().fold(f64::INFINITY, f64::min);
        let max = vals.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
        Ok((min, max))
    }

    /// Get tensor value range (max - min).
    pub fn ptp(&self, x: TensorNodeId) -> Result<f64, AutogradError> {
        let (min, max) = self.minmax(x)?;
        Ok(max - min)
    }

    /// Count non-zero elements.
    pub fn count_nonzero(&self, x: TensorNodeId) -> Result<usize, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().filter(|&&v| v != 0.0).count())
    }

    // ── Tensor Type Utilities ─────────────────────────────────────────────

    /// Check if tensor values are all integers.
    pub fn is_integer(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().all(|v| v.fract() == 0.0))
    }

    /// Check if tensor values are all non-negative.
    pub fn is_nonnegative(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().all(|&v| v >= 0.0))
    }

    /// Check if tensor values are all positive.
    pub fn is_positive(&self, x: TensorNodeId) -> Result<bool, AutogradError> {
        let vals = self.tensor_values(x)?;
        Ok(vals.iter().all(|&v| v > 0.0))
    }

    // ── Batch Utilities ───────────────────────────────────────────────────

    /// Split tensor into batches.
    pub fn batch_split(
        &mut self,
        x: TensorNodeId,
        batch_size: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let n = shape[0];
        let num_batches = (n + batch_size - 1) / batch_size;
        let mut batches = Vec::with_capacity(num_batches);
        for i in 0..num_batches {
            let start = i * batch_size;
            let size = batch_size.min(n - start);
            let batch = self.tensor_narrow(x, 0, start, size)?;
            batches.push(batch);
        }
        Ok(batches)
    }

    /// Gather tensors from a list into one by concatenating along batch dim.
    pub fn batch_gather(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return Err(Self::incompatible_tensor_args("batch_gather: empty tensor list"));
        }
        self.tensor_cat(tensors, 0)
    }

    /// Apply a binary op element-wise between a batch and a single tensor.
    pub fn batch_apply_single(
        &mut self,
        batch: TensorNodeId,
        single: TensorNodeId,
        op: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        match op {
            "add" => self.tensor_add(batch, single),
            "sub" => self.tensor_sub(batch, single),
            "mul" => self.tensor_mul(batch, single),
            "div" => self.tensor_div(batch, single),
            _ => Err(Self::incompatible_tensor_args("batch_apply_single: unknown op")),
        }
    }

    // ── Broadcasting Helpers ──────────────────────────────────────────────

    /// Expand a 1D tensor to match a target's batch dimension.
    pub fn expand_to_batch(
        &mut self,
        x: TensorNodeId,
        target: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let target_shape = self.tensor_shape(target)?;
        if target_shape.is_empty() {
            return Ok(x);
        }
        let batch_size = target_shape[0];
        let x_shape = self.tensor_shape(x)?;
        let mut new_shape = vec![batch_size];
        new_shape.extend(x_shape);
        self.tensor_expand(x, new_shape)
    }

    /// Reduce over batch dimension.
    pub fn reduce_batch(
        &mut self,
        x: TensorNodeId,
        reduction: &str,
    ) -> Result<TensorNodeId, AutogradError> {
        match reduction {
            "mean" => self.tensor_mean_dim(x, 0),
            "sum" => self.tensor_sum_dim(x, 0),
            "max" => Ok(self.tensor_max_dim(x, 0)?.0),
            "min" => Ok(self.tensor_min_dim(x, 0)?.0),
            _ => Err(Self::incompatible_tensor_args("reduce_batch: unknown reduction")),
        }
    }

    // ── Sequence Utilities ────────────────────────────────────────────────

    /// Create attention mask from sequence lengths.
    ///
    /// Returns mask of shape [batch, max_len] with 1s for valid positions.
    pub fn length_to_mask(
        &mut self,
        lengths: &[usize],
        max_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let batch_size = lengths.len();
        let mut mask_data = vec![0.0_f64; batch_size * max_len];
        for (i, &len) in lengths.iter().enumerate() {
            for j in 0..len.min(max_len) {
                mask_data[i * max_len + j] = 1.0;
            }
        }
        self.tensor_variable(mask_data, vec![batch_size, max_len], false)
    }

    // ── Pooling Utilities ─────────────────────────────────────────────────

    /// Global average pooling for any dimension.
    ///
    /// Averages over all spatial dimensions.
    pub fn global_avg_pool(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        match shape.len() {
            3 => {
                let pooled = self.tensor_mean_dim(x, 2)?;
                Ok(pooled)
            }
            4 => {
                let (n, c, _, _) = (shape[0], shape[1], shape[2], shape[3]);
                self.tensor_adaptive_avg_pool2d(x, (1, 1))
            }
            5 => {
                let (n, c, _, _, _) = (shape[0], shape[1], shape[2], shape[3], shape[4]);
                self.tensor_adaptive_avg_pool3d(x, (1, 1, 1))
            }
            _ => Err(Self::incompatible_tensor_args("global_avg_pool: unsupported dim")),
        }
    }

    /// Global max pooling for any dimension.
    pub fn global_max_pool(
        &mut self,
        x: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        match shape.len() {
            3 => {
                let (pooled, _) = self.tensor_max_dim(x, 2)?;
                Ok(pooled)
            }
            4 => {
                let (pooled, _) = self.tensor_adaptive_max_pool2d(x, (1, 1))?;
                Ok(pooled)
            }
            5 => {
                let (pooled, _) = self.tensor_adaptive_max_pool3d(x, (1, 1, 1))?;
                Ok(pooled)
            }
            _ => Err(Self::incompatible_tensor_args("global_max_pool: unsupported dim")),
        }
    }

    // ── Index Utilities ───────────────────────────────────────────────────

    /// Create index tensor from range.
    pub fn arange_tensor(
        &mut self,
        start: usize,
        end: usize,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        let data: Vec<f64> = (start..end).map(|x| x as f64).collect();
        self.tensor_variable(data, vec![end - start], requires_grad)
    }

    /// Create linspace tensor.
    pub fn linspace_tensor(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if steps == 0 {
            return self.tensor_variable(vec![], vec![0], requires_grad);
        }
        if steps == 1 {
            return self.tensor_variable(vec![start], vec![1], requires_grad);
        }
        let step = (end - start) / (steps - 1) as f64;
        let data: Vec<f64> = (0..steps).map(|i| start + step * i as f64).collect();
        self.tensor_variable(data, vec![steps], requires_grad)
    }

    /// Create logspace tensor.
    pub fn logspace_tensor(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        base: f64,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if steps == 0 {
            return self.tensor_variable(vec![], vec![0], requires_grad);
        }
        if steps == 1 {
            return self.tensor_variable(vec![base.powf(start)], vec![1], requires_grad);
        }
        let step = (end - start) / (steps - 1) as f64;
        let data: Vec<f64> = (0..steps)
            .map(|i| base.powf(start + step * i as f64))
            .collect();
        self.tensor_variable(data, vec![steps], requires_grad)
    }

    /// Create meshgrid from 1D tensors.
    pub fn meshgrid_2d(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<(TensorNodeId, TensorNodeId), AutogradError> {
        let x_vals = self.tensor_values(x)?;
        let y_vals = self.tensor_values(y)?;
        let nx = x_vals.len();
        let ny = y_vals.len();
        let mut xx_data = Vec::with_capacity(ny * nx);
        let mut yy_data = Vec::with_capacity(ny * nx);
        for yv in &y_vals {
            for xv in &x_vals {
                xx_data.push(*xv);
                yy_data.push(*yv);
            }
        }
        let xx = self.tensor_variable(xx_data, vec![ny, nx], false)?;
        let yy = self.tensor_variable(yy_data, vec![ny, nx], false)?;
        Ok((xx, yy))
    }

    // ── Tensor Operations ─────────────────────────────────────────────────

    /// Outer product of two 1D tensors.
    pub fn outer_product(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape.len() != 1 || b_shape.len() != 1 {
            return Err(Self::incompatible_tensor_args("outer_product: inputs must be 1D"));
        }
        let a_col = self.tensor_unsqueeze(a, 1)?;
        let b_row = self.tensor_unsqueeze(b, 0)?;
        self.tensor_matmul(a_col, b_row)
    }

    /// Kronecker product of two 2D tensors.
    pub fn kron(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let a_shape = self.tensor_shape(a)?;
        let b_shape = self.tensor_shape(b)?;
        if a_shape.len() != 2 || b_shape.len() != 2 {
            return Err(Self::incompatible_tensor_args("kron: inputs must be 2D"));
        }
        let (m, n) = (a_shape[0], a_shape[1]);
        let (p, q) = (b_shape[0], b_shape[1]);
        let a_vals = self.tensor_values(a)?;
        let b_vals = self.tensor_values(b)?;
        let mut result = vec![0.0_f64; m * p * n * q];
        for i in 0..m {
            for j in 0..n {
                let a_val = a_vals[i * n + j];
                for k in 0..p {
                    for l in 0..q {
                        let b_val = b_vals[k * q + l];
                        let row = i * p + k;
                        let col = j * q + l;
                        result[row * (n * q) + col] = a_val * b_val;
                    }
                }
            }
        }
        self.tensor_variable(result, vec![m * p, n * q], false)
    }

    /// Block diagonal matrix from a list of 2D tensors.
    pub fn block_diag(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return Err(Self::incompatible_tensor_args("block_diag: empty tensor list"));
        }
        let mut total_rows = 0;
        let mut total_cols = 0;
        let mut shapes = Vec::new();
        for &t in tensors {
            let shape = self.tensor_shape(t)?;
            if shape.len() != 2 {
                return Err(Self::incompatible_tensor_args("block_diag: tensors must be 2D"));
            }
            shapes.push((shape[0], shape[1]));
            total_rows += shape[0];
            total_cols += shape[1];
        }
        let mut result = vec![0.0_f64; total_rows * total_cols];
        let mut row_offset = 0;
        let mut col_offset = 0;
        for (&t, &(rows, cols)) in tensors.iter().zip(shapes.iter()) {
            let vals = self.tensor_values(t)?;
            for i in 0..rows {
                for j in 0..cols {
                    let row = row_offset + i;
                    let col = col_offset + j;
                    result[row * total_cols + col] = vals[i * cols + j];
                }
            }
            row_offset += rows;
            col_offset += cols;
        }
        self.tensor_variable(result, vec![total_rows, total_cols], false)
    }

    // ── Weight Decay Utilities ────────────────────────────────────────────

    /// Apply L2 weight decay to weights.
    ///
    /// Returns weights - weight_decay * weights.
    pub fn apply_weight_decay(
        &mut self,
        weights: TensorNodeId,
        weight_decay: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let decay = self.full(vec![1], weight_decay, false)?;
        let penalty = self.tensor_mul(weights, decay)?;
        self.tensor_sub(weights, penalty)
    }

    /// Compute L2 regularization term.
    ///
    /// Returns sum of squared weights * lambda / 2.
    pub fn l2_regularization(
        &mut self,
        weights: TensorNodeId,
        lambda: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let sq = self.tensor_mul(weights, weights)?;
        let sum = self.tensor_sum(sq)?;
        let half_lambda = self.full(vec![1], lambda / 2.0, false)?;
        self.tensor_mul(sum, half_lambda)
    }

    /// Compute L1 regularization term.
    ///
    /// Returns sum of absolute weights * lambda.
    pub fn l1_regularization(
        &mut self,
        weights: TensorNodeId,
        lambda: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let abs = self.tensor_abs(weights)?;
        let sum = self.tensor_sum(abs)?;
        let lam = self.full(vec![1], lambda, false)?;
        self.tensor_mul(sum, lam)
    }

    // ── Learning Rate Utilities ───────────────────────────────────────────

    /// Compute learning rate with linear warmup.
    pub fn lr_linear_warmup(
        current_step: usize,
        warmup_steps: usize,
        base_lr: f64,
    ) -> f64 {
        if current_step < warmup_steps {
            base_lr * current_step as f64 / warmup_steps as f64
        } else {
            base_lr
        }
    }

    /// Compute learning rate with cosine annealing.
    pub fn lr_cosine_annealing(
        current_step: usize,
        total_steps: usize,
        base_lr: f64,
        min_lr: f64,
    ) -> f64 {
        if current_step >= total_steps {
            return min_lr;
        }
        let progress = current_step as f64 / total_steps as f64;
        min_lr + (base_lr - min_lr) * (1.0 + (std::f64::consts::PI * progress).cos()) / 2.0
    }

    /// Compute learning rate with warmup + cosine decay.
    pub fn lr_warmup_cosine(
        current_step: usize,
        warmup_steps: usize,
        total_steps: usize,
        base_lr: f64,
        min_lr: f64,
    ) -> f64 {
        if current_step < warmup_steps {
            Self::lr_linear_warmup(current_step, warmup_steps, base_lr)
        } else {
            Self::lr_cosine_annealing(
                current_step - warmup_steps,
                total_steps - warmup_steps,
                base_lr,
                min_lr,
            )
        }
    }

    // ── Tokenizer Utilities ───────────────────────────────────────────────

    /// Add BOS (Beginning of Sequence) token.
    pub fn add_bos_token(
        &mut self,
        input: TensorNodeId,
        bos_id: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            return Err(Self::incompatible_tensor_args("add_bos_token: input cannot be scalar"));
        }
        let mut bos_shape = shape.clone();
        bos_shape[shape.len() - 1] = 1;
        let bos = self.full(bos_shape, bos_id, false)?;
        self.tensor_cat(&[bos, input], shape.len() - 1)
    }

    /// Add EOS (End of Sequence) token.
    pub fn add_eos_token(
        &mut self,
        input: TensorNodeId,
        eos_id: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            return Err(Self::incompatible_tensor_args("add_eos_token: input cannot be scalar"));
        }
        let mut eos_shape = shape.clone();
        eos_shape[shape.len() - 1] = 1;
        let eos = self.full(eos_shape, eos_id, false)?;
        self.tensor_cat(&[input, eos], shape.len() - 1)
    }

    /// Pad sequence to target length.
    pub fn pad_sequence_to_length(
        &mut self,
        input: TensorNodeId,
        target_length: usize,
        pad_id: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let current_length = shape[shape.len() - 1];
        if current_length >= target_length {
            return Ok(input);
        }
        let pad_length = target_length - current_length;
        let mut pad_shape = shape.clone();
        pad_shape[shape.len() - 1] = pad_length;
        let pad = self.full(pad_shape, pad_id, false)?;
        self.tensor_cat(&[input, pad], shape.len() - 1)
    }

    // ── Numerical Stability Utilities ────────────────────────────────────

    /// Clamp values to avoid numerical instability (log of small numbers etc).
    pub fn clamp_for_log(
        &mut self,
        input: TensorNodeId,
        min_val: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_clamp_min(input, min_val)
    }

    /// Safe log: clamps input to avoid -inf.
    pub fn safe_log(
        &mut self,
        input: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let clamped = self.tensor_clamp_min(input, eps)?;
        self.tensor_log(clamped)
    }

    /// Safe division: avoids div by zero by adding eps to denominator.
    pub fn safe_div(
        &mut self,
        num: TensorNodeId,
        denom: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let eps_tensor = self.full(vec![1], eps, false)?;
        let safe_denom = self.tensor_add(denom, eps_tensor)?;
        self.tensor_div(num, safe_denom)
    }

    /// Numerically stable sigmoid using tanh: sigmoid(x) = 0.5 * (tanh(x/2) + 1).
    pub fn stable_sigmoid(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let half = self.full(vec![1], 0.5, false)?;
        let half_x = self.tensor_mul(input, half)?;
        let tanh_half = self.tensor_tanh(half_x)?;
        let one = self.full(vec![1], 1.0, false)?;
        let plus_one = self.tensor_add(tanh_half, one)?;
        self.tensor_mul(plus_one, half)
    }

    /// Softsign activation: x / (1 + |x|).
    pub fn softsign(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let abs_x = self.tensor_abs(input)?;
        let one = self.full(vec![1], 1.0, false)?;
        let denom = self.tensor_add(abs_x, one)?;
        self.tensor_div(input, denom)
    }

    /// Threshold activation: replaces values <= threshold with value.
    pub fn threshold_activation(
        &mut self,
        input: TensorNodeId,
        thresh: f64,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let data = self.tensor_values(input)?;
        let requires_grad = self.tensor_tape.tensor_requires_grad(input)?;
        let result: Vec<f64> = data.iter().map(|&x| if x > thresh { x } else { value }).collect();
        self.tensor_variable(result, shape, requires_grad)
    }

    // ── Batch Utilities ──────────────────────────────────────────────────

    /// Get batch size from a batched tensor.
    pub fn batch_size(&self, input: TensorNodeId) -> Result<usize, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.is_empty() {
            return Err(Self::incompatible_tensor_args("batch_size: scalar has no batch dimension"));
        }
        Ok(shape[0])
    }

    /// Repeat tensor along batch dimension.
    pub fn repeat_batch(
        &mut self,
        input: TensorNodeId,
        repeats: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let mut repeat_dims = vec![1; shape.len()];
        repeat_dims[0] = repeats;
        self.tensor_repeat(input, &repeat_dims)
    }

    /// Interleave batches from two tensors: [a0, b0, a1, b1, ...].
    pub fn interleave_batch(
        &mut self,
        a: TensorNodeId,
        b: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape_a = self.tensor_shape(a)?;
        let shape_b = self.tensor_shape(b)?;
        if shape_a != shape_b {
            return Err(Self::incompatible_tensor_args("interleave_batch: shapes must match"));
        }
        let stacked = self.tensor_stack(&[a, b], 1)?;
        let mut new_shape = shape_a.clone();
        new_shape[0] *= 2;
        self.tensor_reshape(stacked, new_shape)
    }

    // ── Sequence Utilities ───────────────────────────────────────────────

    /// Get the last token from each sequence in a batch: [B, T, D] -> [B, D].
    pub fn get_last_token(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(Self::incompatible_tensor_args("get_last_token: requires at least 2D tensor"));
        }
        let t = shape[1];
        let sliced = self.tensor_narrow(input, 1, t - 1, 1)?;
        self.tensor_squeeze(sliced, 1)
    }

    /// Get the first token from each sequence in a batch: [B, T, D] -> [B, D].
    pub fn get_first_token(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let sliced = self.tensor_narrow(input, 1, 0, 1)?;
        self.tensor_squeeze(sliced, 1)
    }

    /// Shift sequence left (for causal language modeling targets).
    pub fn shift_left(
        &mut self,
        input: TensorNodeId,
        pad_value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(Self::incompatible_tensor_args("shift_left: requires at least 2D tensor"));
        }
        let t = shape[1];
        let shifted = self.tensor_narrow(input, 1, 1, t - 1)?;
        let mut pad_shape = shape.clone();
        pad_shape[1] = 1;
        let pad = self.full(pad_shape, pad_value, false)?;
        self.tensor_cat(&[shifted, pad], 1)
    }

    /// Shift sequence right (for decoder input from targets).
    pub fn shift_right(
        &mut self,
        input: TensorNodeId,
        pad_value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() < 2 {
            return Err(Self::incompatible_tensor_args("shift_right: requires at least 2D tensor"));
        }
        let t = shape[1];
        let shifted = self.tensor_narrow(input, 1, 0, t - 1)?;
        let mut pad_shape = shape.clone();
        pad_shape[1] = 1;
        let pad = self.full(pad_shape, pad_value, false)?;
        self.tensor_cat(&[pad, shifted], 1)
    }

    // ── Tensor Norm Utilities ────────────────────────────────────────────

    /// Compute Frobenius norm: sqrt(sum(x^2)).
    pub fn frobenius_norm(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let sq = self.tensor_mul(input, input)?;
        let sum = self.tensor_sum(sq)?;
        self.tensor_sqrt(sum)
    }

    /// Compute L1 norm: sum(|x|).
    pub fn l1_norm(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let abs = self.tensor_abs(input)?;
        self.tensor_sum(abs)
    }

    /// Compute max norm: max(|x|).
    pub fn max_norm(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let abs = self.tensor_abs(input)?;
        let shape = self.tensor_shape(abs)?;
        let ndim = shape.len();
        let flat = if ndim > 1 {
            self.tensor_flatten(abs, 0, ndim - 1)?
        } else {
            abs
        };
        self.tensor_amax(flat, 0)
    }

    /// Normalize tensor to unit norm.
    pub fn normalize_to_unit(
        &mut self,
        input: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let norm = self.frobenius_norm(input)?;
        let eps_tensor = self.full(vec![1], eps, false)?;
        let safe_norm = self.tensor_add(norm, eps_tensor)?;
        self.tensor_div(input, safe_norm)
    }

    // ── Reduction Utilities ──────────────────────────────────────────────

    /// Compute mean along last dimension.
    pub fn mean_last_dim(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let last_dim = shape.len() - 1;
        self.tensor_mean_dim(input, last_dim)
    }

    /// Compute sum along last dimension.
    pub fn sum_last_dim(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let last_dim = shape.len() - 1;
        self.tensor_sum_dim(input, last_dim)
    }

    /// Compute max along last dimension (values only).
    pub fn max_last_dim(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let last_dim = shape.len() - 1;
        self.tensor_amax(input, last_dim)
    }

    /// Compute min along last dimension (values only).
    pub fn min_last_dim(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let last_dim = shape.len() - 1;
        self.tensor_amin(input, last_dim)
    }

    // ── Shape Manipulation Utilities ─────────────────────────────────────

    /// Add a dimension at the end of the tensor.
    pub fn unsqueeze_last(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        self.tensor_unsqueeze(input, shape.len())
    }

    /// Add a dimension at the beginning of the tensor.
    pub fn unsqueeze_first(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_unsqueeze(input, 0)
    }

    /// Broadcast tensor to match target shape.
    pub fn broadcast_to(
        &mut self,
        input: TensorNodeId,
        target_shape: Vec<usize>,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_expand(input, target_shape)
    }

    /// Flatten all dimensions.
    pub fn flatten_all(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let numel: usize = shape.iter().product();
        self.tensor_reshape(input, vec![numel])
    }

    /// Flatten except batch dimension.
    pub fn flatten_except_batch(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() <= 1 {
            return Ok(input);
        }
        let batch = shape[0];
        let rest: usize = shape[1..].iter().product();
        self.tensor_reshape(input, vec![batch, rest])
    }

    // ── Masking Utilities ────────────────────────────────────────────────

    /// Create a mask from length values (for variable-length sequences).
    pub fn lengths_to_mask(
        &mut self,
        lengths: TensorNodeId,
        max_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let lengths_data = self.tensor_values(lengths)?;
        let batch_size = lengths_data.len();
        let mut mask_data = vec![0.0f64; batch_size * max_len];
        for (b, &len) in lengths_data.iter().enumerate() {
            let len_usize = len as usize;
            for t in 0..len_usize.min(max_len) {
                mask_data[b * max_len + t] = 1.0;
            }
        }
        self.tensor_variable(mask_data, vec![batch_size, max_len], false)
    }

    /// Apply mask to tensor (sets masked positions to value).
    pub fn masked_fill(
        &mut self,
        input: TensorNodeId,
        mask: TensorNodeId,
        value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let value_tensor = self.full(vec![1], value, false)?;
        self.tensor_where(mask, value_tensor, input)
    }

    // ── Embedding Utilities ──────────────────────────────────────────────

    /// Simple embedding lookup (like nn.Embedding without trainable weights).
    pub fn embedding_lookup(
        &mut self,
        weight: TensorNodeId,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_index_select(weight, 0, indices)
    }

    /// Sum of embeddings for a bag of indices.
    pub fn embedding_bag_sum(
        &mut self,
        weight: TensorNodeId,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let embedded = self.tensor_index_select(weight, 0, indices)?;
        self.tensor_sum_dim(embedded, 0)
    }

    /// Mean of embeddings for a bag of indices.
    pub fn embedding_bag_mean(
        &mut self,
        weight: TensorNodeId,
        indices: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let embedded = self.tensor_index_select(weight, 0, indices)?;
        self.tensor_mean_dim(embedded, 0)
    }

    // ── Distance Utilities ───────────────────────────────────────────────

    /// Compute pairwise L2 distance squared between two sets of vectors.
    pub fn pairwise_distance_squared(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let diff = self.tensor_sub(x, y)?;
        let sq = self.tensor_mul(diff, diff)?;
        let shape = self.tensor_shape(sq)?;
        let last_dim = shape.len() - 1;
        self.tensor_sum_dim(sq, last_dim)
    }

    /// Compute cosine distance: 1 - cosine_similarity.
    pub fn cosine_distance(
        &mut self,
        x: TensorNodeId,
        y: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(x)?;
        let last_dim = shape.len() - 1;
        let sim = self.tensor_cosine_similarity(x, y, last_dim, eps)?;
        let one = self.full(vec![1], 1.0, false)?;
        self.tensor_sub(one, sim)
    }

    // ── Comparison Utilities ─────────────────────────────────────────────

    /// Check if all elements are True (> 0).
    pub fn all_true(
        &mut self,
        input: TensorNodeId,
    ) -> Result<bool, AutogradError> {
        let data = self.tensor_values(input)?;
        Ok(data.iter().all(|&x| x > 0.0))
    }

    /// Check if any element is True (> 0).
    pub fn any_true(
        &mut self,
        input: TensorNodeId,
    ) -> Result<bool, AutogradError> {
        let data = self.tensor_values(input)?;
        Ok(data.iter().any(|&x| x > 0.0))
    }

    // ── Gradient Control ─────────────────────────────────────────────────

    /// Detach tensor from computation graph (creates a leaf copy).
    pub fn detach_copy(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let data = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        self.tensor_variable(data, shape, false)
    }

    /// Create a copy with gradients enabled.
    pub fn requires_grad_copy(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let data = self.tensor_values(input)?;
        let shape = self.tensor_shape(input)?;
        self.tensor_variable(data, shape, true)
    }

    // ── Tensor Arithmetic Utilities ──────────────────────────────────────

    /// Compute element-wise power with scalar exponent.
    pub fn pow_scalar(
        &mut self,
        input: TensorNodeId,
        exponent: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let exp_tensor = self.full(vec![1], exponent, false)?;
        self.tensor_pow_tensor(input, exp_tensor)
    }

    /// Compute cube of each element.
    pub fn cube(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let sq = self.tensor_mul(input, input)?;
        self.tensor_mul(sq, input)
    }

    /// Add scalar to tensor.
    pub fn add_scalar(
        &mut self,
        input: TensorNodeId,
        scalar: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let s = self.full(vec![1], scalar, false)?;
        self.tensor_add(input, s)
    }

    /// Subtract scalar from tensor.
    pub fn sub_scalar(
        &mut self,
        input: TensorNodeId,
        scalar: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let s = self.full(vec![1], scalar, false)?;
        self.tensor_sub(input, s)
    }

    /// Multiply tensor by scalar.
    pub fn mul_scalar(
        &mut self,
        input: TensorNodeId,
        scalar: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let s = self.full(vec![1], scalar, false)?;
        self.tensor_mul(input, s)
    }

    /// Divide tensor by scalar.
    pub fn div_scalar(
        &mut self,
        input: TensorNodeId,
        scalar: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let s = self.full(vec![1], scalar, false)?;
        self.tensor_div(input, s)
    }

    // ── Statistics Utilities ─────────────────────────────────────────────

    /// Compute variance of all elements.
    pub fn global_var(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let flat = self.flatten_all(input)?;
        self.tensor_var(flat, 1)
    }

    /// Compute standard deviation of all elements.
    pub fn global_std(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let var = self.global_var(input)?;
        self.tensor_sqrt(var)
    }

    /// Compute median of all elements.
    pub fn global_median(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let flat = self.flatten_all(input)?;
        self.tensor_median(flat)
    }

    // ── Concatenation Utilities ──────────────────────────────────────────

    /// Concatenate tensors along the first dimension.
    pub fn cat_dim0(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_cat(tensors, 0)
    }

    /// Concatenate tensors along the last dimension.
    pub fn cat_last_dim(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        if tensors.is_empty() {
            return Err(Self::incompatible_tensor_args("cat_last_dim: empty tensor list"));
        }
        let shape = self.tensor_shape(tensors[0])?;
        let last_dim = shape.len() - 1;
        self.tensor_cat(tensors, last_dim)
    }

    /// Stack tensors along a new first dimension.
    pub fn stack_dim0(
        &mut self,
        tensors: &[TensorNodeId],
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_stack(tensors, 0)
    }

    // ── Random Utilities ─────────────────────────────────────────────────

    /// Sample from standard normal distribution (mean=0, std=1).
    pub fn randn_std(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_randn(shape, requires_grad)
    }

    /// Sample from uniform distribution [0, 1).
    pub fn rand_01(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_uniform(0.0, 1.0, shape, requires_grad)
    }

    /// Sample from uniform distribution [-1, 1).
    pub fn rand_symmetric(
        &mut self,
        shape: Vec<usize>,
        requires_grad: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_uniform(-1.0, 1.0, shape, requires_grad)
    }

    // ── Clipping Utilities ───────────────────────────────────────────────

    /// Clip values to a symmetric range [-bound, bound].
    pub fn clip_symmetric(
        &mut self,
        input: TensorNodeId,
        bound: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_clamp(input, -bound, bound)
    }

    /// Clip to positive values only (equivalent to ReLU but more readable).
    pub fn clip_positive(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_clamp_min(input, 0.0)
    }

    /// Clip to [0, 1] range (useful for probabilities).
    pub fn clip_probability(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_clamp(input, 0.0, 1.0)
    }

    // ── Linear Algebra Shortcuts ─────────────────────────────────────────

    /// Compute trace of a square matrix.
    pub fn trace_matrix(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_trace(input)
    }

    /// Compute matrix determinant.
    pub fn det_matrix(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_det(input)
    }

    /// Compute matrix inverse.
    pub fn inv_matrix(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linalg_inv(input)
    }

    /// Transpose 2D matrix.
    pub fn transpose_2d(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_transpose(input, 0, 1)
    }

    // ── Normalization Shortcuts ──────────────────────────────────────────

    /// Apply L2 normalization along last dimension.
    pub fn normalize_l2(
        &mut self,
        input: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let last_dim = shape.len() - 1;
        let sq = self.tensor_mul(input, input)?;
        let sum_sq = self.tensor_sum_dim(sq, last_dim)?;
        let eps_t = self.full(vec![1], eps, false)?;
        let sum_with_eps = self.tensor_add(sum_sq, eps_t)?;
        let norm = self.tensor_sqrt(sum_with_eps)?;
        let norm_expanded = self.tensor_unsqueeze(norm, last_dim)?;
        self.tensor_div(input, norm_expanded)
    }

    /// Apply min-max normalization to [0, 1] range.
    pub fn normalize_minmax(
        &mut self,
        input: TensorNodeId,
        eps: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let flat = self.flatten_all(input)?;
        let min_val = self.tensor_amin(flat, 0)?;
        let max_val = self.tensor_amax(flat, 0)?;
        let shifted = self.tensor_sub(input, min_val)?;
        let range = self.tensor_sub(max_val, min_val)?;
        let eps_t = self.full(vec![1], eps, false)?;
        let safe_range = self.tensor_add(range, eps_t)?;
        self.tensor_div(shifted, safe_range)
    }

    // ── Index Utilities ──────────────────────────────────────────────────

    /// Create indices [0, 1, 2, ..., n-1].
    pub fn arange_int(
        &mut self,
        n: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let data: Vec<f64> = (0..n).map(|i| i as f64).collect();
        self.tensor_variable(data, vec![n], false)
    }

    /// Create linearly spaced values.
    pub fn linspace_simple(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_linspace(start, end, steps, false)
    }

    /// Create logarithmically spaced values.
    pub fn logspace_simple(
        &mut self,
        start: f64,
        end: f64,
        steps: usize,
        base: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_logspace(start, end, steps, base, false)
    }

    // ── Attention Helpers ────────────────────────────────────────────────

    /// Create causal attention mask for sequence length.
    pub fn create_causal_mask(
        &mut self,
        seq_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.causal_mask(seq_len)
    }

    /// Create padding attention mask from lengths.
    pub fn create_padding_mask(
        &mut self,
        lengths: TensorNodeId,
        max_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        self.lengths_to_mask(lengths, max_len)
    }

    /// Scale queries for attention (divide by sqrt(d_k)).
    pub fn scale_for_attention(
        &mut self,
        query: TensorNodeId,
        d_k: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let scale = 1.0 / (d_k as f64).sqrt();
        let scale_t = self.full(vec![1], scale, false)?;
        self.tensor_mul(query, scale_t)
    }

    // ── Tensor Property Queries ──────────────────────────────────────────

    /// Get total number of dimensions.
    pub fn ndim(&self, input: TensorNodeId) -> Result<usize, AutogradError> {
        let shape = self.tensor_shape(input)?;
        Ok(shape.len())
    }

    /// Check if tensor is 1D.
    pub fn is_1d(&self, input: TensorNodeId) -> Result<bool, AutogradError> {
        let shape = self.tensor_shape(input)?;
        Ok(shape.len() == 1)
    }

    /// Check if tensor is 2D.
    pub fn is_2d(&self, input: TensorNodeId) -> Result<bool, AutogradError> {
        let shape = self.tensor_shape(input)?;
        Ok(shape.len() == 2)
    }

    /// Check if tensor is square matrix.
    pub fn is_square(&self, input: TensorNodeId) -> Result<bool, AutogradError> {
        let shape = self.tensor_shape(input)?;
        Ok(shape.len() == 2 && shape[0] == shape[1])
    }

    /// Check if tensor is contiguous (always true for dense).
    pub fn is_contiguous(&self, _input: TensorNodeId) -> bool {
        true
    }

