    // ── Comparison Operations ─────────────────────────────────────────────

    /// Count non-zero elements.
    pub fn nonzero_count(
        &mut self,
        input: TensorNodeId,
    ) -> Result<usize, AutogradError> {
        let count = self.tensor_count_nonzero(input)?;
        let values = self.tensor_values(count)?;
        Ok(values[0] as usize)
    }

    // ── Batch Operations ──────────────────────────────────────────────────

    /// Split batch into chunks.
    pub fn split_batch(
        &mut self,
        input: TensorNodeId,
        chunk_size: usize,
    ) -> Result<Vec<TensorNodeId>, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let batch_size = shape[0];
        let num_chunks = (batch_size + chunk_size - 1) / chunk_size;
        self.tensor_chunk(input, num_chunks, 0)
    }

    /// Get single batch element.
    pub fn get_batch_item(
        &mut self,
        input: TensorNodeId,
        index: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let requires_grad = self.tensor_tape.tensor_requires_grad(input)?;
        let indices = self.tensor_tape.leaf(vec![index as f64], vec![1], requires_grad)?;
        let selected = self.tensor_index_select(input, 0, indices)?;
        self.tensor_squeeze(selected, 0)
    }

    // ── Sequence Operations ───────────────────────────────────────────────

    /// Pad sequence to length.
    pub fn pad_sequence_end(
        &mut self,
        input: TensorNodeId,
        target_len: usize,
        pad_value: f64,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let current_len = shape[shape.len() - 1];
        if current_len >= target_len {
            return Ok(input);
        }
        let pad_len = target_len - current_len;
        let mut pad = vec![0; shape.len() * 2];
        pad[0] = pad_len;
        self.tensor_pad(input, &pad, pad_value)
    }

    /// Truncate sequence to length.
    pub fn truncate_sequence(
        &mut self,
        input: TensorNodeId,
        max_len: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        let current_len = shape[shape.len() - 1];
        if current_len <= max_len {
            return Ok(input);
        }
        let dim = shape.len() - 1;
        self.tensor_narrow(input, dim, 0, max_len)
    }

    // ── Image-like Operations ─────────────────────────────────────────────

    /// Normalize image tensor (NCHW format).
    pub fn normalize_image(
        &mut self,
        input: TensorNodeId,
        mean: &[f64],
        std: &[f64],
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("expected NCHW"));
        }
        let c = shape[1];
        let mean_t = self.tensor_tape.leaf(mean.to_vec(), vec![1, c, 1, 1], false)?;
        let std_t = self.tensor_tape.leaf(std.to_vec(), vec![1, c, 1, 1], false)?;
        let centered = self.tensor_sub(input, mean_t)?;
        self.tensor_div(centered, std_t)
    }

    /// Denormalize image tensor (NCHW format).
    pub fn denormalize_image(
        &mut self,
        input: TensorNodeId,
        mean: &[f64],
        std: &[f64],
    ) -> Result<TensorNodeId, AutogradError> {
        let shape = self.tensor_shape(input)?;
        if shape.len() != 4 {
            return Err(Self::incompatible_tensor_args("expected NCHW"));
        }
        let c = shape[1];
        let mean_t = self.tensor_tape.leaf(mean.to_vec(), vec![1, c, 1, 1], false)?;
        let std_t = self.tensor_tape.leaf(std.to_vec(), vec![1, c, 1, 1], false)?;
        let scaled = self.tensor_mul(input, std_t)?;
        self.tensor_add(scaled, mean_t)
    }

    // ── Boolean Tensor Operations ─────────────────────────────────────────

    /// Convert tensor to boolean mask (nonzero = true).
    pub fn to_bool_mask(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let zero = self.full(vec![1], 0.0, false)?;
        self.tensor_ne(input, zero)
    }

    /// Invert boolean mask.
    pub fn invert_mask(
        &mut self,
        mask: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        self.tensor_logical_not(mask)
    }

    // ── Embedding Utilities ───────────────────────────────────────────────

    /// Apply embedding dropout (zero entire embedding vectors).
    pub fn embedding_dropout(
        &mut self,
        embeddings: TensorNodeId,
        p: f64,
        training: bool,
    ) -> Result<TensorNodeId, AutogradError> {
        if !training || p == 0.0 {
            return Ok(embeddings);
        }
        let shape = self.tensor_shape(embeddings)?;
        let batch_seq_shape = vec![shape[0], shape[1], 1];
        let mask = self.tensor_randn(batch_seq_shape.clone(), false)?;
        let threshold = self.full(batch_seq_shape, 1.0 - p, false)?;
        let keep_mask = self.tensor_gt(mask, threshold)?;
        let scale = 1.0 / (1.0 - p);
        let scale_tensor = self.full(vec![1], scale, false)?;
        let masked = self.tensor_mul(embeddings, keep_mask)?;
        self.tensor_mul(masked, scale_tensor)
    }

