    /// Check for NaN or Inf values.
    pub fn has_anomalies(&mut self, input: TensorNodeId) -> Result<bool, AutogradError> {
        let is_finite = self.tensor_isfinite(input)?;
        let all_finite = self.tensor_all(is_finite)?;
        Ok(!all_finite)
    }

    /// Get basic tensor statistics as tuple (min, max, mean).
    pub fn basic_stats(&mut self, input: TensorNodeId) -> Result<(f64, f64, f64), AutogradError> {
        let min = self.min_value(input)?;
        let max = self.max_value(input)?;
        let mean = self.mean_value(input)?;
        Ok((min, max, mean))
    }

    // ── Reshape Utilities ─────────────────────────────────────────────────

    /// Reshape to 1D (flatten all dimensions).
    pub fn reshape_flat(
        &mut self,
        input: TensorNodeId,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel = self.tensor_numel(input)?;
        self.tensor_reshape(input, vec![numel])
    }

    /// Reshape to 2D with inferred second dimension.
    pub fn reshape_2d(
        &mut self,
        input: TensorNodeId,
        first_dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel = self.tensor_numel(input)?;
        let second_dim = numel / first_dim;
        self.tensor_reshape(input, vec![first_dim, second_dim])
    }

    /// Reshape to 3D with inferred third dimension.
    pub fn reshape_3d(
        &mut self,
        input: TensorNodeId,
        first_dim: usize,
        second_dim: usize,
    ) -> Result<TensorNodeId, AutogradError> {
        let numel = self.tensor_numel(input)?;
        let third_dim = numel / (first_dim * second_dim);
        self.tensor_reshape(input, vec![first_dim, second_dim, third_dim])
    }

