        let values = session.tensor_values(y).expect("values should resolve");
        assert!(values[0].abs() < 1e-10);
        // tanh(10) ≈ 1 - 2*e^(-20) ≈ 0.99999999; tanh(-10) ≈ -1 + 2*e^(-20)
