    // ---- cross_entropy_loss ----

    #[test]
    fn session_cross_entropy_loss_basic() {
        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
        // logits: batch=1, classes=3
        let logits = session
            .tensor_variable(vec![2.0, 1.0, 0.1], vec![1, 3], true)
            .expect("logits");
        // target: class 0 (highest logit)
        let targets = session
            .tensor_variable(vec![0.0], vec![1], false)
            .expect("targets");
        let loss = session
            .cross_entropy_loss(logits, targets)
            .expect("cross_entropy");
        let val = session.tensor_values(loss).expect("vals")[0];
        // cross_entropy with correct class should be relatively low
        assert!(val > 0.0, "cross entropy should be positive, got {}", val);
        assert!(
            val < 2.0,
            "cross entropy for correct class should be small, got {}",
            val
        );
    }

    #[test]
    fn session_cross_entropy_loss_wrong_class_is_higher() {
        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
        // logits: batch=1, classes=3: class 0 has highest logit
        let logits = session
            .tensor_variable(vec![5.0, 1.0, 0.1], vec![1, 3], false)
            .expect("logits");

        // Target correct class (0) - should have low loss
        let target_correct = session
            .tensor_variable(vec![0.0], vec![1], false)
            .expect("targets_correct");
        let loss_correct = session
            .cross_entropy_loss(logits, target_correct)
            .expect("ce_correct");
        let val_correct = session.tensor_values(loss_correct).expect("vals")[0];

        // Target wrong class (2) - should have higher loss
        let logits2 = session
            .tensor_variable(vec![5.0, 1.0, 0.1], vec![1, 3], false)
            .expect("logits2");
        let target_wrong = session
            .tensor_variable(vec![2.0], vec![1], false)
            .expect("targets_wrong");
        let loss_wrong = session
            .cross_entropy_loss(logits2, target_wrong)
            .expect("ce_wrong");
        let val_wrong = session.tensor_values(loss_wrong).expect("vals")[0];

        assert!(
            val_wrong > val_correct,
            "wrong class loss ({}) should be higher than correct class loss ({})",
            val_wrong,
            val_correct
        );
    }

    #[test]
    fn session_cross_entropy_loss_rejects_rank0_logits() {
        let mut session = FrankenTorchSession::new(ExecutionMode::Strict);
        let logits = session
            .tensor_variable(vec![2.0], vec![], false)
            .expect("rank-0 logits");
        let targets = session
            .tensor_variable(vec![0.0], vec![1], false)
            .expect("targets");
        let err = session
            .cross_entropy_loss(logits, targets)
            .expect_err("rank-0 logits should fail closed");
        assert!(matches!(
            err,
            AutogradError::Dispatch(ft_dispatch::DispatchError::Kernel(
                ft_kernel_cpu::KernelError::InvalidDimension { dim: 0, ndim: 0 }
            ))
        ));
    }

    #[test]
    fn cross_entropy_label_smoothing_zero_matches_unsmoothed() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let logits = s
            .tensor_variable(vec![2.0, 1.0, 0.1], vec![1, 3], false)
            .unwrap();
        let targets = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss_plain = s.cross_entropy_loss(logits, targets).unwrap();

        let logits2 = s
            .tensor_variable(vec![2.0, 1.0, 0.1], vec![1, 3], false)
            .unwrap();
        let targets2 = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss_smooth = s
            .cross_entropy_loss_with_smoothing(logits2, targets2, 0.0)
            .unwrap();

        let v1 = s.tensor_values(loss_plain).unwrap()[0];
        let v2 = s.tensor_values(loss_smooth).unwrap()[0];
        assert!(
            (v1 - v2).abs() < 1e-10,
            "smoothing=0 should match plain: {v1} vs {v2}"
        );
    }

    #[test]
    fn cross_entropy_label_smoothing_increases_loss() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // Confident correct prediction: loss should increase with smoothing
        let logits = s
            .tensor_variable(vec![10.0, 0.0, 0.0], vec![1, 3], false)
            .unwrap();
        let targets = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss_0 = s.cross_entropy_loss(logits, targets).unwrap();

        let logits2 = s
            .tensor_variable(vec![10.0, 0.0, 0.0], vec![1, 3], false)
            .unwrap();
        let targets2 = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss_s = s
            .cross_entropy_loss_with_smoothing(logits2, targets2, 0.1)
            .unwrap();

        let v0 = s.tensor_values(loss_0).unwrap()[0];
        let vs = s.tensor_values(loss_s).unwrap()[0];
        assert!(
            vs > v0,
            "label smoothing should increase loss for confident predictions: {v0} vs {vs}"
        );
    }

    #[test]
    fn cross_entropy_with_smoothing_propagates_gradient_through_logits() {
        // Regression test for frankentorch-ilwr.
        // cross_entropy_loss_with_smoothing previously extracted
        // scalar values from nll and uniform_loss, computed the
        // (1 - s) * nll + s * uniform blend in plain f64, and
        // rebuilt a requires_grad=false leaf — silently severing
        // autograd for the entire label-smoothing training path.
        // After replacing the scalar arithmetic with tensor_lerp
        // (which is autograd-aware), gradients flow back to logits.
        //
        // Sanity test: confident logits with label_smoothing=0.1
        // should still produce a non-zero gradient on the logits,
        // pointing the wrong-class entries down (less mass) and the
        // correct-class entry's gradient adjusted by the smoothing
        // factor. We just check non-zero finite gradient — exact
        // values depend on the smoothing formula and would be
        // brittle to assert exactly.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let logits = s
            .tensor_variable(vec![5.0, 0.0, 0.0], vec![1, 3], true)
            .unwrap();
        let targets = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss = s
            .cross_entropy_loss_with_smoothing(logits, targets, 0.1)
            .unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, logits)
            .expect("CE-with-smoothing must propagate gradient through logits");
        assert_eq!(grad.len(), 3);
        assert!(
            grad.iter().all(|g| g.is_finite()),
            "CE-with-smoothing gradient must be finite, got {grad:?}"
        );
        // At least one entry should be meaningfully non-zero.
        assert!(
            grad.iter().any(|&g| g.abs() > 1e-6),
            "CE-with-smoothing gradient should be non-zero, got {grad:?}"
        );
        // Gradient should sum to ~0 (since softmax probabilities sum
        // to 1 and the gradient through log_softmax has the form
        // softmax - target_distribution, both summing to 1).
        let total: f64 = grad.iter().sum();
        assert!(
            total.abs() < 1e-10,
            "CE-with-smoothing gradient should sum to 0, got {total}"
        );
    }

    #[test]
    fn cross_entropy_label_smoothing_full_uniform() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // smoothing=1.0: loss = -mean(log_probs) regardless of target
        let logits = s
            .tensor_variable(vec![1.0, 1.0, 1.0], vec![1, 3], false)
            .unwrap();
        let targets = s.tensor_variable(vec![0.0], vec![1], false).unwrap();
        let loss = s
            .cross_entropy_loss_with_smoothing(logits, targets, 1.0)
            .unwrap();
        let val = s.tensor_values(loss).unwrap()[0];
        // Uniform logits: -mean(log(1/3)) = log(3) ≈ 1.099
        assert!(
            (val - 3.0_f64.ln()).abs() < 0.01,
            "full smoothing = uniform loss = log(3), got {val}"
        );
    }

