        let x = session
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], false)
            .expect("x");
        let y = session
            .tensor_variable(vec![4.0, 5.0], vec![2], false)
            .expect("y");
        let grids = session.tensor_meshgrid(&[x, y]).expect("meshgrid");
        assert_eq!(grids.len(), 2);
        // Grid X should be [[1,1],[2,2],[3,3]] (shape [3,2])
