        let t = s.tensor_variable(vec![0.0, 1.0], vec![2], false).unwrap();
        let out = s.tensor_bincount(t, None, 5).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert_eq!(vals.len(), 5);
