    #[test]
    fn xlog1py_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s
            .tensor_variable(vec![0.0, 2.0, 1.0], vec![3], false)
            .unwrap();
        let y = s
            .tensor_variable(vec![1.0, 1.0, 0.0], vec![3], false)
            .unwrap();
        let result = s.tensor_xlog1py(x, y).unwrap();
        let vals = s.tensor_values(result).unwrap();
        assert!((vals[0]).abs() < 1e-12, "0 * log1p(1) = 0");
        assert!(
            (vals[1] - 2.0 * 2.0_f64.ln()).abs() < 1e-10,
            "2 * log1p(1) = 2*ln(2)"
        );
        assert!((vals[2]).abs() < 1e-12, "1 * log1p(0) = 0");
    }

    #[test]
    fn xlog1py_propagates_nan_from_y_when_x_is_zero() {
        // Regression test for frankentorch-duf7. scipy.special.xlog1py
        // and torch.special.xlog1py both propagate NaN from y when
        // x == 0 (their mask is x == 0 && !isnan(y)). Previously
        // tensor_xlog1py's mask was just (x == 0) so it returned 0
        // for (0, NaN), diverging from scipy. The fix tightens the
        // mask to also exclude NaN y, so NaN survives the masked
        // branch as a genuine NaN output.
        //
        // Other masked-branch behaviors are preserved:
        //   (0, -1)         → 0  (the y == -1 pole convention)
        //   (0, finite)     → 0
        //   (0, +inf)       → 0
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s
            .tensor_variable(vec![0.0, 0.0, 0.0, 0.0], vec![4], false)
            .unwrap();
        let y = s
            .tensor_variable(vec![f64::NAN, -1.0, 1.0, f64::INFINITY], vec![4], false)
            .unwrap();
        let out = s.tensor_xlog1py(x, y).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert!(vals[0].is_nan(), "(0, NaN) must yield NaN, got {}", vals[0]);
        assert_eq!(vals[1], 0.0, "(0, -1) must yield 0, got {}", vals[1]);
        assert_eq!(vals[2], 0.0, "(0, 1) must yield 0, got {}", vals[2]);
        assert_eq!(vals[3], 0.0, "(0, +inf) must yield 0, got {}", vals[3]);
    }

    #[test]
    fn xlog1py_propagates_gradients_through_x_and_y() {
        // Regression test for frankentorch-1tax: tensor_xlog1py used
        // to fail-loud reject tracked inputs because the body
        // extracted values and rebuilt a fresh requires_grad=false
        // leaf. After the where(x==0, 0, x*log1p(y)) composition fix
        // gradients flow through both x and y; the rejection guard
        // is gone (test renamed from xlog1py_rejects_grad_input).
        //
        // Analytical derivatives where x != 0:
        //   d xlog1py / dx = log1p(y) = log(1 + y)
        //   d xlog1py / dy = x / (1 + y)
        // Where x == 0, the convention pins both gradients to 0.
        //
        // For x = [2.0, 0.0, 3.0], y = [1.0, 1.0, 4.0]:
        //   output  = [2*ln(2), 0,        3*ln(5)]
        //   sum loss → incoming = ones
        //   grad_x  = [ln(2),   0,        ln(5)]   (mask zeros position 1)
        //   grad_y  = [2/2,     0,        3/5]     (mask zeros position 1)
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s
            .tensor_variable(vec![2.0, 0.0, 3.0], vec![3], true)
            .unwrap();
        let y = s
            .tensor_variable(vec![1.0, 1.0, 4.0], vec![3], true)
            .unwrap();
        let out = s.tensor_xlog1py(x, y).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad_x = s
            .tensor_gradient(&report, x)
            .expect("xlog1py must propagate gradient to x");
        let grad_y = s
            .tensor_gradient(&report, y)
            .expect("xlog1py must propagate gradient to y");

        let expect_x = [2.0_f64.ln(), 0.0, 5.0_f64.ln()];
        let expect_y = [2.0 / 2.0, 0.0, 3.0 / 5.0];
        for (i, (&g, &e)) in grad_x.iter().zip(expect_x.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "xlog1py grad_x[{i}] = {g}, expected log1p(y_i) (or 0): {e}"
            );
        }
        for (i, (&g, &e)) in grad_y.iter().zip(expect_y.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "xlog1py grad_y[{i}] = {g}, expected x_i/(1+y_i) (or 0): {e}"
            );
        }
    }

    #[test]
    fn entr_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![0.0, 0.5, 1.0, -0.1], vec![4], false)
            .unwrap();
        let result = s.tensor_entr(input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        assert!((vals[0]).abs() < 1e-12, "entr(0) = 0");
        assert!(
            (vals[1] - 0.5 * 0.5_f64.ln().abs()).abs() < 1e-10,
            "entr(0.5) = 0.5 * ln(2)"
        );
        assert!((vals[2]).abs() < 1e-12, "entr(1) = -1*ln(1) = 0");
        assert!(vals[3] == f64::NEG_INFINITY, "entr(negative) = -inf");
    }

    #[test]
    fn entr_propagates_gradients_on_positive_branch() {
        // Regression test for frankentorch-1tax: tensor_entr used to
        // fail-loud reject tracked inputs. After the nested-where
        // composition fix, gradients flow through the smooth-branch
        // chain rule.
        //
        // d/dx entr(x) = d/dx (-x * log(x)) = -log(x) - 1   (x > 0)
        //
        // For input [0.25, 0.5, 1.0, 2.0] under sum loss:
        //   grad = [-log(0.25) - 1, -log(0.5) - 1,
        //           -log(1.0) - 1, -log(2.0) - 1]
        //        = [+0.3863..., +0.3069..., -1.0,        -1.6931...]
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let xs = vec![0.25, 0.5, 1.0, 2.0];
        let input = s.tensor_variable(xs.clone(), vec![4], true).unwrap();
        let out = s.tensor_entr(input).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("entr must propagate gradient through the input");
        for (i, (&g, &x)) in grad.iter().zip(xs.iter()).enumerate() {
            let want = -x.ln() - 1.0;
            assert!(
                (g - want).abs() < 1e-12,
                "entr grad[{i}] at x={x} = {g}, expected -log(x) - 1 = {want}"
            );
        }
    }

    #[test]
    fn entr_zero_and_negative_branches_block_gradient() {
        // At x == 0 and x < 0 the composition's masks route the
        // output through constants (0 and -inf respectively), so the
        // gradient back to the input is zero rather than the
        // undefined limit (+inf at x=0+, 0 at x<0). PyTorch returns
        // NaN at x=0; FrankenTorch's mask-blocked-zero is consistent
        // with the constant-branch backward semantics elsewhere
        // (where, scatter, etc.).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s
            .tensor_variable(vec![0.0, -1.0, 0.5], vec![3], true)
            .unwrap();
        let out = s.tensor_entr(input).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        // entr(-1.0) is -inf, so the loss is -inf; backward through
        // a -inf-finite incoming gradient still propagates 0 at the
        // masked-out positions and -log(0.5) - 1 at the smooth one.
        // Forward+backward must not panic.
        let report = s.tensor_backward(loss);
        assert!(
            report.is_ok(),
            "entr backward must not panic on mixed zero / negative / positive input"
        );
    }

    #[test]
    fn polygamma_n1_trigamma() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // trigamma(1) = pi^2/6 ≈ 1.6449
        let input = s.tensor_variable(vec![1.0], vec![1], false).unwrap();
        let result = s.tensor_polygamma(1, input).unwrap();
        let vals = s.tensor_values(result).unwrap();
        let expected = std::f64::consts::PI.powi(2) / 6.0;
        assert!(
            (vals[0] - expected).abs() < 0.01,
            "trigamma(1) ≈ {expected}, got {}",
            vals[0]
        );
    }

    #[test]
    fn polygamma_propagates_gradient_via_next_order() {
        // Regression test for frankentorch-1tax: tensor_polygamma
        // (n >= 1) used to fail-loud reject tracked inputs. After
        // wrapping in tensor_apply_function with a polygamma_approx(n+1, x)
        // backward, gradients flow through.
        //
        // d/dx polygamma(n, x) = polygamma(n + 1, x).
        //
        // For n = 1 (trigamma) at x = 2:
        //   d/dx trigamma(2) = polygamma(2, 2) = -2 * (zeta(3) - 1)
        //                     ≈ -0.40411380631918857
        // Loose 5e-3 tolerance reflects polygamma_approx's envelope
        // (the same precision regime the trigamma forward test uses).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let input = s.tensor_variable(vec![2.0], vec![1], true).unwrap();
        let out = s.tensor_polygamma(1, input).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("polygamma must propagate gradient via next-order backward");
        let expected = -2.0 * (1.202_056_903_159_594_3 - 1.0); // -2*(zeta(3)-1)
        assert!(
            (grad[0] - expected).abs() < 5e-3,
            "polygamma(1) grad at x=2 = {}, expected polygamma(2, 2) = {expected}",
            grad[0]
        );
    }

    #[test]
    fn multigammaln_propagates_gradient_via_digamma_sum() {
        // Regression test for frankentorch-1tax. d/dx multigammaln(x, p)
        // = sum_{i=0..p-1} digamma(x - i/2). Verify via finite
        // differences (loose since both digamma and the sum
        // accumulate hand-rolled approximation error).
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let p = 3;
        let x = 5.0;
        let input = s.tensor_variable(vec![x], vec![1], true).unwrap();
        let out = s.tensor_multigammaln(input, p).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, input)
            .expect("multigammaln must propagate gradient via digamma-sum backward");

        // Finite-difference reference using the public forward path.
        let h = 1e-5;
        let fwd = |xv: f64| -> f64 {
            let mut sess = FrankenTorchSession::new(ExecutionMode::Strict);
            let inp = sess.tensor_variable(vec![xv], vec![1], false).unwrap();
            let result = sess.tensor_multigammaln(inp, p).unwrap();
            sess.tensor_values(result).unwrap()[0]
        };
        let fd = (fwd(x + h) - fwd(x - h)) / (2.0 * h);

        assert!(
            (grad[0] - fd).abs() < 1e-4,
            "multigammaln grad at x={x}, p={p} = {}, finite-diff = {fd}",
            grad[0]
        );
    }

