    // ── hamming_window tests (frankentorch-lg75) ──────────────────────

    #[test]
    fn hamming_window_non_periodic_matches_expected_values() {
        // hamming_window(4, periodic=false): denom = 3.
        // n=0: 0.54 - 0.46*cos(0) = 0.08
        // n=1: 0.54 - 0.46*cos(2π/3) = 0.54 - 0.46*(-0.5) = 0.77
        // n=2: same as n=1 by symmetry = 0.77
        // n=3: same as n=0 by symmetry = 0.08
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.hamming_window(4, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!((vals[0] - 0.08).abs() < 1e-10, "endpoint 0 = {}", vals[0]);
        assert!((vals[1] - 0.77).abs() < 1e-10, "n=1 = {}", vals[1]);
        assert!((vals[2] - 0.77).abs() < 1e-10, "n=2 = {}", vals[2]);
        assert!((vals[3] - 0.08).abs() < 1e-10, "endpoint 3 = {}", vals[3]);
    }

    #[test]
    fn hamming_window_periodic_uses_n_denominator() {
        // periodic=true: denom = N. For N=4: cos(2πn/4) = cos(πn/2).
        // n=0: 0.54 - 0.46*1 = 0.08
        // n=1: 0.54 - 0.46*0 = 0.54
        // n=2: 0.54 - 0.46*(-1) = 1.0
        // n=3: 0.54 - 0.46*0 = 0.54
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.hamming_window(4, true, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!((vals[0] - 0.08).abs() < 1e-10);
        assert!((vals[1] - 0.54).abs() < 1e-10);
        assert!((vals[2] - 1.0).abs() < 1e-10);
        assert!((vals[3] - 0.54).abs() < 1e-10);
    }

    #[test]
    fn hamming_window_length_one_returns_constant() {
        // Length-1 edge case: cos(0) = 1, so single value = 0.08.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.hamming_window(1, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert_eq!(vals.len(), 1);
        assert!((vals[0] - 0.08).abs() < 1e-10);
    }

    #[test]
    fn hamming_window_rejects_zero_length() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let result = s.hamming_window(0, false, false);
        assert!(result.is_err(), "hamming_window(0) must fail closed");
    }

    // ── blackman_window tests (frankentorch-fhrd) ─────────────────────

    #[test]
    fn blackman_window_non_periodic_matches_expected_values() {
        // blackman_window(4, periodic=false): denom = 3.
        // n=0: 0.42 - 0.5*cos(0) + 0.08*cos(0) = 0.42 - 0.5 + 0.08 = 0
        // n=3: same as n=0 by symmetry = 0
        // Interior values are higher.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.blackman_window(4, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!(vals[0].abs() < 1e-10, "endpoint 0 = {}", vals[0]);
        assert!(vals[3].abs() < 1e-10, "endpoint 3 = {}", vals[3]);
        assert!(vals[1] > 0.5 && vals[1] < 1.0, "n=1 interior = {}", vals[1]);
        assert!(vals[2] > 0.5 && vals[2] < 1.0, "n=2 interior = {}", vals[2]);
        // Symmetric: vals[1] == vals[2].
        assert!((vals[1] - vals[2]).abs() < 1e-10);
    }

    #[test]
    fn blackman_window_periodic_uses_n_denominator() {
        // periodic=true, N=4: denom = 4. cos(2π·0/4) = 1, cos(4π·0/4) = 1.
        // n=0: 0.42 - 0.5 + 0.08 = 0
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.blackman_window(4, true, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!(vals[0].abs() < 1e-10, "n=0 periodic = {}", vals[0]);
    }

    #[test]
    fn blackman_window_length_one_returns_constant() {
        // Length-1: cos(0) = 1 across both terms; w = 0.42 - 0.5 + 0.08 = 0.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.blackman_window(1, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert_eq!(vals.len(), 1);
        assert!(vals[0].abs() < 1e-10);
    }

    #[test]
    fn blackman_window_rejects_zero_length() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let result = s.blackman_window(0, false, false);
        assert!(result.is_err(), "blackman_window(0) must fail closed");
    }

    // ── bartlett_window tests (frankentorch-q4hs) ─────────────────────

    #[test]
    fn bartlett_window_non_periodic_matches_expected_values() {
        // bartlett_window(5, periodic=false): denom = 4.
        // n=0: 1 - |0 - 1| = 0
        // n=1: 1 - |0.5 - 1| = 0.5
        // n=2: 1 - |1 - 1| = 1.0 (peak)
        // n=3: 1 - |1.5 - 1| = 0.5
        // n=4: 1 - |2 - 1| = 0
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.bartlett_window(5, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!(vals[0].abs() < 1e-10, "endpoint 0 = {}", vals[0]);
        assert!((vals[1] - 0.5).abs() < 1e-10, "n=1 = {}", vals[1]);
        assert!((vals[2] - 1.0).abs() < 1e-10, "peak = {}", vals[2]);
        assert!((vals[3] - 0.5).abs() < 1e-10, "n=3 = {}", vals[3]);
        assert!(vals[4].abs() < 1e-10, "endpoint 4 = {}", vals[4]);
    }

    #[test]
    fn bartlett_window_periodic_uses_n_denominator() {
        // periodic=true, N=4: denom = 4.
        // n=0: 1 - 1 = 0
        // n=1: 1 - 0.5 = 0.5
        // n=2: 1 - 0 = 1.0 (peak shifted)
        // n=3: 1 - 0.5 = 0.5
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.bartlett_window(4, true, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert!(vals[0].abs() < 1e-10);
        assert!((vals[1] - 0.5).abs() < 1e-10);
        assert!((vals[2] - 1.0).abs() < 1e-10);
        assert!((vals[3] - 0.5).abs() < 1e-10);
    }

    #[test]
    fn bartlett_window_length_one_returns_constant() {
        // Length-1: 1 - |0 - 1| = 0. Single-element edge case.
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let window = s.bartlett_window(1, false, false).unwrap();
        let vals = s.tensor_values(window).unwrap();
        assert_eq!(vals.len(), 1);
        // n=0, denom=1: 1 - |0 - 1| = 0
        assert!(vals[0].abs() < 1e-10);
    }

