    #[test]
    fn quantile_propagates_nan() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s
            .tensor_variable(vec![1.0, f64::NAN, 3.0], vec![3], false)
            .unwrap();
        let out = s.tensor_quantile(x, 0.5).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert!(vals[0].is_nan(), "quantile should propagate NaN");
    }

    #[test]
    fn quantile_propagates_gradients_to_input() {
        // Regression test for frankentorch-1tax: tensor_quantile used
        // to extract values and rebuild a fresh requires_grad=false
        // leaf, severing the tape. After the
        // reshape+sort+narrow+lerp composition, gradients flow back
        // to the input position(s) that hold the order statistic(s)
        // being interpolated.
        //
        // For a sorted input [1, 2, 3, 4] with q=0.5, the median is
        // (sorted[1] + sorted[2]) / 2 = (2 + 3) / 2 = 2.5. With the
        // sorted permutation being identity here, narrow lands on
        // positions 1 and 2, lerp blends them with weight 0.5, and
        // backward through (lerp-of-narrow-of-sort) routes:
        //   d output / d sorted[1] = 0.5
        //   d output / d sorted[2] = 0.5
        //   sort backward then maps these back to original positions.
        //
        // For sum loss (incoming grad = 1) on a 1-element output:
        //   grad[i] = 0.5 if input[i] is the (n-1)*q-th or
        //               (n-1)*q+1-th order statistic
        //   grad[i] = 0   otherwise
        //
        // For input = [1, 2, 3, 4] (already sorted), q = 0.5:
        //   idx = 1.5 → lo=1, hi=2, frac=0.5
        //   lo_val = sorted[1] = 2 (was input[1])
        //   hi_val = sorted[2] = 3 (was input[2])
        //   grad = [0, 0.5, 0.5, 0]
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![4], true)
            .unwrap();
        let out = s.tensor_quantile(x, 0.5).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, x)
            .expect("quantile must propagate gradient to input order statistics");
        assert_eq!(grad, &[0.0, 0.5, 0.5, 0.0]);
    }

    // ── clip_grad_norm_ tests ───────────────────────────────────────────

    #[test]
    fn clip_grad_norm_scales_when_exceeding() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s.tensor_variable(vec![1.0, 2.0], vec![2], true).unwrap();
        let y = s.tensor_variable(vec![3.0, 4.0], vec![2], true).unwrap();

        // Create large gradients: loss = sum(x) + sum(y)
        let sx = s.tensor_sum(x).unwrap();
        let sy = s.tensor_sum(y).unwrap();
        let loss = s.tensor_add(sx, sy).unwrap();
        let _report = s.tensor_backward(loss).unwrap();

        // Set large gradients manually
        s.tensor_set_accumulated_gradient(x, vec![3.0, 4.0])
            .unwrap();
        s.tensor_set_accumulated_gradient(y, vec![0.0, 0.0])
            .unwrap();

        // L2 norm = sqrt(9+16) = 5.0, clip to max_norm=2.5
        let total_norm = s.clip_grad_norm_(&[x, y], 2.5, 2.0).unwrap();
        assert!(
            (total_norm - 5.0).abs() < 1e-8,
            "total norm should be 5.0, got {total_norm}"
        );

        let grad_x = s.tensor_accumulated_gradient(x).unwrap().unwrap();
        // Scaled by 2.5/(5.0+1e-6) ≈ 0.5
        assert!(
            (grad_x[0] - 1.5).abs() < 1e-4,
            "grad should be ~1.5, got {}",
            grad_x[0]
        );
        assert!(
            (grad_x[1] - 2.0).abs() < 1e-4,
            "grad should be ~2.0, got {}",
            grad_x[1]
        );
    }

    #[test]
    fn clip_grad_norm_no_clip_when_below() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s.tensor_variable(vec![1.0], vec![1], true).unwrap();
        let loss = s.tensor_sum(x).unwrap();
        let _report = s.tensor_backward(loss).unwrap();

        s.tensor_set_accumulated_gradient(x, vec![0.5]).unwrap();

        // norm = 0.5, max_norm = 10.0 → no clipping
        let total_norm = s.clip_grad_norm_(&[x], 10.0, 2.0).unwrap();
        assert!((total_norm - 0.5).abs() < 1e-8);
        let grad = s.tensor_accumulated_gradient(x).unwrap().unwrap();
        assert!((grad[0] - 0.5).abs() < 1e-8, "gradient should be unchanged");
    }

    #[test]
    fn clip_grad_norm_inf_norm() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let x = s.tensor_variable(vec![1.0, 2.0], vec![2], true).unwrap();
        let loss = s.tensor_sum(x).unwrap();
        let _report = s.tensor_backward(loss).unwrap();

        s.tensor_set_accumulated_gradient(x, vec![10.0, -20.0])
            .unwrap();

        let total_norm = s.clip_grad_norm_(&[x], 5.0, f64::INFINITY).unwrap();
        assert!((total_norm - 20.0).abs() < 1e-8, "inf norm should be 20.0");
    }

