    // ── trapezoid tests ─────────────────────────────────────────────────

    #[test]
    fn trapezoid_uniform_spacing() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // y = [1, 2, 3], uniform dx=1 → ∫ = 0.5*(1+2)*1 + 0.5*(2+3)*1 = 1.5 + 2.5 = 4.0
        let y = s
            .tensor_variable(vec![1.0, 2.0, 3.0], vec![3], false)
            .unwrap();
        let out = s.tensor_trapezoid(y, None, 0).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert!(
            (vals[0] - 4.0).abs() < 1e-10,
            "expected 4.0, got {}",
            vals[0]
        );
    }

    #[test]
    fn trapezoid_with_x() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        // y = [1, 1], x = [0, 10] → ∫ = 0.5*(1+1)*10 = 10.0
        let y = s.tensor_variable(vec![1.0, 1.0], vec![2], false).unwrap();
        let x = s.tensor_variable(vec![0.0, 10.0], vec![2], false).unwrap();
        let out = s.tensor_trapezoid(y, Some(x), 0).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert!((vals[0] - 10.0).abs() < 1e-10);
    }

    #[test]
    fn trapezoid_propagates_gradient_through_y() {
        // Regression test for frankentorch-b4ys. tensor_trapezoid
        // used to extract values, compute the integral in plain f64,
        // and rebuild a non-grad leaf — silently severing autograd.
        // After composing through narrow + add + mul + sum_dim,
        // gradients flow.
        //
        // For y = [1, 2, 3, 4] with uniform spacing (dx=1):
        //   integral = 0.5*((1+2) + (2+3) + (3+4))
        //            = 0.5*(3 + 5 + 7) = 0.5*15 = 7.5
        // Gradient w.r.t. y[i]:
        //   y[0] is in pair (0,1): contributes 0.5
        //   y[1] is in pairs (0,1) and (1,2): contributes 0.5 + 0.5 = 1.0
        //   y[2] is in pairs (1,2) and (2,3): contributes 0.5 + 0.5 = 1.0
        //   y[3] is in pair (2,3): contributes 0.5
        //   grad_y = [0.5, 1.0, 1.0, 0.5]
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let y = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![4], true)
            .unwrap();
        let integral = s.tensor_trapezoid(y, None, 0).unwrap();
        let report = s.tensor_backward(integral).unwrap();
        let grad = s
            .tensor_gradient(&report, y)
            .expect("trapezoid must propagate gradient through y");
        let expected = [0.5_f64, 1.0, 1.0, 0.5];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "trapezoid grad[{i}] = {g}, expected {e}"
            );
        }
    }

    #[test]
    fn trapezoid_single_point() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let y = s.tensor_variable(vec![5.0], vec![1], false).unwrap();
        let out = s.tensor_trapezoid(y, None, 0).unwrap();
        let vals = s.tensor_values(out).unwrap();
        assert_eq!(vals[0], 0.0, "single point integral should be 0");
    }

    // ── cumulative_trapezoid tests ──────────────────────────────────────

    #[test]
    fn cumulative_trapezoid_basic() {
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let y = s
            .tensor_variable(vec![0.0, 1.0, 3.0], vec![3], false)
            .unwrap();
        let out = s.tensor_cumulative_trapezoid(y, None, 0).unwrap();
        let vals = s.tensor_values(out).unwrap();
        let shape = s.tensor_shape(out).unwrap();
        assert_eq!(shape, &[2]);
        // step 0: 0.5*(0+1)*1 = 0.5
        assert!((vals[0] - 0.5).abs() < 1e-10);
        // step 1: 0.5 + 0.5*(1+3)*1 = 0.5 + 2.0 = 2.5
        assert!((vals[1] - 2.5).abs() < 1e-10);
    }

    #[test]
    fn cumulative_trapezoid_propagates_gradient_through_y() {
        // Regression test for frankentorch-atg3.
        // tensor_cumulative_trapezoid used to extract values, run a
        // running-sum loop in plain f64, and rebuild a non-grad leaf.
        // After composing through narrow + add + mul + cumsum,
        // gradients flow.
        //
        // For y = [1, 2, 3, 4] with uniform dx=1:
        //   pair_avgs = [0.5*(1+2), 0.5*(2+3), 0.5*(3+4)] = [1.5, 2.5, 3.5]
        //   cumsum = [1.5, 4.0, 7.5]
        // Under sum loss (= 1.5 + 4.0 + 7.5 = 13.0):
        //   The cumsum backward gives reverse-cumulative grad on the
        //   weighted_avgs: grad_w_avg = [3, 2, 1] (entry i contributes
        //   to (n-i) elements of cumsum).
        //   weighted_avg[d] = 0.5 * (y[d] + y[d+1])
        //   d weighted_avg[d] / d y[d]   = 0.5
        //   d weighted_avg[d] / d y[d+1] = 0.5
        //   So grad_y[k] = 0.5 * (sum of grad_w_avg[d] for d s.t. d == k or d+1 == k)
        //   y[0]: only d=0 contributes (k = d) → 0.5 * 3 = 1.5
        //   y[1]: d=0 (k = d+1) and d=1 (k = d) → 0.5 * (3 + 2) = 2.5
        //   y[2]: d=1 (k = d+1) and d=2 (k = d) → 0.5 * (2 + 1) = 1.5
        //   y[3]: only d=2 (k = d+1) → 0.5 * 1 = 0.5
        //   grad_y = [1.5, 2.5, 1.5, 0.5]
        let mut s = FrankenTorchSession::new(ExecutionMode::Strict);
        let y = s
            .tensor_variable(vec![1.0, 2.0, 3.0, 4.0], vec![4], true)
            .unwrap();
        let out = s.tensor_cumulative_trapezoid(y, None, 0).unwrap();
        let loss = s.tensor_sum(out).unwrap();
        let report = s.tensor_backward(loss).unwrap();
        let grad = s
            .tensor_gradient(&report, y)
            .expect("cumulative_trapezoid must propagate gradient through y");
        let expected = [1.5_f64, 2.5, 1.5, 0.5];
        for (i, (&g, &e)) in grad.iter().zip(expected.iter()).enumerate() {
            assert!(
                (g - e).abs() < 1e-12,
                "cumulative_trapezoid grad[{i}] = {g}, expected {e}"
            );
        }
    }

