        let out = s.tensor_nanmedian(input).unwrap();
        let vals = s.tensor_values(out).unwrap();
        // Non-NaN values: [1, 3, 2] sorted = [1, 2, 3], median = 2
        assert!((vals[0] - 2.0).abs() < 1e-10);
