        assert!((vals[0] - 0.5).abs() < 1e-10); // ndtr(0) = 0.5
        assert!((vals[1] - 0.8413447).abs() < 1e-5); // ndtr(1)
        assert!((vals[2] - 0.1586553).abs() < 1e-5); // ndtr(-1) = 1 - ndtr(1)
        assert!((vals[3] - 0.9772499).abs() < 1e-5); // ndtr(2)
