        let vals = s.tensor_values(result).unwrap();
        assert!((vals[0] - (-std::f64::consts::LN_2)).abs() < 1e-5);
        assert!((vals[1] - (-0.172754)).abs() < 1e-5);
        assert!((vals[2] - (-1.841022)).abs() < 1e-5);
